INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('uízo a outra pessoa ou ao Estado, ou de obter para si ou para outra pessoa benefício ilegítimo, destruir, danificar, tornar não utilizável, fizer desaparecer, dissimular ou subtrair documento ou notação técnica, de que não pode ou não pode exclusivamente dispor, ou de que outra pessoa pode legalmente exigir a entrega ou apresentação, é punido com pena de prisão até três anos ou com pena de multa. 
  2 - A tentativa é punível. 
  3 - É correspondentemente aplicável o disposto no n.º 4 do artigo 256.º 
  4 - Quando sejam particulares os ofendidos, o procedimento criminal depende de queixa. 
  Artigo 260.º 
  Atestado falso 
  1 - O médico, dentista, enfermeiro, parteira, dirigente ou empregado de laboratório ou de instituição de investigação que sirva fins médicos, ou pessoa encarregada de fazer autópsias, que passar atestado ou certificado que sabe não corresponder à verdade, sobre o estado do corpo ou da saúde física ou mental, o nascimento ou a morte de uma pessoa, destinado a fazer fé perante autoridade pública ou a prejudicar interesses de outra pessoa, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  2 - Na mesma pena incorre o veterinário que passar atestados nos termos e com os fins descritos no número anterior relativamente a animais. 
  3 - Na mesma pena incorrem as pessoas referidas nos números anteriores que passarem atestado ou certificado ignorando se correspondem à verdade os factos deles constantes. 
  4 - Na mesma pena incorre quem passar atestado ou certificado referido nos n.os 1 e 2 arrogando-se falsamente as qualidades ou funções neles referidas. 
  5 - Quem fizer uso dos referidos certificados ou atestados falsos, com o fim de enganar autoridade pública ou prejudicar interesses de outra pessoa, é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  Artigo 261.º 
  Uso de documento de identificação ou de viagem alheio 
  1 - Quem, com intenção de causar prejuízo a outra pessoa ou ao Estado, de obter para si ou para outra pessoa benefício ilegítimo, ou de preparar, facilitar, executar ou encobrir outro crime, utilizar documento de identificação ou de viagem emitido a favor de outra pessoa, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  2 - Na mesma pena incorre quem, com intenção de tornar possível o facto descrito no número anterior, facultar documento de identificação ou de viagem a pessoa a favor de quem não foi emitido. 
  SECÇÃO III 
  Falsificação de moeda, título de crédito e valor selado 
  Artigo 262.º 
  Contrafacção de moeda 
  1 - Quem praticar contrafacção de moeda, com intenção de a pôr em circulação como legítima, é punido com pena de prisão de três a doze anos. 
  2 - Quem, com a intenção de a pôr em circulação, falsificar ou alterar o valor facial de moeda legítima para valor superior é punido com pena de prisão de dois a oito anos. 
  Artigo 263.º 
  Depreciação do valor de moeda metálica 
  1 - Quem, com intenção de a pôr em ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('circulação como íntegra, depreciar moeda metálica legítima, diminuindo por qualquer modo o seu valor, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  2 - Com a mesma pena é punido quem, sem autorização legal e com intenção de a passar ou pôr em circulação, fabricar moeda metálica com o mesmo ou com maior valor que o da legítima. 
  3 - A tentativa é punível. 
  Artigo 264.º 
  Passagem de moeda falsa de concerto com o falsificador 
  1 - Nas penas indicadas nos artigos 262.º e 263.º incorre quem, concertando-se com o agente dos factos neles descritos, passar ou puser em circulação por qualquer modo, incluindo a exposição à venda, as ditas moedas. 
  2 - A tentativa é punível. 
  Artigo 265.º 
  Passagem de moeda falsa 
  1 - Quem, por qualquer modo, incluindo a exposição à venda, passar ou puser em circulação: 
  a) Como legítima ou intacta, moeda falsa ou falsificada; 
  b) Moeda metálica depreciada, pelo seu pleno valor; ou 
  c) Moeda metálica com o mesmo ou maior valor que o da legítima, mas fabricada sem autorização legal; 
  é punido, no caso da alínea a), com pena de prisão até cinco anos e, no caso das alíneas b) e c), com pena de prisão até um ano ou com pena de multa até 120 dias. 
  2 - Se o agente só tiver conhecimento de que a moeda é falsa ou falsificada depois de a ter recebido, é punido: 
  a) No caso da alínea a) do número anterior, com prisão até um ano ou multa até 240 dias; 
  b) No caso das alíneas b) e c) do número anterior com pena de multa até 90 dias. 
  3 - No caso da alínea a) do n.º 1, a tentativa é punível. 
  Artigo 266.º 
  Aquisição de moeda falsa para ser posta em circulação 
  1 - Quem adquirir, receber em depósito, transportar, exportar, importar ou por outro modo introduzir em território português, para si ou para outra pessoa, com intenção de, por qualquer meio, incluindo a exposição à venda, a passar ou pôr em circulação: 
  a) Como legítima ou intacta, moeda falsa ou falsificada; 
  b) Moeda metálica depreciada, pelo seu pleno valor; ou 
  c) Moeda metálica com o mesmo ou maior valor do que o da legítima, mas fabricada sem autorização legal; 
  é punido, no caso da alínea a), com pena de prisão até três anos ou com pena de multa e, no caso das alíneas b) e c), com pena de prisão até seis meses ou com pena de multa até 60 dias. 
  2 - A tentativa é punível. 
  Artigo 267.º 
  Títulos equiparados a moeda 
  1 - Para efeitos do disposto nos artigos 262.º a 266.º, são equiparados a moeda: 
  a) Os títulos de crédito nacionais e estrangeiros constantes, por força da lei, de um tipo de papel e de impressão especialmente destinados a garanti-los contra o perigo de imitações e que, pela sua natureza e finalidade, não possam, só por si, deixar de incorporar um valor patrimonial; 
  b) Os bilhetes ou fracções da lotaria nacional; e 
  c) Os cartões de garantia ou de crédito. 
  2 - O disposto no número anterior não abrange a falsificação relativamente a elementos a cuja garantia e ident','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ificação especialmente se não destine o uso do papel ou da impressão. 
  Artigo 268.º 
  Contrafacção de valores selados 
  1 - Quem, com intenção de os empregar ou de, por qualquer forma, incluindo a exposição à venda, os pôr em circulação como legítimos ou intactos, praticar contrafacção ou falsificação de valores selados ou timbrados cujo fornecimento seja exclusivo do Estado Português, nomeadamente papel selado de letra, selos fiscais ou postais, é punido com pena de prisão de um a cinco anos. 
  2 - Quem: 
  a) Empregar como legítimos ou intactos os referidos valores selados ou timbrados, quando falsos ou falsificados; ou 
  b) Com a intenção referida no n.º 1, adquirir, receber em depósito, importar ou por outro modo introduzir em território português, para si ou para outra pessoa, os referidos valores selados ou timbrados, quando falsos ou falsificados; 
  é punido com pena de prisão até três anos ou com pena de multa. 
  3 - Se, no caso da alínea a) do número anterior, o agente só tiver tido conhecimento de que os valores selados ou timbrados são falsos ou falsificados depois de os ter recebido, é punido com pena de multa até 90 dias. 
  4 - Se a falsificação consistir em fazer desaparecer dos referidos valores selados ou timbrados o sinal de já haverem servido, o agente é punido com pena de multa até 60 dias. 
  SECÇÃO IV 
  Falsificação de cunhos, pesos e objectos análogos 
  Artigo 269.º 
  Contrafacção de selos, cunhos, marcas ou chancelas 
  1 - Quem, com intenção de os empregar como autênticos ou intactos, contrafizer ou falsificar selos, cunhos, marcas ou chancelas de qualquer autoridade ou repartição pública é punido com pena de prisão de um a cinco anos. 
  2 - Quem, com a referida intenção, adquirir, receber em depósito, importar, ou por outro modo introduzir em território português, para si ou para outra pessoa, os objectos referidos no número anterior, quando falsos ou falsificados, é punido com pena de prisão até três anos ou com pena de multa. 
  3 - Quem, com intenção de causar prejuízo a outra pessoa ou ao Estado, utilizar, sem autorização de quem de direito, objectos referidos no n.º 1, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  Artigo 270.º 
  Pesos e medidas falsos 
  1 - Quem, com intenção de causar prejuízo a outra pessoa ou ao Estado: 
  a) Apuser sobre pesos, medidas, balanças ou outros instrumentos de medida uma punção falsa ou tiver falsificado a existente; 
  b) Alterar, qualquer que seja a sua natureza, pesos, medidas, balanças ou outros instrumentos de medida, que estejam sujeitos legalmente à existência de uma punção; ou 
  c) Utilizar pesos, medidas, balanças ou outros instrumentos de medida falsos ou falsificados; 
  é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  2 - A tentativa é punível. 
  SECÇÃO V 
  Disposição comum 
  Artigo 271.º 
  Actos preparatórios 
  1 - Quem preparar a execução dos actos referidos nos artigos 256.º, 262.º, 263','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('.º, no n.º 1 do artigo 268.º, no n.º 1 do artigo 269.º, ou no artigo 270.º, fabricando, importando, adquirindo para si ou para outra pessoa, fornecendo, expondo à venda ou retendo: 
  a) Formas, cunhos, clichés, prensas de cunhar, punções, negativos, fotografias ou outros instrumentos que, pela sua natureza, são utilizáveis para realizar crimes; ou 
  b) Papel, holograma ou outro elemento igual ou susceptível de se confundir com os que são particularmente fabricados para evitar imitações ou utilizados no fabrico de documento autêntico ou de igual valor, moeda, título de crédito ou valor selado; 
  é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  2 - É correspondentemente aplicável à falsificação dos títulos constantes do artigo 267.º o disposto no número anterior. 
  3 - Não é punível pelos números anteriores quem voluntariamente: 
  a) Abandonar a execução do acto preparado e prevenir o perigo, por ele causado, de que outra pessoa continue a preparar o acto ou o execute, ou se esforçar seriamente nesse sentido, ou impedir a consumação; e 
  b) Destruir ou inutilizar os meios ou objectos referidos nos números anteriores, ou der à autoridade pública conhecimento deles ou a ela os entregar. 
  CAPÍTULO III 
  Dos crimes de perigo comum 
  Artigo 272.º 
  Incêndios, explosões e outras condutas especialmente perigosas 
  1 - Quem: 
  a) Provocar incêndio de relevo, nomeadamente pondo fogo a edifício, construção ou meio de transporte; 
  b) Provocar explosão por qualquer forma, nomeadamente mediante utilização de explosivos; 
  c) Libertar gases tóxicos ou asfixiantes; 
  d) Emitir radiações ou libertar substâncias radioactivas; 
  e) Provocar inundação, desprendimento de avalanche, massa de terra ou de pedras; ou 
  f) Provocar desmoronamento ou desabamento de construção; 
  e criar deste modo perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado, é punido com pena de prisão de três a dez anos. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão de um a oito anos. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até cinco anos. 
  Artigo 273.º 
  Energia nuclear 
  Se os factos descritos no artigo anterior forem praticados mediante libertação de energia nuclear, o agente é punido com pena de prisão: 
  a) De cinco a quinze anos no caso do n.º 1; 
  b) De três a dez anos no caso do n.º 2; 
  c) De um a oito anos no caso do n.º 3. 
  Artigo 274.º 
  Incêndio florestal 
  1 - Quem provocar incêndio em floresta, mata, arvoredo ou seara, próprias ou alheias, é punido com pena de prisão de um a oito anos. 
  2 - Se, através da conduta referida no número anterior, o agente: 
  a) Criar perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado; 
  b) Deixar a vítima em situação económica difícil; ou 
  c) Actu','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ar com intenção de obter benefício económico; 
  é punido com pena de prisão de três a doze anos. 
  3 - Se o perigo previsto na alínea a) do n.º 2 for criado por negligência, o agente é punido com pena de prisão de dois a dez anos. 
  4 - Se a conduta prevista no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até três anos ou com pena de multa. 
  5 - Se a conduta prevista no número anterior for praticada por negligência grosseira ou criar perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado, o agente é punido com pena de prisão até cinco anos. 
  6 - Quem impedir o combate aos incêndios referidos nos números anteriores é punido com pena de prisão de um a oito anos. 
  7 - Quem dificultar a extinção dos incêndios referidos nos números anteriores, designadamente destruindo ou tornando inutilizável o material destinado a combatê-los, é punido com pena de prisão de um a cinco anos. 
  8 - Não é abrangida pelo disposto nos n.os 1 a 5 a realização de trabalhos e outras operações que, segundo os conhecimentos e a experiência da técnica florestal, se mostrarem indicados e forem levados a cabo, de acordo com as regras aplicáveis, por pessoa qualificada ou devidamente autorizada, para combater incêndios, prevenir, debelar ou minorar a deterioração do património florestal ou garantir a sua defesa ou conservação. 
  9 - Quando qualquer dos crimes previstos nos números anteriores for cometido por inimputável, é aplicável a medida de segurança prevista no artigo 91.º, sob a forma de internamento intermitente e coincidente com os meses de maior risco de ocorrência de fogos. 
  Artigo 275.º 
  Actos preparatórios Quem, para preparar a execução de um dos crimes previstos nos artigos 272.º a 274.º, fabricar, dissimular, adquirir para si ou para outra pessoa, entregar, detiver ou importar substância explosiva ou capaz de produzir explosão nuclear, radioactiva ou própria para fabricação de gases tóxicos ou asfixiantes, ou aparelhagem necessária para a execução de tais crimes, é punido com pena de prisão até três anos ou com pena de multa. 
  Artigo 276.º 
  Instrumentos de escuta telefónica 
  Quem importar, fabricar, guardar, comprar, vender, ceder ou adquirir a qualquer título, transportar, distribuir ou detiver instrumento ou aparelhagem especificamente destinados à montagem de escuta telefónica, ou à violação de correspondência ou de telecomunicações, fora das condições legais ou em contrário das prescrições da autoridade competente, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  Artigo 277.º 
  Infracção de regras de construção, dano em instalações e perturbação de serviços 
  1 - Quem: 
  a) No âmbito da sua actividade profissional infringir regras legais, regulamentares ou técnicas que devam ser observadas no planeamento, direcção ou execução de construção, demolição ou instalação, ou na sua modificação ou conservação; 
  b) Destruir, danific','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ar ou tornar não utilizável, total ou parcialmente, aparelhagem ou outros meios existentes em local de trabalho e destinados a prevenir acidentes, ou, infringindo regras legais, regulamentares ou técnicas, omitir a instalação de tais meios ou aparelhagem; 
  c) Destruir, danificar ou tornar não utilizável, total ou parcialmente, instalação para aproveitamento, produção, armazenamento, condução ou distribuição de água, óleo, gasolina, calor, electricidade, gás ou energia nuclear, ou para protecção contra forças da natureza; ou 
  d) Impedir ou perturbar a exploração de serviços de comunicações ou de fornecimento ao público de água, luz, energia ou calor, subtraindo ou desviando, destruindo, danificando ou tornando não utilizável, total ou parcialmente, coisa ou energia que serve tais serviços; 
  e criar deste modo perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado, é punido com pena de prisão de um a oito anos. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão até cinco anos. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até três anos ou com pena de multa. 
  Artigo 278.º 
  Danos contra a natureza 
  1 - Quem, não observando disposições legais, regulamentares ou obrigações impostas pela autoridade competente em conformidade com aquelas disposições: 
  a) Eliminar exemplares de fauna ou flora em número significativo ou de espécie protegida ou ameaçada de extinção; 
  b) Destruir habitat natural protegido ou habitat natural causando a este perdas em espécies de fauna ou flora selvagens legalmente protegidas ou em número significativo; 
  c) Afectar gravemente recursos do subsolo; 
  é punido com pena de prisão até três anos ou com pena de multa até 600 dias. 
  2 - Quem comercializar ou detiver para comercialização exemplar de fauna ou flora de espécie protegida, vivo ou morto, bem como qualquer parte ou produto obtido a partir daquele, é punido com pena de prisão até seis meses ou com pena de multa até 120 dias. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até um ano ou com pena de multa. 
  Artigo 279.º 
  Poluição 
  1 - Quem, não observando disposições legais, regulamentares ou obrigações impostas pela autoridade competente em conformidade com aquelas disposições: 
  a) Poluir águas ou solos ou, por qualquer forma, degradar as suas qualidades; 
  b) Poluir o ar mediante utilização de aparelhos técnicos ou de instalações; ou 
  c) Provocar poluição sonora mediante utilização de aparelhos técnicos ou de instalações, em especial de máquinas ou de veículos terrestres, fluviais, marítimos ou aéreos de qualquer natureza; 
  de forma grave, é punido com pena de prisão até três anos ou com pena de multa até 600 dias. 
  2 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' prisão até um ano ou com pena de multa. 
  3 - Para os efeitos dos números anteriores, o agente actua de forma grave quando: 
  a) Prejudicar, de modo duradouro, o bem-estar das pessoas na fruição da natureza; 
  b) Impedir, de modo duradouro, a utilização de recurso natural; ou 
  c) Criar o perigo de disseminação de microrganismo ou substância prejudicial para o corpo ou saúde das pessoas. 
  Artigo 280.º 
  Poluição com perigo comum 
  Quem, mediante conduta descrita nas alíneas do n.º 1 do artigo anterior, criar perigo para a vida ou para a integridade física de outrem, para bens patrimoniais alheios de valor elevado ou para monumentos culturais ou históricos, é punido com pena de prisão: 
  a) De um a oito anos, se a conduta e a criação do perigo forem dolosas; 
  b) Até cinco anos, se a conduta for dolosa e a criação do perigo ocorrer por negligência. 
  Artigo 281.º 
  Perigo relativo a animais ou vegetais 
  1 - Quem: 
  a) Difundir doença, praga, planta ou animal nocivos; ou 
  b) Manipular, fabricar ou produzir, importar, armazenar, ou puser à venda ou em circulação, alimentos ou forragens destinados a animais domésticos alheios; 
  e criar deste modo perigo de dano a número considerável de animais alheios, domésticos ou úteis ao homem, ou a culturas, plantações ou florestas alheias, é punido com pena de prisão até dois anos ou com pena de multa. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão até um ano ou com pena de multa até 240 dias. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até seis meses ou com pena de multa até 120 dias. 
  Artigo 282.º 
  Corrupção de substâncias alimentares ou medicinais 
  1 - Quem: 
  a) No aproveitamento, produção, confecção, fabrico, embalagem, transporte, tratamento, ou outra actividade que sobre elas incida, de substâncias destinadas a consumo alheio, para serem comidas, mastigadas, bebidas, para fins medicinais ou cirúrgicos, as corromper, falsificar, alterar, reduzir o seu valor nutritivo ou terapêutico ou lhes juntar ingredientes; ou 
  b) Importar, dissimular, vender, expuser à venda, tiver em depósito para venda ou, por qualquer forma, entregar ao consumo alheio substâncias que forem objecto de actividades referidas na alínea anterior ou que forem utilizadas depois do prazo da sua validade ou estiverem avariadas, corruptas ou alteradas por acção do tempo ou dos agentes a cuja acção estão expostas; 
  e criar deste modo perigo para a vida ou para a integridade física de outrem é punido com pena de prisão de um a oito anos. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão até cinco anos. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até três anos ou com pena de multa. 
  Artigo 283.º 
  Propagação de doença, alteração de análise ou de receituário 
  1 - ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Quem: 
  a) Propagar doença contagiosa; 
  b) Como médico ou seu empregado, enfermeiro ou empregado de laboratório, ou pessoa legalmente autorizada a elaborar exame ou registo auxiliar de diagnóstico ou tratamento médico ou cirúrgico, fornecer dados ou resultados inexactos; ou 
  c) Como farmacêutico ou empregado de farmácia fornecer substâncias medicinais em desacordo com o prescrito em receita médica; 
  e criar deste modo perigo para a vida ou perigo grave para a integridade física de outrem é punido com pena de prisão de um a oito anos. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão até cinco anos. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até três anos ou com pena de multa. 
  Artigo 284.º 
  Recusa de médico 
  O médico que recusar o auxílio da sua profissão em caso de perigo para a vida ou de perigo grave para a integridade física de outra pessoa, que não possa ser removido de outra maneira, é punido com pena de prisão até cinco anos. 
  Artigo 285.º 
  Agravação pelo resultado 
  Se dos crimes previstos nos artigos 272.º a 274.º, 277.º, 280.º, ou 282.º a 284.º resultar morte ou ofensa à integridade física grave de outra pessoa, o agente é punido com a pena que ao caso caberia, agravada de um terço nos seus limites mínimo e máximo. 
  Artigo 286.º 
  Atenuação especial e dispensa de pena 
  Se, nos casos previstos nos artigos 272.º a 274.º, 277.º, ou 280.º a 284.º, o agente remover voluntariamente o perigo antes de se ter verificado dano considerável, a pena é especialmente atenuada ou pode ter lugar a dispensa de pena. 
  CAPÍTULO IV 
  Dos crimes contra a segurança das comunicações 
  Artigo 287.º 
  Captura ou desvio de aeronave, navio, comboio 
  ou veículo de transporte colectivo de passageiros 
  1 - Quem se apossar de, ou desviar da sua rota normal, aeronave em voo, ou navio em curso de navegação, nos quais se encontrem pessoas, é punido com pena de prisão de cinco a quinze anos. 
  2 - Quem se apossar de comboio em circulação no qual se encontrem pessoas, ou o desviar do seu trajecto normal, é punido com pena de prisão de dois a dez anos. 
  3 - Quem se apossar de, ou desviar da sua rota normal, veículo de transporte colectivo de passageiros em trânsito é punido com pena de prisão de um a oito anos. 
  4 - Considera-se: 
  a) Uma aeronave em voo desde o momento em que, terminado o embarque, tenham sido fechadas todas as portas exteriores até ao momento em que uma dessas portas seja aberta para o desembarque. Em caso de aterragem forçada o voo é considerado como estando a decorrer até que a autoridade competente se responsabilize pela aeronave, bem como pelas pessoas e bens a bordo; 
  b) Um navio em curso de navegação desde o momento em que o pessoal de terra ou a tripulação comecem as operações preparatórias de uma determinada viagem até à chegada a local de destino; 
  c) Um comboio em curso de circulaç','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ão desde o momento em que, terminado o embarque de passageiros, se inicia a marcha até ao momento em que deva ter lugar o desembarque; 
  d) Um veículo de transporte colectivo de passageiros em trânsito desde o momento em que, terminado o embarque de passageiros, se inicia a marcha até ao momento em que deva ter lugar o desembarque. 
  Artigo 288.º 
  Atentado à segurança de transporte por ar, água ou caminho de ferro 
  1 - Quem atentar contra a segurança de transporte por ar, água ou caminho de ferro: 
  a) Destruindo, suprimindo, danificando ou tornando não utilizável instalação, material ou sinalização; 
  b) Colocando obstáculo ao funcionamento ou circulação; 
  c) Dando falso aviso ou sinal; ou 
  d) Praticando acto do qual possa resultar desastre; 
  é punido com pena de prisão de um a oito anos. 
  2 - Se, através da conduta referida no número anterior, o agente criar perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado, é punido com pena de prisão de três a dez anos. 
  3 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão de dois a oito anos. 
  4 - Se a conduta referida no n.º 2 for praticada por negligência, o agente é punido com pena de prisão até cinco anos. 
  Artigo 289.º 
  Condução perigosa de meio de transporte por ar, água ou caminho de ferro 
  1 - Quem conduzir veículo destinado a transporte por ar, água ou caminho de ferro, não estando em condições de o fazer com segurança ou violando grosseiramente as regras de condução, e criar deste modo perigo para a vida ou para a integridade física de outrem ou para bens patrimoniais alheios de valor elevado, é punido com pena de prisão de um a oito anos. 
  2 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão até cinco anos. 
  3 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até três anos ou com pena de multa. 
  Artigo 290.º 
  Atentado à segurança de transporte rodoviário 
  1 - Quem atentar contra a segurança de transporte rodoviário: 
  a) Destruindo, suprimindo, danificando ou tornando não utilizável via de comunicação, material circulante, obra de arte, instalação ou sinalização; 
  b) Colocando obstáculo ao funcionamento ou à circulação; 
  c) Dando falso aviso ou sinal; ou 
  d) Praticando acto do qual possa resultar desastre; 
  é punido com pena de prisão de um a cinco anos. 
  2 - Se, através da conduta referida no número anterior, o agente criar perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado, é punido com pena de prisão de dois a oito anos. 
  3 - Se o perigo referido no número anterior for criado por negligência, o agente é punido com pena de prisão de um a cinco anos. 4 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até dois anos ou com','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' pena de multa. 
  Artigo 291.º 
  Condução perigosa de veículo rodoviário 
  1 - Quem conduzir veículo, com ou sem motor, em via pública ou equiparada: 
  a) Não estando em condições de o fazer com segurança, por se encontrar em estado de embriaguez ou sob influência de álcool, estupefacientes, substâncias psicotrópicas ou produtos com efeito análogo, ou por deficiência física ou psíquica ou fadiga excessiva; ou 
  b) Violando grosseiramente as regras da circulação rodoviária relativas à prioridade, à obrigação de parar, à ultrapassagem, à mudança de direcção, à passagem de peões, à inversão do sentido de marcha em auto-estradas ou em estradas fora de povoações, à marcha atrás em auto-estradas ou em estradas fora de povoações, ao limite de velocidade ou à obrigatoriedade de circular na faixa de rodagem da direita; 
  e criar deste modo perigo para a vida ou para a integridade física de outrem, ou para bens patrimoniais alheios de valor elevado, é punido com pena de prisão até três anos ou com pena de multa. 
  2 - Quem conduzir veículo, com ou sem motor, em via pública ou equiparada e nela realizar actividades não autorizadas, de natureza desportiva ou análoga, que violem as regras previstas na alínea b) do número anterior, é punido com pena de prisão até três anos ou com pena de multa. 
  3 - Se o perigo referido no n.º 1 for criado por negligência, o agente é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  4 - Se a conduta referida no n.º 1 for praticada por negligência, o agente é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  Artigo 292.º 
  Condução de veículo em estado de embriaguez ou sob a influência de estupefacientes ou substâncias psicotrópicas 
  1 - Quem, pelo menos por negligência, conduzir veículo, com ou sem motor, em via pública ou equiparada, com uma taxa de álcool no sangue igual ou superior a 1,2 g/l, é punido com pena de prisão até um ano ou com pena de multa até 120 dias, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - Na mesma pena incorre quem, pelo menos por negligência, conduzir veículo, com ou sem motor, em via pública ou equiparada, não estando em condições de o fazer com segurança, por se encontrar sob influência de estupefacientes, substâncias psicotrópicas ou produtos com efeito análogo perturbadores da aptidão física, mental ou psicológica. 
  Artigo 293.º 
  Lançamento de projéctil contra veículo 
  Quem arremessar projéctil contra veículo em movimento, de transporte por ar, água ou terra, é punido com pena de prisão até um ano ou com pena de multa até 120 dias, se pena mais grave lhe não couber por força de outra disposição legal. 
  Artigo 294.º 
  Agravação, atenuação especial e dispensa de pena 
  1 - Quando os crimes previstos nos artigos 291.º e 292.º forem cometidos no exercício da respectiva actividade por condutores de veículos de transporte escolar, ligeiros de aluguer para transporte público de aluguer, pesados de p','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('assageiros ou de mercadorias ou de transporte de mercadorias perigosas, o agente é punido com a pena que ao caso caberia, agravada de um terço nos seus limites mínimo e máximo. 
  2 - É aplicável o disposto no número anterior aos condutores de veículos de socorro ou de emergência que cometam os crimes previstos na alínea a) do n.º 1 e nos n.os 2 e 3 do artigo 291.º e no artigo 292.º 
  3 - Aos casos previstos nos artigos 287.º a 291.º aplica-se o disposto nos artigos 285.º e 286.º, ainda que com as agravações previstas nos números anteriores. 
  CAPÍTULO V 
  Dos crimes contra a ordem e a tranquilidade públicas 
  SECÇÃO I 
  Dos crimes de anti-socialidade perigosa 
  Artigo 295.º 
  Embriaguez e intoxicação 
  1 - Quem, pelo menos por negligência, se colocar em estado de inimputabilidade derivado da ingestão ou consumo de bebida alcoólica ou de substância tóxica e, nesse estado, praticar um facto ilícito típico é punido com pena de prisão até cinco anos ou com pena de multa até 600 dias. 
  2 - A pena não pode ser superior à prevista para o facto ilícito típico praticado. 
  3 - O procedimento criminal depende de queixa ou de acusação particular se o procedimento pelo facto ilícito típico praticado também dependesse de uma ou de outra. Artigo 296.º 
  Utilização de menor na mendicidade 
  Quem utilizar menor ou pessoa psiquicamente incapaz na mendicidade é punido com pena de prisão até três anos. 
  SECÇÃO II 
  Dos crimes contra a paz pública 
  Artigo 297.º 
  Instigação pública a um crime 
  1 - Quem, em reunião pública, através de meio de comunicação social, por divulgação de escrito ou outro meio de reprodução técnica, provocar ou incitar à prática de um crime determinado é punido com pena de prisão até três anos ou com pena de multa, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - É correspondentemente aplicável o disposto no n.º 2 do artigo 295.º 
  Artigo 298.º 
  Apologia pública de um crime 
  1 - Quem, em reunião pública, através de meio de comunicação social, por divulgação de escrito ou outro meio de reprodução técnica, recompensar ou louvar outra pessoa por ter praticado um crime, de forma adequada a criar perigo da prática de outro crime da mesma espécie, é punido com pena de prisão até seis meses ou com pena de multa até 60 dias, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - É correspondentemente aplicável o disposto no n.º 2 do artigo 295.º 
  Artigo 299.º 
  Associação criminosa 
  1 - Quem promover ou fundar grupo, organização ou associação cuja finalidade ou actividade seja dirigida à prática de um ou mais crimes é punido com pena de prisão de um a cinco anos. 
  2 - Na mesma pena incorre quem fizer parte de tais grupos, organizações ou associações ou quem os apoiar, nomeadamente fornecendo armas, munições, instrumentos de crime, guarda ou locais para as reuniões, ou qualquer auxílio para que se recrutem novos elementos. 
  3 - Quem chefiar ou dirigir os grupos, or','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ganizações ou associações referidos nos números anteriores é punido com pena de prisão de dois a oito anos. 
  4 - As penas referidas podem ser especialmente atenuadas ou não ter lugar a punição se o agente impedir ou se esforçar seriamente por impedir a continuação dos grupos, organizações ou associações, ou comunicar à autoridade a sua existência de modo a esta poder evitar a prática de crimes. 
  5 - Para os efeitos do presente artigo, considera-se que existe grupo, organização ou associação quando esteja em causa um conjunto de, pelo menos, três pessoas, actuando concertadamente durante um certo período de tempo. 
  Artigo 300.º 
  Organizações terroristas 
  (Revogado pela Lei n.º 52/2003, de 22 de Agosto.) 
  Artigo 301.º 
  Terrorismo 
  (Revogado pela Lei n.º 52/2003, de 22 de Agosto.) 
  Artigo 302.º 
  Participação em motim 
  1 - Quem tomar parte em motim durante o qual forem cometidas colectivamente violências contra pessoas ou contra a propriedade é punido com pena de prisão até um ano ou com pena de multa até 120 dias, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - Se o agente tiver provocado ou dirigido o motim, é punido com pena de prisão até três anos ou com pena de multa. 
  3 - O agente não é punido se se tiver retirado do motim por ordem ou admoestação da autoridade sem ter cometido ou provocado violência. 
  Artigo 303.º 
  Participação em motim armado 
  1 - Os limites mínimo e máximo das penas previstas nos n.os 1 e 2 do artigo anterior são elevados ao dobro se o motim for armado. 
  2 - Considera-se armado o motim em que um dos intervenientes é portador de arma de fogo ostensiva, ou em que vários dos participantes são portadores de armas de fogo, ostensivas ou ocultas, ou de objectos, ostensivos ou ocultos, susceptíveis de serem utilizados como tal. 
  3 - Para efeito do disposto no número anterior não se considera armado o motim: 
  a) Em que as armas são trazidas acidentalmente e sem intenção de as utilizar; ou 
  b) Quando os participantes que tragam armas imediatamente se retirarem ou forem expulsos. 
  4 - Quem trouxer arma sem conhecimento dos outros é punido como se efectivamente participasse em motim armado. 
  5 - É correspondentemente aplicável o disposto no n.º 3 do artigo anterior. 
  Artigo 304.º 
  Desobediência a ordem de dispersão de reunião pública 
  1 - Quem não obedecer a ordem legítima de se retirar de ajuntamento ou reunião pública, dada por autoridade competente, com advertência de que a desobediência constitui crime, é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  2 - Se o desobediente for promotor da reunião ou ajuntamento, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  Artigo 305.º 
  Ameaça com prática de crime 
  Quem, mediante ameaça com a prática de crime, ou fazendo crer simuladamente que um crime vai ser cometido, causar alarme ou inquietação entre a população é punido com pena de prisão até dois ano','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s ou com pena de multa até 240 dias. 
  Artigo 306.º 
  Abuso e simulação de sinais de perigo 
  Quem utilizar abusivamente sinal ou chamada de alarme ou de socorro, ou simuladamente fizer crer que é necessário auxílio alheio em virtude de desastre, perigo ou situação de necessidade colectiva, é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  SECÇÃO III 
  Dos crimes contra sinais de identificação 
  Artigo 307.º 
  Abuso de designação, sinal ou uniforme 
  1 - Quem, ilegitimamente e com intenção de fazer crer que lhe pertencem, utilizar ou usar designação, sinal, uniforme ou traje próprios de função do serviço público, nacional ou estrangeiro, é punido com pena de prisão até seis meses ou com pena de multa até 60 dias. 
  2 - Se a designação, sinal, uniforme ou traje for privativo de pessoa que exerça autoridade pública, o agente é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  TÍTULO V 
  Dos crimes contra o Estado 
  CAPÍTULO I 
  Dos crimes contra a segurança do Estado 
  SECÇÃO I 
  Dos crimes contra a soberania nacional 
  SUBSECÇÃO I 
  Dos crimes contra a independência e a integridade nacionais 
  Artigo 308.º 
  Traição à Pátria 
  Aquele que, por meio de usurpação ou abuso de funções de soberania: 
  a) Tentar separar da Mãe-Pátria ou entregar a país estrangeiro ou submeter à soberania estrangeira todo o território português ou parte dele; ou 
  b) Ofender ou puser em perigo a independência do País; 
  é punido com pena de prisão de dez a vinte anos. 
  Artigo 309.º 
  Serviço militar em forças armadas inimigas 
  (Revogado pela Lei n.º 100/2003, de 15 de Novembro.) 
  Artigo 310.º 
  Inteligências com o estrangeiro para provocar guerra 
  (Revogado pela Lei n.º 100/2003, de 15 de Novembro.) 
  Artigo 311.º 
  Prática de actos adequados a provocar guerra 
  (Revogado pela Lei n.º 100/2003, de 15 de Novembro.) 
  Artigo 312.º 
  Inteligências com o estrangeiro para constranger 
  o Estado Português 
  (Revogado pela Lei n.º 100/2003, de 15 de Novembro.) 
  Artigo 313.º 
  Ajuda a forças armadas inimigas 
  (Revogado pela Lei n.º 100/2003, de 15 de Novembro.) 
  Artigo 314.º 
  Campanha contra esforço de guerra 
  (Revogado pela Lei n.º 100/2003, de 15 de Novembro.) 
  Artigo 315.º 
  Sabotagem contra a defesa nacional 
  (Revogado pela Lei n.º 100/2003, de 15 de Novembro.) 
  Artigo 316.º 
  Violação de segredo de Estado 
  1 - Quem, pondo em perigo interesses do Estado Português relativos à independência nacional, à unidade e à integridade do Estado ou à sua segurança interna e externa, transmitir, tornar acessível a pessoa não autorizada, ou tornar público facto ou documento, plano ou objecto que devem, em nome daqueles interesses, manter-se secretos é punido com pena de prisão de dois a oito anos. 
  2 - Quem destruir, subtrair ou falsificar documento, plano ou objecto referido no número anterior, pondo em perigo interesses no mesmo número indicados, é punido com pena de prisão de','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' dois a oito anos. 
  3 - Se o agente praticar facto descrito nos números anteriores violando dever especificamente imposto pelo estatuto da sua função ou serviço, ou da missão que lhe foi conferida por autoridade competente, é punido com pena de prisão de três a dez anos. 
  4 - Se o agente praticar por negligência os factos referidos nos n.os 1 e 2, tendo acesso aos objectos ou segredos de Estado em razão da sua função ou serviço, ou da missão que lhe foi conferida por autoridade competente, é punido com pena de prisão até três anos. 
  Artigo 317.º 
  Espionagem 
  1 - Quem: 
  a) Colaborar com governo, associação, organização ou serviço de informações estrangeiros, ou com agente seu, com intenção de praticar facto referido no artigo anterior; ou 
  b) Recrutar, acolher ou receber agente que pratique facto referido no artigo anterior ou na alínea anterior, ou, de qualquer modo, favorecer a prática de tal facto; 
  é punido com pena de prisão de três a dez anos. 
  2 - Se o agente praticar facto descrito no número anterior violando dever especificamente imposto pelo estatuto da sua função ou serviço, ou da missão que lhe foi conferida por autoridade competente, é punido com pena de prisão de cinco a quinze anos. 
  Artigo 318.º 
  Meios de prova de interesse nacional 
  1 - Quem falsificar, subtrair, destruir, inutilizar, fizer desaparecer ou dissimular meio de prova sobre facto referente a relações entre Portugal e Estado estrangeiro ou organização internacional, adequado a pôr em perigo direitos ou interesses nacionais, é punido com pena de prisão de um a oito anos. 
  2 - Se a acção se traduzir em arrancar, deslocar, colocar falsamente, tornar irreconhecível ou, de qualquer modo, suprimir marcos, balizas ou outros sinais indicativos dos limites do território português o agente é punido com pena de prisão até três anos. 
  Artigo 319.º 
  Infidelidade diplomática 
  1 - Quem, representando oficialmente o Estado Português, com intenção de provocar prejuízo a direitos ou interesses nacionais: 
  a) Conduzir negócio de Estado com governo estrangeiro ou organização internacional; ou 
  b) Perante eles assumir compromissos sem para isso estar devidamente autorizado em nome de Portugal; 
  é punido com pena de prisão de um a oito anos. 
  2 - O procedimento criminal depende de participação do Governo Português. 
  Artigo 320.º 
  Usurpação de autoridade pública portuguesa 
  Quem, em território português, com usurpação de funções, exercer, a favor de Estado estrangeiro ou de agente deste, acto privativo de autoridade portuguesa, é punido com pena de prisão até cinco anos, se pena mais grave lhe não couber por força de outra disposição legal. 
  Artigo 321.º 
  Entrega ilícita de pessoa a entidade estrangeira 
  Quem, em território português, praticar factos conducentes à entrega ilícita de pessoa, nacional ou estrangeira, a Estado estrangeiro, a agente deste ou a qualquer entidade pública ou particular existente nesse Estado, usando para tal fim de','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' violência ou de fraude, é punido com pena de prisão até cinco anos, se pena mais grave lhe não couber por força de outra disposição legal. 
  SUBSECÇÃO II 
  Dos crimes contra Estados estrangeiros e organizações internacionais 
  Artigo 322.º 
  Crimes contra pessoa que goze de protecção internacional 
  1 - Quem atentar contra a vida, a integridade física ou a liberdade de pessoa que goze de protecção internacional, encontrando-se o ofendido em Portugal no desempenho de funções oficiais, é punido com pena de prisão de um a oito anos, se pena mais grave lhe não couber por forca de outra disposição legal. 
  2 - Quem ofender a honra de pessoa que goze de protecção internacional e se encontre nas condições referidas no número anterior é punido com pena de prisão até dois anos ou com pena de multa, se pena mais grave lhe não couber por força de outra disposição legal. 
  3 - Gozam de protecção internacional para efeito do disposto nos números anteriores: 
  a) Chefe de Estado, incluindo membro de órgão colegial que exerça, nos termos constitucionais, as funções de Chefe de Estado, Chefe de Governo ou Ministro dos Negócios Estrangeiros, bem como membros de família que os acompanhem; e 
  b) Representante ou funcionário de Estado estrangeiro ou agente de organização internacional que, no momento do crime, goze de protecção especial segundo o direito internacional, bem como membros de família que com ele vivam. 
  Artigo 323.º 
  Ultraje de símbolos estrangeiros 
  Quem, publicamente, por palavras, gestos, divulgação de escrito ou outro meio de comunicação com o público, injuriar bandeira oficial ou outro símbolo de soberania de Estado estrangeiro ou de organização internacional de que Portugal seja membro é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  Artigo 324.º 
  Condições de punibilidade e de procedibilidade 
  1 - O procedimento criminal pelos crimes previstos nesta subsecção depende, salvo tratado ou convenção internacional em contrário, de participação do Governo Português. Tratando-se de crime contra a honra é também necessário que seja feita participação pelo governo estrangeiro ou pelo representante da organização internacional. 
  2 - Relativamente a Estado estrangeiro, seu representante ou funcionário, é necessário à aplicação das disposições da presente subsecção que: 
  a) Portugal mantenha com o Estado estrangeiro relações diplomáticas; e 
  b) Haja reciprocidade no tratamento penal do facto, no momento da sua prática e do seu julgamento. 
  SECÇÃO II 
  Dos crimes contra a realização do Estado de direito 
  Artigo 325.º 
  Alteração violenta do Estado de direito 
  1 - Quem, por meio de violência ou ameaça de violência, tentar destruir, alterar ou subverter o Estado de direito constitucionalmente estabelecido é punido com pena de prisão de três a doze anos. 
  2 - Se o facto descrito no número anterior for praticado por meio de violência armada, o agente é punido com pena de prisão de cinco a quinze anos','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('. 
  3 - No caso previsto no número anterior a pena é especialmente atenuada se o agente, não tendo exercido funções de comando, se render sem opor resistência, ou entregar ou abandonar as armas antes ou imediatamente depois de advertência da autoridade. 
  Artigo 326.º 
  Incitamento à guerra civil ou à alteração violenta do Estado de direito 
  1 - Quem publicamente incitar habitantes do território português ou forças militares, militarizadas ou de segurança ao serviço de Portugal à guerra civil ou à prática da conduta referida no artigo anterior é punido com pena de prisão de um a oito anos. 
  2 - Se o facto descrito no número anterior for acompanhado de distribuição de armas, o agente é punido com pena de prisão de cinco a quinze anos. 
  Artigo 327.º 
  Atentado contra o Presidente da República 
  1 - Quem atentar contra a vida, a integridade física ou a liberdade do Presidente da República ou de quem constitucionalmente o substituir é punido com pena de prisão de cinco a quinze anos, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - Em caso de consumação do crime contra a vida, a integridade física ou a liberdade, o agente é punido com a pena correspondente ao crime praticado agravada de um terço nos seus limites mínimo e máximo. 
  Artigo 328.º 
  Ofensa à honra do Presidente da República 
  1 - Quem injuriar ou difamar o Presidente da República, ou quem constitucionalmente o substituir, é punido com pena de prisão até três anos ou com pena de multa. 
  2 - Se a injúria ou a difamação forem feitas por meio de palavras proferidas publicamente, de publicação de escrito ou de desenho, ou por qualquer meio técnico de comunicação com o público, o agente é punido com pena de prisão de seis meses a três anos ou com pena de multa não inferior a 60 dias. 
  3 - O procedimento criminal cessa se o Presidente da República expressamente declarar que dele desiste. 
  Artigo 329.º 
  Sabotagem 
  Quem destruir, impossibilitar o funcionamento ou desviar dos seus fins normais, definitiva ou temporariamente, total ou parcialmente, meios ou vias de comunicação, instalações de serviços públicos ou destinadas ao abastecimento e satisfação de necessidades vitais da população, infra-estruturas de relevante valor para a economia, a segurança ou a defesa nacional, com intenção de destruir, alterar ou subverter o Estado de direito constitucionalmente estabelecido, é punido com pena de prisão de três a dez anos. 
  Artigo 330.º 
  Incitamento à desobediência colectiva 
  1 - Quem, com intenção de destruir, alterar ou subverter pela violência o Estado de direito constitucionalmente estabelecido, incitar, em reunião pública ou por qualquer meio de comunicação com o público, à desobediência colectiva de leis de ordem pública, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  2 - Na mesma pena incorre quem, com a intenção referida no número anterior, publicamente ou por qualquer meio de comunicação com o público','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (': 
  a) Divulgar notícias falsas ou tendenciosas susceptíveis de provocar alarme ou inquietação na população; 
  b) Provocar ou tentar provocar, pelos meios referidos na alínea anterior, divisões no seio das Forças Armadas, entre estas e as forças militarizadas ou de segurança, ou entre qualquer destas e os órgãos de soberania; ou 
  c) Incitar à luta política pela violência. 
  Artigo 331.º 
  Ligações com o estrangeiro 
  Quem, com intenção de destruir, alterar ou subverter pela violência o Estado de direito constitucionalmente estabelecido, se puser em ligação com governo de Estado estrangeiro, com partido, associação, instituição ou grupo estrangeiro ou com algum dos seus agentes para: 
  a) Receber instruções, directivas, dinheiro ou valores; ou 
  b) Colaborar em actividades consistindo: 
  i) Na recolha, preparação ou divulgação pública de notícias falsas ou grosseiramente deformadas; 
  ii) No aliciamento de agentes ou em facilitar aquelas actividades, fornecendo local para reuniões, subsidiando-as ou fazendo a sua propaganda; 
  iii) Em promessas ou dádivas; ou 
  iv) Em ameaçar outra pessoa ou utilizar fraude contra ela; 
  é punido com pena de prisão até cinco anos, se pena mais grave lhe não couber por força de outra disposição legal. 
  Artigo 332.º 
  Ultraje de símbolos nacionais e regionais 
  1 - Quem publicamente, por palavras, gestos ou divulgação de escrito, ou por outro meio de comunicação com o público, ultrajar a República, a Bandeira ou o Hino Nacionais, as armas ou emblemas da soberania portuguesa, ou faltar ao respeito que lhes é devido, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  2 - Se os factos descritos no número anterior forem praticados contra as Regiões Autónomas, as Bandeiras ou Hinos Regionais, ou os emblemas da respectiva autonomia, o agente é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  Artigo 333.º 
  Coacção contra órgãos constitucionais 
  1 - Quem, por violência ou ameaça de violência, impedir ou constranger o livre exercício das funções de órgão de soberania ou de ministro da República é punido com pena de prisão de um a oito anos, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - Se os factos descritos no número anterior forem praticados contra órgão de governo próprio das Regiões Autónomas, o agente é punido com pena de prisão de um a cinco anos, se pena mais grave lhe não couber por força de outra disposição legal. 
  3 - Se os factos descritos no n.º 1 forem praticados contra órgão de autarquia local, o agente é punido com pena de prisão até três anos. 
  4 - Se os factos descritos no n.º 1 forem praticados: 
  a) Contra membro de órgão referido no n.º 1, o agente é punido com pena de prisão até cinco anos; 
  b) Contra membro de órgão referido no n.º 2, o agente é punido com pena de prisão até três anos; 
  c) Contra membro de órgão referido no n.º 3, o agente é punido com pena de prisão até dois anos. 
  Ar','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('tigo 334.º 
  Perturbação do funcionamento de órgão constitucional 
  Quem, com tumultos, desordens ou vozearias, perturbar ilegitimamente: 
  a) O funcionamento de órgão referido no n.º 1 ou no n.º 2 do artigo anterior, não sendo seu membro, é punido, respectivamente, com pena de prisão até três anos, ou com pena de prisão até um ano; 
  b) O exercício de funções de pessoa referida no n.º 4 do artigo anterior é punido com pena de prisão até dois anos no caso da alínea a) ou com pena de prisão até seis meses no caso da alínea b). 
  Artigo 335.º 
  Tráfico de influência 
  1 - Quem, por si ou por interposta pessoa, com o seu consentimento ou ratificação, solicitar ou aceitar, para si ou para terceiro, vantagem patrimonial ou não patrimonial, ou a sua promessa, para abusar da sua influência, real ou suposta, junto de qualquer entidade pública, é punido: 
  a) Com pena de prisão de seis meses a cinco anos, se pena mais grave lhe não couber por força de outra disposição legal, se o fim for o de obter uma qualquer decisão ilícita favorável; 
  b) Com pena de prisão até seis meses ou com pena de multa até 60 dias, se pena mais grave lhe não couber por força de outra disposição legal, se o fim for o de obter uma qualquer decisão lícita favorável. 
  2 - Quem, por si ou por interposta pessoa, com o seu consentimento ou ratificação, der ou prometer vantagem patrimonial ou não patrimonial às pessoas referidas no número anterior para os fins previstos na alínea a) é punido com pena de prisão até três anos ou com pena de multa. 
  SECÇÃO III 
  Dos crimes eleitorais 
  Artigo 336.º 
  Falsificação do recenseamento eleitoral 
  1 - Quem: 
  a) Provocar a sua inscrição no recenseamento eleitoral fornecendo elementos falsos; 
  b) Inscrever outra pessoa no recenseamento eleitoral sabendo que ela não tem o direito de aí se inscrever; 
  c) Impedir a inscrição de outra pessoa que sabe ter direito a inscrever-se; ou 
  d) Por qualquer outro modo falsificar o recenseamento eleitoral; 
  é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  2 - Quem, como membro de comissão de recenseamento, com intuito fraudulento, não proceder à elaboração ou à correcção dos cadernos eleitorais é punido com pena de prisão até três anos ou com pena de multa. 
  3 - A tentativa é punível. 
  Artigo 337.º 
  Obstrução à inscrição de eleitor 
  1 - Quem, por meio de violência, ameaça de violência ou artifício fraudulento, determinar eleitor a não se inscrever no recenseamento eleitoral ou a inscrever-se fora da unidade geográfica ou do local próprio, ou para além do prazo, é punido com pena de prisão até um ano ou com pena de multa até 120 dias, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - A tentativa é punível. 
  Artigo 338.º 
  Perturbação de assembleia eleitoral 
  1 - Quem por meio de violência, ameaça de violência ou participando em tumulto, desordem ou vozearia, impedir ou perturbar gravemente a realização, funcionamento ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ou apuramento de resultados de assembleia ou colégio eleitoral, destinados, nos termos da lei, à eleição de órgão de soberania, de deputado ao Parlamento Europeu, de órgão de Região Autónoma ou de autarquia local, ou a referendos é punido com pena de prisão até três anos ou com pena de multa. 
  2 - Quem entrar armado em assembleia ou colégio eleitoral, não pertencendo a força pública devidamente autorizada, é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  3 - A tentativa é punível. 
  Artigo 339.º 
  Fraude em eleição 
  1 - Quem, em eleição referida no n.º 1 do artigo anterior: 
  a) Votar em mais de uma secção ou assembleia de voto, mais de uma vez ou com várias listas na mesma secção ou assembleia de voto, ou actuar por qualquer forma que conduza a um falso apuramento do escrutínio; ou 
  b) Falsear o apuramento, a publicação ou a acta oficial do resultado da votação; 
  é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  2 - A tentativa é punível. 
  Artigo 340.º Coacção de eleitor 
  Quem, em eleição referida no n.º 1 do artigo 338.º, por meio de violência, ameaça de violência ou de grave mal, constranger eleitor a votar, o impedir de votar ou o forçar a votar num certo sentido, é punido com pena de prisão até cinco anos, se pena mais grave lhe não couber por força de outra disposição legal. 
  Artigo 341.º 
  Fraude e corrupção de eleitor 
  1 - Quem, em eleição referida no n.º 1 do artigo 338.º: 
  a) Mediante artifício fraudulento, levar eleitor a votar, o impedir de votar, ou o levar a votar em certo sentido; ou 
  b) Comprar ou vender voto; 
  é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  2 - A tentativa é punível. 
  Artigo 342.º 
  Violação do segredo de escrutínio 
  Quem, em eleição referida no n.º 1 do artigo 338.º, realizada por escrutínio secreto, violando disposição legal destinada a assegurar o segredo de escrutínio, tomar conhecimento ou der a outra pessoa conhecimento do sentido de voto de um eleitor é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  Artigo 343.º 
  Agravação 
  As penas previstas nos artigos desta secção, com ressalva da prevista no n.º 2 do artigo 336.º, são agravadas de um terço nos seus limites mínimo e máximo se o agente for membro de comissão recenseadora, de secção ou assembleia de voto, ou for delegado de partido político à comissão, secção ou assembleia. 
  SECÇÃO IV 
  Disposições comuns 
  Artigo 344.º 
  Actos preparatórios 
  Os actos preparatórios dos crimes previstos nos artigos 308.º a 317.º e nos artigos 325.º a 327.º são punidos com pena de prisão até três anos. 
  Artigo 345.º 
  Atenuação especial 
  Quando um crime previsto neste capítulo supuser a produção de um perigo, a pena é especialmente atenuada se o agente voluntariamente fizer diminuir por forma considerável o perigo produzido pela conduta ou o afastar. 
  Artigo 346.º 
  Penas acessórias 
  Quem for condenado por cri','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('me previsto no presente capítulo pode, atenta a concreta gravidade do facto e a sua projecção na idoneidade cívica do agente, ser incapacitado para eleger Presidente da República, membro de assembleia legislativa ou de autarquia local, para ser eleito como tal ou para ser jurado, por período de dois a dez anos. 
  CAPÍTULO II 
  Dos crimes contra a autoridade pública 
  SECÇÃO I 
  Da resistência e desobediência à autoridade pública 
  Artigo 347.º 
  Resistência e coacção sobre funcionário 
  1 - Quem empregar violência, incluindo ameaça grave ou ofensa à integridade física, contra funcionário ou membro das Forças Armadas, militarizadas ou de segurança, para se opor a que ele pratique acto relativo ao exercício das suas funções, ou para o constranger a que pratique acto relativo ao exercício das suas funções, mas contrário aos seus deveres, é punido com pena de prisão até cinco anos. 
  2 - A mesma pena é aplicável a quem desobedecer ao sinal de paragem e dirigir contra funcionário ou membro das Forças Armadas, militarizadas ou de segurança, veículo, com ou sem motor, que conduza em via pública ou equiparada, ou embarcação, que pilote em águas interiores fluviais ou marítimas, para se opor a que ele pratique acto relativo ao exercício das suas funções, ou para o constranger a que pratique acto relativo ao exercício das suas funções, mas contrário aos seus deveres, se pena mais grave lhe não couber por força de outra disposição legal. 
  Artigo 348.º 
  Desobediência 
  1 - Quem faltar à obediência devida a ordem ou a mandado legítimos, regularmente comunicados e emanados de autoridade ou funcionário competente, é punido com pena de prisão até um ano ou com pena de multa até 120 dias se: 
  a) Uma disposição legal cominar, no caso, a punição da desobediência simples; ou 
  b) Na ausência de disposição legal, a autoridade ou o funcionário fizerem a correspondente cominação. 
  2 - A pena é de prisão até dois anos ou de multa até 240 dias nos casos em que uma disposição legal cominar a punição da desobediência qualificada. 
  SECÇÃO II 
  Da tirada e evasão de presos e do não cumprimento de obrigações impostas por sentença criminal 
  Artigo 349.º 
  Tirada de presos 
  Quem: 
  a) Por meio de violência, ameaça ou artifício, libertar pessoa legalmente privada da liberdade; ou 
  b) Instigar, promover ou, por qualquer forma, auxiliar a evasão de pessoa legalmente privada da liberdade; 
  é punido com pena de prisão até cinco anos. 
  Artigo 350.º 
  Auxílio de funcionário à evasão 
  1 - O funcionário encarregado da guarda de pessoa legalmente privada da liberdade que a libertar, deixar evadir, ou facilitar, promover ou, por qualquer forma, auxiliar a sua evasão é punido com pena de prisão de um a oito anos. 
  2 - O funcionário que, não sendo encarregado da guarda, estiver obrigado, em virtude da função que desempenha, a exercer vigilância sobre pessoa legalmente privada da liberdade ou a impedir a sua evasão e praticar a conduta referida no número','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' anterior é punido com pena de prisão até cinco anos. 
  Artigo 351.º 
  Negligência na guarda 
  O funcionário encarregado da guarda de pessoa legalmente privada da liberdade que, por negligência grosseira, permitir a sua evasão é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  Artigo 352.º 
  Evasão 
  1 - Quem, encontrando-se legalmente privado da liberdade, se evadir é punido com pena de prisão até dois anos. 
  2 - Se o agente espontaneamente se entregar às autoridades até à declaração de contumácia, a pena pode ser especialmente atenuada. 
  Artigo 353.º 
  Violação de imposições, proibições ou interdições 
  Quem violar imposições, proibições ou interdições determinadas por sentença criminal, a título de pena aplicada em processo sumaríssimo, de pena acessória ou de medida de segurança não privativa da liberdade, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  Artigo 354.º 
  Motim de presos 
  Os presos, detidos ou internados que se amotinarem e, concertando as suas forças: 
  a) Atacarem funcionário legalmente encarregado da sua guarda, tratamento ou vigilância, ou o constrangerem, por meio de violência ou ameaça de violência, a praticar acto ou a abster-se de o praticar; ou 
  b) Promoverem a sua evasão ou a evasão de terceiro; 
  são punidos com pena de prisão de um a oito anos. 
  SECÇÃO III 
  Da violação de providências públicas 
  Artigo 355.º 
  Descaminho ou destruição de objectos 
  colocados sob o poder público 
  Quem destruir, danificar ou inutilizar, total ou parcialmente, ou, por qualquer forma, subtrair ao poder público a que está sujeito, documento ou outro objecto móvel, bem como coisa que tiver sido arrestada, apreendida ou objecto de providência cautelar, é punido com pena de prisão até cinco anos, se pena mais grave lhe não couber por força de outra disposição legal. 
  Artigo 356.º 
  Quebra de marcas e de selos 
  Quem abrir, romper ou inutilizar, total ou parcialmente, marcas ou selos, apostos legitimamente, por funcionário competente, para identificar ou manter inviolável qualquer coisa, ou para certificar que sobre esta recaiu arresto, apreensão ou providência cautelar, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  Artigo 357.º 
  Arrancamento, destruição ou alteração de editais 
  Quem arrancar, destruir, danificar, alterar ou, por qualquer forma, impedir que se conheça edital afixado por funcionário competente é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  SECÇÃO IV 
  Usurpação de funções 
  Artigo 358.º 
  Usurpação de funções 
  Quem: 
  a) Sem para tal estar autorizado, exercer funções ou praticar actos próprios de funcionário, de comando militar ou de força de segurança pública, arrogando-se, expressa ou tacitamente, essa qualidade; 
  b) Exercer profissão ou praticar acto próprio de uma profissão para a qual a lei exige título ou preenchimento de certas condições, arrogando-se, exp','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ressa ou tacitamente, possuí-lo ou preenchê-las, quando o não possui ou não as preenche; ou 
  c) Continuar no exercício de funções públicas, depois de lhe ter sido oficialmente notificada demissão ou suspensão de funções; 
  é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  CAPÍTULO III 
  Dos crimes contra a realização da justiça 
  Artigo 359.º 
  Falsidade de depoimento ou declaração 
  1 - Quem prestar depoimento de parte, fazendo falsas declarações relativamente a factos sobre os quais deve depor, depois de ter prestado juramento e de ter sido advertido das consequências penais a que se expõe com a prestação de depoimento falso, é punido com pena de prisão até três anos ou com pena de multa. 
  2 - Na mesma pena incorrem o assistente e as partes civis relativamente a declarações que prestarem em processo penal, bem como o arguido relativamente a declarações sobre a identidade e os antecedentes criminais. 
  Artigo 360.º 
  Falsidade de testemunho, perícia, interpretação ou tradução 
  1 - Quem, como testemunha, perito, técnico, tradutor ou intérprete, perante tribunal ou funcionário competente para receber como meio de prova, depoimento, relatório, informação ou tradução, prestar depoimento, apresentar relatório, der informações ou fizer traduções falsos, é punido com pena de prisão de seis meses a três anos ou com pena de multa não inferior a 60 dias. 
  2 - Na mesma pena incorre quem, sem justa causa, se recusar a depor ou a apresentar relatório, informação ou tradução. 
  3 - Se o facto referido no n.º 1 for praticado depois de o agente ter prestado juramento e ter sido advertido das consequências penais a que se expõe, a pena é de prisão até cinco anos ou de multa até 600 dias. 
  Artigo 361.º 
  Agravação 
  1 - As penas previstas nos artigos 359.º e 360.º são agravadas de um terço nos seus limites mínimo e máximo se: 
  a) O agente actuar com intenção lucrativa; 
  b) Do facto resultar demissão de lugar, perda de posição profissional ou destruição das relações familiares ou sociais de outra pessoa; ou 
  c) Do facto resultar que, em vez do agente, outra pessoa seja condenada pelo crime que aquele praticou. 
  2 - Se das condutas descritas nos artigos 359.º ou 360.º resultar privação da liberdade de uma pessoa, o agente é punido com pena de prisão de um a oito anos. 
  Artigo 362.º 
  Retractação 
  1 - A punição pelos artigos 359.º, 360.º e 361.º, alínea a), não tem lugar se o agente se retractar voluntariamente, a tempo de a retractação poder ser tomada em conta na decisão e antes que tenha resultado do depoimento, relatório, informação ou tradução falsos, prejuízo para terceiro. 
  2 - A retractação pode ser feita, conforme os casos, perante o tribunal, o Ministério Público ou o órgão de polícia criminal. 
  Artigo 363.º 
  Suborno 
  Quem convencer ou tentar convencer outra pessoa, através de dádiva ou promessa de vantagem patrimonial ou não patrimonial, a praticar os factos previstos nos artigos 359.º','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' ou 360.º, sem que estes venham a ser cometidos, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  Artigo 364.º 
  Atenuação especial e dispensa da pena 
  As penas previstas nos artigos 359.º, 360.º e 363.º são especialmente atenuadas, podendo ter lugar a dispensa de pena quando: 
  a) A falsidade disser respeito a circunstâncias que não tenham significado essencial para a prova a que o depoimento, relatório, informação ou tradução se destinar; ou 
  b) O facto tiver sido praticado para evitar que o agente, o cônjuge, um adoptante ou adoptado, os parentes ou afins até ao 2.º grau, ou a pessoa, de outro ou do mesmo sexo, que com aquele viva em condições análogas às dos cônjuges, se expusessem ao perigo de virem a ser sujeitos a pena ou a medida de segurança. 
  Artigo 365.º 
  Denúncia caluniosa 
  1 - Quem, por qualquer meio, perante autoridade ou publicamente, com a consciência da falsidade da imputação, denunciar ou lançar sobre determinada pessoa a suspeita da prática de crime, com intenção de que contra ela se instaure procedimento, é punido com pena de prisão até três anos ou com pena de multa. 
  2 - Se a conduta consistir na falsa imputação de contra-ordenação ou falta disciplinar, o agente é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  3 - Se o meio utilizado pelo agente se traduzir em apresentar, alterar ou desvirtuar meio de prova, o agente é punido: 
  a) No caso do n.º 1, com pena de prisão até cinco anos; 
  b) No caso do n.º 2, com pena de prisão até três anos ou com pena de multa. 
  4 - Se do facto resultar privação da liberdade do ofendido, o agente é punido com pena de prisão de um a oito anos. 
  5 - A requerimento do ofendido o tribunal ordena o conhecimento público da sentença condenatória, nos termos do artigo 189.º 
  Artigo 366.º 
  Simulação de crime 
  1 - Quem, sem o imputar a pessoa determinada, denunciar crime ou fizer criar suspeita da sua prática à autoridade competente, sabendo que ele se não verificou, é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  2 - Se o facto respeitar a contra-ordenação ou ilícito disciplinar, o agente é punido com pena de multa até 60 dias. Artigo 367.º 
  Favorecimento pessoal 
  1 - Quem, total ou parcialmente, impedir, frustrar ou iludir actividade probatória ou preventiva de autoridade competente, com intenção ou com consciência de evitar que outra pessoa, que praticou um crime, seja submetida a pena ou medida de segurança, é punido com pena de prisão até três anos ou com pena de multa. 
  2 - Na mesma pena incorre quem prestar auxílio a outra pessoa com a intenção ou com a consciência de, total ou parcialmente, impedir, frustrar ou iludir execução de pena ou de medida de segurança que lhe tenha sido aplicada. 
  3 - A pena a que o agente venha a ser condenado, nos termos dos números anteriores, não pode ser superior à prevista na lei para o facto cometido pela pessoa em benefício da qual se actuou','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('. 
  4 - A tentativa é punível. 
  5 - Não é punível: 
  a) O agente que, com o facto, procurar ao mesmo tempo evitar que contra si seja aplicada ou executada pena ou medida de segurança; 
  b) O cônjuge, os adoptantes ou adoptados, os parentes ou afins até ao 2.º grau ou a pessoa, de outro ou do mesmo sexo, que viva em situação análoga à dos cônjuges com aquela em benefício da qual se actuou. 
  Artigo 368.º 
  Favorecimento pessoal praticado por funcionário 
  Quando o favorecimento previsto no artigo anterior for praticado por funcionário que intervenha ou tenha competência para intervir no processo, ou por quem tenha competência para ordenar a execução de pena ou de medida de segurança, ou seja incumbido de a executar, o agente é punido com pena de prisão até cinco anos. 
  Artigo 368.º-A 
  Branqueamento 
  1 - Para efeitos do disposto nos números seguintes, consideram-se vantagens os bens provenientes da prática, sob qualquer forma de comparticipação, dos factos ilícitos típicos de lenocínio, abuso sexual de crianças ou de menores dependentes, extorsão, tráfico de estupefacientes e substâncias psicotrópicas, tráfico de armas, tráfico de órgãos ou tecidos humanos, tráfico de espécies protegidas, fraude fiscal, tráfico de influência, corrupção e demais infracções referidas no n.º 1 do artigo 1.º da Lei n.º 36/94, de 29 de Setembro, e dos factos ilícitos típicos puníveis com pena de prisão de duração mínima superior a seis meses ou de duração máxima superior a cinco anos, assim como os bens que com eles se obtenham. 
  2 - Quem converter, transferir, auxiliar ou facilitar alguma operação de conversão ou transferência de vantagens, obtidas por si ou por terceiro, directa ou indirectamente, com o fim de dissimular a sua origem ilícita, ou de evitar que o autor ou participante dessas infracções seja criminalmente perseguido ou submetido a uma reacção criminal, é punido com pena de prisão de dois a doze anos. 
  3 - Na mesma pena incorre quem ocultar ou dissimular a verdadeira natureza, origem, localização, disposição, movimentação ou titularidade das vantagens, ou os direitos a ela relativos. 
  4 - A punição pelos crimes previstos nos n.os 2 e 3 tem lugar ainda que os factos que integram a infracção subjacente tenham sido praticados fora do território nacional, ou ainda que se ignore o local da prática do facto ou a identidade dos seus autores. 
  5 - O facto não é punível quando o procedimento criminal relativo aos factos ilícitos típicos de onde provêm as vantagens depender de queixa e a queixa não tenha sido tempestivamente apresentada. 
  6 - A pena prevista nos n.os 2 e 3 é agravada de um terço se o agente praticar as condutas de forma habitual. 
  7 - Quando tiver lugar a reparação integral do dano causado ao ofendido pelo facto ilícito típico de cuja prática provêm as vantagens, sem dano ilegítimo de terceiro, até ao início da audiência de julgamento em 1.ª instância, a pena é especialmente atenuada. 
  8 - Verificados os requisitos previ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('stos no número anterior, a pena pode ser especialmente atenuada se a reparação for parcial. 
  9 - A pena pode ser especialmente atenuada se o agente auxiliar concretamente na recolha das provas decisivas para a identificação ou a captura dos responsáveis pela prática dos factos ilícitos típicos de onde provêm as vantagens. 
  10 - A pena aplicada nos termos dos números anteriores não pode ser superior ao limite máximo da pena mais elevada de entre as previstas para os factos ilícitos típicos de onde provêm as vantagens. 
  Artigo 369.º 
  Denegação de justiça e prevaricação 
  1 - O funcionário que, no âmbito de inquérito processual, processo jurisdicional, por contra-ordenação ou disciplinar, conscientemente e contra direito, promover ou não promover, conduzir, decidir ou não decidir, ou praticar acto no exercício de poderes decorrentes do cargo que exerce, é punido com pena de prisão até dois anos ou com pena de multa até 120 dias. 
  2 - Se o facto for praticado com intenção de prejudicar ou beneficiar alguém, o funcionário é punido com pena de prisão até cinco anos. 
  3 - Se, no caso do n.º 2, resultar privação da liberdade de uma pessoa, o agente é punido com pena de prisão de um a oito anos. 
  4 - Na pena prevista no número anterior incorre o funcionário que, sendo para tal competente, ordenar ou executar medida privativa da liberdade de forma ilegal, ou omitir ordená-la ou executá-la nos termos da lei. 
  5 - No caso referido no número anterior, se o facto for praticado com negligência grosseira, o agente é punido com pena de prisão até dois anos ou com pena de multa. 
  Artigo 370.º 
  Prevaricação de advogado ou de solicitador 
  1 - O advogado ou solicitador que intencionalmente prejudicar causa entregue ao seu patrocínio é punido com pena de prisão até três anos ou com pena de multa. 
  2 - Em igual pena incorre o advogado ou solicitador que, na mesma causa, advogar ou exercer solicitadoria relativamente a pessoas cujos interesses estejam em conflito, com intenção de actuar em benefício ou em prejuízo de alguma delas. 
  Artigo 371.º 
  Violação de segredo de justiça 
  1 - Quem, independentemente de ter tomado contacto com o processo, ilegitimamente der conhecimento, no todo ou em parte, do teor de acto de processo penal que se encontre coberto por segredo de justiça, ou a cujo decurso não for permitida a assistência do público em geral, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias, salvo se outra pena for cominada para o caso pela lei de processo. 
  2 - Se o facto descrito no número anterior respeitar: 
  a) A processo por contra-ordenação, até à decisão da autoridade administrativa; ou 
  b) A processo disciplinar, enquanto se mantiver legalmente o segredo; 
  o agente é punido com pena de prisão até seis meses ou com pena de multa até 60 dias. 
  CAPÍTULO IV 
  Dos crimes cometidos no exercício 
  de funções públicas 
  SECÇÃO I 
  Da corrupção 
  Artigo 372.º 
  Corrupção passiva para acto ilícit','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o 
  1 - O funcionário que por si, ou por interposta pessoa, com o seu consentimento ou ratificação, solicitar ou aceitar, para si ou para terceiro, sem que lhe seja devida, vantagem patrimonial ou não patrimonial, ou a sua promessa, para um qualquer acto ou omissão contrários aos deveres do cargo, ainda que anteriores àquela solicitação ou aceitação, é punido com pena de prisão de um a oito anos. 
  2 - Se o agente, antes da prática do facto, voluntariamente repudiar o oferecimento ou a promessa que aceitara, ou restituir a vantagem, ou, tratando-se de coisa fungível, o seu valor, é dispensado de pena. 
  3 - A pena é especialmente atenuada se o agente auxiliar concretamente na recolha das provas decisivas para a identificação ou a captura de outros responsáveis. 
  Artigo 373.º 
  Corrupção passiva para acto lícito 
  1 - O funcionário que por si, ou por interposta pessoa, com o seu consentimento ou ratificação, solicitar ou aceitar, para si ou para terceiro, sem que lhe seja devida, vantagem patrimonial ou não patrimonial, ou a sua promessa, para um qualquer acto ou omissão não contrários aos deveres do cargo, ainda que anteriores àquela solicitação ou aceitação, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  2 - Na mesma pena incorre o funcionário que por si, ou por interposta pessoa, com o seu consentimento ou ratificação, solicitar ou aceitar, para si ou para terceiro, sem que lhe seja devida, vantagem patrimonial ou não patrimonial de pessoa que perante ele tenha tido, tenha ou venha a ter qualquer pretensão dependente do exercício das suas funções públicas. 
  3 - É correspondentemente aplicável o disposto na alínea b) do artigo 364.º e nos n.os 2 e 3 do artigo anterior. 
  Artigo 374.º 
  Corrupção activa 
  1 - Quem por si, ou por interposta pessoa com o seu consentimento ou ratificação, der ou prometer a funcionário, ou a terceiro com conhecimento daquele, vantagem patrimonial ou não patrimonial que ao funcionário não seja devida, com o fim indicado no artigo 372.º, é punido com pena de prisão de seis meses a cinco anos. 
  2 - Se o fim for o indicado no artigo 373.º, o agente é punido com pena de prisão até seis meses ou com pena de multa até 60 dias. 
  3 - É correspondentemente aplicável o disposto na alínea b) do artigo 364.º 
  SECÇÃO II 
  Do peculato 
  Artigo 375.º 
  Peculato 
  1 - O funcionário que ilegitimamente se apropriar, em proveito próprio ou de outra pessoa, de dinheiro ou qualquer coisa móvel, pública ou particular, que lhe tenha sido entregue, esteja na sua posse ou lhe seja acessível em razão das suas funções, é punido com pena de prisão de um a oito anos, se pena mais grave lhe não couber por força de outra disposição legal. 
  2 - Se os valores ou objectos referidos no número anterior forem de diminuto valor, nos termos da alínea c) do artigo 202.º, o agente é punido com pena de prisão até três anos ou com pena de multa. 
  3 - Se o funcionário der de empréstimo, empenhar ou, de ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('qualquer forma, onerar valores ou objectos referidos no n.º 1, é punido com pena de prisão até três anos ou com pena de multa, se pena mais grave lhe não couber por força de outra disposição legal. 
  Artigo 376.º 
  Peculato de uso 
  1 - O funcionário que fizer uso ou permitir que outra pessoa faça uso, para fins alheios àqueles a que se destinem, de veículos ou de outras coisas móveis de valor apreciável, públicos ou particulares, que lhe forem entregues, estiverem na sua posse ou lhe forem acessíveis em razão das suas funções, é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  2 - Se o funcionário, sem que especiais razões de interesse público o justifiquem, der a dinheiro público destino para uso público diferente daquele a que está legalmente afectado, é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  Artigo 377.º 
  Participação económica em negócio 
  1 - O funcionário que, com intenção de obter, para si ou para terceiro, participação económica ilícita, lesar em negócio jurídico os interesses patrimoniais que, no todo ou em parte, lhe cumpre, em razão da sua função, administrar, fiscalizar, defender ou realizar, é punido com pena de prisão até cinco anos. 
  2 - O funcionário que, por qualquer forma, receber, para si ou para terceiro, vantagem patrimonial por efeito de acto jurídico-civil relativo a interesses de que tinha, por força das suas funções, no momento do acto, total ou parcialmente, a disposição, administração ou fiscalização, ainda que sem os lesar, é punido com pena de prisão até seis meses ou com pena de multa até 60 dias. 
  3 - A pena prevista no número anterior é também aplicável ao funcionário que receber, para si ou para terceiro, por qualquer forma, vantagem patrimonial por efeito de cobrança, arrecadação, liquidação ou pagamento que, por força das suas funções, total ou parcialmente, esteja encarregado de ordenar ou fazer, posto que não se verifique prejuízo para a Fazenda Pública ou para os interesses que lhe estão confiados. 
  SECÇÃO III 
  Do abuso de autoridade 
  Artigo 378.º 
  Violação de domicílio por funcionário 
  O funcionário que, abusando dos poderes inerentes às suas funções, praticar o crime previsto no n.º 1 do artigo 190.º, ou violar o domicílio profissional de quem, pela natureza da sua actividade, estiver vinculado ao dever de sigilo, é punido com pena de prisão até três anos ou com pena de multa. 
  Artigo 379.º 
  Concussão 
  1 - O funcionário que, no exercício das suas funções ou de poderes de facto delas decorrentes, por si ou por interposta pessoa com o seu consentimento ou ratificação, receber, para si, para o Estado ou para terceiro, mediante indução em erro ou aproveitamento de erro da vítima, vantagem patrimonial que lhe não seja devida, ou seja superior à devida, nomeadamente contribuição, taxa, emolumento, multa ou coima, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias, se pena mais grave lhe não couber por','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' força de outra disposição legal. 
  2 - Se o facto for praticado por meio de violência ou ameaça com mal importante, o agente é punido com pena de prisão de um a oito anos, se pena mais grave lhe não couber por força de outra disposição legal. 
  Artigo 380.º 
  Emprego de força pública contra a execução da lei ou de ordem legítima 
  O funcionário que, sendo competente para requisitar ou ordenar emprego da força pública, requisitar ou ordenar este emprego para impedir a execução de lei, mandado regular da justiça ou ordem legítima de autoridade pública, é punido com pena de prisão até dois anos ou com pena de multa até 240 dias. 
  Artigo 381.º 
  Recusa de cooperação 
  O funcionário que, tendo recebido requisição legal de autoridade competente para prestar a devida cooperação à administração da justiça ou a qualquer serviço público, se recusar a prestá-la, ou sem motivo legítimo a não prestar, é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  Artigo 382.º 
  Abuso de poder 
  O funcionário que, fora dos casos previstos nos artigos anteriores, abusar de poderes ou violar deveres inerentes às suas funções, com intenção de obter, para si ou para terceiro, benefício ilegítimo ou causar prejuízo a outra pessoa, é punido com pena de prisão até três anos ou com pena de multa, se pena mais grave lhe não couber por força de outra disposição legal. 
  SECÇÃO IV 
  Da violação de segredo 
  Artigo 383.º 
  Violação de segredo por funcionário 
  1 - O funcionário que, sem estar devidamente autorizado, revelar segredo de que tenha tomado conhecimento ou que lhe tenha sido confiado no exercício das suas funções, ou cujo conhecimento lhe tenha sido facilitado pelo cargo que exerce, com intenção de obter, para si ou para outra pessoa, benefício, ou com a consciência de causar prejuízo ao interesse público ou a terceiros, é punido com pena de prisão até três anos ou com pena de multa. 
  2 - Se o funcionário praticar o facto previsto no número anterior criando perigo para a vida ou para a integridade física de outrem ou para bens patrimoniais alheios de valor elevado é punido com pena de prisão de um a cinco anos. 
  3 - O procedimento criminal depende de participação da entidade que superintender no respectivo serviço ou de queixa do ofendido. 
  Artigo 384.º 
  Violação de segredo de correspondência ou de telecomunicações 
  O funcionário de serviços dos correios, telégrafos, telefones ou telecomunicações que, sem estar devidamente autorizado: 
  a) Suprimir ou subtrair carta, encomenda, telegrama ou outra comunicação confiada àqueles serviços e que lhe é acessível em razão das suas funções; 
  b) Abrir carta, encomenda ou outra comunicação que lhe é acessível em razão das suas funções ou, sem a abrir, tomar conhecimento do seu conteúdo; 
  c) Revelar a terceiros comunicações entre determinadas pessoas, feitas pelo correio, telégrafo, telefone ou outros meios de telecomunicações daqueles serviços, de que teve conhecimento em razão','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' das suas funções; 
  d) Gravar ou revelar a terceiro o conteúdo, total ou parcial, das comunicações referidas, ou tornar-lhe possível ouvi-las ou tomar delas conhecimento; ou 
  e) Permitir ou promover os factos referidos nas alíneas anteriores; 
  é punido com pena de prisão de seis meses a três anos ou com pena de multa não inferior a 60 dias. 
  SECÇÃO V 
  Do abandono de funções 
  Artigo 385.º 
  Abandono de funções 
  O funcionário que ilegitimamente, com intenção de impedir ou de interromper serviço público, abandonar as suas funções ou negligenciar o seu cumprimento é punido com pena de prisão até um ano ou com pena de multa até 120 dias. 
  SECÇÃO VI 
  Disposição geral 
  Artigo 386.º 
  Conceito de funcionário 
  1 - Para efeito da lei penal a expressão funcionário abrange: 
  a) O funcionário civil; 
  b) O agente administrativo; e 
  c) Quem, mesmo provisória ou temporariamente, mediante remuneração ou a título gratuito, voluntária ou obrigatoriamente, tiver sido chamado a desempenhar ou a participar no desempenho de uma actividade compreendida na função pública administrativa ou jurisdicional, ou, nas mesmas circunstâncias, desempenhar funções em organismos de utilidade pública ou nelas participar. 
  2 - Ao funcionário são equiparados os gestores, titulares dos órgãos de fiscalização e trabalhadores de empresas públicas, nacionalizadas, de capitais públicos ou com participação maioritária de capital público e ainda de empresas concessionárias de serviços públicos. 
  3 - São ainda equiparados ao funcionário, para efeitos do disposto nos artigos 372.º a 374.º: 
  a) Os magistrados, funcionários, agentes e equiparados da União Europeia, independentemente da nacionalidade e residência; 
  b) Os funcionários nacionais de outros Estados membros da União Europeia, quando a infracção tiver sido cometida, total ou parcialmente, em território português; 
  c) Todos os que exerçam funções idênticas às descritas no n.º 1 no âmbito de qualquer organização internacional de direito público de que Portugal seja membro, quando a infracção tiver sido cometida, total ou parcialmente, em território português; 
  d) Todos os que exerçam funções no âmbito de procedimentos de resolução extrajudicial de conflitos. 
  4 - A equiparação a funcionário, para efeito da lei penal, de quem desempenhe funções políticas é regulada por lei especial.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Rectif. n.º 102/2007, de 31 de Outubro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 59/2007, de 04 de Setembro','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:3  
    
  Portaria n.º 109/2005, de 27 de Janeiro  (versão actualizada) APLICA A VIGILÂNCIA ELECTRÓNICA A TODAS AS COMARCAS DO TERRITÓRIO    
    
 
  
                         
                          
SUMÁRIOAplica os meios de vigilância electrónica para fiscalização do cumprimento da obrigação de permanência na habitação que podem ser mandados utilizar pelos tribunais competentes com jurisdição em todas as comarcas do território nacional. Revoga a Portaria n
Após a conclusão do programa experimental de vigilância electrónica destinado a desenvolver as estratégias de implementação deste novo método de controlo penal, de acordo com uma experiência limitada no espaço e no tempo, e em face dos resultados positivos, o Governo estabeleceu um novo programa de acção para o desenvolvimento da vigilância electrónica no sistema penal português, nos termos aprovados pela Resolução do Conselho de Ministros n.º 144/2004, de 28 de Outubro. 
  Em cumprimento deste programa, procede-se, agora, à generalização a todo o território nacional da utilização da vigilância electrónica, como meio de controlo do cumprimento da medida de coacção de obrigação de permanência na habitação, prevista no artigo 201.º do Código de Processo Penal. 
  Assim:
  Manda o Governo, nos termos da alínea a) do n.º 4 da Resolução do Conselho de Ministros n.º 144/2004, de 28 de Outubro, pelo Ministro da Justiça, o seguinte:  1.º Âmbito geográfico de aplicação da vigilância electrónica
                            
                           
                             
                               
                             
     Os meios de vigilância electrónica para fiscalização do cumprimento da obrigação de permanência na habitação, prevista no artigo 201.º do Código de Processo Penal, podem ser mandados utilizar pelos tribunais competentes com jurisdição em todas as comarcas do território nacional.            
         
   
     
                         
                          
  2.º Norma revogatória
                            
                           
                             
                               
                             
     É revogada a Portaria n.º 189/2004, de 26 de Fevereiro.
  
  Consultar a Portaria n.º 189/2004, de 26 de Fevereiro             
         
   
     
                         
                          
  3.º Entrada em vigor
                            
                           
                             
                               
                             
     A presente portaria produz efeitos no dia 1 de Março de 2005.
  
  O Ministro da Justiça, José Pedro Aguiar Branco, em 17 de Janeiro de 2005.','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:41  
    
  Lei n.º 33/2010, de 02 de Setembro  (versão actualizada) MEIOS TÉCNICOS DE CONTROLO À DISTÂNCIA (VIGILÂNCIA ELECTRÓNICA)    
    
 
Contém as seguintes alterações:   - Lei n.º 94/2017, de 23 de Agosto  
                         
                          
SUMÁRIORegula a utilização de meios técnicos de controlo à distância (vigilância electrónica) e revoga a Lei n.º 122/99, de 20 de Agosto, que regula a vigilância electrónica prevista no artigo 201.º do Código de Processo Penal
Lei n.º 33/2010, de 2 de Setembro 
  Regula a utilização de meios técnicos de controlo à distância (vigilância electrónica) e revoga a Lei n.º 122/99, de 20 de Agosto, que regula a vigilância electrónica prevista no artigo 201.º do Código de Processo Penal. 
  A Assembleia da República decreta, nos termos da alínea c) do artigo 161.º da Constituição, o seguinte:
  
  CAPÍTULO I 
  Parte geral  Artigo 1.º 
Âmbito
                            
                           
                             
                               
                             
     A presente lei regula a utilização de meios técnicos de controlo à distância, adiante designados por vigilância electrónica, para fiscalização: 
  a) Do cumprimento da medida de coacção de obrigação de permanência na habitação, prevista no artigo 201.º do Código de Processo Penal; 
  b) Da execução da pena de prisão em regime de permanência na habitação, prevista nos artigos 43.º e 44.º do Código Penal;
  c) Da execução da adaptação à liberdade condicional, prevista no artigo 62.º do Código Penal; 
  d) Da modificação da execução da pena de prisão, prevista no artigo 120.º do Código da Execução das Penas e Medidas Privativas da Liberdade; 
  e) Da aplicação das medidas e penas previstas no artigo 35.º da Lei n.º 112/2009, de 16 de Setembro.
  f) Da obrigação de permanência na habitação prevista nos n.os 1 e 3 do artigo 274.º-A do Código Penal.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 94/2017, de 23 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 33/2010, de 02 de Setembro   
     
                         
                          
  Artigo 2.º Sistemas tecnológicos
                            
                           
                             
                               
                             
     1 - A vigilância electrónica pode ser efectuada por: 
  a) Monitorização telemática posicional; 
  b) Verificação de voz; 
  c) Outros meios tecnológicos que venham a ser reconhecidos como idóneos. 
  2 - O reconhecimento de idoneidade e as características dos equipamentos a utilizar na vigilância electrónica são determinados por portaria do membro do Governo responsável pela área da justiça.            
         
   
     
                         
                          
  Artigo 3.º Princípios orientadores da execução
                            
                           
                    ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('         
                               
                             
     1 - A execução da vigilância electrónica assegura o respeito pela dignidade da pessoa humana e os direitos e interesses jurídicos não afectados pela decisão que a aplicou. 
  2 - A vigilância electrónica não acarreta qualquer encargo financeiro para o arguido ou condenado.            
         
   
     
                         
                          
  Artigo 4.º 
Consentimento
                            
                           
                             
                               
                             
     1 - A vigilância electrónica depende do consentimento do arguido ou condenado. 
  2 - O consentimento é prestado pessoalmente perante o juiz, na presença do defensor, e reduzido a auto. 
  3 - Sempre que a vigilância electrónica for requerida pelo arguido ou condenado, o consentimento considera-se prestado por simples declaração pessoal deste no requerimento. 
  4 - A utilização da vigilância electrónica depende ainda do consentimento das pessoas, maiores de 16 anos, que coabitem com o arguido ou condenado. 
  5 - As pessoas referidas no número anterior prestam o seu consentimento aos serviços de reinserção social, por simples declaração escrita, a qual deve acompanhar a informação referida no n.º 2 do artigo 7.º, ou ser enviada, posteriormente, ao juiz. 
  6 - O consentimento do arguido ou condenado é revogável a todo o tempo.
  7 - Não se aplica o disposto no n.º 1 se o condenado ou o arguido não possuírem o discernimento necessário para avaliar o sentido e o alcance do consentimento.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 94/2017, de 23 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 33/2010, de 02 de Setembro   
     
                         
                          
  Artigo 5.º Direitos do arguido ou condenado
                            
                           
                             
                               
                             
     O arguido ou condenado tem, em especial, os seguintes direitos: 
  a) Participar na elaboração e conhecer o plano de reinserção social delineado pelos serviços de reinserção social em função das suas necessidades; 
  b) Receber dos serviços de reinserção social um documento onde constem os seus direitos e deveres, informação sobre os períodos de vigilância electrónica, bem como um guia dos procedimentos a observar durante a respectiva execução; 
  c) Aceder a um número de telefone de acesso livre, de ligação aos serviços de reinserção social que executam a decisão judicial.            
         
   
     
                         
                          
  Artigo 6.º Deveres do arguido ou condenado
                            
                           
                             
                               
                             
     Recaem sobre o arguido ou condenado os deveres','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' de: 
  a) Permanecer nos locais onde é exercida vigilância electrónica durante os períodos de tempo fixados; 
  b) Cumprir o definido no plano de reinserção social; 
  c) Cumprir as indicações que forem dadas pelos serviços de reinserção social para a verificação de voz; 
  d) Receber os serviços de reinserção social e cumprir as suas orientações, bem como responder aos contactos, nomeadamente por via telefónica, que por estes forem feitos durante os períodos de vigilância electrónica; 
  e) Contactar os serviços de reinserção social, com pelo menos três dias úteis de antecedência, sempre que pretenda obter autorização judicial para se ausentar excepcionalmente durante o período de vigilância electrónica, fornecendo para o efeito as informações necessárias; 
  f) Solicitar aos serviços de reinserção social autorização para se ausentar do local de vigilância electrónica quando estejam em causa motivos imprevistos e urgentes; 
  g) Apresentar justificação das ausências que ocorram durante os períodos de vigilância electrónica; 
  h) Abster-se de qualquer acto que possa afectar o normal funcionamento dos equipamentos de vigilância electrónica; 
  i) Contactar de imediato os serviços de reinserção social se ocorrerem anomalias que possam afectar o normal funcionamento do equipamento de vigilância electrónica, nomeadamente interrupções do fornecimento de electricidade ou das ligações telefónicas; 
  j) Permitir a remoção dos equipamentos pelos serviços de reinserção social após o termo da medida ou da pena.            
         
   
     
                         
                          
  Artigo 7.º 
Decisão
                            
                           
                             
                               
                             
     1 - Sem prejuízo do disposto no artigo 213.º do Código de Processo Penal, a utilização de meios de vigilância electrónica é decidida por despacho do juiz, a requerimento do Ministério Público ou do arguido, durante a fase do inquérito, e oficiosamente ou a requerimento do arguido ou condenado, depois do inquérito. 
  2 - O juiz solicita prévia informação aos serviços de reinserção social sobre a situação pessoal, familiar, laboral e social do arguido ou condenado, e da sua compatibilidade com as exigências da vigilância eletrónica e os sistemas tecnológicos a utilizar.
  3 - A decisão prevista no n.º 1 é sempre precedida de audição do Ministério Público, do arguido ou condenado. 
  4 - A decisão especifica os locais e os períodos de tempo em que a vigilância eletrónica é exercida e o modo como é efetuada, levando em conta, nomeadamente, o tempo de permanência na habitação e as autorizações de ausência estabelecidas na decisão de aplicação da medida ou da pena.
  5 - A decisão que fixa a vigilância electrónica pode determinar que os serviços de reinserção social, quando suspeitem que uma ocorrência anómala seja passível de colocar em risco a vítima ou o queixoso do procedimento criminal, os i','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('nformem de imediato. 
  6 - A decisão é comunicada ao arguido ou condenado e seu defensor, aos serviços de reinserção social e, quando aplicável, ao estabelecimento prisional onde aqueles se encontrem, bem como aos órgãos de polícia criminal competentes, para os efeitos previstos no n.º 3 do artigo 8.º e nos n.os 1 e 2 do artigo 12.º            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 94/2017, de 23 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 33/2010, de 02 de Setembro   
     
                         
                          
  Artigo 8.º Início da execução
                            
                           
                             
                               
                             
     1 - A vigilância electrónica inicia-se no prazo máximo de quarenta e oito horas após a recepção da decisão do tribunal por parte dos serviços de reinserção social, com a instalação dos meios técnicos de vigilância electrónica, em presença do arguido ou condenado. 
  2 - O início da vigilância electrónica é comunicado pelos serviços de reinserção social ao tribunal. 
  3 - No caso de reclusos, os serviços de reinserção social acordam com os serviços prisionais o momento em que aqueles são conduzidos ao local de vigilância electrónica.            
         
   
     
                         
                          
  Artigo 9.º Entidade encarregada da execução
                            
                           
                             
                               
                             
     1 - Cabe à Direcção-Geral de Reinserção Social, adiante designada por DGRS, proceder à execução da vigilância electrónica. 
  2 - A DGRS pode recorrer aos serviços de outras entidades para adquirir, instalar, assegurar e manter o funcionamento dos meios técnicos utilizados na vigilância electrónica. 
  3 - Nas respostas a alertas e alarmes, no âmbito da execução da vigilância electrónica, as viaturas da DGRS podem utilizar os sinais sonoros e luminosos previstos no Código da Estrada para os serviços urgentes de interesse público.            
         
   
     
                         
                          
  Artigo 10.º Relatórios
                            
                           
                             
                               
                             
     1 - Os serviços de reinserção social informam o tribunal sobre a execução da medida ou da pena, através da elaboração de relatórios periódicos. 
  2 - Os serviços de reinserção social informam o tribunal, através do envio de um relatório de incidentes, sempre que ocorram circunstâncias susceptíveis de comprometer a execução da medida ou da pena. 
  3 - O relatório referido no número anterior tem carácter de urgência, devendo ser presente ao juiz de imediato, que decide as providências que se afigurarem necessárias ao caso, nomeadamente a revogação da vigilância electrónica.    ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('        
         
   
     
                         
                          
  Artigo 11.º 
Ausências do local de vigilância electrónica
                            
                           
                             
                               
                             
     1 - As ausências do local determinado para a vigilância eletrónica são autorizadas pelo juiz, mediante informação prévia dos serviços de reinserção social quanto ao sistema tecnológico a utilizar, podendo o despacho ter natureza genérica.
  2 - Excepcionalmente, podem os serviços de reinserção social autorizar que o arguido ou condenado se ausente do local de vigilância electrónica quando estejam em causa motivos imprevistos e urgentes. 
  3 - As ausências previstas no número anterior dependem de solicitação prévia aos serviços de reinserção social, nos termos do disposto na alínea f) do artigo 6.º, que decidem tendo em conta os fundamentos invocados, a segurança da comunidade e o controlo de execução da medida ou da pena. 
  4 - Os serviços de reinserção social fiscalizam as ausências, conforme as finalidades e horários autorizados, podendo para o efeito recorrer a meios móveis de monitorização electrónica. 
  5 - Os serviços de reinserção social informam o tribunal de todas as ausências concedidas nos termos dos números anteriores, em sede de relatório de execução a enviar periodicamente, conforme definido no artigo anterior, e com as especificidades definidas na parte especial da presente lei.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 94/2017, de 23 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 33/2010, de 02 de Setembro   
     
                         
                          
  Artigo 12.º Ausências ilegítimas do local de vigilância electrónica
                            
                           
                             
                               
                             
     1 - Sem prejuízo do n.º 2 do artigo 10.º, em caso de ausência ilegítima do local de vigilância electrónica por parte do arguido ou condenado, os serviços de reinserção social comunicam este facto ao tribunal competente, ao Ministério Público e às forças e serviços de segurança, comunicando igualmente a captura. 
  2 - Qualquer autoridade judiciária ou agente de serviço ou força de segurança tem o dever de capturar e conduzir ao local de vigilância electrónica qualquer arguido ou condenado que se ausente, sem autorização, deste local, sem prejuízo da decisão do juiz ao abrigo do disposto do n.º 3 do artigo 10.º 
  3 - Quando considerarem que a ausência ilegítima do local de vigilância electrónica por parte do arguido ou condenado pode criar perigo para o ofendido, os serviços de reinserção social informam-no da ocorrência, reportando-o igualmente à entidade policial da área de residência do ofendido. 
  4 - Ao condenado que dolosamente se tiver eximido, total ou parcialmente, à exe','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('cução de pena de prisão com vigilância electrónica é aplicável o disposto no n.º 2 do artigo 97.º do Código de Execução das Penas e Medidas Privativas da Liberdade.            
         
   
     
                         
                          
  Artigo 13.º Aviso por incumprimento
                            
                           
                             
                               
                             
     1 - Sem prejuízo do disposto no n.º 2 do artigo 10.º, os serviços de reinserção social podem emitir avisos escritos ao arguido ou condenado quando ocorram incumprimentos pouco graves no âmbito da execução da medida ou da pena. 
  2 - Ao terceiro aviso corresponde necessariamente a elaboração de relatório de incidentes para os autos, nos termos dos n.os 2 e 3 do artigo 10.º            
         
   
     
                         
                          
  Artigo 14.º Revogação da vigilância electrónica
                            
                           
                             
                               
                             
     Sem prejuízo do disposto no Código Penal, no Código de Processo Penal e no Código da Execução das Penas e Medidas Privativas da Liberdade, a decisão que fixa a vigilância electrónica é revogada quando: 
  a) O arguido ou condenado revogar o consentimento; 
  b) O arguido ou condenado danificar o equipamento de monitorização, com intenção de impedir ou dificultar a vigilância, ou, por qualquer forma, iludir os serviços de vigilância ou se eximir a esta; 
  c) O arguido ou condenado violar gravemente os deveres a que está sujeito.            
         
   
     
                         
                          
  Artigo 15.º Termo da vigilância electrónica
                            
                           
                             
                               
                             
     1 - A decisão que determine o termo da vigilância electrónica da medida prevista na alínea a) do artigo 1.º, e que não implique condução ao estabelecimento prisional, deve ser cumprida até às 24 horas do dia em que é recebida pelos serviços de reinserção social. 
  2 - A desinstalação dos equipamentos nos casos previstos nas alíneas b), c) e d) do artigo 1.º, e que não implique condução ao estabelecimento prisional, ocorre durante a manhã do dia fixado na decisão para o seu termo. 
  3 - A decisão que, determinando o termo da vigilância electrónica, implique condução ao estabelecimento prisional, é comunicada em simultâneo aos serviços de reinserção social e ao órgão de polícia criminal competente. 
  4 - As entidades previstas no número anterior cooperam para que a diligência de condução do arguido ou condenado ao estabelecimento prisional seja cumprida no prazo de vinte e quatro horas, sendo imediatamente precedida pela desinstalação dos equipamentos de vigilância electrónica.            
         
   
     
                         
                     ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('     
CAPÍTULO II 
  Parte especial 
  SECÇÃO I 
  Medida de coacção de obrigação de permanência na habitação  Artigo 16.º Execução
                            
                           
                             
                               
                             
     1 - A execução da medida prevista na alínea a) do artigo 1.º, inicia-se após a instalação dos meios de vigilância electrónica, podendo o juiz, até ao início da execução, aplicar ao arguido as medidas de coacção que, entretanto, se mostrarem necessárias. 
  2 - O juiz pode associar à medida de coacção a obrigação de o arguido não contactar, por qualquer meio, com determinadas pessoas.            
         
   
     
                         
                          
  Artigo 17.º Relatórios periódicos
                            
                           
                             
                               
                             
     Os relatórios periódicos sobre a execução da medida de coacção referidos no n.º 1 do artigo 10.º têm periodicidade trimestral, devendo ser apresentados até cinco dias úteis antes do prazo para o respectivo reexame.            
         
   
     
                         
                          
  Artigo 18.º  Reexame da decisão
                            
                           
                             
                               
                             
     1 - Oficiosamente, de três em três meses, o juiz procede ao reexame das condições em que foi decidida a utilização da vigilância electrónica e à avaliação da sua execução, mantendo, alterando ou revogando a decisão. 
  2 - Para efeitos do número anterior, o juiz ouve o Ministério Público e o arguido e considera o teor do relatório de execução trimestral elaborado pelos serviços de reinserção social.            
         
   
     
                         
                          
  SECÇÃO II 
  Pena de prisão em regime de permanência na habitação  Artigo 19.º 
Execução
                            
                           
                             
                               
                             
     1 - Se do processo não resultar a informação necessária para a execução da pena de prisão em regime de permanência na habitação, referida na alínea b) do artigo 1.º, o tribunal solícita aos serviços de reinserção social a informação prévia prevista no n.º 2 do artigo 7.º, a elaborar no prazo de sete dias úteis.
  2 - O tribunal notifica os serviços de reinserção social da sentença transitada em julgado que decida a execução da pena de prisão em regime de permanência na habitação, devendo estes serviços proceder à instalação dos equipamentos de vigilância eletrónica no prazo máximo de quarenta e oito horas.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 94/2017, de 23 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 33/2010, de 02 de Setembro   
     
 ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                        
                          
  Artigo 20.º 
Individualização da execução
                            
                           
                             
                               
                             
     1 - A execução da pena de prisão em regime de permanência na habitação orienta-se pelo princípio da individualização e tem por base a avaliação das necessidades de ressocialização do condenado.
  2 - Sempre que a duração da pena for superior a seis meses ou sempre que o condenado não tiver ainda completado 21 anos de idade, os serviços de reinserção social elaboram um plano de reinserção social, que planifica as atividades e programas que visem a preparação do condenado para conduzir a sua vida de modo socialmente responsável, sem cometer crimes.
  3 - O plano de reinserção social, a elaborar no prazo de 30 dias, é homologado pelo tribunal, bem como as alterações relevantes que venham a justificar-se no decurso da execução.
  4 - (Revogado.)            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 94/2017, de 23 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 33/2010, de 02 de Setembro   
     
                         
                          
  Artigo 20.º-A 
Apoio social e económico
                            
                           
                             
                               
                             
     1 - A execução da pena de prisão em regime de permanência na habitação não afeta o direito aos benefícios de segurança social previstos na lei.
  2 - No decurso da execução da pena de prisão em regime de permanência na habitação é prestado apoio social e económico ao condenado e ao seu agregado familiar que dele careçam para reforçar as condições de reinserção social.
  3 - A execução da pena de prisão em regime de permanência na habitação não desobriga as entidades públicas competentes da prestação de apoio social e económico no âmbito das respetivas atribuições, designadamente em matéria de segurança e ação social, emprego, formação profissional, ensino e saúde.
  
  Aditado pelo seguinte diploma: Lei n.º 94/2017, de 23 de Agosto            
         
   
     
                         
                          
  Artigo 21.º Relatórios periódicos
                            
                           
                             
                               
                             
     Os relatórios periódicos de execução previstos no n.º 1 do artigo 10.º são elaborados a meio da pena, quando esta for superior a seis meses, e cinco dias úteis antes do seu termo, salvo se o juiz tiver estabelecido outra periodicidade.            
         
   
     
                         
                          
SECÇÃO III 
  Modificação da execução da pena de prisão de reclusos portadores de doença grave, evolutiva e irreversível ou de deficiência grave e permanente ou de idade avançada  Artigo 22.º Aus','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ências do local de vigilância electrónica
                            
                           
                             
                               
                             
     Sem prejuízo do disposto no artigo 7.º, a decisão que determine a modificação da execução da pena de prisão referida na alínea d) do artigo 1.º especifica as autorizações de ausência necessárias à prestação de cuidados de saúde ao condenado portador de doença grave, evolutiva e irreversível ou de deficiência grave e permanente ou de idade avançada.            
         
   
     
                         
                          
SECÇÃO IV 
  Adaptação à liberdade condicional com vigilância electrónica  Artigo 23.º Execução
                            
                           
                             
                               
                             
     1 - Tendo em vista o cumprimento do disposto no artigo 62.º do Código Penal, o tribunal de execução das penas solicita aos serviços de reinserção social, para além do relatório previsto na alínea b) do n.º 4 do artigo 188.º do Código de Execução das Penas e Medidas Privativas da Liberdade, a informação prévia prevista no n.º 2 do artigo 7.º da presente lei, a qual pode ser acompanhada do plano de reinserção social para homologação. 
  2 - Para além do disposto no n.º 2 do artigo 177.º do Código da Execução das Penas e Medidas Privativas da Liberdade, o despacho que concede o período de adaptação à liberdade condicional determina ainda a data do seu termo, bem como a data de apreciação da liberdade condicional. 
  3 - O tribunal notifica os serviços de reinserção social da decisão, para os efeitos previstos no disposto no n.º 7 do artigo 188.º do Código de Execução das Penas e Medidas Privativas da Liberdade. 
  4 - A decisão de concessão da adaptação à liberdade condicional com vigilância electrónica pode determinar que o condenado mantenha as condições decorrentes do regime aberto voltado para o exterior a que estava sujeito.            
         
   
     
                         
                          
  Artigo 24.º 
Regime de progressividade da execução
                            
                           
                             
                               
                             
     1 - Sem prejuízo do disposto no n.º 4 do artigo anterior, o tribunal pode determinar a execução da adaptação à liberdade condicional em regime de progressividade, com base nos relatórios previstos no n.º 4 do artigo 188.º do Código da Execução das Penas e das Medidas Privativas da Liberdade e em outros elementos que o tribunal solicite aos serviços de reinserção social, nos termos do n.º 5 do artigo 188.º do mesmo Código.
  2 - O regime de progressividade consiste no faseamento da execução, de modo a que o confinamento inicial do condenado à habitação possa ser progressivamente reduzido, através da concessão de períodos de ausência destinados à prossecução de atividades út','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('eis ao processo de ressocialização.
  3 - O período diário de confinamento nunca pode ser inferior a doze horas, salvo situações excecionais a autorizar pelo juiz.
  4 - O tribunal pode autorizar os serviços de reinserção social a administrar o regime de progressividade, sem prejuízo de ser informado, nos relatórios periódicos, da sua execução.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 94/2017, de 23 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 33/2010, de 02 de Setembro   
     
                         
                          
  Artigo 25.º Relatórios periódicos
                            
                           
                             
                               
                             
     Os relatórios periódicos de execução previstos no n.º 1 do artigo 10.º são elaborados a meio do período de adaptação à liberdade condicional e cinco dias úteis antes da data prevista para apreciação da transição para liberdade condicional, salvo se o juiz tiver estabelecido outra periodicidade.            
         
   
     
                         
                          
SECÇÃO V 
  Das medidas e penas de afastamento do arguido ou condenado em contexto de violência doméstica  Artigo 26.º Execução
                            
                           
                             
                               
                             
     1 - Para aplicação das medidas e penas referidas na alínea e) do artigo 1.º, a informação mencionada no n.º 2 do artigo 7.º da presente lei e no n.º 4 do artigo 35.º da Lei n.º 112/2009, de 16 de Setembro, deve ainda atender à compatibilidade da condição pessoal, familiar, laboral ou social da vítima com as exigências da vigilância electrónica. 
  2 - À utilização de meios técnicos de controlo à distância para fiscalização das medidas de afastamento é aplicável o regime previsto no artigo 36.º da Lei n.º 112/2009, de 16 de Setembro. 
  3 - A execução da medida ou pena inicia-se quando instalados todos os meios de vigilância electrónica junto da vítima e do arguido ou condenado.            
         
   
     
                         
                          
  Artigo 27.º Comunicações
                            
                           
                             
                               
                             
     1 - Para os efeitos previstos no n.º 3 do artigo 35.º da Lei n.º 112/2009, de 16 de Setembro, os serviços de reinserção social comunicam aos serviços de apoio à vítima o início da execução da pena ou medida e as respectivas condições de aplicação. 
  2 - Durante a execução da medida, os serviços de reinserção social e os serviços de apoio à vítima comunicam reciprocamente qualquer circunstância susceptível de pôr em causa a protecção da vítima.            
         
   
     
                         
                          
  Artigo 28.º Relatórios periódicos
        ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                    
                           
                             
                               
                             
     Os serviços de reinserção social remetem à autoridade judiciária competente relatórios trimestrais sobre a execução das medidas e penas, salvo se na decisão constar outra periodicidade.            
         
   
     
                         
                          
  SECÇÃO VI 
  Obrigação de permanência na habitação por crime de incêndio florestal  Artigo 28.º-A 
Execução
                            
                           
                             
                               
                             
     1 - Se do processo não resultar a informação necessária para a imposição da obrigação de permanência na habitação referida na alínea f) do artigo 1.º, o tribunal solicita aos serviços de reinserção social a informação prévia prevista no n.º 2 do artigo 7.º, a elaborar no prazo de sete dias úteis.
  2 - O tribunal notifica os serviços de reinserção social da decisão transitada em julgado que imponha a obrigação de permanência na habitação referida no número anterior, tendo em vista a instalação dos equipamentos de vigilância eletrónica para o período coincidente com os meses de maior risco de ocorrência de fogos.
  
  Aditado pelo seguinte diploma: Lei n.º 94/2017, de 23 de Agosto            
         
   
     
                         
                          
  Artigo 28.º-B 
Ausências do local de vigilância electrónica
                            
                           
                             
                               
                             
     Sem prejuízo do disposto no artigo 7.º, a decisão que imponha a agente inimputável a obrigação de permanência na habitação referida na alínea f) do artigo 1.º especifica as autorizações de ausência necessárias à submissão do condenado a tratamentos e regimes de cura ambulatórios apropriados.
  Aditado pelo seguinte diploma: Lei n.º 94/2017, de 23 de Agosto            
         
   
     
                         
                          
CAPÍTULO III 
  Do tratamento dos dados da vigilância electrónica  Artigo 29.º Base de dados
                            
                           
                             
                               
                             
     1 - Para efeitos da presente lei é criada e mantida pela DGRS uma base de dados constituída por: 
  a) Nome completo, data de nascimento, filiação, estado civil, sexo, naturalidade, nacionalidade, residência actual conhecida e número de identificação civil e fiscal dos arguidos ou condenados sujeitos a vigilância electrónica; 
  b) Indicação da medida ou pena aplicada; 
  c) Data de início, suspensão e fim da vigilância electrónica; 
  d) Tribunal e número de processo à ordem do qual foi decretada; 
  e) Tipos de crimes imputados; 
  f) Tipo de relação existente entre o arguido ou condenado e a vítima, em caso de prática de crimes','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' de violência doméstica e conexos; 
  g) Data da prática dos factos; 
  h) Local de instalação da vigilância; 
  i) Registos da monitorização da vigilância electrónica. 
  2 - A DGRS é a entidade responsável pelo tratamento da base de dados referida no número anterior. 
  3 - A DGRS pode recolher imagens de rosto dos arguidos ou condenados para inserção no sistema informático de monitorização electrónica, apenas para acesso dos agentes intervenientes nas operações de vigilância electrónica, com a finalidade de reconhecimento do vigiado, não as podendo utilizar para outro efeito. 
  4 - A DGRS pode recolher e registar amostras de voz para verificação da permanência do vigiado em determinado local.            
         
   
     
                         
                          
  Artigo 30.º Acesso e rectificação dos dados
                            
                           
                             
                               
                             
     1 - Para além do titular, têm acesso à base de dados os técnicos dos serviços de reinserção social afectos aos serviços de vigilância electrónica e os das entidades referidas no n.º 2 do artigo 9.º, devidamente credenciados por aqueles para administrar o sistema informático, ficando todos obrigados ao sigilo profissional, mesmo após o termo das suas funções. 
  2 - Ao arguido ou condenado é reconhecido o direito de conhecer o conteúdo dos registos dos dados que lhe respeitem, bem como o direito a obter a sua actualização ou a correcção dos dados inexactos, o preenchimento dos total ou parcialmente omissos e a eliminação dos indevidamente registados, nos termos da alínea d) do n.º 1 do artigo 11.º da Lei da Protecção de Dados Pessoais, aprovada pela Lei n.º 67/98, de 26 de Outubro.            
         
   
     
                         
                          
  Artigo 31.º Transmissão dos dados
                            
                           
                             
                               
                             
     As autoridades judiciárias e os órgãos de polícia criminal podem solicitar aos serviços de reinserção social informação da base de dados de vigilância electrónica para fins de investigação criminal.            
         
   
     
                         
                          
  Artigo 32.º Conservação de dados
                            
                           
                             
                               
                             
     1 - Os dados referidos no artigo 29.º são conservados durante a execução das penas e medidas com vigilância electrónica e até 18 meses após o seu termo. 
  2 - Findo o prazo referido no número anterior, os dados são retirados do sistema informático e conservados em suporte adequado em arquivo próprio dos serviços de reinserção social. 
  3 - Exceptuam-se do disposto nos números anteriores os dados relativos à fiscalização do cumprimento de medida de coação que são ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('imediatamente eliminados quando a decisão de arquivamento do inquérito se torne definitiva ou o despacho de não pronúncia ou a sentença absolutória transitem em julgado.            
         
   
     
                         
                          
  Artigo 33.º Destruição de dados
                            
                           
                             
                               
                             
     Os dados referentes aos vigiados sujeitos a vigilância electrónica conservados em suporte fora do sistema informático são destruídos três anos após a extinção da pena ou o fim da medida com vigilância electrónica.            
         
   
     
                         
                          
  Artigo 34.º Segurança da informação
                            
                           
                             
                               
                             
     1 - À base de dados devem ser conferidas as garantias de segurança necessárias a impedir a consulta, a modificação, a supressão, o adicionamento, a destruição ou a comunicação de dados por forma não consentida pela presente lei. 
  2 - São objecto de controlo, tendo em vista a segurança da informação: 
  a) Os suportes de dados e o respectivo transporte, a fim de impedir que possam ser lidos, divulgados, copiados, alterados ou eliminados por pessoa não autorizada; 
  b) A inserção de dados, a fim de impedir a introdução, bem como qualquer tomada de conhecimento, divulgação, alteração ou eliminação não autorizada de dados pessoais; 
  c) Os sistemas de tratamento de dados, para impedir que possam ser utilizados por pessoas não autorizadas, através de instalações de transmissão de dados; 
  d) O acesso aos dados, para que só as pessoas autorizadas possam ter acesso aos dados; 
  e) A transmissão dos dados, para garantir que a sua utilização seja limitada às entidades autorizadas; 
  f) A introdução de dados pessoais nos sistemas de tratamento, de forma a verificar-se que dados foram introduzidos, quando e por quem.            
         
   
     
                         
                          
  Artigo 35.º Norma subsidiária
                            
                           
                             
                               
                             
     As disposições do presente capítulo são interpretadas e complementadas nos termos da Lei da Protecção de Dados Pessoais, aprovada pela Lei n.º 67/98, de 26 de Outubro.            
         
   
     
                         
                          
CAPÍTULO IV 
  Disposições finais  Artigo 36.º Comunicações
                            
                           
                             
                               
                             
     As comunicações efectuadas entre o tribunal e os serviços de reinserção social são realizadas preferencialmente por via electrónica, devendo, neste caso, ser tomadas as medidas adequadas para asseg','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('urar a segurança da informação, de modo a impedir o risco de esta ser vista e utilizada por terceiros não autorizados.            
         
   
     
                         
                          
  Artigo 37.º Norma revogatória
                            
                           
                             
                               
                             
     É revogada a Lei n.º 122/99, de 20 de Agosto, e o artigo 2.º da Lei n.º 115/2009, de 12 de Outubro. 
  Consultar o  LEI DA VIGILÂNCIA ELECTRÓNICA(actualizado face ao diploma em epígrafe)
  Consultar o  CÓDIGO DA EXECUÇÃO DAS PENAS E MEDIDAS PRIVATIVAS DA LIBERDADE (actualizado face ao diploma em epígrafe)            
         
   
     
                         
                          
  Artigo 38.º Entrada em vigor
                            
                           
                             
                               
                             
     A presente lei entra em vigor 30 dias após a sua publicação. 
  Aprovada em 22 de Julho de 2010. 
  O Presidente da Assembleia da República, Jaime Gama. 
  Promulgada em 20 de Agosto de 2010. 
  Publique-se. 
  O Presidente da República, Aníbal Cavaco Silva. 
  Referendada em 23 de Agosto de 2010. 
  O Primeiro-Ministro, José Sócrates Carvalho Pinto de Sousa.','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:98  
    
  Lei n.º 112/2009, de 16 de Setembro  (versão actualizada) REGIME JURÍDICO APLICÁVEL À PREVENÇÃO DA VIOLÊNCIA DOMÉSTICA E À PROTECÇÃO E ASSISTÊNCIA SUAS VÍ    
    
 
Contém as seguintes alterações:   - Lei n.º 19/2013, de 21 de Fevereiro   - Retificação n.º 15/2013, de 19 de Março   - Lei n.º 82-B/2014, de 31 de Dezembro   - Lei n.º 129/2015, de 03 de Setembro   - Lei n.º 42/2016, de 28 de Dezembro   - Lei n.º 24/2017, de 24 de Maio   - Lei n.º 2/2020, de 31 de Março   - Lei n.º 54/2020, de 26 de Agosto   - DL n.º 101/2020, de 26 de Novembro   - Lei n.º 57/2021, de 16 de Agosto  
                         
                          
SUMÁRIOEstabelece o regime jurídico aplicável à prevenção da violência doméstica, à protecção e à assistência das suas vítimas e revoga a Lei n.º 107/99, de 3 de Agosto, e o Decreto-Lei n.º 323/2000, de 19 de Dezembro
Lei n.º 112/2009 , de 16 de Setembro 
  Estabelece o regime jurídico aplicável à prevenção da violência doméstica, à protecção e à assistência das suas vítimas e revoga a Lei n.º 107/99, de 3 de Agosto, e o Decreto-Lei n.º 323/2000, de 19 de Dezembro. 
  A Assembleia da República decreta, nos termos da alínea c) do artigo 161.º da Constituição, o seguinte: 
  
  CAPÍTULO I
  Disposições gerais  Artigo 1.º 
Objeto
                            
                           
                             
                               
                             
     A presente lei estabelece o regime jurídico aplicável à prevenção da violência doméstica e à proteção e à assistência das suas vítimas.            
         
   
     
                         
                          
  Artigo 2.º 
Definições
                            
                           
                             
                               
                             
     Para efeitos de aplicação da presente lei, considera-se:
  a) Vítima a pessoa singular que sofreu um dano, nomeadamente um atentado à sua integridade física ou psíquica, um dano emocional ou moral, ou uma perda material, diretamente causada por ação ou omissão, no âmbito do crime de violência doméstica previsto no artigo 152.º do Código Penal, incluindo as crianças ou os jovens até aos 18 anos que sofreram maus tratos relacionados com exposição a contextos de violência doméstica;
  b) Vítima especialmente vulnerável a vítima cuja especial fragilidade resulte, nomeadamente, da sua diminuta ou avançada idade, do seu estado de saúde ou do facto de o tipo, o grau e a duração da vitimização haver resultado em lesões com consequências graves no seu equilíbrio psicológico ou nas condições da sua integração social;
  c) Técnico de apoio à vítima a pessoa devidamente habilitada que, no âmbito das suas funções, presta assistência direta às vítimas;
  d) Rede nacional de apoio às vítimas de violência doméstica o conjunto dos organismos vocacionados para o apoio às vítimas, incluindo o organismo da Administração Pública responsável pela ár','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ea da cidadania e da igualdade de género, o Instituto da Segurança Social, I. P. (ISS, I. P.), as casas de abrigo, as estruturas de atendimento, as respostas de acolhimento de emergência, as respostas específicas de organismos da Administração Pública e o serviço telefónico gratuito com cobertura nacional de informação a vítimas de violência doméstica;
  e) Organizações de apoio à vítima as organizações da sociedade civil, não governamentais (organizações não governamentais, organizações não governamentais de mulheres, instituições particulares de solidariedade social, fundações ou outras associações sem fins lucrativos), legalmente estabelecidas, cuja atividade se processa em cooperação com a ação do Estado e demais organismos públicos;
  f) Programa para autores de crimes no contexto da violência doméstica a intervenção estruturada junto dos autores de crimes no contexto da violência doméstica, que promova a mudança do seu comportamento criminal, contribuindo para a prevenção da reincidência, proposta e executada pelos serviços de reinserção social, ou por outras entidades competentes em razão da matéria.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro    - 2ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  CAPÍTULO II
  Finalidades  Artigo 3.º 
Finalidades
                            
                           
                             
                               
                             
     A presente lei estabelece um conjunto de medidas que têm por fim:
  a) Desenvolver políticas de sensibilização nas áreas da educação, da informação, da saúde, da segurança, da justiça e do apoio social, dotando os poderes públicos de instrumentos adequados para atingir esses fins;
  b) Consagrar os direitos das vítimas, assegurando a sua proteção célere e eficaz;
  c) Criar medidas de proteção com a finalidade de prevenir, evitar e punir a violência doméstica;
  d) Consagrar uma resposta integrada dos serviços sociais de emergência e de apoio à vítima, assegurando um acesso rápido e eficaz a esses serviços;
  e) Tutelar os direitos dos trabalhadores vítimas de violência doméstica;
  f) Garantir os direitos económicos da vítima de violência doméstica, para facilitar a sua autonomia;
  g) Criar políticas públicas destinadas a garantir a tutela dos direitos da vítima de violência doméstica;
  h) Assegurar uma proteção policial e jurisdicional célere e eficaz às vítimas de violência doméstica;
  i) Assegurar a aplicação de medidas de coação e reações penais adequadas aos autores do crime de violência doméstica, promovendo a aplicação de medidas complementares de prevenção e tratamento;
  j) Incentivar a criação e o desenvolvimento de associações e organizações da sociedade civil que tenham','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' por objetivo atuar contra a violência doméstica, promovendo a sua colaboração com as autoridades públicas;
  l) Garantir a prestação de cuidados de saúde adequados às vítimas de violência doméstica;
  m) Prever a análise retrospetiva de situações de homicídio ocorrido em contexto de violência doméstica e que tenham sido já objeto de decisão judicial transitada em julgado ou de decisão de arquivamento, com vista a retirar conclusões que permitam a implementação de novas metodologias preventivas ao nível dos procedimentos dos serviços da Administração Pública com intervenção na proteção das vítimas.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 4.º 
Plano Nacional Contra a Violência Doméstica
                            
                           
                             
                               
                             
     1 - Ao Governo compete elaborar e aprovar um Plano Nacional Contra a Violência Doméstica (PNCVD), obrigatoriamente avaliado e atualizado, e cuja aplicação deve ser prosseguida em coordenação com as demais políticas setoriais e com a sociedade civil.
  2 - A dinamização, o acompanhamento e a execução das medidas constantes do PNCVD competem ao organismo da Administração Pública responsável pela área da cidadania e da igualdade de género.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 4.º-A 
Análise retrospetiva de situações de homicídio em violência doméstica
                            
                           
                             
                               
                             
     1 - Os serviços da Administração Pública com intervenção na proteção das vítimas de violência doméstica realizam uma análise retrospetiva das situações de homicídio ocorrido em contexto de violência doméstica e que tenham sido já objeto de decisão judicial transitada em julgado ou de decisão de arquivamento, visando retirar conclusões que permitam a implementação de novas metodologias preventivas ao nível dos respetivos procedimentos.
  2 - Para efeitos do número anterior, é constituída uma Equipa de Análise Retrospetiva de Homicídio em Violência Doméstica composta por:
  a) Um representante designado pelo membro do Governo responsável pela área da justiça;
  b) Um representante designado pelo membro do Governo responsável pela área da saúde;
  c) Um representante designado pelo membro do Governo responsável pela área do trabalho, solidariedade e segurança social;
  d) Um representante da Secretaria-Geral do Ministério da Administração Interna ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('(SGMAI);
  e) Um representante do organismo da Administração Pública responsável pela área da cidadania e da igualdade de género;
  f) Um representante do Ministério Público;
  g) Um representante da Comissão Nacional de Promoção dos Direitos e Proteção das Crianças e Jovens;
  h) Um representante da força de segurança territorialmente competente na área em que tiver sido praticado o crime.
  3 - Para além dos elementos referidos no número anterior, podem ainda integrar a equipa um ou mais representantes de entidades locais, incluindo organizações da sociedade civil, que tenham tido intervenção no caso.
  4 - A análise prevista no n.º 1 compreende exclusivamente a análise dos seguintes elementos:
  a) Documentação constante do processo judicial;
  b) Documentação técnica das entidades representadas na equipa;
  c) Depoimentos prestados pelos técnicos que acompanharam o caso;
  d) Demais documentação de natureza técnica considerada relevante.
  5 - Para efeitos do disposto no presente artigo, as entidades públicas ou privadas com intervenção neste domínio devem facultar toda a documentação e prestar outras informações relevantes solicitadas para o efeito.
  6 - Sempre que se justificar, a Equipa de Análise Retrospetiva de Homicídio em Violência Doméstica produz recomendações tendo em vista a implementação de novas metodologias preventivas ao nível dos procedimentos.
  7 - Os elementos da Equipa de Análise Retrospetiva de Homicídio em Violência Doméstica estão sujeitos ao dever de confidencialidade.
  8 - Os representantes das entidades que integram a Equipa de Análise Retrospetiva de Homicídio em Violência Doméstica não têm, pelo exercício destas funções, direito a receber qualquer tipo de remuneração ou abono.
  9 - O procedimento previsto no presente artigo é regulamentado por portaria aprovada pelos membros do Governo responsáveis pelas áreas da administração interna, da cidadania e da igualdade de género, da saúde, da justiça e da segurança social.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  CAPÍTULO III
  Princípios  Artigo 5.º 
Princípio da igualdade
                            
                           
                             
                               
                             
     Toda a vítima, independentemente da ascendência, nacionalidade, condição social, sexo, etnia, língua, idade, religião, deficiência, convicções políticas ou ideológicas, orientação sexual, cultura e nível educacional goza dos direitos fundamentais inerentes à dignidade da pessoa humana, sendo-lhe assegurada a igualdade de oportunidades para viver sem violência e preservar a sua saúde física e mental.            
         
   
     
                         
                          
  Artigo 6.º 
Princípio do respeito e ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('reconhecimento
                            
                           
                             
                               
                             
     1 - À vítima é assegurado, em todas as fases e instâncias de intervenção, tratamento com respeito pela sua dignidade pessoal.
  2 - O Estado assegura às vítimas especialmente vulneráveis a possibilidade de beneficiar de um tratamento específico, o mais adaptado possível à sua situação.            
         
   
     
                         
                          
  Artigo 7.º 
Princípio da autonomia da vontade
                            
                           
                             
                               
                             
     A intervenção junto da vítima está limitada ao respeito integral da sua vontade, sem prejuízo das demais disposições aplicáveis no âmbito da legislação penal e processual penal.            
         
   
     
                         
                          
  Artigo 8.º 
Princípio da confidencialidade
                            
                           
                             
                               
                             
     Sem prejuízo do disposto no Código de Processo Penal, os serviços de apoio técnico à vítima asseguram o adequado respeito pela sua vida privada, garantindo o sigilo das informações que esta prestar.            
         
   
     
                         
                          
  Artigo 9.º 
Princípio do consentimento
                            
                           
                             
                               
                             
     1 - Sem prejuízo do disposto no Código de Processo Penal, qualquer intervenção de apoio à vítima deve ser efetuada após esta prestar o seu consentimento livre e esclarecido.
  2 - A intervenção de apoio específico, nos termos da presente lei, ao jovem vítima de violência doméstica, com idade igual ou superior a 16 anos, depende somente do seu consentimento.
  3 - A intervenção de apoio específico, nos termos da presente lei, à criança ou jovem vítima de violência doméstica, com idade inferior a 16 anos, depende do consentimento de representante legal, ou na sua ausência ou se este for o agente do crime, da entidade designada pela lei e do consentimento da criança ou jovem com idade igual ou superior a 12 anos.
  4 - O consentimento da criança ou jovem com idades compreendidas entre os 12 e os 16 anos é bastante para legitimar a intervenção de apoio específico nos termos da presente lei, caso as circunstâncias impeçam a receção, em tempo útil, de declaração sobre o consentimento de representante legal, ou na sua ausência ou se este for o agente do crime, da entidade designada pela lei.
  5 - A criança ou jovem vítima de violência doméstica, com idade inferior a 12 anos, tem o direito a pronunciar-se, em função da sua idade e grau de maturidade, sobre o apoio específico nos termos da presente lei.','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('
  6 - A vítima pode, em qualquer momento, revogar livremente o seu consentimento.
  7 - O disposto no presente artigo não prejudica os procedimentos de urgência previstos nos artigos 91.º e 92.º da Lei de Proteção das Crianças e Jovens em Perigo, aprovada pela Lei n.º 147/99, de 1 de setembro.            
         
   
     
                         
                          
  Artigo 10.º 
Proteção da vítima que careça de capacidade para prestar o seu consentimento
                            
                           
                             
                               
                             
     1 - Fora do âmbito do processo penal, qualquer intervenção de apoio a vítima que careça de capacidade para prestar o seu consentimento apenas poderá ser efetuada em seu benefício direto.
  2 - Sempre que, nos termos da lei, um maior careça, em virtude de perturbação mental, de doença ou por motivo similar, de capacidade para consentir numa intervenção, esta não poderá ser efetuada sem a autorização do seu representante, ou na sua ausência ou se este for o agente do crime, de uma autoridade ou de uma pessoa ou instância designada nos termos da lei.
  3 - A vítima em causa deve, na medida do possível, participar no processo de autorização.            
         
   
     
                         
                          
  Artigo 11.º 
Princípio da informação
                            
                           
                             
                               
                             
     O Estado assegura à vítima a prestação de informação adequada à tutela dos seus direitos, designadamente sobre os serviços de apoio e as medidas legais disponíveis, garantindo que a mesma é prestada em tempo útil e em língua que a vítima compreenda.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 12.º 
Princípio do acesso equitativo aos cuidados de saúde
                            
                           
                             
                               
                             
     O Estado, tendo em conta as necessidades de saúde, assegura as medidas adequadas com vista a garantir o acesso equitativo da vítima aos cuidados de saúde de qualidade apropriada.            
         
   
     
                         
                          
  Artigo 13.º 
Obrigações profissionais e regras de conduta
                            
                           
                             
                               
                             
     Qualquer intervenção de apoio técnico à vítima deve ser efetuada na observância das normas e obrigações profissionais, bem como das regras de conduta aplicáveis ao caso concreto.            
         
   
     
               ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('          
                          
  CAPÍTULO IV
  Estatuto de vítima
  SECÇÃO I
  Atribuição, direitos e cessação do estatuto de vítima  Artigo 14.º 
Atribuição do estatuto de vítima
                            
                           
                             
                               
                             
     1 - Apresentada a denúncia da prática do crime de violência doméstica, não existindo fortes indícios de que a mesma é infundada, as autoridades judiciárias ou os órgãos de polícia criminal competentes atribuem à vítima, para todos os efeitos legais, o estatuto de vítima.
  2 - Sempre que existam filhos menores, o regime de visitas do agressor deve ser avaliado, podendo ser suspenso ou condicionado, nos termos da lei aplicável.
  3 - No mesmo ato é entregue à vítima documento comprovativo do referido estatuto, que compreende os direitos e deveres estabelecidos na presente lei, além da cópia do respetivo auto de notícia, ou da apresentação de queixa.
  4 - Em situações excecionais e devidamente fundamentadas pode ser atribuído o estatuto de vítima pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, valendo este para os efeitos previstos na presente lei, com exceção dos relativos aos procedimentos policiais e judiciários.
  5 - A vítima e as autoridades competentes estão obrigadas a um dever especial de cooperação, devendo agir sob os ditames da boa fé.
  6 - Sempre que existam filhos menores, a atribuição de estatuto de vítima à criança e à pessoa adulta é comunicada imediatamente pelas autoridades judiciárias ou pelos órgãos de polícia criminal à comissão de proteção de crianças e jovens e ao tribunal de família e menores territorialmente competentes.
  7 - Sempre que a comunicação referida no número anterior tenha por destinatário o tribunal de família e menores territorialmente competente, deve ser acompanhada de cópia do respetivo auto de notícia ou da apresentação de denúncia, incluindo cópia da documentação relativa a diligências complementares entretanto efetuadas.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro    - 2ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 15.º 
Direito à informação
                            
                           
                             
                               
                             
     1 - É garantida à vítima, desde o seu primeiro contacto com as autoridades competentes para a aplicação da lei, o acesso às seguintes informações:
  a) O tipo de serviços ou de organizações a que pode dirigir-se para obter apoio;
  b) O tipo de apoio que pode receber;
  c) Onde e como pode apresentar denúncia;
  d) Quais os procedimentos sequentes à denúnci','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a e qual o seu papel no âmbito dos mesmos;
  e) Como e em que termos pode receber proteção;
  f) Em que medida e em que condições tem acesso a:
  i) Aconselhamento jurídico; ou
  ii) Apoio judiciário; ou
  iii) Outras formas de aconselhamento;
  g) Quais os requisitos que regem o seu direito a indemnização;
  h) Quais os mecanismos especiais de defesa que pode utilizar, sendo residente em outro Estado.
  2 - Sempre que a vítima o solicite junto da entidade competente para o efeito, e sem prejuízo do regime do segredo de justiça, deve ainda ser-lhe assegurada informação sobre:
  a) O seguimento dado à denúncia;
  b) Os elementos pertinentes que lhe permitam, após a acusação ou a decisão instrutória, ser inteirada do estado do processo e da situação processual do arguido, por factos que lhe digam respeito, salvo em casos excecionais que possam prejudicar o bom andamento dos autos;
  c) A sentença do tribunal.
  3 - Devem ser promovidos os mecanismos adequados para fornecer à vítima a informação sobre a libertação de agente detido, preso preventivamente ou condenado pela prática do crime de violência doméstica, no âmbito do processo penal.
  4 - A vítima deve ainda ser informada, sempre que tal não perturbe o normal desenvolvimento do processo penal, sobre o nome do agente responsável pela investigação, bem como da possibilidade de entrar em contacto com o mesmo para obter informações sobre o estado do processo penal.
  5 - Deve ser assegurado à vítima o direito de optar por não receber as informações referidas nos números anteriores, salvo quando a comunicação das mesmas for obrigatória nos termos do processo penal aplicável.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 16.º 
Direito à audição e à apresentação de provas
                            
                           
                             
                               
                             
     1 - A vítima que se constitua assistente colabora com o Ministério Público de acordo com o estatuto do assistente em processo penal.
  2 - As autoridades apenas devem inquirir a vítima na medida do necessário para os fins do processo penal.            
         
   
     
                         
                          
  Artigo 17.º 
Garantias de comunicação
                            
                           
                             
                               
                             
     1 - Devem ser tomadas as medidas necessárias, em condições comparáveis às aplicáveis ao agente do crime, para minimizar tanto quanto possível os problemas de comunicação, quer em relação à compreensão, quer em relação à intervenção da vítima na qualidade de sujeito processual nos diversos atos processuais do processo penal em causa.
  2 - ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('São aplicáveis nas situações referidas no número anterior, as disposições legais em vigor relativas à nomeação de intérprete.            
         
   
     
                         
                          
  Artigo 18.º 
Assistência específica à vítima
                            
                           
                             
                               
                             
     O Estado assegura, gratuitamente nos casos estabelecidos na lei, que a vítima tenha acesso a consulta jurídica e a aconselhamento sobre o seu papel durante o processo e, se necessário, o subsequente apoio judiciário quando esta seja sujeito em processo penal.            
         
   
     
                         
                          
  Artigo 19.º 
Despesas da vítima resultantes da sua participação no processo penal
                            
                           
                             
                               
                             
     À vítima que intervenha na qualidade de sujeito no processo penal, deve ser proporcionada a possibilidade de ser reembolsada das despesas efetuadas em resultado da sua legítima participação no processo penal, nos termos estabelecidos na lei.            
         
   
     
                         
                          
  Artigo 20.º 
Direito à proteção
                            
                           
                             
                               
                             
     1 - É assegurado um nível adequado de proteção à vítima e, sendo caso disso, à sua família ou a pessoas em situação equiparada, nomeadamente no que respeita à segurança e salvaguarda da vida privada, sempre que as autoridades competentes considerem que existe uma ameaça séria de represálias, de situações de revitimação ou fortes indícios de que essa privacidade possa ser perturbada.
  2 - O contacto entre vítimas e arguidos em todos os locais que impliquem a presença em diligências conjuntas, nomeadamente nos edifícios dos tribunais, deve ser evitado, sem prejuízo da aplicação das regras processuais estabelecidas no Código de Processo Penal.
  3 - Às vítimas especialmente vulneráveis deve ser assegurado o direito a beneficiarem, por decisão judicial, de condições de depoimento, por qualquer meio compatível, que as protejam dos efeitos do depoimento prestado em audiência pública.
  4 - O juiz, ou, durante a fase de inquérito, o Ministério Público, deve determinar, sempre que tal se mostre imprescindível à proteção da vítima e obtido o seu consentimento, que lhe seja assegurado apoio psicossocial e proteção por teleassistência, por período não superior a seis meses, prorrogável se as circunstâncias associadas à proteção da vítima o justificarem.
  5 - A vítima pode requerer que a sua morada seja ocultada nas notificações das autoridades competentes que tenham o suspeito ou o arguido como destinatário.
  6 - Por regulamentação do Governo é definido o organismo da Admin','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('istração Pública responsável pelos sistemas técnicos de teleassistência, que pode recorrer a regimes de parceria para os instalar, assegurar e manter em funcionamento.
  7 - A proteção por teleassistência considera-se automaticamente extinta decorrido um período equivalente ao prazo inicialmente determinado, acrescido de duas prorrogações, quando não tenha ocorrido a comunicação fundamentada da decisão de extinção ou prorrogação ao organismo referido no número anterior.
  8 - O disposto nos números anteriores não prejudica a aplicação das demais soluções constantes do regime especial de proteção de testemunhas, nomeadamente no que se refere à proteção dos familiares da vítima.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro   - Lei n.º 54/2020, de 26 de Agosto   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro    - 2ª versão: Lei n.º 129/2015, de 03 de Setembro    - 3ª versão: Lei n.º 54/2020, de 26 de Agosto   
     
                         
                          
  Artigo 21.º 
Direito a indemnização e a restituição de bens
                            
                           
                             
                               
                             
     1 - À vítima é reconhecido, no âmbito do processo penal, o direito a obter uma decisão de indemnização por parte do agente do crime, dentro de um prazo razoável.
  2 - Para efeito da presente lei, há sempre lugar à aplicação do disposto no artigo 82.º-A do Código de Processo Penal, exceto nos casos em que a vítima a tal expressamente se opuser.
  3 - Salvo necessidade imposta pelo processo penal, os objetos restituíveis pertencentes à vítima e apreendidos no processo penal são imediatamente examinados e devolvidos.
  4 - Independentemente do andamento do processo, à vítima é reconhecido o direito a retirar da residência todos os seus bens de uso pessoal e, ainda, sempre que possível, os seus bens móveis próprios, bem como os bens pertencentes a filhos menores e a pessoa maior de idade que se encontre na direta dependência da vítima em razão de afetação grave, permanente e incapacitante no plano psíquico ou físico, devendo os bens constar de lista disponibilizada no âmbito do processo e sendo a vítima acompanhada, quando necessário, por autoridade policial.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 22.º 
Condições de prevenção da vitimização secundária
                            
                           
                             
                               
                             
     1 - A vítima tem direito a ser ouvida em ambiente informal e reservado, devendo ser cr','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('iadas as adequadas condições para prevenir a vitimização secundária e para evitar que sofra pressões.
  2 - A vítima tem ainda direito, sempre que possível, e de forma imediata, a dispor de adequado atendimento psicológico e psiquiátrico por parte de equipas multidisciplinares de profissionais habilitadas à despistagem e terapia dos efeitos associados ao crime de violência doméstica.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 23.º 
Vítima residente noutro Estado
                            
                           
                             
                               
                             
     1 - A vítima não residente em Portugal beneficia das medidas adequadas ao afastamento das dificuldades que surjam em razão da sua residência, especialmente no que se refere ao andamento do processo penal.
  2 - A vítima não residente em Portugal beneficia ainda da possibilidade de prestar declarações para memória futura imediatamente após ter sido cometida a infração, bem como da audição através de videoconferência e de teleconferência.
  3 - É ainda assegurado à vítima de crime praticado fora de Portugal a possibilidade de apresentar denúncia junto das autoridades nacionais, sempre que não tenha tido a possibilidade de o fazer no Estado onde foi cometido o crime, caso em que as autoridades nacionais devem transmiti-la prontamente às autoridades competentes do território onde foi cometido o crime.
  4 - No caso de a vítima residir ou se ausentar para outro Estado-membro da União Europeia, a mesma pode solicitar a emissão de uma decisão europeia de proteção com respeito às medidas de coação, injunções ou regras de conduta no âmbito da suspensão provisória do processo em fase de inquérito, ou a penas principais ou acessórias nas quais sejam decretadas medidas de proteção nos termos previstos no regime jurídico correspondente.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 24.º 
Cessação do estatuto de vítima
                            
                           
                             
                               
                             
     1 - O estatuto de vítima cessa por vontade expressa da vítima ou por verificação da existência de fortes indícios de denúncia infundada.
  2 - O estatuto de vítima cessa igualmente com o arquivamento do inquérito, do despacho de não pronúncia ou após o trânsito em julgado da decisão que ponha termo à causa, salvo se, a requerimento da vítima junto do Ministério Público ou do tribunal competente, consoante os casos, a ne','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('cessidade da sua proteção o justificar.
  3 - A cessação do estatuto da vítima não prejudica, sempre que as circunstâncias do caso forem consideradas justificadas pelos correspondentes serviços, a continuação das modalidades de apoio social que tenham sido estabelecidas.
  4 - A cessação do estatuto da vítima, quando ocorra, em nenhum caso prejudica as regras aplicáveis do processo penal.            
         
   
     
                         
                          
  SECÇÃO II
  Proteção policial e tutela judicial  Artigo 25.º 
Acesso ao direito
                            
                           
                             
                               
                             
     1 - É garantida à vítima, com prontidão, consulta jurídica a efetuar por advogado, bem como a célere e sequente concessão de apoio judiciário, com natureza urgente, nos termos legais.
  2 - Quando o mesmo facto der causa a diversos processos, deve ser assegurada, sempre que possível, a nomeação do mesmo mandatário ou defensor oficioso à vítima.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 2/2020, de 31 de Março
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 26.º 
Assessoria e consultoria técnicas
                            
                           
                             
                               
                             
     Os gabinetes de apoio aos magistrados judiciais e do Ministério Público previstos na Lei de Organização do Sistema Judiciário devem, sempre que possível, incluir assessoria e consultoria técnicas na área da violência doméstica.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 27.º 
Gabinetes de atendimento e informação à vítima nos órgãos de polícia criminal
                            
                           
                             
                               
                             
     1 - Os gabinetes de atendimento a vítimas a funcionar junto dos órgãos de polícia criminal asseguram a prevenção, o atendimento e o acompanhamento das situações de violência doméstica.
  2 - Cada força e serviço de segurança constituem a sua rede de gabinetes de atendimento, dotados de condições adequadas, nomeadamente de privacidade, ao atendimento de vítimas.
  3 - O disposto nos números anteriores deve igualmente ser concretizado, sempre que possível, nas instalações dos departamentos de investigação e ação penal (DIAP).            
         
   
     
                         
                          
  Artigo 27.º-A 
Intervenção dos órgãos de polícia criminal
                            
                 ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('          
                             
                               
                             
     1 - No cumprimento das disposições aplicáveis às situações de violência doméstica, as forças e os serviços de segurança adotam os procedimentos necessários para assegurar o acompanhamento e a proteção policial das vítimas.
  2 - A proteção policial de uma vítima de violência doméstica, no âmbito judicial ou fora dele, deve assentar na prestação de orientações de autoproteção ou num plano individualizado de segurança, elaborado pela autoridade de polícia localmente competente, em função do nível de risco de revitimação, nível este que orienta o momento da reavaliação desse risco.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 28.º 
Celeridade processual
                            
                           
                             
                               
                             
     1 - Os processos por crime de violência doméstica têm natureza urgente, ainda que não haja arguidos presos.
  2 - A natureza urgente dos processos por crime de violência doméstica implica a aplicação do regime previsto no n.º 2 do artigo 103.º do Código de Processo Penal.            
         
   
     
                         
                          
  Artigo 29.º 
Denúncia do crime
                            
                           
                             
                               
                             
     1 - A denúncia de natureza criminal é feita nos termos gerais, sempre que possível, através de formulários próprios, nomeadamente autos de notícia padrão, criados no âmbito da prevenção, da investigação criminal e do apoio às vítimas.
  2 - É ainda assegurada a existência de formulários próprios no âmbito do sistema de queixa eletrónica, que garante a conexão com um sítio da Internet de acesso público com informações específicas sobre violência doméstica.
  3 - A denúncia é de imediato elaborada pela entidade que a receber e, quando feita a entidade diversa do Ministério Público, é a este imediatamente transmitida, acompanhada da primeira avaliação de risco da vítima efetuada pelos órgãos de polícia criminal, sendo igualmente remetidas ao Ministério Público as reavaliações subsequentes que forem realizadas.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro    - 2ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 29.º-A 
Medidas de proteção à vítima
                            
                           
                ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('             
                               
                             
     1 - Logo que tenha conhecimento da denúncia, sem prejuízo das medidas cautelares e de polícia já adotadas, o Ministério Público, caso não se decida pela avocação, determina ao órgão de polícia criminal, pela via mais expedita, a realização de atos processuais urgentes de aquisição de prova que habilitem, no mais curto período de tempo possível sem exceder as 72 horas, à tomada de medidas de proteção à vítima e à promoção de medidas de coação relativamente ao arguido.
  2 - Com a denúncia, a vítima é sempre encaminhada para as estruturas locais de apoio, em vista à elaboração de plano de segurança, caso não tenha sido elaborado pelo órgão de polícia criminal e para efeitos do recebimento de demais apoio legalmente previsto.
  
  Aditado pelo seguinte diploma: Lei n.º 129/2015, de 03 de Setembro            
         
   
     
                         
                          
  Artigo 30.º 
Detenção
                            
                           
                             
                               
                             
     1 - Em caso de flagrante delito por crime de violência doméstica, a detenção efetuada mantém-se até o detido ser apresentado a audiência de julgamento sob a forma sumária ou a primeiro interrogatório judicial para eventual aplicação de medida de coação ou de garantia patrimonial, sem prejuízo do disposto no n.º 3 do artigo 143.º, no n.º 1 do artigo 261.º, no n.º 4 do artigo 382.º e no n.º 3 do artigo 385.º do Código de Processo Penal.
  2 - Para além do previsto no n.º 1 do artigo 257.º do Código de Processo Penal, a detenção fora de flagrante delito pelo crime previsto no número anterior pode ser efetuada por mandado do juiz ou do Ministério Público, se houver perigo de continuação da atividade criminosa ou se tal se mostrar imprescindível à proteção da vítima.
  3 - Para além das situações previstas no n.º 2 do artigo 257.º do Código de Processo Penal, as autoridades policiais podem também ordenar a detenção fora de flagrante delito pelo crime previsto no n.º 1, por iniciativa própria, quando:
  a) Se encontre verificado qualquer dos requisitos previstos no número anterior; e
  b) Não for possível, dada a situação de urgência e de perigo na demora, aguardar pela intervenção da autoridade judiciária.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 31.º 
Medidas de coação urgentes
                            
                           
                             
                               
                             
     1 - Após a constituição de arguido pelo crime de violência doméstica, o juiz pondera, no prazo máximo de 48 horas, a aplicação, com respeito pelos pressupostos g','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('erais e específicos de aplicação das medidas de coação previstas no Código de Processo Penal, de medida ou medidas de entre as seguintes:
  a) Não adquirir, não usar ou entregar, de forma imediata, armas ou outros objetos e utensílios que detiver, capazes de facilitar a continuação da atividade criminosa;
  b) Sujeitar, mediante consentimento prévio, a frequência de programa para arguidos em crimes no contexto da violência doméstica;
  c) Não permanecer nem se aproximar da residência onde o crime tenha sido cometido, onde habite a vítima ou que seja casa de morada da família, impondo ao arguido a obrigação de a abandonar;
  d) Não contactar com a vítima, com determinadas pessoas ou frequentar certos lugares ou certos meios, bem como não contactar, aproximar-se ou visitar animais de companhia da vítima ou da família;
  e) Restringir o exercício de responsabilidades parentais, da tutela, do exercício de medidas relativas a maior acompanhado, da administração de bens ou da emissão de títulos de crédito.
  2 - O disposto nas alíneas c) e d) do número anterior mantém a sua relevância mesmo nos casos em que a vítima tenha abandonado a residência em razão da prática ou de ameaça séria do cometimento do crime de violência doméstica.
  3 - As medidas previstas neste artigo são sempre cumuláveis com qualquer outra medida de coação prevista no Código de Processo Penal.
  4 - As medidas de coação que impliquem a restrição de contacto entre progenitores ou entre estes e os seus descendentes são imediatamente comunicadas pelo tribunal ao Ministério Público junto do tribunal competente, para efeitos de instauração, com caráter de urgência, do respetivo processo de regulação ou alteração da regulação do exercício das responsabilidades parentais e/ou da providência tutelar cível entendida adequada.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro   - Lei n.º 24/2017, de 24 de Maio   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro    - 2ª versão: Lei n.º 129/2015, de 03 de Setembro    - 3ª versão: Lei n.º 24/2017, de 24 de Maio   
     
                         
                          
  Artigo 32.º 
Recurso à videoconferência ou à teleconferência
                            
                           
                             
                               
                             
     1 - Os depoimentos e declarações das vítimas, quando impliquem a presença do arguido, são prestados através de videoconferência ou de teleconferência, se o tribunal, designadamente a requerimento da vítima ou do Ministério Público, o entender como necessário para garantir a prestação de declarações ou de depoimento sem constrangimentos, podendo, para o efeito, solicitar parecer aos profissionais de saúde, aos técnicos de apoio à vítima ou a outros profissionais que acompanhem a evolução da situação.
  2 - A vítima é acom','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('panhada, sempre que o solicitar, na prestação das declarações ou do depoimento, pelo técnico de apoio à vítima ou por outro profissional que lhe tenha vindo a prestar apoio psicológico ou psiquiátrico.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 33.º 
Declarações para memória futura
                            
                           
                             
                               
                             
     1 - O juiz, a requerimento da vítima ou do Ministério Público, pode proceder à inquirição daquela no decurso do inquérito, a fim de que o depoimento possa, se necessário, ser tomado em conta no julgamento.
  2 - O Ministério Público, o arguido, o defensor e os advogados constituídos no processo são notificados da hora e do local da prestação do depoimento para que possam estar presentes, sendo obrigatória a comparência do Ministério Público e do defensor.
  3 - A tomada de declarações é realizada em ambiente informal e reservado, com vista a garantir, nomeadamente, a espontaneidade e a sinceridade das respostas, devendo a vítima ser assistida no decurso do ato processual pelo técnico de apoio à vítima ou por outro profissional que lhe tenha vindo a prestar apoio psicológico ou psiquiátrico, previamente autorizados pelo tribunal.
  4 - A inquirição é feita pelo juiz, podendo em seguida o Ministério Público, os advogados constituídos e o defensor, por esta ordem, formular perguntas adicionais.
  5 - É correspondentemente aplicável o disposto nos artigos 352.º, 356.º, 363.º e 364.º do Código de Processo Penal.
  6 - O disposto nos números anteriores é correspondentemente aplicável a declarações do assistente e das partes civis, de peritos e de consultores técnicos e acareações.
  7 - A tomada de declarações nos termos dos números anteriores não prejudica a prestação de depoimento em audiência de julgamento, sempre que ela for possível e não puser em causa a saúde física ou psíquica de pessoa que o deva prestar.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 34.º 
Tomada de declarações
                            
                           
                             
                               
                             
     Se, por fundadas razões, a vítima se encontrar impossibilitada de comparecer na audiência, pode o tribunal ordenar, oficiosamente ou a requerimento, que lhe sejam tomadas declarações no lugar em que se encontre, em dia e hora que lhe comunicará, aplicando-se correspondentemente o disposto no artigo 319.º do Código de Process','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o Penal.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 34.º-A 
Avaliação de risco da vítima na fase de julgamento
                            
                           
                             
                               
                             
     No despacho que designa dia para a audiência de julgamento, o tribunal solicita a avaliação de risco atualizada da vítima.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 34.º-B 
Suspensão da execução da pena de prisão
                            
                           
                             
                               
                             
     1 - A suspensão da execução da pena de prisão de condenado pela prática de crime de violência doméstica previsto no artigo 152.º do Código Penal é sempre subordinada ao cumprimento de deveres ou à observância de regras de conduta, impostos separada ou cumulativamente, ou ao acompanhamento de regime de prova, em qualquer caso se incluindo regras de conduta que protejam a vítima, designadamente o afastamento do condenado da vítima, da sua residência ou local de trabalho e a proibição de contactos, por qualquer meio.
  2 - O disposto no número anterior sobre as medidas de proteção é aplicável aos menores, nos casos previstos no n.º 2 do artigo 152.º do Código Penal.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 35.º 
Meios técnicos de controlo à distância
                            
                           
                             
                               
                             
     1 - O tribunal, com vista à aplicação das medidas e penas previstas nos artigos 52.º e 152.º do Código Penal, no artigo 281.º do Código de Processo Penal e no artigo 31.º da presente lei, deve, sempre que tal se mostre imprescindível para a proteção da vítima, determinar que o cumprimento daquelas medidas seja fiscalizado por meios técnicos de controlo à distância.
  2 - O controlo à distância é efetuado, no respeito pela dignidade pessoal do arguido, por monitorização telemática posicional, ou outra tecnologia idónea, de acordo com os sistemas tecnológicos adequados.
  3 - O controlo à distância cabe aos serviços de reinserção social e é executado em estreita articulação com os serviços de apoio à vítima, sem prejuízo do uso dos siste','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('mas complementares de teleassistência referidos no n.º 6 do artigo 20.º
  4 - Para efeitos do disposto no n.º 1, o juiz solicita prévia informação aos serviços encarregados do controlo à distância sobre a situação pessoal, familiar, laboral e social do arguido ou do agente.
  5 - À revogação, alteração e extinção das medidas de afastamento fiscalizadas por meios técnicos de controlo à distância aplicam-se as regras previstas nos artigos 55.º a 57.º do Código Penal e nos artigos 212.º e 282.º do Código de Processo Penal.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 19/2013, de 21 de Fevereiro   - Retificação n.º 15/2013, de 19 de Março   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro    - 2ª versão: Lei n.º 19/2013, de 21 de Fevereiro    - 3ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 36.º 
Consentimento
                            
                           
                             
                               
                             
     1 - A utilização dos meios técnicos de controlo à distância depende do consentimento do arguido ou do agente e, nos casos em que a sua utilização abranja a participação da vítima, depende igualmente do consentimento desta.
  2 - A utilização dos meios técnicos de controlo à distância depende ainda do consentimento das pessoas que o devam prestar, nomeadamente das pessoas que vivam com o arguido ou o agente e das que possam ser afetadas pela permanência obrigatória do arguido ou do agente em determinado local.
  3 - O consentimento do arguido ou do agente é prestado pessoalmente perante o juiz, na presença do defensor, e reduzido a auto.
  4 - Sempre que a utilização dos meios técnicos de controlo à distância for requerida pelo arguido ou pelo agente, o consentimento considera-se prestado por simples declaração deste no requerimento.
  5 - As vítimas e as pessoas referidas no n.º 2 prestam o seu consentimento aos serviços encarregados da execução dos meios técnicos de controlo à distância por simples declaração escrita, que o enviam posteriormente ao juiz.
  6 - Os consentimentos previstos neste artigo são revogáveis a todo o tempo.
  7 - Não se aplica o disposto nos números anteriores sempre que o juiz, de forma fundamentada, determine que a utilização de meios técnicos de controlo à distância é imprescindível para a proteção dos direitos da vítima.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 19/2013, de 21 de Fevereiro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 37.º 
Comunicação obrigatória e tratamento de dados
                            
                           
                             
                               
        ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                     
     (Revogado.)            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro    - 2ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 37.º-A 
Base de Dados de Violência contra as Mulheres e Violência Doméstica
                            
                           
                             
                               
                             
     1 - É criada a Base de Dados de Violência contra as Mulheres e Violência Doméstica (BDVMVD), sendo o respetivo tratamento da responsabilidade da SGMAI.
  2 - O tratamento de dados efetuado no âmbito da BDVMVD reporta-se aos casos em que foi iniciado procedimento criminal no âmbito da violência contra as mulheres e/ou violência doméstica, e tem por finalidades exclusivas:
  a) Promover um conhecimento aprofundado ao nível da violência contra as mulheres e violência doméstica, contribuindo para o desenvolvimento da política criminal, da política de segurança e das demais políticas públicas especificamente direcionadas para a prevenção e combate a estas formas de violência;
  b) Obter uma visão global e integrada em matéria de homicídios e de outras formas de violência contra as mulheres e violência doméstica, através do tratamento e cruzamento de informação proveniente do sistema de justiça penal e que englobe dados com origem noutros setores, e que viabilize a análise das trajetórias dos casos.
  3 - Os dados tratados abrangem as seguintes tipologias:
  a) Ocorrências registadas pelos órgãos de polícia criminal, respetivas avaliações de risco, detenções efetuadas e medidas cautelares de polícia adotadas;
  b) Decisões sobre atribuição do estatuto de vítima;
  c) Medidas de proteção à vítima adotadas aquando do início do procedimento ou no seu decurso, seja por via dos órgãos de polícia criminal, do tribunal ou da rede nacional de apoio às vítimas de violência doméstica, designadamente o acompanhamento da vítima por técnico ou pessoa da sua confiança nos atos processuais, acompanhamento policial para retirada de bens da residência por parte da vítima, recurso a declarações para memória futura, aplicação da medida de teleassistência e recurso a estrutura ou resposta da rede nacional de apoio às vítimas de violência doméstica;
  d) Processos de promoção dos direitos e proteção de crianças e existência de procedimentos contemporâneos relacionados com o exercício das responsabilidades parentais;
  e) Medidas de coação aplicadas;
  f) Decisões europeias de investigação e decisões europeias de proteção;
  g) Resultados dos processos ao longo das fases de inquérito, instrução criminal, julgamento e recurso, situações de reclassificação do crime inicialmente registado, penas principais e acessórias e medidas de segurança a inimp','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('utáveis;
  h) Caracterização e situação dos condenados a cumprir pena de prisão e em regime de permanência na habitação e cumprimento do direito da vítima de ser informada sobre a libertação ou evasão da pessoa detida, acusada, pronunciada ou condenada;
  i) Identificação de processos com análise retrospetiva de homicídio em contexto de violência doméstica;
  j) Indemnização atribuída às vítimas.
  4 - A BDVMVD abrange as situações de maus tratos cometidos no contexto da violência doméstica, configurando o crime de violência doméstica previsto no artigo 152.º do Código Penal ou outro crime cometido contra uma das pessoas previstas no n.º 1 do mesmo artigo e que tenha moldura penal mais grave, incluindo, nomeadamente, homicídio, ofensa à integridade física grave e violação, e ainda outras situações não contidas nas anteriores, mas que se incluam na esfera da violência contra as mulheres, configurando, designadamente, crime de violação, mutilação genital feminina ou perseguição.
  5 - Os dados constantes na BDVMVD são provenientes das seguintes fontes:
  a) Guarda Nacional Republicana;
  b) Polícia de Segurança Pública;
  c) Polícia Judiciária;
  d) Sistema informático de suporte à atividade dos tribunais, gerido pelo Instituto de Gestão Financeira e Equipamentos da Justiça, IP;
  e) Procuradoria-Geral da República;
  f) Comissão para a Cidadania e a Igualdade de Género (CIG);
  g) Comissão Nacional de Promoção dos Direitos e Proteção das Crianças e Jovens;
  h) Direção-Geral de Reinserção e Serviços Prisionais;
  i) Comissão de Proteção a Vítimas de Crime;
  j) ISS, IP.
  6 - O acesso à BDVMVD é feito por utilizadores da SGMAI, dos órgãos de polícia criminal e do Ministério Público.
  7 - O tratamento de dados no âmbito da BDVMVD destina-se a permitir a análise das trajetórias de casos através da integração dos dados constantes das diversas fontes, mediante a interconexão entre a BDVMVD e as bases de dados onde se encontram os dados referidos no n.º 3, por referência ao NUIPC e aos dados estritamente necessários à identificação das vítimas e denunciados, com exclusão de quaisquer outros dados pessoais.
  8 - É objeto de regulamento próprio, submetido a parecer prévio da Comissão Nacional de Proteção de Dados:
  a) O elenco concreto de crimes abrangidos pela BDVMVD;
  b) O modelo de dados a comunicar segundo a fonte;
  c) As formas de comunicação dos dados, privilegiando-se, sempre que possível, a implementação de soluções automáticas que visem a interoperabilidade entre sistemas informáticos;
  d) Os perfis de acesso;
  e) Os prazos de conservação para os dados;
  f) As regras e medidas de segurança a implementar, tendo em vista a proteção dos dados pessoais e que se mostrem necessárias em resultado da realização da avaliação de impacto sobre a proteção de dados.
  9 - O regulamento de funcionamento da BDVMVD referido no número anterior é aprovado, no prazo de 180 dias, através de portaria aprovada pelos membros do Governo responsáveis pelas áreas','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' da cidadania e da igualdade de género, da administração interna, da justiça e do trabalho, solidariedade e segurança social, e mediante consulta prévia do Conselho Superior de Magistratura e da Procuradoria-Geral da República.
  10 - Os dados e indicadores tratados ao nível da BDVMVD são comunicados, sem identificação de dados pessoais, à CIG, com uma periodicidade trimestral, tendo em vista a atualização permanente do respetivo portal que promove o acesso e a publicitação dos principais dados e indicadores.
  11 - Qualquer tratamento de dados e sua disponibilização a terceiros é sempre efetuada sem identificação de dados pessoais e todos os utilizadores da BDVMVD, cujo perfil viabilize algum acesso a dados pessoais, estão sujeitos ao dever de confidencialidade.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 37.º-B 
Comunicação obrigatória de decisões judiciais
                            
                           
                             
                               
                             
     (Revogado.)            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 24/2017, de 24 de Maio
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 38.º 
Medidas de apoio à reinserção do agente
                            
                           
                             
                               
                             
     1 - O Estado deve promover a criação das condições necessárias ao apoio psicológico e psiquiátrico aos agentes condenados pela prática de crimes de violência doméstica, bem como àqueles em relação aos quais tenha recaído decisão de suspensão provisória do processo, obtido o respetivo consentimento.
  2 - São definidos e implementados programas para autores de crimes no contexto da violência doméstica, designadamente com vista à suspensão da execução da pena de prisão.            
         
   
     
                         
                          
  Artigo 39.º 
Encontro restaurativo
                            
                           
                             
                               
                             
     (Revogado.)            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 40.º 
Apoio financeiro
                            
                           
                             
                               
                             
     A vítima de violência doméstic','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a beneficia de apoio financeiro do Estado, nos termos da legislação aplicável.            
         
   
     
                         
                          
  SECÇÃO III
  Tutela social  Artigo 41.º 
Cooperação das entidades empregadoras
                            
                           
                             
                               
                             
     Sempre que possível, e quando a dimensão e a natureza da entidade empregadora o permitam, esta deve tomar em consideração de forma prioritária:
  a) O pedido de mudança do trabalhador a tempo completo que seja vítima de violência doméstica para um trabalho a tempo parcial que se torne disponível no órgão ou serviço;
  b) O pedido de mudança do trabalhador a tempo parcial que seja vítima de violência doméstica para um trabalho a tempo completo ou de aumento do seu tempo de trabalho.            
         
   
     
                         
                          
  Artigo 42.º 
Transferência a pedido do trabalhador
                            
                           
                             
                               
                             
     1 - Nos termos do Código do Trabalho, o trabalhador vítima de violência doméstica tem direito a ser transferido, temporária ou definitivamente, a seu pedido, para outro estabelecimento da empresa, verificadas as seguintes condições:
  a) Apresentação de denúncia;
  b) Saída da casa de morada de família no momento em que se efetive a transferência.
  2 - Em situação prevista no número anterior, o empregador apenas pode adiar a transferência com fundamento em exigências imperiosas ligadas ao funcionamento da empresa ou serviço ou até que exista posto de trabalho compatível disponível.
  3 - No caso previsto no número anterior, o trabalhador tem direito a suspender o contrato de imediato até que ocorra a transferência.
  4 - É garantida a confidencialidade da situação que motiva as alterações contratuais do número anterior, se solicitado pelo interessado.
  5 - O disposto nos números anteriores é aplicável, com as devidas adaptações, aos trabalhadores que exercem funções públicas, independentemente da modalidade de constituição da relação jurídica de emprego público ao abrigo da qual exercem as respetivas funções.
  6 - Na situação de suspensão a que se refere o n.º 3, são aplicáveis aos trabalhadores que exercem funções públicas, com as necessárias adaptações, os efeitos previstos no artigo 277.º da Lei Geral do Trabalho em Funções Públicas, aprovada pela Lei n.º 35/2014, de 20 de junho.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 43.º 
Faltas
                            
                           
                             
                               ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('
                             
     As faltas dadas pela vítima que sejam motivadas por impossibilidade de prestar trabalho em razão da prática do crime de violência doméstica são, de acordo com o regime legal aplicável, consideradas justificadas.            
         
   
     
                         
                          
  Artigo 43.º-A 
Licença de reestruturação familiar
                            
                           
                             
                               
                             
     1 - O trabalhador vítima de violência doméstica, a quem tenha sido atribuído o respetivo estatuto e que se veja obrigado a sair da sua residência, em razão da prática do crime de violência doméstica, tem direito a uma licença pelo período máximo de 10 dias seguidos.
  2 - Não determinam perda de quaisquer direitos, salvo quanto à retribuição, as ausências ao trabalho resultantes do gozo da licença referida no número anterior.
  3 - O disposto nos números anteriores é aplicável ao trabalhador por conta de outrem e ao trabalhador em exercício de funções públicas, independentemente da modalidade de vínculo de emprego público.
  
  Aditado pelo seguinte diploma: Decreto-Lei n.º 101/2020, de 26 de Novembro            
         
   
     
                         
                          
  Artigo 43.º-B 
Subsídio de reestruturação familiar
                            
                           
                             
                               
                             
     1 - O subsídio de reestruturação familiar é concedido a vítima de violência doméstica a quem tenha sido atribuído o respetivo estatuto, nos seguintes termos:
  a) Quando se trate de trabalhador por conta de outrem ou em exercício de funções públicas, o montante diário do subsídio corresponde a 1/30 do valor da remuneração base líquida auferida no mês anterior à apresentação de requerimento, durante o período da licença prevista no artigo anterior;
  b) Quando se trate de trabalhador independente, o montante diário do subsídio corresponde a 1/30 do rendimento relevante apurado na última declaração trimestral, com um limite máximo equivalente a 10 dias;
  c) Quando se trate de membro de órgão estatutário de pessoa coletiva, o montante diário do subsídio corresponde a 1/30 do valor da remuneração base líquida auferida no mês anterior à apresentação de requerimento, com um limite máximo equivalente a 10 dias;
  d) Quando se trate de profissional não abrangido pelo sistema de proteção social da segurança social ou quando não detenha qualquer vínculo laboral ou profissional, o montante diário do subsídio corresponde a 1/30 do valor do indexante dos apoios sociais (IAS), com um limite máximo equivalente a 10 dias.
  2 - O montante diário mínimo do subsídio previsto no presente artigo não pode ser inferior a 1/30 do valor do IAS.
  3 - A atribuição do subsídio depende da apresentação de requerimento instruído com cópia do documento comprovati','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('vo do estatuto de vítima de violência doméstica, previsto no artigo 14.º
  4 - O subsídio previsto no presente artigo não é cumulável com prestações imediatas de segurança social.
  
  Aditado pelo seguinte diploma: Decreto-Lei n.º 101/2020, de 26 de Novembro            
         
   
     
                         
                          
  Artigo 43.º-C 
Responsabilidade pelo pagamento do subsídio de reestruturação familiar
                            
                           
                             
                               
                             
     1 - A responsabilidade pelo pagamento do subsídio de reestruturação familiar compete ao sistema de segurança social, com exceção do pagamento do subsídio de trabalhador abrangido pelo re - gime de proteção social convergente, em que a responsabilidade compete ao empregador público.
  2 - No âmbito do sistema de segurança social, o encargo resultante do pagamento do subsídio de reestruturação familiar constitui despesa do subsistema de solidariedade.
  3 - O procedimento de reconhecimento do direito, a atribuição e o pagamento do subsídio de reestruturação familiar têm natureza urgente.
  
  Aditado pelo seguinte diploma: Decreto-Lei n.º 101/2020, de 26 de Novembro            
         
   
     
                         
                          
  Artigo 44.º 
Instrumentos de regulamentação coletiva de trabalho
                            
                           
                             
                               
                             
     Os instrumentos de regulamentação coletiva de trabalho, sempre que possível, devem estabelecer, para a admissão em regime de tempo parcial e para a mobilidade geográfica, preferências em favor dos trabalhadores que beneficiem do estatuto de vítima.            
         
   
     
                         
                          
  Artigo 45.º 
Apoio ao arrendamento
                            
                           
                             
                               
                             
     A vítima tem direito a apoio ao arrendamento, à atribuição de fogo social ou a modalidade específica equiparável, nos termos definidos na lei ou em protocolos celebrados com entidades para o efeito.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 46.º 
Rendimento social de inserção
                            
                           
                             
                               
                             
     1 - A vítima tem, nos termos da lei, direito ao rendimento social de inserção, sendo o respetivo pedido tramitado com caráter de urgência.
  2 - Para efeitos da determinação do montante do rendimento social de inserção a atribuir a vítima','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s de violência doméstica às quais tenha sido atribuído esse estatuto e se encontrem comprovadamente em processo de autonomização, não são considerados quaisquer rendimentos do trabalho de outros elementos do agregado familiar.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 82-B/2014, de 31 de Dezembro   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro    - 2ª versão: Lei n.º 82-B/2014, de 31 de Dezembro   
     
                         
                          
  Artigo 47.º 
Abono de família
                            
                           
                             
                               
                             
     A requerimento da vítima, opera-se a transferência da perceção do abono de família relativamente aos filhos menores que consigo se encontrem.            
         
   
     
                         
                          
  Artigo 48.º 
Acesso ao emprego e a formação profissional
                            
                           
                             
                               
                             
     1 - À vítima de violência doméstica deve ser assegurada prioridade no acesso às ofertas de emprego, à integração em programas de formação profissional ou em qualquer outra medida ativa de emprego.
  2 - É igualmente assegurada à vítima prioridade no atendimento nos centros de emprego e centros de emprego e formação profissional do Instituto do Emprego e Formação Profissional, I. P. (IEFP, I. P.,), que deve ser realizado em condições de privacidade.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 49.º 
Tratamento clínico
                            
                           
                             
                               
                             
     O Serviço Nacional de Saúde assegura a prestação de assistência direta à vítima por parte de técnicos especializados e promove a existência de gabinetes de atendimento e tratamento clínico com vista à prevenção do fenómeno da violência doméstica.            
         
   
     
                         
                          
  Artigo 50.º 
Isenção de taxas moderadoras
                            
                           
                             
                               
                             
     A vítima está isenta do pagamento das taxas moderadoras no âmbito do Serviço Nacional de Saúde.            
         
   
     
                         
                          
  Artigo 51.º 
Restituição das prestações
                            
                           
                             
                          ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('     
                             
     1 - As prestações económicas e sociais inerentes ao estatuto de vítima que tenham sido pagas indevidamente devem ser restituídas.
  2 - Consideram-se como indevidamente pagas as prestações económicas e sociais cuja atribuição tenha sido baseada em falsas declarações de quem haja beneficiado do estatuto de vítima ou na omissão de informações legalmente exigidas.            
         
   
     
                         
                          
  Artigo 52.º 
Falsas declarações
                            
                           
                             
                               
                             
     Sem prejuízo da responsabilidade penal, a prestação de falsas declarações no âmbito do estatuto de vítima determina a cessação das prestações económicas e sociais previstas na lei.            
         
   
     
                         
                          
  CAPÍTULO V
  Rede nacional  Artigo 53.º 
Rede nacional de apoio às vítimas de violência doméstica
                            
                           
                             
                               
                             
     1 - A rede nacional de apoio às vítimas de violência doméstica compreende o organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, o ISS, I. P., as casas de abrigo, as respostas de acolhimento de emergência e as estruturas de atendimento.
  2 - Integram ainda a rede nacional de apoio às vítimas as respostas específicas do artigo 62.º
  3 - No âmbito da rede, é também assegurada a existência de um serviço telefónico permanente, gratuito e com cobertura nacional, de informação a vítimas de violência doméstica.
  4 - (Revogado.)
  5 - (Revogado.)
  6 - (Revogado.)
  7 - (Revogado.)
  8 - No quadro da rede nacional de apoio às vítimas de violência doméstica, a relevância das organizações de apoio à vítima é reconhecida pelo Estado e o seu papel é estimulado por este, nomeadamente na concretização das políticas de apoio.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 53.º-A 
Articulação no âmbito da rede e com outros intervenientes
                            
                           
                             
                               
                             
     1 - Quaisquer modalidades de apoio público à constituição ou funcionamento das casas de abrigo, das estruturas de atendimento e das respostas de acolhimento de emergência carecem da supervisão técnica do organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, nos termos da alínea j) do artigo 58.º, sendo da responsabilidade do ISS, I. P., a respetiva fiscalização, nos termos das suas atri','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('buições, bem como o apoio técnico e o acompanhamento daquelas respostas sociais objeto de acordo de cooperação.
  2 - Nos casos em que as vítimas são pessoas idosas ou em situação dependente, sem retaguarda familiar, deve o ISS, I. P., ou outro organismo competente, desenvolver um encaminhamento prioritário para o acolhimento no âmbito da rede de serviços e equipamentos sociais, sem prejuízo da articulação devida com a rede nacional de apoio a vítimas de violência doméstica.
  3 - As forças e serviços de segurança atuam em estreita cooperação com a rede nacional de apoio às vítimas de violência doméstica.
  4 - Nas situações em que as vítimas de violência doméstica sejam crianças ou jovens de menor idade, compete à Comissão Nacional de Proteção das Crianças e Jovens em Risco e às comissões de proteção das crianças e jovens estabelecer os procedimentos de proteção nos termos das suas atribuições legais, sem prejuízo das modalidades de cooperação possíveis com os organismos e entidades da rede nacional de apoio às vítimas de violência doméstica.
  5 - Todos os intervenientes na rede e todas as entidades que com a mesma cooperam devem articular-se tendo em vista a concretização, em cada momento, das medidas que se revelarem mais adequadas à proteção das vítimas.
  
  Aditado pelo seguinte diploma: Lei n.º 129/2015, de 03 de Setembro            
         
   
     
                         
                          
  Artigo 54.º 
Gratuitidade
                            
                           
                             
                               
                             
     1 - Os serviços prestados através da rede nacional de apoio às vítimas de violência doméstica são gratuitos.
  2 - Por comprovada insuficiência de meios económicos, o apoio jurídico prestado às vítimas é gratuito.            
         
   
     
                         
                          
  Artigo 55.º 
Participação das autarquias locais
                            
                           
                             
                               
                             
     1 - No âmbito das suas competências e atribuições, as autarquias locais podem deter estruturas integradas na rede nacional de apoio às vítimas de violência doméstica, colaborar na divulgação de outras estruturas em funcionamento nas respetivas áreas territoriais e ceder equipamentos para a criação de respostas no âmbito da rede nacional.
  2 - Nos casos em que a propriedade dos equipamentos seja das autarquias locais, a manutenção das instalações é assegurada por esta, podendo nos restantes casos, e sempre que possível, contribuir para o bom estado de conservação das mesmas.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 56.º 
Financia','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('mento
                            
                           
                             
                               
                             
     1 - Em matéria de investimento para construção e equipamento de respostas na área da violência doméstica, o apoio público da administração central enquadra-se em programas específicos de investimento para equipamentos sociais.
  2 - O apoio financeiro referido no número anterior pode ser assegurado por verbas oriundas dos fundos comunitários, nos termos dos regulamentos aplicáveis.
  3 - O apoio financeiro para funcionamento das respostas sociais na área da violência doméstica rege-se pelo regime de cooperação, nos termos da legislação em vigor.            
         
   
     
                         
                          
  Artigo 57.º 
Colaboração com entidades estrangeiras
                            
                           
                             
                               
                             
     No âmbito da rede nacional de apoio às vítimas de violência doméstica podem estabelecer-se acordos de cooperação com entidades similares estrangeiras para segurança dos respetivos utentes.            
         
   
     
                         
                          
  Artigo 58.º 
Comissão para a Cidadania e a Igualdade de Género
                            
                           
                             
                               
                             
     A Comissão para a Cidadania e a Igualdade de Género é responsável pelo desenvolvimento das políticas de proteção e promoção dos direitos das vítimas de violência doméstica, cabendo-lhe, nomeadamente:
  a) Participar nas alterações legislativas que respeitem ao âmbito do seu mandato;
  b) Promover os protocolos com os organismos e serviços com intervenção nesta área e as organizações não-governamentais ou outras entidades privadas;
  c) Promover formação especializada das equipas multidisciplinares que compõem a rede nacional;
  d) Colaborar na inserção de conteúdos específicos nos planos curriculares e de formação de todos os profissionais que, direta ou indiretamente, contactam com o fenómeno da violência doméstica;
  e) Solicitar e coordenar as auditorias e os estudos de diagnóstico e avaliação das carências, medidas e respostas sociais;
  f) Dinamizar, coordenar e acompanhar a elaboração do diagnóstico da situação das vítimas;
  g) Concertar a ação de todas as entidades públicas e privadas, estruturas e programas de intervenção na área das vítimas, de modo a reforçar estratégias de cooperação e de racionalização de recursos;
  h) Cooperar com a Comissão Nacional de Proteção das Crianças e Jovens em Risco no desenvolvimento das políticas, estratégias e ações relativas à promoção e proteção das crianças e jovens vítimas de violência doméstica;
  i) Certificar, para o efeito, as entidades cuja atividade na área da violência doméstica implique, pela sua relevância, integração na','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' rede nacional de apoio às vítimas de violência doméstica;
  j) Assegurar a supervisão técnica nas respostas específicas de atendimento e de acolhimento de vítimas, procedendo à verificação da conformidade dos procedimentos adotados com as orientações técnicas nacionais, comunitárias e europeias sobre a matéria e à sua articulação com as políticas públicas, bem como à monitorização do trabalho das equipas quanto aos modelos de intervenção e práticas de atuação, que deve atender às orientações emanadas pelos serviços de segurança social, e à formação, informação e atualização das competências técnico-científicas das pessoas que as integram;
  k) Organizar e coordenar o registo de dados de violência doméstica, desagregados por idade, nacionalidade e sexo, com a finalidade de recolha e análise de elementos de informação relativos às ocorrências reportadas às forças de segurança e das decisões judiciárias que, nos termos da lei, devam ser comunicadas;
  l) Emitir os pareceres previstos na lei.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 58.º-A 
Competências do Instituto da Segurança Social, I. P.
                            
                           
                             
                               
                             
     Ao ISS, I. P., compete, em matéria de políticas públicas de combate à violência doméstica e da proteção e promoção dos direitos das vítimas, nomeadamente:
  a) Desenvolver a cooperação com as instituições particulares de solidariedade social ou equiparadas, no âmbito dos respetivos acordos de cooperação celebrados para as respostas sociais de apoio às vítimas de violência doméstica;
  b) Assegurar a fiscalização, o apoio técnico e o acompanhamento das respostas sociais, nos termos do n.º 1 do artigo 53.º-A;
  c) Garantir a devida articulação e coordenação com outros organismos e estruturas, nomeadamente no âmbito da rede nacional, por forma a proteger as vítimas e a promover a sua integração social;
  d) Promover procedimentos de resposta, em situação de emergência, designadamente no âmbito da Linha Nacional de Emergência Social, a vítimas de violência doméstica;
  e) Participar nas alterações legislativas que respeitem ao seu âmbito de atuação;
  f) Participar na implementação e execução do Plano Nacional Contra a Violência Doméstica;
  g) Participar na definição da estratégia nacional para o combate à violência doméstica;
  h) Assegurar a recolha e o tratamento dos dados estatísticos relativos à violência doméstica, no âmbito das suas competências.
  i) Proceder ao reconhecimento do direito, à atribuição e ao pagamento do subsídio de reestruturação familiar das vítimas de violência doméstica, da responsabilidade do sistema de segurança social, nos termos definidos no arti','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('go 43.º-C.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 101/2020, de 26 de Novembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 59.º 
Cobertura territorial da rede nacional
                            
                           
                             
                               
                             
     1 - Cabe ao Estado promover a criação, a instalação, a expansão e o apoio ao funcionamento das casas de abrigo e restantes estruturas que integram a rede nacional.
  2 - A rede de casas de abrigo e as restantes estruturas que integram a rede nacional devem assegurar a cobertura equilibrada do território nacional e da população, devendo abranger todos os distritos.
  3 - Nas áreas metropolitanas de Lisboa e do Porto, a rede referida nos números anteriores deve contemplar, pelo menos, duas casas de abrigo.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 60.º 
Casas de abrigo
                            
                           
                             
                               
                             
     1 - As casas de abrigo são as unidades residenciais destinadas a acolhimento temporário a vítimas, acompanhadas ou não de filhos menores.
  2 - Ao Estado incumbe conceder apoio, com caráter de prioridade, às casas de abrigo de mulheres vítimas de violência doméstica e assegurar o anonimato das mesmas.            
         
   
     
                         
                          
  Artigo 61.º 
Estruturas de atendimento
                            
                           
                             
                               
                             
     1 - As estruturas de atendimento são constituídas por uma ou mais equipas técnicas de entidades públicas dependentes da administração central ou local, de entidades que com aquelas tenham celebrado protocolos de cooperação e de outras organizações de apoio à vítima que assegurem, de forma integrada, com caráter de continuidade, o atendimento, o apoio e o reencaminhamento personalizado de vítimas, tendo em vista a sua proteção.
  2 - Os protocolos de cooperação a que se refere o número anterior devem merecer acordo entre os organismos da Administração Pública responsáveis pelas áreas da cidadania e da igualdade de género e da segurança social, assegurando a sua conformidade com os parâmetros da presente lei e do PNCVD.
  3 - As equipas a que se refere o n.º 1 têm uma natureza multidisciplinar, integrando preferencialmente técnicos de apoio à vítima.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 1','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('29/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 61.º-A 
Respostas de acolhimento de emergência
                            
                           
                             
                               
                             
     As respostas de acolhimento de emergência visam o acolhimento urgente de vítimas acompanhadas ou não de filhos menores, pelo período necessário à avaliação da sua situação, assegurando a proteção da sua integridade física e psicológica.
  
  Aditado pelo seguinte diploma: Lei n.º 129/2015, de 03 de Setembro            
         
   
     
                         
                          
  Artigo 62.º 
Respostas específicas de organismos da Administração Pública
                            
                           
                             
                               
                             
     Os organismos da Administração Pública, designadamente no âmbito do serviço nacional de saúde, das forças e serviços de segurança, do IEFP, I. P., dos serviços da segurança social e dos serviços de apoio ao imigrante, devem promover o atendimento específico às vítimas de violência doméstica no âmbito das respetivas competências.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 63.º 
Objetivos das casas de abrigo
                            
                           
                             
                               
                             
     São objetivos das casas de abrigo:
  a) Acolher temporariamente vítimas, acompanhadas ou não de filhos menores;
  b) Nos casos em que tal se justifique, promover, durante a permanência na casa de abrigo, aptidões pessoais, profissionais e sociais das vítimas, suscetíveis de evitarem eventuais situações de exclusão social e tendo em vista a sua efetiva reinserção social.            
         
   
     
                         
                          
  Artigo 64.º 
Funcionamento das casas de abrigo
                            
                           
                             
                               
                             
     1 - As casas de abrigo são organizadas em unidades que favoreçam uma relação afetiva do tipo familiar, uma vida diária personalizada e a integração na comunidade.
  2 - Para efeitos do número anterior, as casas de abrigo regem-se nos termos descritos na presente lei, no seu regulamento interno e pelas normas aplicáveis às entidades que revistam a mesma natureza jurídica com acordos de cooperação celebrados, desde que não contrariem as normas constantes na presente lei.
  3 - O regulamento interno de funcionamento, a apro','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('var pelos membros do Governo responsáveis pelas áreas da cidadania e da igualdade de género e da solidariedade e segurança social, ou por quem estes designarem, é obrigatoriamente dado a conhecer às vítimas aquando da sua admissão, devendo ser subscrito por estas o correspondente termo de aceitação.
  4 - As casas de abrigo dispõem, para efeitos de orientação técnica, de, pelo menos, um licenciado nas áreas sociais ou comportamentais, preferencialmente psicólogo e ou técnico de serviço social, que atua em articulação com a equipa técnica.
  5 - Atendendo à natureza e fins prosseguidos pelas casas de abrigo, as autoridades policiais territorialmente competentes prestam todo o apoio necessário com vista à proteção dos trabalhadores e das vítimas, assegurando uma vigilância adequada junto das mesmas.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 65.º 
Organização e gestão das casas de abrigo
                            
                           
                             
                               
                             
     1 - As casas de abrigo podem funcionar em equipamentos pertencentes a entidades públicas ou particulares sem fins lucrativos.
  2 - As casas de abrigo devem coordenar-se com as restantes estruturas que integram a rede nacional.
  3 - Tratando-se de entidades particulares sem fins lucrativos, o Estado apoia a sua ação mediante a celebração de acordos de cooperação.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 66.º 
Equipa técnica
                            
                           
                             
                               
                             
     1 - As casas de abrigo dispõem de uma equipa técnica, integrando preferencialmente técnicos de apoio à vítima, a quem cabe o diagnóstico da situação das vítimas acolhidas na instituição, designadamente de avaliação de risco e das suas necessidades, bem como o apoio na definição e execução dos projetos de promoção dos seus direitos e autonomização.
  2 - A equipa deve ter uma constituição pluridisciplinar, integrando as valências de direito, psicologia e serviço social.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 67.º 
Formação da equipa técnica
                            
                           
                             
        ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                       
                             
     O organismo da Administração Pública responsável pela área da cidadania e da igualdade de género assegura, sem prejuízo da participação de outras entidades, a formação específica ao pessoal técnico das casas de abrigo e dos centros de atendimento.            
         
   
     
                         
                          
  Artigo 68.º 
Acolhimento
                            
                           
                             
                               
                             
     1 - A admissão das vítimas nas casas de abrigo processa-se por indicação da equipa técnica das entidades que integram a rede nacional e, em situação de emergência, também por indicação dos órgãos de polícia criminal na sequência de pedido da vítima, de acordo com a avaliação de grau de risco.
  2 - O acolhimento é assegurado pela instituição que melhor possa garantir as necessidades de apoio efetivo à vítima de acordo com a análise da competente equipa técnica.
  3 - O acolhimento nas casas de abrigo é de curta duração, pressupondo o retorno da vítima à vida na comunidade de origem, ou outra por que tenha optado, em prazo não superior a seis meses.
  4 - A permanência por mais de seis meses pode ser autorizada, a título excecional, mediante parecer fundamentado da equipa técnica acompanhado do relatório de avaliação da situação da vítima.
  5 - O disposto no presente artigo não prejudica a existência de acolhimento de crianças e jovens, decidido pelo tribunal competente, nos termos dos artigos 49.º a 54.º da Lei de Proteção das Crianças e Jovens em Perigo.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 69.º 
Causas imediatas de cessação do acolhimento
                            
                           
                             
                               
                             
     Constituem causas imediatas de cessação de acolhimento, entre outras:
  a) O termo do prazo previsto nos n.os 3 e 4 do artigo anterior;
  b) A manifestação de vontade da vítima;
  c) O incumprimento das regras de funcionamento da casa de abrigo.            
         
   
     
                         
                          
  Artigo 70.º 
Direitos e deveres da vítima e dos filhos menores em acolhimento
                            
                           
                             
                               
                             
     1 - A vítima e os filhos menores acolhidos em casas de abrigo têm os seguintes direitos:
  a) Alojamento e alimentação em condições de dignidade;
  b) Usufruir de um espaço de privacidade e de um grau de autonomia na condução da sua vida pessoal adequados à sua idade e situação.
  2 - Constitui dever e','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('special da vítima e dos filhos menores acolhidos em casas de abrigo cumprir as respetivas regras de funcionamento.            
         
   
     
                         
                          
  Artigo 71.º 
Denúncia
                            
                           
                             
                               
                             
     1 - Os responsáveis das casas de abrigo devem denunciar aos serviços do Ministério Público competentes as situações de vítimas de que tenham conhecimento, para efeitos de instauração do respetivo procedimento criminal.
  2 - Quando os responsáveis das casas de abrigo encontrem motivos de fundada suspeita de terem os filhos menores acolhidos sido também vítimas de violência doméstica, devem denunciar imediatamente tal circunstância ao Ministério Público, por meio e forma que salvaguardem a confidencialidade da informação.            
         
   
     
                         
                          
  Artigo 72.º 
Domicílio da vítima acolhida em casa de abrigo
                            
                           
                             
                               
                             
     A vítima acolhida em casa de abrigo considera-se domiciliada no centro de atendimento que processou a respetiva admissão.            
         
   
     
                         
                          
  Artigo 73.º 
Assistência médica e medicamentosa
                            
                           
                             
                               
                             
     Mediante declaração emitida pela entidade gestora da casa de abrigo onde a vítima se encontra acolhida, os serviços de saúde integrados no serviço nacional de saúde dessa área providenciam toda a assistência necessária à vítima e aos seus filhos, garantindo a confidencialidade dos dados.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 74.º 
Acesso aos estabelecimentos de ensino
                            
                           
                             
                               
                             
     1 - Aos filhos menores das vítimas acolhidas nas casas de abrigo é garantida a transferência escolar, sem observância do numerus clausus, para estabelecimento escolar mais próximo da respetiva casa de abrigo.
  2 - A referida transferência opera-se com base em declaração emitida pelo centro de atendimento que providenciou a admissão da vítima.
  3 - O estabelecimento escolar referido no n.º 1 está obrigado a garantir sigilo relativamente às informações a que possa ter acesso por motivo do processo de transferência.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 75.º 
Núcleos de atendimento
                            
                           
                             
                               
                             
     (Revogado.)            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 76.º 
Grupos de ajuda mútua
                            
                           
                             
                               
                             
     Tendo em vista a autonomização das vítimas, os grupos de ajuda mútua de cariz comunitário que visem promover a autoajuda e o empoderamento das vítimas são certificados pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, sempre que o requeiram, para efeitos de integração na rede nacional de apoio às vítimas de violência doméstica.            
         
   
     
                         
                          
  CAPÍTULO VI
  Educação para a cidadania  Artigo 77.º 
Educação
                            
                           
                             
                               
                             
     Incumbe ao Estado definir, nos objetivos e linhas de orientação curricular da educação pré-escolar, dos ciclos do ensino básico e secundário, os princípios orientadores de um programa de prevenção do crime de violência doméstica, de acordo com o desenvolvimento físico, emocional, psicológico e social das crianças que frequentem aqueles estabelecimentos de educação, tendo em vista, nomeadamente, proporcionar-lhes noções básicas sobre:
  a) O fenómeno da violência e a sua diversidade de manifestações, origens e consequências;
  b) O respeito a que têm direito, da sua intimidade e da reserva da sua vida privada;
  c) Os comportamentos parentais e o inter-relacionamento na vida familiar;
  d) A violência simbólica e o seu caráter estrutural e institucional;
  e) Relações de poder que marcam as interações pessoais, grupais e sociais;
  f) O relacionamento entre crianças, adolescentes, jovens e pessoas em idade adulta.            
         
   
     
                         
                          
  Artigo 78.º 
Sensibilização e informação
                            
                           
                             
                               
                             
     O Estado assegura a promoção de políticas de prevenção de violência doméstica através da:
  a) Elaboração de guiões e produtos educativos para ações de sensibilização e informação nas escolas que incluam as temáticas da educação para a igualdade de género, p','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ara a não-violência e para a paz, para os afetos, bem como da relação entre género e multiculturalismo e da resolução de conflitos através da comunicação;
  b) Criação e divulgação de materiais informativos e pedagógicos dirigidos à população estudantil;
  c) Realização de concursos nas escolas para selecionar os melhores materiais pedagógicos produzidos a fim de integrarem exposições temporárias;
  d) Dinamização de ações de sensibilização junto das escolas, em parceria com os restantes atores da comunidade educativa, por parte de militares e agentes das forças de segurança envolvidos em programas de proximidade, comunitários e de apoio à vítima;
  e) Elaboração de guiões e produtos para sensibilização das famílias sobre a necessidade de adotarem estratégias educativas alternativas à violência;
  f) Sensibilização para a eliminação de todas as referências sexistas e discriminatórias dos materiais escolares;
  g) Dinamização de ações de sensibilização junto dos organismos da Administração Pública e empresas públicas de forma a modificar as condutas que favorecem, estimulam e perpetuam a violência doméstica;
  h) Promoção de campanhas nacionais e locais nos meios de comunicação social;
  i) Divulgação de material informativo acerca dos indícios reveladores da violência junto dos profissionais de saúde, destinado a sensibilizá-los para a deteção desses casos;
  j) Promoção da expansão da base de conhecimentos e o intercâmbio, com entidades nacionais e estrangeiras, da informação, da identificação e da difusão de boas práticas para a prevenção da violência doméstica.            
         
   
     
                         
                          
  Artigo 79.º 
Formação
                            
                           
                             
                               
                             
     1 - Na medida das necessidades, deve ser promovida formação específica na área da violência doméstica a docentes da educação pré-escolar, dos ensinos básico e secundário, para que adquiram conhecimentos e técnicas que os habilitem a educar as crianças no respeito pelos direitos e liberdades fundamentais, pela igualdade entre homens e mulheres, pelo princípio da tolerância e na prevenção e resolução pacífica dos conflitos, no âmbito da vida familiar e social, bem como na deteção das formas de violência.
  2 - Aos profissionais da área da saúde cuja atuação se revele relevante na matéria deve ser ministrada formação sobre violência doméstica, que inclui a preparação para a deteção precoce dos casos de violência e, sempre que existam indícios reveladores da prática do crime, a sensibilização para a sua denúncia.
  3 - As atividades de formação do Centro de Estudos Judiciários contemplam conteúdos sobre o crime de violência doméstica, as suas causas e consequências.
  4 - Os órgãos de polícia criminal e os técnicos de medicina legal recebem componente formativa específica na área da violência doméstica com vista à prevenção de forma','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s de vitimização secundária, nomeadamente no âmbito da recolha dos meios de prova.            
         
   
     
                         
                          
  Artigo 80.º 
Protocolos
                            
                           
                             
                               
                             
     1 - Os estabelecimentos de ensino e de educação e entidades especialmente vocacionadas para o acompanhamento de situações resultantes do crime de violência doméstica podem celebrar protocolos de cooperação.
  2 - As autarquias que tenham, ou desejem ter, projetos contra a violência, nomeadamente espaços de informação sobre a problemática da violência doméstica, são apoiadas mediante a celebração de protocolos, tendo em vista a realização de campanhas e ações de sensibilização nas comunidades locais e o alargamento da cobertura nacional da rede de apoio às vítimas.
  3 - O Estado promove, com as ordens profissionais da área da saúde, a celebração dos protocolos necessários à divulgação regular de material informativo sobre violência doméstica nos consultórios e nas farmácias.
  4 - Podem ser celebrados protocolos entre o organismo da Administração Pública responsável pela área da cidadania e da igualdade de género e os vários organismos da Administração Pública envolvidos na proteção e na assistência à vítima com vista à definição dos procedimentos administrativos de comunicação de dados e ao desenvolvimento integrado das políticas de rede de tutela da vítima e de sensibilização contra a violência doméstica.
  5 - O organismo da Administração Pública responsável pela área da cidadania e da igualdade de género pode ainda celebrar protocolos com as organizações não governamentais com vista à articulação dos procedimentos relativos à proteção e à assistência à vítima.            
         
   
     
                         
                          
  Artigo 80.º-A 
Orçamento
                            
                           
                             
                               
                             
     1 - Cada entidade inscreve no respetivo orçamento os encargos decorrentes da execução da presente lei.
  2 - Do montante das verbas referidas no número anterior e da sua execução, bem como da estimativa do montante correspondente a isenções concedidas a pessoas com estatuto de vítima de violência doméstica, é dado conhecimento ao membro do Governo responsável pela área da igualdade, até ao final do primeiro trimestre do ano subsequente.
  Aditado pelo seguinte diploma: Lei n.º 42/2016, de 28 de Dezembro            
         
   
     
                         
                          
  CAPÍTULO VII
  Disposições finais  Artigo 81.º 
Disposições transitórias
                            
                           
                             
                               
                             
     1 - Até à sua revisão, mantém-se em vigor, com as necessárias adaptações, ','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o Decreto Regulamentar n.º 1/2006, de 25 de janeiro.
  2 - (Revogado.)            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro   
     
                         
                          
  Artigo 82.º 
Disposição revogatória
                            
                           
                             
                               
                             
     São revogados a Lei n.º 107/99, de 3 de agosto, e o Decreto-Lei n.º 323/2000, de 19 de dezembro.            
         
   
     
                         
                          
  Artigo 83.º 
Regulamentação
                            
                           
                             
                               
                             
     1 - Os atos regulamentares necessários à execução da presente lei são aprovados pelo Governo no prazo de 180 dias.
  2 - O modelo de documento comprovativo da atribuição do estatuto de vítima, previsto no n.º 1 do artigo 14.º, é aprovado por portaria dos membros do Governo responsáveis pelas áreas da cidadania e da igualdade de género, da administração interna e da justiça.
  3 - As características dos sistemas tecnológicos de controlo à distância previstos no artigo 35.º são aprovadas por portaria do membro do Governo responsável pela área da justiça.
  4 - As condições de utilização inicial dos meios técnicos de teleassistência, previstos nos n.os 4 e 6 do artigo 20.º, e dos meios de controlo à distância, previstos no artigo 35.º, são fixadas por portaria dos membros do Governo responsáveis pelas áreas da cidadania e da igualdade de género, da justiça e do organismo da Administração Pública previsto no n.º 6 do artigo 20.º
  5 - Os requisitos e qualificações necessários à habilitação dos técnicos de apoio à vítima previstos na alínea c) do artigo 2.º são definidos por despacho dos membros do Governo responsáveis pelas áreas da cidadania e da igualdade de género, da justiça, da formação profissional e da solidariedade e segurança social.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 129/2015, de 03 de Setembro   - Lei n.º 57/2021, de 16 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 112/2009, de 16 de Setembro    - 2ª versão: Lei n.º 129/2015, de 03 de Setembro   
     
                         
                          
  Artigo 84.º 
Entrada em vigor
                            
                           
                             
                               
                             
     A presente lei entra em vigor 30 dias após a sua publicação.','462');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:18  
    
  DL n.º 26/2021, de 31 de Março  (versão actualizada) BOLSA NACIONAL DE ALOJAMENTO URGENTE E TEMPORÁRIO    
    
 
Contém as seguintes alterações:   - DL n.º 41/2023, de 02 de Junho  
                         
                          
SUMÁRIOProcede à criação da Bolsa Nacional de Alojamento Urgente e Temporário
Decreto-Lei n.º 26/2021, de 31 de março
  O XXII Governo Constitucional, consciente da necessidade urgente de identificar a habitação como um dos pilares do Estado Social, inscreveu no seu programa o compromisso de criar uma Bolsa Nacional de Alojamento Urgente que, em complementaridade com a oferta pública de habitação e a ação municipal, assegure uma resposta temporária de recurso para as situações de emergência.
  A universalidade do direito à habitação afirma-se na promoção de políticas públicas que têm como destinatário a comunidade como um todo, e não apenas uma parte dela, porque é em comunidade que construímos este direito, alicerçado nos princípios do Estado Social que materializa.
  Nesse mesmo sentido, foi inscrito no Plano de Estabilização Económica e Social, aprovado pela Resolução do Conselho de Ministros n.º 41/2020, de 6 de junho, a criação de um programa de apoio à criação da Bolsa Nacional de Alojamento de Emergência, com vista a comparticipar os investimentos para este fim a realizar por entidades públicas e do terceiro setor.
  Um dos maiores problemas que Portugal enfrenta na atualidade ao nível da habitação é a ausência de uma resposta estruturada a necessidades urgentes de alojamento, decorrentes de eventos imprevisíveis ou excecionais (tais como, catástrofes naturais, incêndios, pandemias, movimentos migratórios), ou decorrentes da necessidade de alojamento urgente, de forma temporária, de pessoas que se encontrem em risco iminente de ficar privadas de habitação (como, situações de violência doméstica, de tráfico de seres humanos, pessoas ao abrigo da proteção internacional, situações de desinstitucionalização, pessoas em situação de sem-abrigo, ou ainda pessoas em risco de desalojamento devido a precariedade e insegurança extrema do local em que vivem).
  Neste momento, as respostas sociais existentes no país, nomeadamente, centros de acolhimento temporário ou apoios da Segurança Social ou de outras entidades com vista a cobrir os custos com o arrendamento de alojamentos no mercado, estão muito subdimensionadas e são demasiado limitadas no tempo.
  Acresce que, o parque habitacional público, dada a sua muito reduzida dimensão, é já incapaz de dar resposta às necessidades estruturais e permanentes de habitação, pelo que é também insuficiente para acomodar as necessidades urgentes e imprevisíveis.
  Foi neste contexto enquadrado no Plano de Recuperação e Resiliência uma medida que visa apoiar o investimento em imóveis que venham a integrar a Bolsa Nacional de Alojamento Urgente e Temporário, pretendendo-se definir através do presente decreto-lei os termos para a concretização desse objetivo','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('.
  Para tal, prevê-se ainda a criação do Plano Nacional de Alojamento com vista a implementar uma resposta estruturada e transversal para as pessoas que carecem de soluções de alojamento de emergência ou de transição. Esta resposta será concretizada através da Bolsa Nacional de Alojamento Urgente e Temporário a qual visa integrar os imóveis disponíveis, em cada momento, para afetação a alojamento urgente e disponibilização de soluções habitacionais a pessoas em processo de autonomização.
  De modo a identificar a oferta de alojamento a disponibilizar por via desta Bolsa, é prevista também a realização de um Inventário de Alojamento Urgente e Temporário, através do qual se procede ao levantamento, identificação e quantificação dos imóveis que estejam ou possam ser afetos a respostas de alojamento urgente e temporário.
  Foi ouvida a Associação Nacional de Municípios Portugueses.
  Assim:
  Nos termos da alínea a) do n.º 1 do artigo 198.º da Constituição, o Governo decreta o seguinte:
  
  CAPÍTULO I
  Disposições gerais  Artigo 1.º 
Objeto
                            
                           
                             
                               
                             
     O presente decreto-lei procede:
  a) À criação da Bolsa Nacional de Alojamento Urgente e Temporário, doravante designada por Bolsa de Alojamento;
  b) À definição do Plano Nacional de Alojamento Urgente e Temporário, doravante designado por Plano Nacional de Alojamento;
  c) À definição da forma de realização do Inventário de Alojamento Urgente e Temporário, doravante designado por Inventário de Alojamento;
  d) À definição das modalidades e condições dos apoios para promoção das soluções de alojamento urgente e temporário.            
         
   
     
                         
                          
  Artigo 2.º 
Objetivos
                            
                           
                             
                               
                             
     1 - O presente decreto-lei visa criar uma resposta estruturada e transversal para a disponibilização de soluções de alojamento de emergência ou de transição destinadas a pessoas que se encontram em situação de risco e emergência, tendo em vista a sua inclusão social, proteção e autonomização, o combate às desigualdades e a garantia de uma adequada proteção social.
  2 - Para efeito do disposto no presente decreto-lei, considera-se como solução de alojamento a fração habitacional ou o prédio dotado de áreas habitacionais, destinado a alojamento, exclusivo ou coletivo, de pessoas que se encontram numa das situações abrangidas pelo Plano Nacional de Alojamento, e, incluindo quando aplicável, os respetivos espaços complementares de utilização comum, afetos, nomeadamente, à socialização e à prestação de apoio a essas pessoas.            
         
   
     
                         
                          
  CAPÍTULO II
  Do Plano Nacional de Alojamento  Artigo 3.º 
Comissão para a ex','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ecução do Plano Nacional de Alojamento
                            
                           
                             
                               
                             
     1 - É criada uma Comissão para a execução do Plano Nacional de Alojamento (Comissão).
  2 - São competências da Comissão:
  a) Elaborar o Plano Nacional de Alojamento e propô-lo aos membros do Governo responsáveis pelas áreas das finanças, da cidadania e igualdade, da integração e as migrações, da segurança social e da habitação, nos termos do presente decreto-lei, no prazo de 90 dias a contar da data de entrada em vigor do presente decreto-lei;
  b) Acompanhar a execução do Plano Nacional de Alojamento;
  c) Apresentar aos membros do Governo responsáveis pelas áreas das finanças, da cidadania e igualdade, da integração e as migrações, da administração interna, da segurança social e da habitação, no primeiro trimestre de cada ano, um relatório de avaliação global da aplicação do Plano Nacional de Alojamento no ano económico anterior, com as propostas de medidas que considera necessárias para assegurar o cumprimento dos objetivos naquele definidos;
  d) Realizar a revisão bienal do Plano Nacional de Alojamento, prevista no n.º 3 do artigo seguinte.
  3 - A Comissão é constituída por:
  a) Um representante do Instituto da Habitação e da Reabilitação Urbana, I. P. (IHRU, I. P.);
  b) Um representante do Instituto da Segurança Social, I. P. (ISS, I. P.);
  c) Um representante da Comissão para a Cidadania e a Igualdade de Género (CIG);
  d) Um representante da Agência para a Integração, Migrações e Asilo, I. P. (AIMA, I. P.);
  e) Um representante da Associação Nacional de Municípios Portugueses (ANMP).
  4 - A Comissão é coordenada pelos representantes do ISS, I. P., e do IHRU, I. P.
  5 - Para efeitos do disposto no número anterior, deve ser promovida a colaboração das entidades públicas das áreas setoriais consideradas relevantes em função da matéria, nomeadamente da Secretaria-Geral do Ministério da Administração Interna (SGMAI), atentas as situações a incluir nos termos do n.º 2 do artigo 6.º e do capítulo iv.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 41/2023, de 02 de Junho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 26/2021, de 31 de Março   
     
                         
                          
  Artigo 4.º 
Plano Nacional de Alojamento
                            
                           
                             
                               
                             
     1 - O Plano Nacional de Alojamento tem como objetivo criar uma resposta estruturada e transversal para as pessoas que carecem de soluções de alojamento de emergência ou de transição, em função dos imóveis que venham a integrar a bolsa por via do financiamento promovido no presente decreto-lei e com os limites definidos no artigo 17.º, e sem prejuízo das respostas que venham a ser integradas por via d','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o inventário previsto no capítulo iii.
  2 - O Plano Nacional de Alojamento integra ainda soluções de alojamento que venham a ser criadas ao abrigo do n.º 2 do artigo 5.º, conjugado com o n.º 3 do artigo 11.º
  3 - O Plano Nacional de Alojamento previsto nos números anteriores é revisto com periodicidade bienal.
  4 - As soluções habitacionais a promover através do Plano Nacional de Alojamento assentam na reabilitação, construção, aquisição ou arrendamento de imóveis, devendo, para o efeito, ter por base:
  a) O planeamento estratégico das soluções de alojamento a promover e dos apoios existentes nos termos do presente decreto-lei para esse fim, em função das necessidades de soluções de alojamento, inclusive das já existentes, em atenção às especificidades locais e à coesão socioterritorial, de modo a evitar fenómenos de segregação e de exclusão socioterritorial, bem como as necessidades de segurança, confidencialidade e proteção dos destinatários;
  b) A participação de todas as entidades relevantes, públicas ou privadas, na definição e concretização das soluções de alojamento, em função da sua área específica de atuação, de forma a salvaguardar a coerência dos respetivos projetos no âmbito das redes de intervenção especializada que integram;
  c) A garantia da articulação das soluções de alojamento com os objetivos de política pública que as mesmas promovem, em função dos destinatários a que se dirigem, designadamente em termos de inclusão, proteção e autonomização, por forma a que estes sejam providos, não apenas de alojamento, mas do apoio e acompanhamento necessários a assegurar, sempre que aplicável, o processo de transição para uma situação habitacional e financeira autónoma e estável.            
         
   
     
                         
                          
  Artigo 5.º 
Situações abrangidas
                            
                           
                             
                               
                             
     1 - Ficam abrangidas pelo Plano Nacional de Alojamento as seguintes situações de risco e ou emergência social:
  a) Eventos imprevisíveis ou excecionais, designadamente catástrofes naturais, incêndios, pandemias, fluxos migratórios não programados;
  b) Necessidade de alojamento urgente e de autonomização de pessoas que se encontrem privadas, de forma temporária, de habitação, nomeadamente:
  i) Pessoas vítimas de violência doméstica;
  ii) Pessoas vítimas de tráfico de seres humanos;
  iii) Pessoas ao abrigo da proteção internacional, no âmbito das competências das entidades que compõem a formação restrita do Grupo Operativo Único, nos termos estabelecidos pela Resolução do Conselho de Ministros n.º 103/2020, de 23 de novembro;
  iv) Pessoas em situação de sem-abrigo, considerando-se para este efeito as pessoas sinalizadas como tal pelas entidades competentes por estarem sem teto ou sem casa;
  c) Necessidades extraordinárias e devidamente fundamentadas de alojamento urgente e temporário ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('para pessoas em risco iminente e efetivo de ficarem sem alojamento e em situação de sem abrigo ou para jovens ou pessoas com deficiência em acolhimento residencial cujo processo de autonomização esteja comprometido por ausência de recursos ou suporte familiar.
  2 - Podem ainda ser abrangidas pelo Plano Nacional de Alojamento, com as devidas adaptações, as necessidades de fixação local, quando temporária e indispensável ao interesse público, de funcionários e agentes do Estado, nos termos do n.º 3 do artigo 11.º
  3 - Cabe ao IHRU, I. P., definir, no quadro do disposto no presente decreto-lei e no Decreto-Lei n.º 29/2018, de 4 de maio, na sua redação atual, que estabelece o Porta de Entrada - Programa de Apoio ao Alojamento Urgente, a solução de aplicação, conjugada ou autónoma, desses regimes que melhor responde à promoção de soluções de alojamento disponibilizadas no âmbito e em execução do Plano Nacional de Alojamento.
  4 - O disposto no presente artigo não prejudica as competências próprias das autarquias locais e, bem assim, da Santa Casa da Misericórdia de Lisboa, em matéria social.            
         
   
     
                         
                          
  Artigo 6.º 
Entidades gestoras
                            
                           
                             
                               
                             
     1 - A execução do Plano Nacional de Alojamento cabe ao Estado, através do IHRU, I. P., e do ISS, I. P., em articulação com a CIG, a AIMA, I. P., e a ANMP, bem como, quando necessário, com outras entidades competentes para gerir, acompanhar e atribuir soluções de alojamento em concreto.
  2 - No caso de soluções de alojamento definidas ao abrigo do n.º 6 do artigo 8.º, o IHRU, I. P., e o ISS, I. P., devem articular a execução do Plano Nacional de Alojamento com a SGMAI.
  3 - No exercício destas competências, cabe:
  a) Ao IHRU, I. P., a gestão e a concessão dos apoios a que se refere o capítulo iv e outros apoios no âmbito das competências do IHRU, I. P., a realização do inventário e, diretamente ou através de terceiros, o acompanhamento e monitorização da respetiva execução;
  b) Ao ISS, I. P., a identificação das necessidades existentes, a articulação com as entidades competentes, designadamente a CIG e a AIMA, I. P., gerir as necessidades e disponibilização de soluções de alojamento urgente e temporário, nos termos do artigo 10.º, sem prejuízo da articulação com o IHRU, I. P., no acompanhamento e monitorização da execução material do Plano Nacional de Alojamento.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 41/2023, de 02 de Junho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 26/2021, de 31 de Março   
     
                         
                          
  CAPÍTULO III
  Do Inventário de Alojamento e da Bolsa de Alojamento
  SECÇÃO I
  Disposições gerais  Artigo 7.º 
Objetivos
                            
                   ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('        
                             
                               
                             
     1 - O Inventário de Alojamento consiste no levantamento, identificação e quantificação dos imóveis que se encontram ou possam ser afetos a respostas de alojamento urgente e temporário, e que sejam passíveis de integração na Bolsa de Alojamento.
  2 - A Bolsa de Alojamento visa integrar a identificação e a informação sobre a oferta de alojamento urgente e temporário disponível, para resposta às necessidades de emergência social e de acolhimento ou transição, no âmbito de cada uma das finalidades do artigo 4.º, permitindo, na procura de soluções, uma direta articulação entres as diversas entidades competentes.            
         
   
     
                         
                          
  SECÇÃO II
  Do Inventário de Alojamento  Artigo 8.º 
Realização do Inventário
                            
                           
                             
                               
                             
     1 - O Inventário de Alojamento é realizado pelo IHRU, I. P., mediante a identificação, no Inventário a que se refere o n.º 1 do artigo 3.º e os artigos 4.º e 6.º do Decreto-Lei n.º 82/2020, de 2 de outubro, dos imóveis do património imobiliário público que estejam ou possam ser afetos a respostas de alojamento urgente e temporário, bem como através da inserção no mesmo dos dados das respostas sociais de acolhimento de emergência enquadrados pelo ISS, I. P., e das respostas coordenadas pela CIG no que respeita a situações de violência doméstica e de tráfico de seres humanos, nos termos do número seguinte, e dos imóveis promovidos, disponibilizados ou financiados pelo IHRU, I. P., para esse fim.
  2 - Cabe ao ISS, I. P., à CIG e à AIMA, I. P., promover os procedimentos necessários para a identificação no Inventário de Alojamento de todos os imóveis afetos a respostas de alojamento urgente e temporário com os quais tenha contratualizado algum tipo de apoio e que ainda não estejam registados no âmbito do Inventário de Alojamento referido no número anterior.
  3 - Para efeitos dos números anteriores, pode ainda o IHRU, I. P., solicitar a colaboração de outras entidades públicas competentes nessa matéria, nomeadamente quando se trate de respostas promovidas por autarquias locais.
  4 - A informação referida nos números anteriores deve ser remetida no prazo de 60 dias a contar da disponibilização da plataforma referida no n.º 1 e contempla os seguintes elementos:
  a) Identificação dos imóveis afetos a alojamento urgente e temporário;
  b) Indicação dos imóveis que estão disponíveis ou em utilização;
  c) Informação, quanto aos imóveis em utilização, sobre o respetivo regime de atribuição, prazo de utilização e contrapartidas previstas, se aplicável;
  d) No caso das autarquias locais, informação, quanto à sua eventual integração na Bolsa de Alojamento, nos termos definidos no presente decreto-lei.
  5 - As entidades referidas no pr','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('esente artigo têm o dever de atualização da informação prestada, devendo reportar ao IHRU, I. P., qualquer alteração no mais curto prazo possível, sem nunca exceder 30 dias, contados a partir da data do facto que determina a alteração.
  6 - Os imóveis propriedade da área governativa da administração interna que venham a integrar o inventário de alojamento ficam exclusivamente afetos ao alojamento temporário dos elementos que integrem as forças de segurança.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 41/2023, de 02 de Junho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 26/2021, de 31 de Março   
     
                         
                          
  Artigo 9.º 
Colaboração das entidades públicas
                            
                           
                             
                               
                             
     1 - Os organismos da administração direta e indireta têm o dever de colaborar na realização do Inventário de Alojamento, quando solicitados para o efeito.
  2 - O IHRU, I. P., pode solicitar informações aos municípios e freguesias, bem como às Comissões de Coordenação e Desenvolvimento Regional, relativamente ao património objeto do Inventário de Alojamento, que se situe nas respetivas circunscrições territoriais.            
         
   
     
                         
                          
  SECÇÃO III
  Da Bolsa Nacional de Alojamento Urgente e Temporário  Artigo 10.º 
Bolsa Nacional de Alojamento Urgente e Temporário
                            
                           
                             
                               
                             
     1 - A Bolsa de Alojamento integra:
  a) Os imóveis com financiamento através do capítulo iv;
  b) Os imóveis disponíveis, em cada momento, entre os identificados no âmbito do Inventário previsto na secção anterior;
  c) Os imóveis do IHRU, I. P., que, pela sua adequação, sejam por ele destinados a entidades competentes para afetação a alojamento urgente através de arrendamento ou outra modalidade contratual que permita o uso habitacional e ainda, mediante solicitação destas entidades, para disponibilização de soluções habitacionais a pessoas em processo de autonomização.
  2 - Cabe ao ISS, I. P., com a colaboração das demais entidades responsáveis pela elaboração do Plano Nacional de Alojamento, e sem prejuízo das respetivas competências de supervisão e coordenação de respostas sociais, acompanhar e gerir as necessidades e a disponibilização de soluções de alojamento urgente e temporário, de acordo com o património disponível integrado na Bolsa de Alojamento, nos termos do número anterior.
  3 - O modelo de funcionamento e gestão da Bolsa de Alojamento é definido por portaria do membro do Governo responsável pela área da segurança social no prazo de 60 dias a contar da entrada em vigor do presente decreto-lei e após audição da Comissão.            
         
   ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('
     
                         
                          
  CAPÍTULO IV
  Modalidades e condições dos apoios  Artigo 11.º 
Modalidades de apoio
                            
                           
                             
                               
                             
     1 - Nos termos do disposto no n.º 5 do seu artigo 62.º do Decreto-Lei n.º 37/2018, de 4 de junho, na sua redação atual, pode ser solicitado apoio para promoção das soluções de alojamento urgente e temporário, previstas no n.º 1 do artigo 5.º, diretamente junto do IHRU, I. P., não sendo aplicável a estas o disposto nos artigos 6.º a 9.º daquele decreto-lei.
  2 - O disposto no número anterior não prejudica a possibilidade de aplicação conjugada do apoio referido no número anterior com outros apoios concedidos por outras entidades ou ao abrigo de outros programas, desde que efetuada nos termos do disposto nos n.os 3 e 4 do artigo 21.º do Decreto-Lei n.º 37/2018, de 4 de junho, na sua redação atual.
  3 - Podem ainda beneficiar deste apoio, nos termos previstos nos números anteriores, as soluções habitacionais destinadas a alojamento temporário dos elementos das forças de segurança, nos termos de protocolo a definir entre o IHRU, I. P., e a SGMAI.
  4 - O financiamento a que se refere o presente artigo destina-se às soluções habitacionais previstas no n.º 4 do artigo 4.º, com exceção do arrendamento, nos termos a definir em aviso de abertura de candidaturas.            
         
   
     
                         
                          
  Artigo 12.º 
Entidades beneficiárias
                            
                           
                             
                               
                             
     1 - Podem beneficiar do apoio referido no artigo anterior para promoção de soluções de alojamento urgentes e temporárias as entidades referidas nas alíneas a), b) e c) do artigo 26.º do Decreto-Lei n.º 37/2018, de 4 de junho, na sua redação atual, incluindo as que tenham atribuições principais de assistência, apoio ou solidariedade social, desde que detenham igualmente as competências necessárias para a promoção da solução de alojamento, bem como as entidades gestoras de respostas de apoio e acolhimento a vítimas de tráfico de seres humanos.
  2 - No caso das entidades referidas na alínea c) do artigo 26.º do Decreto-Lei n.º 37/2018, de 4 de junho, na sua redação atual, e na parte final do número anterior, o montante total do apoio não pode exceder 85/prct. do valor de referência aplicável ou do valor total das despesas elegíveis, se este for inferior.            
         
   
     
                         
                          
  Artigo 13.º 
Processo de atribuição dos apoios
                            
                           
                             
                               
                             
     1 - As entidades beneficiárias que pretendam candidatar-se a apoio para soluções de alojamento ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('urgente e temporário devem entregar os seus pedidos junto do IHRU, I. P.
  2 - As candidaturas são analisadas e aprovadas pelo IHRU, I. P., nos termos do presente decreto-lei e do Decreto-Lei n.º 37/2018, de 4 de junho, na sua redação atual, designadamente, do seu artigo 63.º, com as necessárias adaptações, tendo em conta a validade e viabilidade das soluções apresentadas, bem como a coerência destas com os fins estabelecidos no presente decreto-lei, sendo os elementos necessários para o efeito definidos na portaria a que se refere o n.º 4 do referido artigo 63.º
  3 - Para efeitos de instrução do procedimento, as entidades beneficiárias são dispensadas de apresentar documentos ou informações que já se encontrem na posse de órgãos, serviços ou entidades da Administração Pública, utilizando-se, sempre que possível, a Plataforma de Interoperabilidade da Administração Pública (iAP).
  4 - A análise das candidaturas previstas no n.º 2 é suportada por parecer do ISS, I. P., sobre o respetivo enquadramento no Plano Nacional de Alojamento, a emitir por este no prazo de 30 dias, em articulação prévia com a CIG e a AIMA, I. P., consoante a matéria, nos termos a protocolar entre estas entidades.
  5 - Excetua-se do disposto no número anterior as candidaturas apresentadas nos termos e para os efeitos do n.º 6 do artigo 8.º
  6 - O IHRU, I. P., deve incluir a informação relativa à forma de apresentação dos pedidos e à obtenção de esclarecimentos em relação aos apoios à promoção de alojamento urgente e temporário objeto do presente decreto-lei de forma autónoma, no âmbito da publicitação a que se refere o artigo 54.º do Decreto-Lei n.º 37/2018, de 4 de junho, na sua redação atual.
  7 - As verbas destinadas aos apoios à promoção das soluções de alojamento urgente e temporário objeto do presente decreto-lei acrescem à dotação do programa 1.º Direito, regulada no artigo 82.º do Decreto-Lei n.º 37/2018, de 4 de junho, na sua redação atual.
  8 - Anualmente, devem ser previstas as verbas necessárias à reabilitação que se mostre necessária nas soluções de alojamento urgente e temporário criado ao abrigo do presente decreto-lei.
  9 - Sempre que se mostre necessário ao cumprimento das finalidades previstas no presente decreto-lei e sempre que possível, deve ser promovida a consulta às bases de dados de outros órgãos, serviços ou entidades públicas, através da iAP.
  10 - Os alojamentos financiados ao abrigo do presente decreto-lei só podem ser desafetados do fim para que foram financiadas decorrido um período de 20 anos a contar da data da sua disponibilização.
  11 - Se, antes de decorrido o período referido no número anterior, o alojamento for desafetado do fim para que foi financiado, fica a entidade obrigada à devolução da totalidade das importâncias recebidas.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 41/2023, de 02 de Junho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 26/2021, de 31 de Março   ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('
     
                         
                          
  Artigo 14.º 
Acompanhamento e fiscalização
                            
                           
                             
                               
                             
     1 - Cabe ao ISS, I. P., e ao IHRU, I. P., no âmbito das suas competências próprias, assegurar o acompanhamento e a fiscalização do cumprimento das condições legais aplicáveis às soluções de alojamento promovidas com apoio financeiro nos termos previstos no presente decreto-lei.
  2 - O disposto no número anterior não prejudica o exercício pelo IHRU, I. P., das competências próprias relacionadas com os processos de financiamento à promoção das soluções de alojamento, podendo, quando isso se justifique, solicitar a colaboração do ISS, I. P.            
         
   
     
                         
                          
  CAPÍTULO V
  Disposições finais e transitórias  Artigo 15.º 
Publicitação dos apoios e disponibilização de outros conteúdos
                            
                           
                             
                               
                             
     1 - No início de cada ano, o IHRU, I. P., publicita no Portal da Habitação os apoios concedidos no ano anterior ao abrigo do presente decreto-lei, garantindo a confidencialidade das soluções de alojamento sempre que aplicável, sem prejuízo do cumprimento das demais condições de publicitação dos benefícios públicos legalmente estabelecidas.
  2 - A publicação, divulgação e disponibilização, para consulta ou outro fim, de informações, documentos e outros conteúdos que, pela sua natureza e nos termos legais, possam ou devam ser disponibilizados ao público, sem prejuízo do uso simultâneo de outros meios, deve estar disponível em formatos abertos, que permitam a leitura por máquina, para ser colocada ou indexada no Portal de Dados Abertos da Administração Pública, em www.dados.gov.pt.            
         
   
     
                         
                          
  Artigo 16.º 
Plataforma electrónica
                            
                           
                             
                               
                             
     1 - Para efeitos do disposto no n.º 2 do artigo 10.º, o ISS, I. P., deve promover a criação de uma plataforma eletrónica para acompanhamento e gestão das necessidades e disponibilização de soluções de alojamento urgente e temporário, nos temos do artigo 10.º, compatível com as plataformas já existentes e que garanta a interoperabilidade entre as diversas entidades, no prazo de seis meses a contar da data de entrada em vigor do presente decreto-lei.
  2 - A plataforma eletrónica deve contemplar a possibilidade de consulta das respostas que integram a Bolsa de Alojamento, garantindo a comunicação entre as diversas entidades.
  3 - Os termos e o acesso à presente plataforma são definidos pela portaria prevista no n.º 3 do artigo 10.º, em articulação com as','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' restantes áreas envolvidas na elaboração do Plano Nacional de Alojamento.            
         
   
     
                         
                          
  Artigo 17.º 
Dotação orçamental
                            
                           
                             
                               
                             
     Os apoios atribuídos ao abrigo do capítulo iv são financiados pelas verbas inscritas para este fim no Plano de Recuperação e Resiliência.            
         
   
     
                         
                          
  Artigo 18.º 
Entrada em vigor e vigência
                            
                           
                             
                               
                             
     1 - O presente decreto-lei entra em vigor no dia seguinte ao da sua publicação.
  2 - O disposto no capítulo iv vigora até ao dia 31 de agosto de 2026.
  
  Visto e aprovado em Conselho de Ministros de 18 de março de 2021. - António Luís Santos da Costa - Mariana Guimarães Vieira da Silva - Eduardo Arménio do Nascimento Cabrita - Alexandra Ludomila Ribeiro Fernandes Leitão - Ana Sofia Pedroso Lopes Antunes - Jorge Moreno Delgado.
  Promulgado em 29 de março de 2021.
  Publique-se.
  O Presidente da República, Marcelo Rebelo de Sousa.
  Referendado em 29 de março de 2021.
  O Primeiro-Ministro, António Luís Santos da Costa.','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:57  
    
  Dec. Regulam. n.º 2/2018, de 24 de Janeiro  (versão actualizada) CASAS DE ABRIGO - ESTRUTURAS DE ATENDIMENTO - RESPOSTAS DE ACOLHIMENTO DE EMERGÊNCIA    
    
 
Contém as seguintes alterações:   - Retificação n.º 11/2018, de 21 de Março   - Dec. Regulam. n.º 3/2020, de 14 de Agosto  
                         
                          
SUMÁRIORegula as condições de organização e funcionamento das estruturas de atendimento, das respostas de acolhimento de emergência e das casas de abrigo que integram a rede nacional de apoio às vítimas de violência doméstica
Decreto Regulamentar n.º 2/2018, de 24 de janeiro
  A violência doméstica tem sido um tema abordado por vários instrumentos internacionais, através dos quais os Estados se comprometeram a prosseguir por todos os meios apropriados uma política no sentido da sua eliminação, reconhecendo-se igualmente a necessidade de prestar assistência às vítimas, através de serviços de variada natureza.
  O Decreto Regulamentar n.º 1/2006, de 25 de janeiro, visou introduzir no ordenamento jurídico um conjunto de normas técnicas relativas às casas de abrigo para vítimas de violência doméstica, com o objetivo de conferir maior uniformidade à sua aplicação, acautelando, nomeadamente, as condições mínimas de abertura e de funcionamento, bem como a qualidade dos serviços prestados no âmbito da então Lei n.º 107/99, de 3 de agosto, regulamentada pelo Decreto-Lei n.º 323/2000, de 19 de dezembro, que estabeleceu o quadro geral da rede pública de casas de apoio dirigidas às mulheres vítimas de violência.
  A Lei n.º 112/2009, de 16 de setembro, que estabelece o regime jurídico aplicável à prevenção da violência doméstica, à proteção e à assistência das suas vítimas, republicada em anexo à Lei n.º 129/2015, de 3 de setembro, procedeu à revogação da Lei n.º 107/99, de 3 de agosto, assim como da respetiva regulamentação, definindo as estruturas e as respostas que integram a rede nacional de apoio às vítimas de violência doméstica.
  Para além do organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, a rede nacional de apoio às vítimas de violência doméstica compreende também o Instituto da Segurança Social, I. P., as casas de abrigo, as estruturas de atendimento, as respostas de acolhimento de emergência, as respostas específicas de organismos da Administração Pública, o serviço telefónico gratuito com cobertura nacional de informação a vítimas de violência doméstica e, ainda, sempre que o requeiram, os grupos de ajuda mútua de cariz comunitário que visem promover a autoajuda e o empoderamento das vítimas tendo em vista a sua autonomização.
  A rede nacional de apoio às vítimas de violência doméstica é constituída por um conjunto de estruturas e respostas que, a par das casas de abrigo, necessitam de ser regulamentadas, agrupando todos os requisitos aplicáveis a cada uma delas, tendo em vista uma harmonização de âmbito nacional das suas regras de funcionam','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ento e garantindo o mesmo nível de qualidade dos serviços prestados, independentemente da sua natureza jurídica.
  Por outro lado, e decorrida uma década da entrada em vigor do Decreto Regulamentar n.º 1/2006, de 25 de janeiro, constata-se que o conteúdo das suas disposições encontra-se não só desajustado às orientações de política nacional e internacional de prevenção da violência doméstica, proteção e assistência das suas vítimas, destacando-se, a este propósito, o previsto na Convenção do Conselho da Europa para a Prevenção e o Combate à Violência contra as Mulheres e a Violência Doméstica (Convenção de Istambul), como desadequado face às alterações entretanto verificadas na composição da atual rede nacional de apoio às vítimas de violência doméstica, ocorridas por via do disposto na Lei n.º 112/2009, de 16 de setembro, na sua redação atual.
  Com o presente decreto regulamentar, para além de se clarificarem os aspetos supra referidos, introduz-se um conjunto de regras e de procedimentos tendo em vista a melhoria e eficácia do funcionamento das estruturas de atendimento, respostas de acolhimento de emergência e casas de abrigo, permitindo quer um processo de autoavaliação das mesmas, quer a revisão, de forma sistemática, do seu desempenho, identificando as oportunidades de melhoria e a ligação entre o que se faz e os resultados que se atingem.
  Foram ouvidos os órgãos de governo próprio das regiões autónomas, a União das Misericórdias Portuguesas, a Confederação Nacional das Instituições de Solidariedade, a União das Mutualidades Portuguesas, o Conselho Consultivo da Comissão para a Cidadania e a Igualdade de Género, a Associação Nacional de Municípios Portugueses e a Comissão Nacional de Proteção de Dados.
  Assim:
  Nos termos da alínea c) do artigo 199.º da Constituição, e da Lei n.º 112/2009, de 16 de setembro, na sua redação atual, o Governo decreta o seguinte:
  
  CAPÍTULO I
  Disposições gerais  Artigo 1.º 
Objeto
                            
                           
                             
                               
                             
     O presente decreto regulamentar regula as condições de organização e funcionamento das estruturas de atendimento, das respostas de acolhimento de emergência e das casas de abrigo que integram a rede nacional de apoio às vítimas de violência doméstica, prevista na Lei n.º 112/2009, de 16 de setembro, na sua redação atual.            
         
   
     
                         
                          
  Artigo 2.º 
Definições
                            
                           
                             
                               
                             
     Para efeitos do presente decreto regulamentar, consideram-se:
  a) Casas de abrigo, as unidades residenciais destinadas a acolhimento temporário a vítimas de violência doméstica do mesmo sexo, acompanhadas ou não de filhos/as menores ou maiores com deficiência na sua dependência;
  b) Estruturas de','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' atendimento, as unidades constituídas por uma ou mais equipas técnicas de entidades públicas dependentes da administração central ou local, de entidades que com aquelas tenham celebrado acordos ou protocolos de cooperação e de outras organizações de apoio à vítima que assegurem, de forma integrada, com caráter de continuidade, o atendimento, o apoio e o reencaminhamento personalizado de vítimas, tendo em vista a sua proteção;
  c) Respostas de acolhimento de emergência, as unidades residenciais que visam o acolhimento urgente de vítimas do mesmo sexo, acompanhadas ou não de filhos/as menores ou maiores com deficiência na sua dependência, pelo período necessário à avaliação da sua situação, assegurando a proteção da sua integridade física e psicológica.            
         
   
     
                         
                          
  Artigo 3.º 
Entidades promotoras
                            
                           
                             
                               
                             
     1 - São promotoras das estruturas de atendimento, respostas de acolhimento de emergência e casas de abrigo as entidades do setor social e solidário e as organizações não-governamentais que tenham celebrado acordos ou protocolos de cooperação com entidades públicas e, subsidiariamente, as entidades públicas com competências nas áreas da prevenção da violência doméstica, da proteção e assistência das suas vítimas.
  2 - Os acordos ou protocolos de cooperação referidos no número anterior devem merecer a concordância entre os organismos da Administração Pública responsáveis pelas áreas da cidadania e da igualdade de género e da segurança social.
  3 - No âmbito das suas atribuições e competências, os municípios asseguram, no respeito pelo disposto no presente decreto regulamentar, a manutenção das estruturas de atendimento, respostas de acolhimento de emergência e casas de abrigo de que sejam proprietários, podendo contribuir para o bom estado de conservação das restantes, designadamente através dos apoios que entendam ser de disponibilizar para o funcionamento das mesmas.            
         
   
     
                         
                          
  Artigo 4.º 
Articulação
                            
                           
                             
                               
                             
     1 - As entidades promotoras devem articular-se entre si ou com as outras entidades que integram a rede nacional de apoio às vítimas de violência doméstica, de forma a garantir:
  a) O atendimento e apoio, de forma integrada e com caráter de continuidade, preferencialmente na sua área de residência, desde o momento da sua sinalização na rede até ao decurso do eventual processo de autonomização;
  b) O acolhimento das vítimas de violência doméstica acompanhadas ou não de filhos/as menores ou maiores com deficiência na sua dependência;
  c) O acompanhamento das vítimas durante o período de acolhimento e apó','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s a sua cessação.
  2 - As entidades promotoras devem cooperar e articular-se entre si através da formalização de parcerias, acordos ou protocolos com outras entidades ou serviços da comunidade vocacionados para a prestação dos apoios adequados às necessidades das vítimas de violência doméstica, designadamente nas áreas da justiça, da saúde, da educação, da administração interna, da segurança social, do emprego, da formação profissional e do sistema de promoção dos direitos e proteção das crianças e jovens.            
         
   
     
                         
                          
  Artigo 5.º 
Gratuitidade
                            
                           
                             
                               
                             
     Os serviços prestados pelas estruturas de atendimento, respostas de acolhimento de emergência e casas de abrigo às vítimas de violência doméstica são gratuitos.            
         
   
     
                         
                          
  Artigo 6.º 
Apoio judiciário
                            
                           
                             
                               
                             
     Sem prejuízo do disposto no artigo anterior, o apoio judiciário é prestado nos termos da legislação em vigor.            
         
   
     
                         
                          
  Artigo 7.º 
Confidencialidade
                            
                           
                             
                               
                             
     1 - As entidades promotoras e os/as respetivos/as trabalhadores/as que intervenham em procedimentos de atendimento, encaminhamento, acolhimento e apoio às vítimas de violência doméstica estão obrigados/as ao dever de confidencialidade.
  2 - O disposto no número anterior é aplicável às pessoas que se encontrem a desempenhar funções em regime de voluntariado e às restantes entidades que, no âmbito das suas funções, colaborem com as entidades promotoras.            
         
   
     
                         
                          
  Artigo 8.º 
Segurança
                            
                           
                             
                               
                             
     Atendendo à natureza e fins prosseguidos pelas estruturas de atendimento, respostas de acolhimento de emergência e casas de abrigo, as autoridades policiais territorialmente competentes prestam todo o apoio necessário com vista à proteção dos/as respetivos/as trabalhadores/as, incluindo as pessoas que se encontrem a desempenhar funções em regime de voluntariado, e das vítimas, assegurando as medidas que se entendam necessárias e convenientes para o efeito.            
         
   
     
                         
                          
  Artigo 9.º 
Proteção de dados
                            
                           
                             
                        ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('       
                             
     1 - As entidades promotoras devem respeitar a legislação em vigor em matéria de proteção de dados pessoais e de segurança da informação.
  2 - Os/As responsáveis pelo tratamento dos dados devem adotar as medidas de segurança técnica e organizacional necessárias a garantir a confidencialidade da informação.
  3 - Para os efeitos do número anterior, devem ser fixados diferentes níveis de acesso à informação, e fundamentada a necessidade de a ela aceder.
  4 - Os dados recolhidos no âmbito dos procedimentos previstos no presente decreto regulamentar destinam-se exclusivamente a instruir esses mesmos procedimentos, sendo vedada a sua introdução noutras bases de dados.            
         
   
     
                         
                          
  Artigo 10.º 
Formação
                            
                           
                             
                               
                             
     O organismo da Administração Pública responsável pela área da cidadania e da igualdade de género assegura, sem prejuízo da participação de outras entidades, a formação específica e especializada dos recursos humanos das estruturas de atendimento, respostas de acolhimento de emergência e casas de abrigo.            
         
   
     
                         
                          
  Artigo 11.º 
Requisitos mínimos
                            
                           
                             
                               
                             
     Sem prejuízo do disposto no presente decreto regulamentar, as estruturas de atendimento, respostas de acolhimento de emergência e casas de abrigo devem adotar os requisitos mínimos de intervenção em situações de violência doméstica e violência de género estabelecidos e divulgados pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, tendo em vista a uniformização, formalização e melhoramento das práticas e procedimentos a desenvolver no âmbito da violência doméstica.            
         
   
     
                         
                          
  Artigo 12.º 
Ficha única de atendimento
                            
                           
                             
                               
                             
     1 - A ficha única de atendimento é um instrumento de sistematização da informação recolhida sobre a vítima e o historial de vitimação que visa padronizar o registo, simplificar a recolha e o tratamento de dados e promover a partilha de informação, evitando situações de vitimação secundária e institucional.
  2 - O modelo de ficha única de atendimento às vítimas de violência doméstica a utilizar pelas estruturas de atendimento, respostas de acolhimento de emergência e pelas casas de abrigo é elaborado no prazo de 180 dias pelos organismos da Administração Pública responsáveis pelas áreas da cidadania e da igualdade de género e da segura','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('nça social, sujeito a consulta aos representantes das entidades do setor social e solidário e à secção das organizações não-governamentais do Conselho Consultivo da Comissão para a Cidadania e a Igualdade de Género.            
         
   
     
                         
                          
  Artigo 13.º 
Avaliação e gestão do grau de risco e das necessidades sociais
                            
                           
                             
                               
                             
     1 - A avaliação e gestão do grau de risco e das necessidades sociais da vítima de violência doméstica é uma metodologia que visa recolher informação acerca das pessoas e das variáveis envolvidas num determinado contexto de violência, com a finalidade de identificar o grau de perigosidade presente e futura, facilitando o processo de tomada de decisão acerca do risco de reincidência da violência, incluindo o risco de violência letal, bem como sobre a necessidade e pertinência de integração na resposta que melhor garanta a proteção e segurança da vítima, apoiando-a nas suas decisões.
  2 - O modelo de avaliação e gestão do grau de risco da vítima de violência doméstica a utilizar pelas estruturas de atendimento, respostas de acolhimento de emergência e casas de abrigo é o que resulta do modelo utilizado pelos órgãos de polícia criminal, tendo em consideração os fatores de risco apurados aquando da sinalização, complementados por uma avaliação atuarial, atendendo ao contexto de violência.
  3 - O modelo de avaliação das necessidades sociais da vítima de violência doméstica a utilizar pelas estruturas de atendimento, respostas de acolhimento de emergência e casas de abrigo é elaborado no prazo de 180 dias pelos organismos da Administração Pública responsáveis pelas áreas da cidadania e da igualdade de género e da segurança social, sujeito a consulta aos representantes das entidades do setor social e solidário e à secção das organizações não-governamentais do Conselho Consultivo da Comissão para a Cidadania e a Igualdade de Género.            
         
   
     
                         
                          
  Artigo 14.º 
Plano de segurança
                            
                           
                             
                               
                             
     1 - O plano de segurança é um instrumento que assenta na definição e prestação de orientações para autoproteção e prevenção do risco e perigo de uma vítima específica, tendo em conta a caracterização da situação atual relatada, bem como na informação relevante recolhida noutras fontes, definindo estratégias de segurança avaliadas pela própria vítima como possíveis de executar, nos vários contextos em que pode ocorrer vitimação, sem aumentar o possível risco de violência.
  2 - Os órgãos de polícia criminal territorialmente competentes devem ter conhecimento de todos os planos de segurança aplicados na respetiva área de intervenção, be','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('m como das eventuais alterações que nos mesmos venham a ser introduzidas.
  3 - O modelo de plano de segurança a utilizar pelas estruturas de atendimento é elaborado no prazo de 180 dias pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género e os serviços competentes da administração interna, sujeito a consulta aos representantes das entidades do setor social e solidário e à secção das organizações não-governamentais do Conselho Consultivo da Comissão para a Cidadania e a Igualdade de Género.            
         
   
     
                         
                          
  Artigo 15.º 
Relatório de encaminhamento
                            
                           
                             
                               
                             
     1 - O relatório de encaminhamento é um documento elaborado pelo/a responsável técnico/a ou pela equipa técnica da entidade encaminhadora, constituído por um conjunto de indicadores e uma avaliação da situação que motivou o pedido de acolhimento da vítima de violência doméstica, a enviar à entidade de acolhimento, nos termos a regulamentar por portaria dos membros do Governo responsáveis pelas áreas da cidadania e da igualdade de género e da segurança social.
  2 - O modelo de relatório de encaminhamento a utilizar pelas entidades encaminhadoras das respostas de acolhimento de emergência ou casas de abrigo é elaborado no prazo de 180 dias pelos organismos da Administração Pública responsáveis pelas áreas da cidadania e da igualdade de género e da segurança social, sujeito a consulta aos representantes das entidades do setor social e solidário e à secção das organizações não-governamentais do Conselho Consultivo da Comissão para a Cidadania e a Igualdade de Género.            
         
   
     
                         
                          
  Artigo 16.º 
Plano individual de intervenção
                            
                           
                             
                               
                             
     1 - O plano individual de intervenção é um documento programático que define os objetivos e as metas a atingir pela vítima num determinado período temporal, elaborado de acordo com os resultados da avaliação e gestão do grau de risco e das necessidades sociais da mesma, tendo em vista a definição de um projeto de vida que inclua o restabelecimento do seu equilíbrio emocional e psicológico, bem como a sua inserção social e autonomização em condições de segurança e dignidade.
  2 - A vítima participa na elaboração do plano individual de intervenção e deve manifestar, por forma expressa, o seu consentimento para a respetiva implementação.
  3 - O plano individual de intervenção a utilizar pelas casas de abrigo tem em consideração o projeto de vida da vítima e dos/as filhos/as acolhidos/as.
  4 - O modelo de plano individual de intervenção a utilizar pelas estruturas de atendimento e pelas casas de abr','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('igo é elaborado no prazo de 180 dias pelos organismos da Administração Pública responsáveis pelas áreas da cidadania e da igualdade de género e da segurança social, sujeito a consulta aos representantes das entidades do setor social e solidário e à secção das organizações não-governamentais do Conselho Consultivo da Comissão para a Cidadania e a Igualdade de Género.            
         
   
     
                         
                          
  Artigo 17.º 
Processo individual
                            
                           
                             
                               
                             
     As estruturas de atendimento, respostas de acolhimento de emergência e as casas de abrigo elaboram um processo individual de cada vítima a quem foi prestado apoio, acompanhamento e acolhimento, nos termos a regulamentar por portaria dos membros do Governo responsáveis pelas áreas da cidadania e da igualdade de género e da segurança social.            
         
   
     
                         
                          
  CAPÍTULO II
  Estruturas de atendimento
  SECÇÃO I
  Objetivos, acompanhamento e encaminhamento  Artigo 18.º 
Objetivos
                            
                           
                             
                               
                             
     São objetivos das estruturas de atendimento:
  a) Assegurar o acompanhamento das vítimas de violência doméstica nas vertentes de atendimento psicossocial e de informação jurídica;
  b) Proceder à avaliação e gestão do grau de risco e das necessidades sociais das vítimas de violência doméstica, de forma a assegurar uma intervenção promotora da segurança ou o seu eventual reencaminhamento e acolhimento em condições de segurança;
  c) Dinamizar ações de informação e de formação sobre a problemática da violência doméstica e de género, junto de públicos estratégicos a nível regional e local, em articulação, designadamente, com as escolas ou agrupamentos, organizações da sociedade civil, autarquias e empresas.            
         
   
     
                         
                          
  Artigo 19.º 
Atendimento e acompanhamento
                            
                           
                             
                               
                             
     1 - O atendimento é efetivado mediante iniciativa da própria vítima por sinalização através de contacto telefónico, nomeadamente por via da Linha do Serviço de Informação a Vítimas de Violência Doméstica e da Linha Nacional de Emergência Social, ou por indicação de outras entidades com competências em matéria de ação social e prevenção e proteção da violência doméstica, nos termos da legislação em vigor aplicável.
  2 - O acompanhamento assenta numa intervenção, pontual ou sistemática, e integrada nas áreas do apoio psicossocial e de informação jurídica, e, sempre que necessário, na elaboração de um plano individual de intervenção, em consonância co','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('m o pedido da vítima e a dinâmica abusiva.
  3 - Nos casos de denúncia pela prática de um crime de violência doméstica, o acompanhamento deve ter também em consideração o plano de segurança da vítima específica previamente realizado pelos respetivos órgãos de polícia criminal ou, na sua ausência, a realizar pela estrutura de atendimento.            
         
   
     
                         
                          
  SECÇÃO II
  Criação e funcionamento  Artigo 20.º 
Criação
                            
                           
                             
                               
                             
     1 - A criação das estruturas de atendimento depende da verificação cumulativa dos seguintes requisitos:
  a) Adequação às necessidades reais da comunidade, devidamente fundamentada através da realização prévia de um diagnóstico sobre a densidade populacional e o impacto da nova estrutura face ao número de estruturas existentes na área geográfica, nos termos do modelo a definir pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género;
  b) Cumprimento das disposições legais relativas à constituição e ao registo da entidade;
  c) Capacidade económica e financeira da entidade;
  d) Existência de instalações devidamente dimensionadas e equipadas, que garantam que o atendimento se efetive em segurança e discrição;
  e) Recursos humanos adequados e preferencialmente com formação específica na área da violência doméstica e de género;
  f) Regulamento interno de funcionamento;
  g) Certificação pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, nos termos do disposto na alínea i) do artigo 58.º da Lei n.º 112/2009, de 16 de setembro, na sua redação atual;
  h) Observância dos requisitos mínimos de intervenção em situações de violência doméstica e violência de género.
  2 - As estruturas de atendimento devem ser concebidas, preferencialmente, em unidades próprias e distintas de outras respostas ou valências, sendo independentes e autónomas.
  3 - O diagnóstico referido na alínea a) do n.º 1 deve ser entregue junto do organismo da Administração Pública responsável pela área da cidadania e da igualdade de género.            
         
   
     
                         
                          
  Artigo 21.º 
Instalações
                            
                           
                             
                               
                             
     1 - A estrutura de atendimento dispõe nas suas instalações dos espaços necessários e adequados à capacidade do serviço a prestar, no cumprimento do disposto na legislação em vigor, nomeadamente em matéria de segurança, higiene e saúde no trabalho, edificações e acessibilidade, designadamente das pessoas com deficiência.
  2 - A estrutura de atendimento dispõe de áreas funcionais, nos termos a regulamentar por portaria dos membros do Governo responsáveis pelas áreas da c','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('idadania e da igualdade de género e da segurança social.
  3 - Os espaços privados existentes nas instalações devem ser concebidos de forma a garantir uma efetiva privacidade às vítimas de violência doméstica.            
         
   
     
                         
                          
  Artigo 22.º 
Funcionamento
                            
                           
                             
                               
                             
     1 - As estruturas de atendimento funcionam durante todo o ano, nos cinco dias úteis da semana, exceto dias feriados, durante 7 horas por dia, devendo as mesmas procurar adequar e flexibilizar o seu horário, de forma a possibilitar às vítimas a efetiva conciliação entre a vida profissional, pessoal e familiar.
  2 - As regras de funcionamento constam no regulamento interno de funcionamento da estrutura de atendimento, sendo dado a conhecer às vítimas e afixado em local bem visível.            
         
   
     
                         
                          
  Artigo 23.º 
Coordenador/a técnico/a
                            
                           
                             
                               
                             
     1 - As estruturas de atendimento dispõem de um/a coordenador/a técnico/a com formação superior, preferencialmente na área das ciências sociais ou humanas.
  2 - São atribuições do/a coordenador/a técnico/a:
  a) Coordenar a equipa técnica;
  b) Definir orientações técnicas de acordo com o modelo de intervenção das estruturas de atendimento;
  c) Assegurar a articulação com outras entidades.            
         
   
     
                         
                          
  Artigo 24.º 
Equipa técnica
                            
                           
                             
                               
                             
     1 - A intervenção nas estruturas de atendimento é assegurada por uma equipa técnica.
  2 - A equipa técnica deve ter uma constituição multidisciplinar, constituída por técnicos/as com formação superior, preferencialmente nas áreas do serviço social, psicologia e direito, num número mínimo de dois, devendo pelo menos um exercer as funções a tempo completo.
  3 - São competências da equipa técnica:
  a) Garantir o atendimento e acompanhamento das vítimas;
  b) Proceder à avaliação e gestão do grau de risco e das necessidades sociais das vítimas;
  c) Elaborar o plano de segurança quando, face à denúncia da prática do crime de violência doméstica, o mesmo não tiver sido desenvolvido pelos respetivos órgãos de polícia criminal, informando-os do mesmo;
  d) Elaborar o plano individual de intervenção, quando aplicável;
  e) Avaliar periodicamente o plano de segurança da vítima específica e o plano individual de intervenção, procedendo aos ajustamentos necessários;
  f) Articular com as demais estruturas que relevem para o processo de acompanhamento, encaminhamento e autonomização da v','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ítima.
  4 - O atendimento e acompanhamento das vítimas previsto na alínea a) do número anterior não pode ter natureza de um processo alternativo de resolução de conflitos, incluindo a mediação e a conciliação, nem pode ser prestado simultaneamente, pela mesma equipa técnica, a vítimas e a agressores/as.            
         
   
     
                         
                          
  CAPÍTULO III
  Respostas de acolhimento de emergência
  SECÇÃO I
  Objetivos, acolhimento e acompanhamento  Artigo 25.º 
Objetivos
                            
                           
                             
                               
                             
     São objetivos das respostas de acolhimento de emergência:
  a) Acolher, transitoriamente, vítimas de violência doméstica em situação de emergência;
  b) Assegurar o acompanhamento das vítimas, acompanhadas ou não de filhos/as menores ou maiores com deficiência na sua dependência;
  c) Proporcionar as condições necessárias à segurança e bem-estar físico e psicológico das vítimas, em situação de crise.            
         
   
     
                         
                          
  Artigo 26.º 
Admissão
                            
                           
                             
                               
                             
     1 - A admissão das vítimas nas respostas de acolhimento de emergência processa-se por indicação da equipa técnica da entidade encaminhadora, com base no pedido de acolhimento de emergência, quando da realização da avaliação da situação resultar inequivocamente que o acolhimento imediato é a resposta que melhor garante a integridade física e psicológica da vítima.
  2 - Para efeitos de admissão nas respostas de acolhimento de emergência, são entidades encaminhadoras:
  a) O organismo da Administração Pública responsável pela área da cidadania e da igualdade de género;
  b) As estruturas de atendimento;
  c) Outras respostas de acolhimento de emergência;
  d) As casas de abrigo;
  e) Os serviços competentes da segurança social;
  f) Os serviços da ação social das câmaras municipais;
  g) Os órgãos de polícia criminal.
  3 - São requisitos de admissão nas respostas de acolhimento de emergência:
  a) O encaminhamento feito por indicação de uma entidade referida no número anterior;
  b) A apresentação, pela entidade encaminhadora, de um pedido de acolhimento de emergência;
  c) A apresentação, pela entidade encaminhadora, do relatório de encaminhamento, constituído por um conjunto de indicadores e pela avaliação da situação que motivou o pedido de acolhimento de emergência;
  d) A aceitação pela vítima, por forma expressa, do recurso à resposta de acolhimento de emergência.
  4 - O pedido de acolhimento de emergência é formalizado por escrito e remetido pela via mais expedita, sem prejuízo da utilização prévia de outros contactos mais céleres que se possam estabelecer entre as entidades envolvidas.
  5 - A avaliação da situação que ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('motivou o pedido de acolhimento de emergência referido na alínea c) do n.º 3 deve conter os seguintes elementos:
  a) Descrição sucinta do historial de vitimação e do episódio atual;
  b) Informações de âmbito jurídico, social e psicológico;
  c) Características sociodemográficas do agregado a acolher;
  d) Referência de eventuais problemas de saúde ou outros que relevem para a adequada prestação dos serviços pela resposta de acolhimento de emergência;
  e) Contactos da entidade e do/a técnico/a responsável pelo pedido de acolhimento de emergência.
  6 - Em situação de emergência, as vítimas podem ser admitidas, durante um período não superior a 72 horas, antes da realização da avaliação prevista no número anterior, nomeadamente por indicação dos órgãos de polícia criminal ou outras entidades encaminhadoras, em concertação com a entidade promotora da resposta de acolhimento de emergência ou da casa de abrigo que disponha de vagas para situações de emergência.            
         
   
     
                         
                          
  Artigo 27.º 
Acolhimento
                            
                           
                             
                               
                             
     1 - O acolhimento é assegurado pela entidade que melhor e com mais celeridade possa garantir uma intervenção imediata face à avaliação da situação que motivou o pedido de acolhimento de emergência, mediante despacho de aceitação do relatório de encaminhamento pelo/a responsável técnico/a.
  2 - A intervenção imediata visa:
  a) Acautelar as condições de segurança e de apoio efetivo da vítima, garantindo a sua integridade física e psicológica, e;
  b) Reencaminhar para uma outra estrutura ou resposta social que se revele mais adequada ou para uma casa de abrigo.
  3 - A intervenção referida no número anterior é da responsabilidade da equipa técnica da entidade que solicitou o acolhimento de emergência em articulação com o/a responsável técnico/a da resposta de acolhimento de emergência.            
         
   
     
                         
                          
  Artigo 28.º 
Duração
                            
                           
                             
                               
                             
     1 - O acolhimento nas respostas de acolhimento de emergência é transitório e de curta duração, pressupondo uma intervenção imediata, não devendo ser superior a 15 dias.
  2 - A título excecional, mediante parecer fundamentado do/a responsável técnico/a da resposta de acolhimento de emergência, acompanhado da avaliação da situação da vítima, o período de acolhimento referido no número anterior pode ser prorrogado, no máximo, por igual período de tempo.
  3 - No caso de vítimas de vulnerabilidade acrescida, designadamente em razão da deficiência, da doença mental, da orientação sexual, da identidade e expressão de género, e da idade, o acolhimento pode ter a duração de três meses, prorrogável, ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('no máximo, por dois períodos de tempo iguais, atendendo à especificidade da situação das vítimas, mediante parecer prévio do organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, com base em requerimento fundamentado do/a responsável técnico/a da resposta de acolhimento de emergência.
  4 - São causas imediatas de cessação do acolhimento:
  a) A manifestação de vontade da vítima, proferida de forma expressa;
  b) Incumprimento das regras estabelecidas no regulamento interno de funcionamento da resposta de acolhimento de emergência;
  c) O termo do período inicial de acolhimento ou da sua prorrogação;
  d) Quando se verifiquem as condições necessárias e efetivas de encaminhamento para uma casa de abrigo ou outra estrutura ou resposta social que se revele adequada.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Dec. Regulam. n.º 3/2020, de 14 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Dec. Regulam. n.º 2/2018, de 24 de Janeiro   
     
                         
                          
  Artigo 29.º 
Acompanhamento
                            
                           
                             
                               
                             
     O acompanhamento assenta numa intervenção sistemática e integrada nas áreas do apoio psicossocial e de informação jurídica, com especial enfoque na implementação de estratégias de intervenção na crise.            
         
   
     
                         
                          
  Artigo 30.º 
Alojamento
                            
                           
                             
                               
                             
     1 - O alojamento consiste no apoio residencial prestado às vítimas, acompanhadas ou não de filhos/as menores ou maiores com deficiência na sua dependência, por um período de tempo determinado, em instalações coletivas ou apartamentos, conforme a situação e as necessidades da vítima e dos/as filhos/as.
  2 - Para efeitos do disposto no número anterior, a entidade responsável pela resposta de acolhimento de emergência pode dispor de apartamentos plurifamiliares ou unifamiliares, em instalações próprias, arrendadas ou cedidas por entidade pública ou privada.
  3 - O alojamento compreende, ainda, a prestação de serviços básicos, nomeadamente alimentação, higiene, proteção e segurança.            
         
   
     
                         
                          
  SECÇÃO II
  Criação e funcionamento  Artigo 31.º 
Criação
                            
                           
                             
                               
                             
     1 - A criação das respostas de acolhimento de emergência está dependente da sua articulação formal com uma estrutura de atendimento e da verificação cumulativa dos requisitos previstos para a criação das casas de abrigo.
  2 - As respostas de acolhimento de ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('emergência devem ser concebidas em unidades próprias e distintas de outras respostas ou valências, sendo independentes e autónomas, garantindo a confidencialidade e a segurança da própria estrutura e do encaminhamento das vítimas e dos/as filhos/as acolhidos/as, à exceção das vagas para situações de emergência disponíveis nas casas de abrigo.            
         
   
     
                         
                          
  Artigo 32.º 
Instalações
                            
                           
                             
                               
                             
     1 - A resposta de acolhimento de emergência dispõe nas suas instalações dos espaços necessários e adequados ao número de vítimas e filhos/as acolhidos/as permitindo que usufruam de um espaço de privacidade e de um grau de autonomia, nos termos da legislação em vigor, nomeadamente em matéria de segurança, higiene e saúde no trabalho, edificações e acessibilidade, designadamente das pessoas com deficiência.
  2 - A capacidade das respostas de acolhimento de emergência não deve exceder o máximo de 15 utentes, incluindo as vítimas e filhos/as acolhidos/as.
  3 - A resposta de acolhimento de emergência dispõe de áreas funcionais, nos termos a regulamentar por portaria dos membros do Governo responsáveis pelas áreas da cidadania e da igualdade de género e da segurança social.
  4 - Nos quartos com mais de uma cama, que possibilitem a permanência das vítimas e dos/as filhos/as acolhidos/as, não deve, preferencialmente, ser alojado mais do que um agregado familiar por quarto.
  5 - Os espaços privados existentes nas instalações das respostas de acolhimento de emergência devem ser concebidos de forma a garantir uma efetiva privacidade.
  6 - As instalações devem estar providas de mobiliário idêntico ao de qualquer habitação, por forma a proporcionar um ambiente próximo e familiar.            
         
   
     
                         
                          
  Artigo 33.º 
Recursos humanos
                            
                           
                             
                               
                             
     1 - A intervenção das respostas de acolhimento de emergência é assegurada, no mínimo, por um/a técnico/a, a quem cabe a avaliação da situação da vítima acolhida, designadamente da avaliação e gestão do grau de risco e das necessidades sociais, bem como o apoio na definição e execução do projeto a desenvolver no período posterior ao acolhimento, em articulação com a equipa técnica da entidade que solicitou o acolhimento de emergência.
  2 - O pessoal que desempenhe as funções referidas no número anterior tem formação superior, preferencialmente nas áreas das ciências sociais ou humanas e, ainda, a qualificação de técnico/a de apoio à vítima e comprovada experiência profissional em metodologias de intervenção em crise.
  3 - As respostas de acolhimento de emergência dispõem, para uma capacidade de 15 vítimas, inclui','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ndo os/as filhos/as acolhidos/as, no mínimo de três ajudantes de ação direta, podendo, sempre que se justifique, haver lugar a um reforço da dotação deste pessoal, desenvolvendo tarefas nos termos definidos para as casas de abrigo.
  4 - Para garantir o acompanhamento durante 24 horas, um/a dos/as ajudantes de ação direta fica afeto/a ao período noturno.            
         
   
     
                         
                          
  Artigo 34.º 
Responsável técnico/a
                            
                           
                             
                               
                             
     1 - As respostas de acolhimento de emergência dispõem de um/a responsável técnico/a com formação superior, preferencialmente na área das ciências sociais ou humanas, contactável durante 24 horas por dia ou, na sua impossibilidade, por um/a técnico/a indicado/a para o efeito.
  2 - São competências do/a responsável técnico/a:
  a) Garantir o acolhimento e o acompanhamento das vítimas e dos/as filhos/as acolhidos/as em conformidade com os seus direitos e deveres;
  b) Promover a avaliação e gestão do grau de risco e das necessidades sociais da vítima, aquando do seu acolhimento;
  c) Emitir parecer sobre a necessidade de prorrogação do período de acolhimento;
  d) Determinar a cessação do acolhimento, nos termos previstos no n.º 4 do artigo 28.º;
  e) Elaborar o relatório de encaminhamento para a casa de abrigo ou outra estrutura ou resposta social que se revele mais adequada, explicitando os motivos do termo do acolhimento na resposta de acolhimento de emergência.
  3 - A cessação do acolhimento nos termos da alínea b) do n.º 4 do artigo 28.º está sujeita à realização de um procedimento administrativo interno, da competência do/a responsável técnico/a, de acordo com as seguintes fases:
  a) Registo das diligências de prova;
  b) Audiência do/a interessado/a;
  c) Decisão final fundamentada.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Dec. Regulam. n.º 3/2020, de 14 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: Dec. Regulam. n.º 2/2018, de 24 de Janeiro   
     
                         
                          
  Artigo 35.º 
Funcionamento
                            
                           
                             
                               
                             
     1 - As respostas de acolhimento de emergência funcionam durante todo o ano, todos os dias da semana, durante 24 horas por dia.
  2 - O regulamento interno de funcionamento da resposta de acolhimento de emergência é afixado em local bem visível, obrigatoriamente dado a conhecer às vítimas aquando da sua admissão, ou quando se verificar a estabilização emocional, devendo ser subscrito por estas o correspondente termo de aceitação, e disponibilizado para consulta, sempre que solicitado pelas mesmas.
  3 - As alterações efetuadas ao regulamento interno são de comunicação obrigatória à','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s vítimas acolhidas.            
         
   
     
                         
                          
  CAPÍTULO IV
  Casas de abrigo
  SECÇÃO I
  Objetivos, admissão e acompanhamento  Artigo 36.º 
Objetivos
                            
                           
                             
                               
                             
     São objetivos das casas de abrigo:
  a) Acolher temporariamente vítimas, acompanhadas ou não de filhos/as menores ou maiores com deficiência na sua dependência;
  b) Assegurar o acompanhamento das vítimas, acompanhadas ou não de filhos/as;
  c) Proporcionar às vítimas e filhos/as acolhidos/as as condições necessárias à sua educação, saúde e bem-estar integral, num ambiente de tranquilidade e segurança;
  d) Desenvolver, durante a permanência na casa de abrigo, aptidões pessoais, profissionais e sociais das vítimas, no sentido de alcançar a sua plena autonomia;
  e) Promover o restabelecimento do equilíbrio emocional e psicológico das vítimas e filhos/as acolhidos/as, tendo em vista a sua reinserção ou autonomização em condições de dignidade e de segurança.            
         
   
     
                         
                          
  Artigo 37.º 
Admissão
                            
                           
                             
                               
                             
     1 - A admissão das vítimas nas casas de abrigo processa-se por indicação do/a responsável técnico/a ou da equipa técnica de entidade encaminhadora, com base no relatório de encaminhamento.
  2 - Para efeitos de admissão nas casas de abrigo, são entidades encaminhadoras:
  a) O organismo da Administração Pública responsável pela área da cidadania e da igualdade de género;
  b) As estruturas de atendimento;
  c) As respostas de acolhimento de emergência;
  d) Outras casas de abrigo;
  e) Os serviços competentes da segurança social;
  f) Os serviços da ação social das câmaras municipais.
  3 - São requisitos de admissão nas casas de abrigo:
  a) O encaminhamento feito por indicação de uma das entidades referidas no número anterior;
  b) A apresentação do relatório de encaminhamento;
  c) A aceitação pela vítima do acolhimento em casa de abrigo e, por forma expressa, do regulamento interno de funcionamento da casa de abrigo.
  4 - Em situação de emergência, e caso não haja possibilidade imediata de integração numa resposta de acolhimento de emergência, a vítima de violência doméstica acompanhada ou não de filhos/as menores ou maiores com deficiência na sua dependência podem ser acolhidos/as durante um período não superior a 72 horas, antes da realização do relatório de encaminhamento referido no número anterior, nomeadamente por indicação das forças de segurança ou outras entidades encaminhadoras.            
         
   
     
                         
                          
  Artigo 38.º 
Acolhimento
                            
                           
                  ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('           
                               
                             
     O acolhimento é assegurado pela entidade que melhor possa garantir as necessidades de segurança e apoio efetivo à vítima mediante despacho de aceitação do relatório de encaminhamento pelo/a diretor/a técnico/a, emitido com base na análise realizada pela equipa técnica da entidade de acolhimento.            
         
   
     
                         
                          
  Artigo 39.º 
Duração
                            
                           
                             
                               
                             
     1 - O acolhimento nas casas de abrigo é temporário, não devendo ser superior a seis meses.
  2 - A título excecional, mediante parecer fundamentado da equipa técnica da casa de abrigo, acompanhado da avaliação da situação da vítima, o período de acolhimento referido no número anterior pode ser prorrogado, no máximo, por igual período de tempo.
  3 - São causas imediatas de cessação do acolhimento:
  a) O termo do período inicial de acolhimento ou da sua prorrogação;
  b) A manifestação de vontade da vítima, proferida de forma expressa;
  c) Incumprimento das regras estabelecidas no regulamento interno de funcionamento da casa de abrigo.            
         
   
     
                         
                          
  Artigo 40.º 
Alojamento
                            
                           
                             
                               
                             
     1 - O alojamento consiste no apoio residencial prestado às vítimas, acompanhadas ou não de filhos/as menores ou maiores com deficiência na sua dependência, por um período de tempo determinado, em instalações coletivas ou apartamentos, conforme a situação e as necessidades da vítima e dos/as filhos/as.
  2 - Para efeitos do disposto no número anterior, a entidade responsável pela casa de abrigo pode dispor de apartamentos plurifamiliares ou unifamiliares, em instalações próprias ou cedidas por entidade pública ou privada.
  3 - O alojamento compreende, ainda, a prestação de serviços básicos, nomeadamente alimentação, higiene, proteção e segurança.            
         
   
     
                         
                          
  Artigo 41.º 
Acompanhamento
                            
                           
                             
                               
                             
     O acompanhamento assenta numa intervenção sistemática e integrada nas áreas do apoio social, psicológico, educacional, profissional e jurídico, e obedece a um plano individual de intervenção.            
         
   
     
                         
                          
  SECÇÃO II
  Criação e funcionamento  Artigo 42.º 
Criação
                            
                           
                             
                               
                             
     1 - A criação das casas de abrigo dep','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ende da verificação cumulativa dos seguintes requisitos:
  a) Cumprimento das disposições legais relativas à constituição, ao registo da entidade e ao licenciamento da atividade;
  b) Capacidade económica e financeira da entidade;
  c) Existência de instalações devidamente dimensionadas e equipadas;
  d) Localização na proximidade de serviços públicos de ensino e saúde, bem como das autoridades policiais;
  e) Recursos humanos adequados, preferencialmente com formação específica na área da violência doméstica e de género;
  f) Regulamento interno de funcionamento;
  g) Parecer técnico do organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, no que respeita ao regulamento interno de funcionamento;
  h) Certificação pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, nos termos do disposto na alínea i) do artigo 58.º da Lei n.º 112/2009, de 16 de setembro, na sua redação atual;
  i) Observância dos requisitos mínimos de intervenção em situações de violência doméstica e violência de género.
  2 - À exceção daquelas que disponham de vagas para situações de emergência, as casas de abrigo devem ser concebidas em unidades próprias e distintas de outras respostas ou valências, sendo independentes e autónomas, garantindo a confidencialidade e a segurança da própria estrutura e do encaminhamento das vítimas e dos/as filhos/as acolhidos/as.
  3 - O projeto de regulamento interno deve ser entregue para aprovação junto dos serviços territorialmente competentes da segurança social, após emissão do parecer técnico referido na alínea h) do n.º 1.            
         
   
     
                         
                          
  Artigo 43.º 
Instalações
                            
                           
                             
                               
                             
     1 - A casa de abrigo dispõe nas suas instalações dos espaços necessários e adequados ao número de vítimas e filhos/as acolhidos/as permitindo que usufruam de um espaço de privacidade e de um grau de autonomia na condução da sua vida pessoal adequados à sua idade e situação, nos termos da legislação em vigor, nomeadamente em matéria de segurança, higiene e saúde no trabalho, edificações e acessibilidade, designadamente das pessoas com deficiência.
  2 - A capacidade das casas de abrigo não deve exceder o máximo de 30 utentes, incluindo as vítimas e filhos/as acolhidos/as.
  3 - A casa de abrigo dispõe de área funcionais, nos termos a regulamentar por portaria dos membros do Governo responsáveis pelas áreas da cidadania e da igualdade de género e da segurança social.
  4 - Nos quartos com mais de uma cama, que possibilitem a permanência das vítimas e dos/as filhos/as acolhidos/as, não deve, preferencialmente, ser alojado mais do que um agregado familiar por quarto.
  5 - Os espaços privados existentes nas instalações das casas de abrigo devem ser concebidos de forma a gar','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('antir uma efetiva privacidade.
  6 - As instalações devem estar providas de mobiliário idêntico ao de qualquer habitação, por forma a proporcionar um ambiente próximo e familiar.
  7 - A casa de abrigo pode integrar apartamentos plurifamiliares ou unifamiliares com vista à gradual autonomização das vítimas acolhidas, de acordo com os respetivos perfis e a fase do plano individual de intervenção em que se encontram.            
         
   
     
                         
                          
  Artigo 44.º 
Recursos humanos
                            
                           
                             
                               
                             
     1 - A intervenção das casas de abrigo é assegurada por uma equipa técnica integrando, preferencialmente, técnicos/as de apoio à vítima, a quem cabe a avaliação da situação da vítima acolhida, designadamente da avaliação e gestão do grau de risco e das necessidades sociais, bem como o apoio na definição e execução dos projetos de promoção dos seus direitos e autonomização.
  2 - O pessoal que desempenhe as funções previstas no número anterior tem formação superior, preferencialmente em psicologia, serviço social, direito e educação social.
  3 - O número de recursos humanos deve ser adequado à capacidade de vítimas na casa de abrigo, a regulamentar por portaria dos membros do Governo responsáveis pelas áreas da cidadania e da igualdade de género e da segurança social.            
         
   
     
                         
                          
  Artigo 45.º 
Diretor/a técnico/a
                            
                           
                             
                               
                             
     1 - As casas de abrigo dispõem de um/a diretor/a técnico/a com formação superior, preferencialmente na área das ciências sociais ou humanas.
  2 - São atribuições do/a diretor/a técnico/a:
  a) Dirigir a casa de abrigo, assumindo a responsabilidade pela programação e pela avaliação das atividades a desenvolver;
  b) Definir a gestão adequada ao bom funcionamento da casa de abrigo;
  c) Coordenar os recursos humanos;
  d) Assegurar a articulação com outras entidades.
  3 - São competências do/a diretor/a técnico/a, designadamente:
  a) Decidir pela prorrogação do período de acolhimento na casa de abrigo;
  b) Velar para que as vítimas e os/as filhos/as acolhidos/as cumpram as regras estabelecidas no regulamento interno de funcionamento da casa de abrigo, com recurso, se necessário, a repreensão oral ou por escrito, consoante a gravidade do incumprimento;
  c) Determinar a cessação do acolhimento, nos termos previstos no n.º 3 do artigo 39.º
  4 - A cessação do acolhimento nos termos da alínea c) do n.º 3 do artigo 39.º está sujeita à realização de um procedimento administrativo interno, da competência do/a diretor/a técnico/a, de acordo com as seguintes fases:
  a) Registo das diligências de prova;
  b) Audiência do/a interessado/a;
  c) D','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ecisão final fundamentada.
  5 - O/a diretor/a técnico/a não deve ser o responsável direto pelo acompanhamento dos processos de apoio e de intervenção das vítimas acolhidas.            
         
   
     
                         
                          
  Artigo 46.º 
Equipa técnica
                            
                           
                             
                               
                             
     São competências da equipa técnica:
  a) Garantir o acolhimento e o acompanhamento das vítimas e dos/as filhos/as acolhidos/as em conformidade com os seus direitos e deveres;
  b) Proceder à avaliação e gestão do grau de risco e das necessidades sociais da vítima, aquando do seu acolhimento;
  c) Elaborar o plano individual de intervenção;
  d) Avaliar periodicamente o plano individual de intervenção, procedendo aos ajustamentos necessários;
  e) Emitir parecer sobre a necessidade de prorrogação do período de acolhimento;
  f) Articular com as demais estruturas de apoio que relevem para o processo de acompanhamento e autonomização da vítima.            
         
   
     
                         
                          
  Artigo 47.º 
Ajudantes de ação direta
                            
                           
                             
                               
                             
     Os/As ajudantes de ação direta asseguram, designadamente, as seguintes tarefas:
  a) Apoio aos cuidados de higiene, alimentação e vestuário das vítimas e dos/as filhos/as acolhidos/as;
  b) Apoio na preparação e confeção de alimentos;
  c) Apoio na organização e utilização da lavandaria;
  d) Vigilância durante o período noturno, nos termos da legislação em vigor.            
         
   
     
                         
                          
  Artigo 48.º 
Funcionamento
                            
                           
                             
                               
                             
     1 - As casas de abrigo funcionam durante todo o ano, todos os dias da semana, durante 24 horas.
  2 - O regulamento interno de funcionamento da casa de abrigo é afixado em local bem visível, obrigatoriamente dado a conhecer às vítimas aquando da sua admissão, devendo ser subscrito por estas o correspondente termo de aceitação, e disponibilizado para consulta sempre que solicitado pelas mesmas.
  3 - As alterações efetuadas ao regulamento interno são de comunicação obrigatória às vítimas acolhidas.            
         
   
     
                         
                          
  CAPÍTULO V
  Financiamento  Artigo 49.º 
Apoios no âmbito do subsistema de ação social
                            
                           
                             
                               
                             
     Ao apoio público, a prestar no âmbito do subsistema de ação social para o funcionamento das respostas a que se referem as alíneas a) e b) do artigo 2.º, é aplicad','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o o disposto na portaria que define os critérios, regras e formas em que assenta o modelo específico da cooperação estabelecida entre o Instituto da Segurança Social, I. P. (ISS, I. P.), e as instituições particulares de solidariedade social, ou legalmente equiparadas, para o desenvolvimento de respostas sociais.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Retificação n.º 11/2018, de 21 de Março
  Versões anteriores deste artigo:    - 1ª versão: Dec. Regulam. n.º 2/2018, de 24 de Janeiro   
     
                         
                          
  Artigo 50.º 
Apoio do Estado
                            
                           
                             
                               
                             
     Os critérios, regras e formas de apoio público prestado pelo Estado às respostas a que se refere o artigo 2.º, quando fora do âmbito do subsistema de ação social, são definidas por despacho do membro do Governo responsável pela área da cidadania e da igualdade.            
         
   
     
                         
                          
  CAPÍTULO VI
  Supervisão, fiscalização e avaliação  Artigo 51.º 
Supervisão técnica
                            
                           
                             
                               
                             
     1 - As respostas de acolhimento de emergência, estruturas de atendimento e casas de abrigo carecem da supervisão técnica do organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, em articulação com os serviços competentes da segurança social.
  2 - A supervisão técnica tem como objetivos:
  a) A verificação da conformidade dos procedimentos adotados com as orientações técnicas nacionais, comunitárias ou europeias sobre a prevenção da violência doméstica, proteção e assistência das suas vítimas e a sua articulação com as políticas públicas;
  b) A monitorização do trabalho das equipas quanto aos modelos de intervenção e práticas de atuação e à formação, informação e atualização das competências técnico-científicas das pessoas que as integram;
  c) A verificação da conformidade com os requisitos mínimos de intervenção no âmbito da violência doméstica e violência de género estabelecidos pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, tendo em vista a uniformização, formalização e melhoramento das práticas e procedimentos a desenvolver no âmbito da violência doméstica.            
         
   
     
                         
                          
  Artigo 52.º 
Fiscalização e controlo
                            
                           
                             
                               
                             
     1 - A constituição e fiscalização do funcionamento das respostas a que se refere o artigo 49.º, desenvolvidas no âmbito do subsistema de ação social, compete ao ISS, I. P., be','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('m como o apoio técnico e o acompanhamento das estruturas e respostas objeto de acordo de cooperação, podendo, sempre que o considerem necessário, solicitar a colaboração do organismo da Administração Pública responsável pela área da cidadania e da igualdade de género.
  2 - A constituição e controlo do funcionamento das respostas a que se refere o artigo 50.º, desenvolvidas fora do âmbito do subsistema de ação social, compete ao organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, nos termos a definir por despacho do membro do Governo responsável pela área da cidadania e da igualdade.            
         
   
     
                         
                          
  Artigo 53.º 
Acompanhamento e avaliação
                            
                           
                             
                               
                             
     1 - O acompanhamento e a avaliação do funcionamento das respostas a que se refere o artigo 2.º é realizada:
  a) Pelo ISS, I. P., nos termos da legislação em vigor, quando desenvolvidas no âmbito do subsistema de ação social, a que se refere o artigo 49.º;
  b) Pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, nos termos a definir por despacho do membro do Governo responsável pela área da cidadania e da igualdade, quando desenvolvidas fora do âmbito do subsistema de ação social, a que se refere o artigo 50.º
  2 - As entidades promotoras devem proceder à realização de inquéritos de satisfação ao atendimento, acolhimento e acompanhamento prestado às vítimas, a disponibilizar ao organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, sempre que solicitado, para efeitos de revisão, em termos sistemáticos, do seu desempenho, por forma a identificar oportunidades de melhoria e a ligação entre o trabalho realizado e os resultados que se atingem.            
         
   
     
                         
                          
  CAPÍTULO VII
  Disposições finais e transitórias  Artigo 54.º 
Período de adaptação
                            
                           
                             
                               
                             
     As respostas de acolhimento de emergência, estruturas de atendimento e casas de abrigo que se encontrem em funcionamento à data da entrada em vigor do presente decreto regulamentar devem adaptar-se às condições previstas no presente decreto regulamentar no prazo de 12 meses contados a partir da data da sua entrada em vigor, podendo ser definidos períodos de adaptação distintos ou situações de exceção através de portaria dos membros do Governo responsáveis pelas áreas da cidadania e da igualdade e da segurança social.            
         
   
     
                         
                          
  Artigo 55.º 
Modelo de regulamento interno
                            
                           
    ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                         
                               
                             
     O modelo de regulamento interno das respostas a que se refere o artigo 2.º é definido nos termos a regulamentar por portaria dos membros do Governo responsáveis pelas áreas da cidadania e da igualdade de género e da segurança social.            
         
   
     
                         
                          
  Artigo 56.º 
Norma revogatória
                            
                           
                             
                               
                             
     É revogado o  Decreto Regulamentar n.º 1/2006, de 25 de janeiro.            
         
   
     
                         
                          
  Artigo 57.º 
Entrada em vigor
                            
                           
                             
                               
                             
     O presente decreto regulamentar entra em vigor no dia seguinte ao da sua publicação.
  
  Visto e aprovado em Conselho de Ministros de 21 de setembro de 2017. - Maria Manuel de Lemos Leitão Marques - Ricardo Emanuel Martins Mourinho Félix - Maria Constança Dias Urbano de Sousa - Francisca Eugénia da Silva Dias Van Dunem - Eduardo Arménio do Nascimento Cabrita - Ana Sofia Pedroso Lopes Antunes.
  Promulgado em 15 de janeiro de 2018.
  Publique-se.
  O Presidente da República, Marcelo Rebelo de Sousa.
  Referendado em 22 de janeiro de 2018.
  O Primeiro-Ministro, António Luís Santos da Costa.','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:12  
    
  Lei n.º 33/98, de 18 de Julho  (versão actualizada) CONSELHOS MUNICIPAIS DE SEGURANÇA     
    
 
Contém as seguintes alterações:   - Lei n.º 106/2015, de 25 de Agosto   - DL n.º 32/2019, de 04 de Março  
                         
                          
SUMÁRIOConselhos municipais de segurança
Lei n.º 33/98 de 18 de julho
  Conselhos municipais de segurança
  A Assembleia da República decreta, nos termos dos artigos 161.º, alínea c), e 166.º, n.º 3, e do artigo 112.º, n.º 5, da Constituição, para valer como lei geral da República, o seguinte: 
  
  Artigo 1.º 
Criação dos conselhos municipais de segurança
                            
                           
                             
                               
                             
     São criados, pela presente lei, os conselhos municipais de segurança.            
         
   
     
                         
                          
  Artigo 2.º 
Funções
                            
                           
                             
                               
                             
     O conselho municipal de segurança, adiante designado por conselho, é uma entidade de âmbito municipal com funções de natureza consultiva, de articulação, coordenação, informação e cooperação, cujos objetivos, composição e funcionamento são regulados pela presente lei.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 32/2019, de 04 de Março
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 106/2015, de 25 de Agosto   
     
                         
                          
  Artigo 3.º 
Objetivos
                            
                           
                             
                               
                             
     Constituem objetivos do conselho:
  a) Contribuir para o aprofundamento do conhecimento da situação de segurança na área do município, através da consulta entre todas as entidades que o constituem;
  b) Formular propostas de solução para os problemas de marginalidade e segurança dos cidadãos no respetivo município e participar em ações de prevenção;
  c) Promover a discussão sobre medidas de combate à criminalidade e à exclusão social do município;
  d) Aprovar pareceres e solicitações a remeter a todas as entidades que julgue oportunos e diretamente relacionados com as questões de segurança e inserção social;
  e) Proceder à avaliação dos dados relativos ao crime de violência doméstica, e tendo em conta os diversos instrumentos nacionais para o seu combate, designadamente os Planos Nacionais de Prevenção e Combate à Violência Doméstica e de Género, e apresentar propostas de ações que contribuam para a prevenção e diminuição deste crime;
  f) Avaliar os números da sinistralidade rodoviária e, tendo em conta a estratégia nacional de segurança rodoviária, formular propostas para a realização de ações que possam contribuir para a redução dos nú','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('meros de acidentes rodoviários no município;
  g) Promover a participação ativa dos cidadãos e das instituições locais na resolução dos problemas de segurança pública.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 106/2015, de 25 de Agosto   - DL n.º 32/2019, de 04 de Março
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 33/98, de 18 de Julho    - 2ª versão: Lei n.º 106/2015, de 25 de Agosto   
     
                         
                          
  Artigo 3.º-A 
Modalidades de funcionamento do conselho municipal de segurança
                            
                           
                             
                               
                             
     O conselho municipal de segurança funciona em modalidade alargada e restrita, doravante designado, respetivamente, de conselho e de conselho restrito.
  
  Aditado pelo seguinte diploma: Decreto-Lei n.º 32/2019, de 04 de Março            
         
   
     
                         
                          
  Artigo 3.º-B 
Composição do conselho
                            
                           
                             
                               
                             
     1 - Integram o conselho:
  a) O presidente da câmara municipal ou o vereador com competência delegada;
  b) O vereador responsável pelo acompanhamento das questões de segurança, ou outro vereador indicado pelo presidente da câmara, caso seja este o responsável por esta área;
  c) O presidente da assembleia municipal;
  d) Os presidentes das juntas de freguesia;
  e) Um representante do ministério público da comarca;
  f) Os comandantes das forças de segurança com competência na área territorial do município;
  g) O comandante da polícia municipal, quando este serviço de polícia exista;
  h) Os responsáveis pelos serviços municipais de proteção civil e pelas corporações de bombeiros;
  i) Representantes das entidades com atividade no setor de apoio social, cultural e desportivo, em número a definir no regulamento de cada conselho;
  j) Um representante dos estabelecimentos de ensino público e um representante dos estabelecimentos de ensino particular e cooperativo que operem no território do município, a designar nos termos do regulamento do conselho;
  k) Um representante dos setores económicos com maior representatividade, a designar nos termos do regulamento do conselho;
  l) Um representante das estruturas integrantes da rede nacional de apoio às vítimas de violência doméstica situadas no município;
  m) Um representante, da área do município, das organizações no âmbito da segurança rodoviária.
  2 - O conselho pode ainda convidar a participar nas suas reuniões entidades e personalidades cuja intervenção considere relevante em função de alguma matéria específica e cuja representatividade não esteja assegurada nos termos do número anterior.
  3 - O conselho é presidido pelo presidente da câmara municipal, ou pel','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o vereador com competência delegada.
  
  Aditado pelo seguinte diploma: Decreto-Lei n.º 32/2019, de 04 de Março            
         
   
     
                         
                          
  Artigo 4.º 
Competências do conselho
                            
                           
                             
                               
                             
     1 - Para a prossecução dos objetivos previstos no artigo 3.º, compete ao conselho emitir parecer sobre:
  a) A evolução dos níveis de criminalidade na área do município;
  b) O dispositivo legal de segurança e a capacidade operacional das forças de segurança no município;
  c) Os índices de segurança e o ordenamento social no âmbito do município;
  d) Os resultados da atividade municipal de proteção civil e de combate aos incêndios;
  e) As condições materiais e os meios humanos empregados nas atividades sociais de apoio aos tempos livres, particularmente dos jovens em idade escolar;
  f) A situação socioeconómica municipal;
  g) O acompanhamento e apoio das ações dirigidas, em particular, à prevenção e controlo da delinquência juvenil, à prevenção da toxicodependência e à análise da incidência social do tráfico de droga;
  h) O levantamento das situações sociais que, pela sua particular vulnerabilidade, se revelem de maior potencialidade criminógena e mais carecidas de apoio à inserção;
  i) Os dados relativos a violência doméstica;
  j) Os resultados da sinistralidade rodoviária municipal;
  k) As propostas de Plano Municipal de Segurança Rodoviária;
  l) Os Programas de Policiamento de Proximidade;
  m) Os Contratos Locais de Segurança.
  2 - Os pareceres referidos no número anterior têm a periodicidade que for definida em regulamento de cada conselho, a aprovar nos termos do artigo 6.º
  3 - Os pareceres referidos no n.º 1 são apreciados pela assembleia municipal sob proposta da câmara municipal, com conhecimento das forças de segurança com competência no município.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 106/2015, de 25 de Agosto   - DL n.º 32/2019, de 04 de Março
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 33/98, de 18 de Julho    - 2ª versão: Lei n.º 106/2015, de 25 de Agosto   
     
                         
                          
  Artigo 5.º 
Composição do conselho restrito
                            
                           
                             
                               
                             
     1 - Integram o conselho restrito:
  a) O presidente da câmara municipal;
  b) O vereador responsável pelo acompanhamento das questões de segurança, ou outro vereador indicado pelo presidente da câmara municipal, caso seja este o responsável por esta área;
  c) Os comandantes das forças de segurança com competência na área territorial do município;
  d) O comandante da polícia municipal, quando este serviço de polícia exista;
  e) (Revogada.)
  f) (Revogada.)','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('
  g) (Revogada.)
  h) (Revogada.)
  i) (Revogada.)
  j) (Revogada.)
  k) (Revogada.)
  l) (Revogada.)
  2 - O conselho restrito pode convidar a participar nas suas reuniões entidades e personalidades cuja intervenção considere relevante em função da matéria.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 106/2015, de 25 de Agosto   - DL n.º 32/2019, de 04 de Março
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 33/98, de 18 de Julho    - 2ª versão: Lei n.º 106/2015, de 25 de Agosto   
     
                         
                          
  Artigo 5.º-A 
Competências do conselho restrito
                            
                           
                             
                               
                             
     1 - É da competência do conselho restrito analisar e avaliar as situações de potencial impacto na segurança ou no sentimento de segurança das populações, nomeadamente as suscitadas no âmbito do conselho.
  2 - Compete ao conselho restrito participar na definição, a nível estratégico, do modelo de policiamento de proximidade a implementar no município.
  3 - Compete ainda ao conselho restrito pronunciar-se sobre:
  a) A rede de esquadras e postos territoriais das forças de segurança;
  b) A criação de programas específicos relacionados com a segurança de pessoas e bens, designadamente na área da prevenção da delinquência juvenil;
  c) Outras estratégias para a eliminação de fatores criminógenos.
  4 - O conselho restrito reúne sempre que convocado pelo presidente, e, no mínimo, com uma periodicidade bimestral.
  
  Aditado pelo seguinte diploma: Decreto-Lei n.º 32/2019, de 04 de Março            
         
   
     
                         
                          
  Artigo 6.º 
Regulamento
                            
                           
                             
                               
                             
     1 - O conselho, na sua primeira reunião, elabora uma proposta de regulamento a submeter à apreciação da assembleia municipal, sob proposta da câmara municipal.
  2 - Caso a assembleia municipal introduza alterações à proposta de regulamento, elabora nova proposta que remete ao conselho, para emissão de parecer no prazo de 30 dias.
  3 - Na primeira sessão, após a receção do parecer do conselho, a assembleia municipal aprova o regulamento.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 32/2019, de 04 de Março
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 106/2015, de 25 de Agosto   
     
                         
                          
  Artigo 7.º 
Reuniões
                            
                           
                             
                               
                             
     1 - O conselho reúne sempre que convocado pelo presidente e, no mínimo, com periodicidade trimestral.
  2 - Em todas as reuniões do consel','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ho há um período aberto ao público para exposição, pelos munícipes, de questões relacionadas com as matérias de segurança no município.
  3 - Da reunião do conselho é elaborada ata, a qual é transmitida por via eletrónica aos membros do governo responsáveis pelas áreas da administração interna e da justiça.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 32/2019, de 04 de Março
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 106/2015, de 25 de Agosto   
     
                         
                          
  Artigo 8.º 
Instalação
                            
                           
                             
                               
                             
     1 - Compete ao presidente da câmara municipal assegurar a instalação do conselho.
  2 - Compete à câmara municipal dar o apoio logístico necessário ao funcionamento do conselho.            
         
   
     
                         
                          
  Artigo 9.º 
Posse
                            
                           
                             
                               
                             
     Os membros de cada conselho tomam posse perante a câmara municipal.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 32/2019, de 04 de Março
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 106/2015, de 25 de Agosto','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:12  
    
  Lei n.º 107/2015, de 25 de Agosto  (versão actualizada) CONSOLIDAÇÃO DA LEGISLAÇÃO EM MATÉRIA DE DIREITOS DAS ASSOCIAÇÕES DE MULHERES    
    
 
  
                         
                          
SUMÁRIOConsolidação da legislação em matéria de direitos das associações de mulheres (revoga as Leis n.os 95/88, de 17 de agosto, 33/91, de 27 de julho, e 10/97, de 12 de maio)
Lei n.º 107/2015, de 25 de agosto
  Consolidação da legislação em matéria de direitos das associações de mulheres (revoga as Leis n.os 95/88, de 17 de agosto, 33/91, de 27 de julho, e 10/97, de 12 de maio)
  Exposição de Motivos
  Tendo como objetivo facilitar o acesso ao direito aos cidadãos e aos operadores jurídicos, a presente lei procede à consolidação dos seguintes diplomas:
  a)  Lei n.º 95/88, de 17 de agosto - Garantia dos direitos das associações de mulheres;
  b)  Lei n.º 33/91, de 27 de julho - Revogação do artigo 10.º da Lei n.º 95/88, de 17 de agosto;
  c)  Lei n.º 10/97, de 12 de maio - Reforça os direitos das associações de mulheres;
  d)  Lei n.º 128/99, de 20 de agosto - Primeira alteração à Lei n.º 10/97, de 12 de maio e segunda alteração à Lei n.º 108/91, de 17 de agosto (Conselho Económico e Social), com a redação dada pela Lei n.º 80/98, de 24 de novembro.
  Assim, criou-se um texto único sobre esta matéria, que respeita as regras e princípios consagrados nas leis vigentes, e que agrega os dois diplomas sobre os direitos das associações das mulheres, e as respetivas alterações.
  Ao proceder a esta consolidação não se introduzem alterações de substância, atualizando-se apenas alguma terminologia utilizada e a designação de instituições mencionadas.
  A aprovação da lei consolidante implica a revogação expressa das leis anteriormente mencionadas, com exceção da Lei n.º 128/99, de 20 de agosto, que é apenas parcialmente revogada, dado que procede a alterações à Lei do Conselho Económico e Social.
  A aprovação desta lei não prejudica nem altera as posições inicialmente tomadas pelos respetivos partidos políticos aquando da aprovação das leis agora consolidadas.
  A Assembleia da República decreta, nos termos da alínea c) do artigo 161.º da Constituição, o seguinte:
  
  Artigo 1.º 
Objeto
                            
                           
                             
                               
                             
     A presente lei visa a consolidação dos direitos das associações de mulheres com o objetivo de eliminar todas as formas de discriminação e assegurar o direito à igualdade de género.            
         
   
     
                         
                          
  Artigo 2.º 
Associação de mulheres
                            
                           
                             
                               
                             
     1 - Para efeitos da presente lei são consideradas como associações de mulheres as que, sendo constituídas nos termos da lei geral e dotadas de pe','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rsonalidade jurídica, prossigam o objetivo referido no artigo anterior e não tenham fins lucrativos.
  2 - As associações de mulheres podem ser de âmbito nacional, regional ou local, conforme circunscrevam a sua atuação a todo o território nacional, a uma região autónoma, distrito ou região administrativa ou a um município e de acordo com o número mínimo de associados, que será, respetivamente, de 1000, 500 e 100.            
         
   
     
                         
                          
  Artigo 3.º 
Representatividade
                            
                           
                             
                               
                             
     As associações de mulheres de âmbito nacional gozam de representatividade genérica.            
         
   
     
                         
                          
  Artigo 4.º 
Direitos de participação e intervenção
                            
                           
                             
                               
                             
     1 - As associações de mulheres com representatividade genérica têm o direito de participar na definição das políticas das grandes linhas de orientação legislativa de promoção dos direitos das mulheres.
  2 - As associações referidas no n.º 1 do artigo 2.º gozam do direito de representação no conselho consultivo da Comissão para a Cidadania e a Igualdade de Género (CIG) e demais organismos consultivos que funcionam junto de entidades públicas que tenham competência na definição das políticas mencionadas no n.º 1 deste artigo.
  3 - Sem prejuízo de outras competências previstas na lei, as associações de mulheres com representatividade genérica, bem como as associações de mulheres representadas no conselho consultivo da Comissão para a Cidadania e a Igualdade de Género (CIG) coletivamente consideradas, gozam do estatuto de parceiro social, com direito, nomeadamente, a representação no Conselho Económico e Social.
  4 - As associações de mulheres de âmbito regional e local têm o direito de ser ouvidas na elaboração dos respetivos planos de desenvolvimento.            
         
   
     
                         
                          
  Artigo 5.º 
Direito de antena
                            
                           
                             
                               
                             
     1 - As associações de mulheres com representatividade genérica, bem como as associações de mulheres representadas no conselho consultivo da Comissão para a Cidadania e a Igualdade de Género que não tenham representatividade genérica e coletivamente consideradas, têm direito a tempo de antena na rádio e na televisão nos mesmos termos das associações profissionais.
  2 - Na proporção de tempo destinado nos termos do número anterior, não pode ser atribuído às associações com representatividade genérica tempo inferior a metade do tempo de antena estabelecido na lei da rádio e da televisão pa','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ra as associações profissionais.            
         
   
     
                         
                          
  Artigo 6.º 
Direito de informação
                            
                           
                             
                               
                             
     As associações de mulheres têm o direito de solicitar as informações que lhes permitam acompanhar o modo de aplicação da legislação referente aos direitos das mulheres, nomeadamente nos seguintes casos:
  a) Situações de discriminação no acesso à formação ou ao trabalho ou nas condições em que o mesmo se exerce;
  b) Aplicação de legislação sobre maternidade e paternidade;
  c) Divulgação nos meios de comunicação social e em especial na publicidade de uma imagem estereotipada da mulher que veicule uma situação de inferioridade desta face ao homem ou a sua afetação exclusiva a tarefas domésticas;
  d) Práticas de violências exercidas sobre mulheres.            
         
   
     
                         
                          
  Artigo 7.º 
Direito de prevenção e controle
                            
                           
                             
                               
                             
     As associações de mulheres têm legitimidade para:
  a) Propor as iniciativas necessárias à prevenção ou cessação de atos ou omissões de entidades públicas que violem os direitos das mulheres, designadamente através do direito de queixa ao Provedor de Justiça;
  b) Exercer o direito de ação popular em defesa dos direitos das mulheres, nos termos do artigo 52.º da Constituição.            
         
   
     
                         
                          
  Artigo 8.º 
Apoio às associações de mulheres
                            
                           
                             
                               
                             
     1 - As associações de mulheres têm direito ao apoio da administração central, regional e local para a prossecução dos seus fins, em termos a regulamentar.
  2 - O Estado, especialmente através da Comissão para a Cidadania e a Igualdade de Género, as autarquias locais e as associações de mulheres podem colaborar entre si na promoção e realização de ações que levem as mulheres a tomar consciência das condições de discriminação a que estão sujeitas e a assumir uma intervenção direta para a sua erradicação.            
         
   
     
                         
                          
  Artigo 9.º 
Formação da juventude
                            
                           
                             
                               
                             
     Os programas escolares devem ser orientados no sentido de sensibilizar e formar a juventude no respeito pelos princípios da igualdade e não discriminação da mulher, promovendo uma mudança de mentalidade no tocante ao papel e estatuto das mulheres na vida familiar e social.            
         
   
 ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('    
                         
                          
  Artigo 10.º 
Registo
                            
                           
                             
                               
                             
     1 - A Comissão para a Cidadania e a Igualdade de Género organiza um registo das associações de mulheres que beneficiam dos direitos reconhecidos pela presente lei.
  2 - Para efeitos do número anterior, as associações de mulheres remetem oficiosamente à Comissão para a Cidadania e a Igualdade de Género uma cópia dos atos de constituição e dos respetivos estatutos.            
         
   
     
                         
                          
  Artigo 11.º 
Norma remissiva
                            
                           
                             
                               
                             
     Às associações de mulheres são aplicáveis as regras do mecenato, nos termos da lei.            
         
   
     
                         
                          
  Artigo 12.º 
Revogação
                            
                           
                             
                               
                             
     1 - São revogados:
  a) A  Lei n.º 95/88, de 17 de agosto, na redação que lhe foi dada pela Lei n.º 33/91, de 27 de julho;
  b) A  Lei n.º 33/91, de 27 de julho;
  c) A  Lei n.º 10/97, de 12 de maio, na redação que lhe foi dada pela Lei n.º 128/99, de 20 de agosto;
  d) Os artigos 1.º e 3.º da  Lei n.º 128/99, de 20 de agosto
  2 - Mantém-se em vigor a regulamentação aprovada nos termos das leis referidas no número anterior.
  
  provada em 22 de julho de 2015.
  A Presidente da Assembleia da República, Maria da Assunção A. Esteves.
  Promulgada em 13 de agosto de 2015.
  Publique-se.
  O Presidente da República, Aníbal Cavaco Silva.
  Referendada em 17 de agosto de 2015.
  Pelo Primeiro-Ministro, Paulo Sacadura Cabral Portas, Vice-Primeiro-Ministro.','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:30  
    
  Lei n.º 23/80, de 26 de Julho  (versão actualizada) CONVENÇÃO CEDAW - ELIMINAÇÃO DE TODAS AS FORMAS DE DISCRIMINAÇÃO CONTRA AS MULHERES    
    
 
  
                         
                          
SUMÁRIORatifica a Convenção sobre a Eliminação de Todas as Formas de Discriminação contra as Mulheres 
SUMÁRIO : Ratifica a Convenção sobre a Eliminação de Todas as Formas de Discriminação contra as Mulheres 
  
  Lei n.º 23/80, de 26 de Julho
  Ratifica a Convenção sobre a Eliminação de Todas as Formas de Discriminação contra as Mulheres 
  A Assembleia da República decreta, nos termos da alínea j) do artigo 164.º e do n.º 2 do artigo 169.º da Constituição, o seguinte: 
  
  ARTIGO ÚNICO
  É aprovada a Convenção sobre a Eliminação de Todas as Formas de Discriminação contra as Mulheres, cujo texto em inglês e respectiva tradução para português vão anexos ao presente diploma. 
  Aprovada em 27 de Junho de 1980.
  O Vice-Presidente da Assembleia da República em exercício, Nuno Aires Rodrigues dos Santos. 
  Promulgado em 14 de Julho de 1980.
  Publique-se.
  O Presidente da República, ANTÓNIO RAMALHO EANES. - O Primeiro-Ministro, Francisco Sá Carneiro. 
  
  ANEXO
  
  Convenção sobre a Eliminação de Todas as Formas de Discriminação contra as Mulheres 
  Os Estados Partes na presente Convenção,
  Considerando que a Carta das Nações Unidas reafirma a fé nos direitos fundamentais do homem, na dignidade e no valor da pessoa humana e na igualdade de direitos dos homens e das mulheres; 
  Considerando que a Declaração Universal dos Direitos do Homem afirma o princípio da não discriminação e proclama que todos os seres humanos nascem livres e iguais em dignidade e em direitos e que cada pessoa pode prevalecer-se de todos os direitos e de todas as liberdades aí enunciados, sem distinção alguma, nomeadamente de sexo; 
  Considerando que os Estados Partes nos pactos internacionais sobre direitos do homem têm a obrigação de assegurar a igualdade de direitos dos homens e das mulheres no exercício de todos os direitos económicos, sociais, culturais, civis e políticos; 
  Considerando as convenções internacionais concluídas sob a égide da Organização das Nações Unidas e das instituições especializadas com vista a promover a igualdade de direitos dos homens e das mulheres; 
  Considerando igualmente as resoluções, declarações e recomendações adoptadas pela Organização das Nações Unidas e pelas instituições especializadas com vista a promover a igualdade de direitos dos homens e das mulheres; 
  Preocupados, no entanto, por constatarem que, apesar destes diversos instrumentos, as mulheres continuam a ser objecto de importantes discriminações; 
  Lembrando que a discriminação contra as mulheres viola os princípios da igualdade de direitos e do respeito da dignidade humana, que dificulta a participação das mulheres, nas mesmas condições que os homens, na vida política, social, económica e cultural do seu país, que cria obstáculos ao crescim','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ento do bem-estar da sociedade e da família e que impede as mulheres de servirem o seu país e a Humanidade em toda a medida das suas possibilidades; 
  Preocupados pelo facto de que em situações de pobreza as mulheres têm um acesso mínimo à alimentação, aos serviços médicos, à educação, à formação e às possibilidades de emprego e à satisfação de outras necessidades; 
  Convencidos de que a instauração da nova ordem económica internacional baseada na equidade e na justiça contribuirá de forma significativa para promover a igualdade entre os homens e as mulheres; 
  Sublinhando que a eliminação do apartheid, de todas as formas de racismo, de discriminação racial, de colonialismo, de neocolonialismo, de agressão, de ocupação e dominação estrangeiras e de ingerência nos assuntos internos dos Estados é indispensável ao pleno gozo dos seus direitos pelos homens e pelas mulheres; 
  Afirmando que o reforço da paz e da segurança internacionais, o abrandamento da tensão internacional, a cooperação entre todos os Estados, sejam quais forem os seus sistemas sociais e económicos, o desarmamento geral e completo, em particular o desarmamento nuclear sob contrôle internacional estrito e eficaz, a afirmação dos princípios da justiça, da igualdade e da vantagem mútua nas relações entre países e a realização do direito dos povos sujeitos a dominação estrangeira e colonial e a ocupação estrangeira à autodeterminação e à independência, assim como o respeito da soberania nacional e da integridade territorial, favorecerão o progresso social e o desenvolvimento e contribuirão en consequência para a realização da plena igualdade entre os homens e as mulheres; 
  Convencidos de que o desenvolvimento pleno de um país, o bem-estar do mundo e a causa da paz necessitam da máxima participação das mulheres, em igualdade com os homens, em todos os domínios; 
  Tomando em consideração a importância da contribuição das mulheres para o bem-estar da família e o progresso da sociedade, que até agora não foi plenamente reconhecida, a importância social da maternidade e do papel de ambos os pais na família e na educação das crianças, e conscientes de que o papel das mulheres na procriação não deve ser uma causa de discriminação, mas de que a educação das crianças exige a partilha das responsabilidades entre os homens, as mulheres e a sociedade no seu conjunto; 
  Conscientes de que é necessária uma mudança no papel tradicional dos homens, tal como no papel das mulheres na família e na sociedade, se se quer alcançar uma real igualdade dos homens e das mulheres; 
  Resolvidos a pôr em prática os princípios enunciados na Declaração sobre a Eliminação da Discriminação contra as Mulheres e, com tal objectivo, a adoptar as medidas necessárias à supressão desta discriminação sob todas as suas formas e em todas as suas manifestações: 
  Acordam no seguinte:PARTE I  ARTIGO 1.º
                            
                           
                             
                              ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' 
                             
     Para os fins da presente Convenção, a expressão discriminação contra as mulheres significa qualquer distinção, exclusão ou restrição baseada no sexo que tenha como efeito ou como objectivo comprometer ou destruir o reconhecimento, o gozo ou o exercício pelas mulheres, seja qual for o seu estado civil, com base na igualdade dos homens e das mulheres, dos direitos do homem e das liberdades fundamentais nos domínios político, económico, social, cultural e civil ou em qualquer outro domínio.            
         
   
     
                         
                          
  ARTIGO 2.º
                            
                           
                             
                               
                             
     Os Estados Partes condenam a discriminação contra as mulheres sob todas as suas formas, acordam em prosseguir, por todos os meios apropriados e sem demora, uma política tendente a eliminar a discriminação contra as mulheres e, com este fim, comprometem-se a: 
  a) Inscrever na sua constituição nacional ou em qualquer outra lei apropriada o princípio da igualdade dos homens e das mulheres, se o mesmo não tiver já sido feito, e assegurar por via legislativa ou por outros meios apropriados a aplicação efectiva do mesmo princípio; 
  b) Adoptar medidas legislativas e outras medidas apropriadas, incluindo a determinação de sanções em caso de necessidade, proibindo toda a discriminação contra as mulheres; 
  c) Instaurar uma protecção jurisdicional dos direitos das mulheres em pé de igualdade com os homens e garantir, por intermédio dos tribunais nacionais competentes e outras instituições públicas, a protecção efectiva das mulheres contra qualquer acto discriminatório; 
  d) Abster-se de qualquer acto ou prática discriminatórios contra as mulheres e actuar por forma que as autoridades e instituições públicas se conformem com esta obrigação; 
  e) Tomar todas as medidas apropriadas para eliminar a discriminação praticada contra as mulheres por uma pessoa, uma organização ou uma empresa qualquer; 
  f) Tomar todas as medidas apropriadas, incluindo disposições legislativas, para modificar ou revogar qualquer lei, disposição regulamentar, costume ou prática que constitua discriminação contra as mulheres; 
  g) Revogar todas as disposições penais que constituam discriminação contra as mulheres.            
         
   
     
                         
                          
  ARTIGO 3.º
                            
                           
                             
                               
                             
     Os Estados Partes tomam em todos os domínios, nomeadamente nos domínios político, social, económico e cultural, todas as medidas apropriadas, incluindo disposições legislativas, para assegurar o pleno desenvolvimento e o progresso das mulheres, com vista a garantir-lhes o exercício e o gozo dos direitos do homem e das liberdades fundamentais, com base ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('na igualdade com os homens.            
         
   
     
                         
                          
  ARTIGO 4.º
                            
                           
                             
                               
                             
     1 - A adopção pelos Estados Partes de medidas temporárias especiais visando acelerar a instauração de uma igualdade de facto entre os homens e as mulheres não é considerada como um acto de discriminação, tal como definido na presente Convenção, mas não deve por nenhuma forma ter como consequência a manutenção de normas desiguais ou distintas; estas medidas devem ser postas de parte quando os objectivos em matéria de igualdade de oportunidades e de tratamento tiverem sido atingidos. 
  2 - A adopção pelos Estados Partes de medidas especiais, incluindo as medidas previstas na presente Convenção que visem proteger a maternidade, não é considerada como um acto discriminatório.            
         
   
     
                         
                          
  ARTIGO 5.º
                            
                           
                             
                               
                             
     Os Estados Partes tomam todas as medidas apropriadas para:
  a) Modificar os esquemas e modelos de comportamento sócio-cultural dos homens e das mulheres com vista a alcançar a eliminação dos preconceitos e das práticas costumeiras, ou de qualquer outro tipo, que se fundem na ideia de inferioridade ou de superioridade de um ou de outro sexo ou de um papel estereotipado dos homens e das mulheres; 
  b) Assegurar que a educação familiar contribua para um entendimento correcto da maternidade como função social e para o reconhecimento da responsabilidade comum dos homens e das mulheres na educação e desenvolvimento dos filhos, devendo entender-se que o interesse das crianças é consideração primordial em todos os casos.            
         
   
     
                         
                          
  ARTIGO 6.º
                            
                           
                             
                               
                             
     Os Estados Partes tomam todas as medidas apropriadas, incluindo disposições legislativas, para suprimir todas as formas de tráfico das mulheres e de exploração da prostituição das mulheres.            
         
   
     
                         
                          
PARTE II  ARTIGO 7.º
                            
                           
                             
                               
                             
     Os Estados Partes tomam todas as medidas apropriadas para eliminar a discriminação contra as mulheres na vida política e pública do país e, em particular, asseguram-lhes, em condições de igualdade com os homens, o direito: 
  a) De votar em todas as eleições e em todos os referendos públicos e de ser elegíveis para todos os organismos publicamente eleitos; ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('
  b) De tomar parte na formulação da política do Estado e na sua execução, de ocupar empregos públicos e de exercer todos os cargos públicos a todos os níveis do governo; 
  c) De participar nas organizações e associações não governamentais que se ocupem da vida pública e política do país.            
         
   
     
                         
                          
  ARTIGO 8.º
                            
                           
                             
                               
                             
     Os Estados Partes tomam todas as medidas apropriadas para que as mulheres, em condições de igualdade com os homens e sem nenhuma discriminação, tenham a possibilidade de representar os seus governos à escala internacional e de participar nos trabalhos das organizações internacionais.            
         
   
     
                         
                          
  ARTIGO 9.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes concedem às mulheres direitos iguais aos dos homens no que respeita à aquisição, mudança e conservação da nacionalidade. Garantem, em particular, que nem o casamento com um estrangeiro nem a mudança de nacionalidade do marido na constância do casamento produzem automaticamente a mudança de nacionalidade da mulher, a tornam apátrida ou a obrigam a adquirir a nacionalidade do marido. 
  2 - Os Estados Partes concedem às mulheres direitos iguais aos dos homens no que respeita à nacionalidade dos filhos.            
         
   
     
                         
                          
PARTE III  ARTIGO 10.º
                            
                           
                             
                               
                             
     Os Estados Partes tomam todas as medidas apropriadas para eliminar a discriminação contra as mulheres com o fim de lhes assegurar direitos iguais aos dos homens no domínio da educação e, em particular, para assegurar, com base na igualdade dos homens e das mulheres: 
  a) As mesmas condições de orientação profissional, de acesso aos estudos e de obtenção de diplomas nos estabelecimentos de ensino de todas as categorias, nas zonas rurais como nas zonas urbanas, devendo esta igualdade ser assegurada no ensino pré-escolar, geral, técnico, profissional e técnico superior, assim como em qualquer outro meio de formação profissional; 
  b) O acesso aos mesmos programas, aos mesmos exames, a um pessoal de ensino possuindo qualificações do mesmo nível, a locais escolares e a equipamento da mesma qualidade; 
  c) A eliminação de qualquer concepção estereotipada dos papéis dos homens e das mulheres a todos os níveis e em todas as formas de ensino, encorajando a coeducação e outros tipos de educação que ajudarão a realizar este objectivo, em particular revendo os livros e programas escolares e adaptando os métodos pedagógic','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('os; 
  d) As mesmas possibilidades no que respeita à concessão de bolsas e outros subsídios para os estudos; 
  e) As mesmas possibilidades de acesso aos programas de educação permanente, incluindo os programas de alfabetização para adultos e de alfabetização funcional, com vista, nomeadamente, a reduzir o mais cedo possível qualquer desnível de instrução que exista entre os homens e as mulheres; 
  f) A redução das taxas de abandono feminino dos estudos e a organização de programas para as raparigas e as mulheres que abandonarem prematuramente a escola; 
  g) As mesmas possibilidades de participar activamente nos desportos e na educação física; 
  h) O acesso a informações específicas de carácter educativo tendentes a assegurar a saúde e o bem-estar das famílias, incluindo a informação e o aconselhamento relativos ao planeamento da família.            
         
   
     
                         
                          
  ARTIGO 11.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes comprometem-se a tomar todas as medidas apropriadas para eliminar a discriminação contra as mulheres no domínio do emprego com o fim de assegurar, com base na igualdade dos homens e das mulheres, os mesmos direitos, em particular: 
  a) O direito ao trabalho, enquanto direito inalienável de todos os seres humanos; 
  b) O direito às mesmas possibilidades de emprego, incluindo a aplicação dos mesmos critérios de selecção em matéria de emprego; 
  c) O direito à livre escolha da profissão e do emprego, o direito à promoção, à estabilidade do emprego e a todas as prestações e condições de trabalho e o direito à formação profissional e à reciclagem, incluindo a aprendizagem, o aperfeiçoamento profissional e a formação permanente; 
  d) O direito à igualdade de remuneração, incluindo prestações, e à igualdade de tratamento para um trabalho de igual valor, assim como à igualdade de tratamento no que respeita à avaliação da qualidade do trabalho; 
  e) O direito à segurança social, nomeadamente às prestações de reforma, desemprego, doença, invalidez e velhice ou relativas a qualquer outra perda de capacidade de trabalho, assim como o direito a férias pagas; 
  f) O direito à protecção da saúde e à segurança nas condições de trabalho, incluindo a salvaguarda da função de reprodução. 
  2 - Com o fim de evitar a discriminação contra as mulheres por causa do casamento ou da maternidade e de garantir o seu direito efectivo ao trabalho, os Estados Partes comprometem-se a tomar medidas apropriadas para: 
  a) Proibir, sob pena de sanções, o despedimento por causa da gravidez ou de gozo do direito a um período de dispensa do trabalho por ocasião da maternidade, bem como a discriminação nos despedimentos fundada no estado matrimonial; 
  b) Instituir a concessão do direito a um período de dispensa do trabalho por ocasião da maternidade pago ou conferindo','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' direito a prestações sociais comparáveis, com a garantia da manutenção do emprego anterior, dos direitos de antiguidade e das vantagens sociais; 
  c) Encorajar o fornecimento dos serviços sociais de apoio necessários para permitir aos pais conciliar as obrigações familiares com as responsabilidades profissionais e a participação na vida pública, em particular favorecendo a criação e o desenvolvimento de uma rede de estabelecimentos de guarda de crianças; 
  d) Assegurar uma protecção especial às mulheres grávidas cujo trabalho é comprovadamente nocivo. 
  3 - A legislação que visa proteger as mulheres nos domínios abrangidos pelo presente artigo será revista periodicamente em função dos conhecimentos científicos e técnicos e será modificada, revogada ou alargada segundo as necessidades.            
         
   
     
                         
                          
  ARTIGO 12.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes tomam todas as medidas apropriadas para eliminar a discriminação contra as mulheres no domínio dos cuidados de saúde, com vista a assegurar-lhes, com base na igualdade dos homens e das mulheres, o acesso aos serviços médicos, incluindo os relativos ao planeamento da família. 
  2 - Não obstante as disposições do parágrafo 1 deste artigo, os Estados Partes fornecerão às mulheres durante a gravidez, durante o parto e depois do parto serviços apropriados e, se necessário, gratuitos, assim como uma nutrição adequada durante a gravidez e o aleitamento.            
         
   
     
                         
                          
  ARTIGO 13.º
                            
                           
                             
                               
                             
     Os Estados Partes comprometem-se a tomar todas as medidas apropriadas para eliminar a discriminação contra as mulheres em outros domínios da vida económica e social, com o fim de assegurar, com base na igualdade dos homens e das mulheres, os mesmos direitos, em particular: 
  a) O direito a prestações familiares;
  b) O direito a empréstimos bancários, empréstimos hipotecários e outras formas de crédito financeiro; 
  c) O direito de participar nas actividades recreativas, nos desportos e em todos os aspectos da vida cultural.            
         
   
     
                         
                          
  ARTIGO 14.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes têm em conta os problemas particulares das mulheres rurais e o papel importante que estas mulheres desempenham para a sobrevivência económica das suas famílias, nomeadamente pelo seu trabalho nos sectores não monetários da economia, e tomam todas as medidas apropriadas para assegurar a aplicação das disposiçõ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('es da presente Convenção às mulheres das zonas rurais. 
  2 - Os Estados Partes tomam todas as medidas apropriadas para eliminar a discriminação contra as mulheres nas zonas rurais, com o fim de assegurar, com base na igualdade dos homens e das mulheres, a sua participação no desenvolvimento rural e nas suas vantagens e, em particular, assegurando-lhes o direito: 
  a) De participar plenamente na elaboração e na execução dos planos do desenvolvimento a todos os níveis; 
  b) De ter acesso aos serviços adequados no domínio da saúde, incluindo a informação, aconselhamento e serviços em matéria de planeamento da família; 
  c) De beneficiar directamente dos programas de segurança social;
  d) De receber qualquer tipo de formação e de educação, escolares ou não, incluindo em matéria de alfabetização funcional, e de poder beneficiar de todos os serviços comunitários e de extensão, nomeadamente para melhorar a sua competência técnica; 
  e) De organizar grupos de entreajuda e cooperativas com o fim de permitir a igualdade de oportunidades no plano económico, quer se trate de trabalho assalariado ou de trabalho independente; 
  f) De participar em todas as actividades da comunidade;
  g) De ter acesso ao crédito e aos empréstimos agrícolas, assim como aos serviços de comercialização e às tecnologias apropriadas, e de receber um tratamento igual nas reformas fundiárias e agrárias e nos projectos de reordenamento rural; 
  h) De beneficiar de condições de vida convenientes, nomeadamente no que diz respeito a alojamento, saneamento, fornecimento de electricidade e de água, transportes e comunicações.            
         
   
     
                         
                          
PARTE IV  ARTIGO 15.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes reconhecem às mulheres a igualdade com os homens perante a lei. 
  2 - Os Estados Partes reconhecem às mulheres em matéria civil, capacidade jurídica idêntica à dos homens e as mesmas possibilidades de exercício dessa capacidade. Reconhecem-lhes, em particular direitos iguais no que respeita à celebração de contrato e à administração dos bens e concedem-lhes o mesmo tratamento em todos os estádios do processo judicial. 
  3 - Os Estados Partes acordam em que qualquer contrato e qualquer outro instrumento privado, seja de que tipo for, que vise limitar a capacidade jurídica da mulher deve ser considerado como nulo. 
  4 - Os Estados Partes reconhecem aos homens e às mulheres os mesmos direitos no que respeita à legislação relativa à livre circulação das pessoas e a liberdade de escolha de residência e domicílio.            
         
   
     
                         
                          
  ARTIGO 16.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes t','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('omam todas as medidas necessárias para eliminar a discriminação contra as mulheres em todas as questões relativas ao casamento e às relações familiares e, em particular, asseguram, com base na igualdade dos homens e das mulheres: 
  a) O mesmo direito de contrair casamento;
  b) O mesmo direito de escolher livremente o cônjuge e de só contrair casamento de livre e plena vontade; 
  c) Os mesmos direitos e as mesmas responsabilidades na constância do casamento e aquando da sua dissolução; 
  d) Os mesmos direitos e as mesmas responsabilidades enquanto pais, seja qual for o estado civil, para as questões relativas aos seus filhos; em todos os casos, o interesse das crianças será a consideração primordial; 
  e) Os mesmos direitos de decidir livremente e com todo o conhecimento de causa do número e do espaçamento dos nascimentos e de ter acesso à informação, à educação e aos meios necessários para permitir o exercício destes direitos; 
  f) Os mesmos direitos e responsabilidades em matéria de tutela, curatela, guarda e adopção das crianças, ou instituições similares, quando estes institutos existam na legislação nacional; em todos os casos, o interesse das crianças será a consideração primordial; 
  g) Os mesmos direitos pessoais ao marido e à mulher, incluindo o que respeita à escolha do nome de família, de uma profissão e de uma ocupação; 
  h) Os mesmos direitos a cada um dos cônjuges em matéria de propriedade, aquisição, gestão, administração, gozo e disposição dos bens, tanto a título gratuito como a título oneroso. 
  2 - A promessa de casamento e o casamento de crianças não terão efeitos jurídicos e todas as medidas necessárias, incluindo disposições legislativas, serão tomadas com o fim de fixar uma idade mínima para o casamento e de tornar obrigatório o registo do casamento num registo oficial.            
         
   
     
                         
                          
PARTE V  ARTIGO 17.º
                            
                           
                             
                               
                             
     1 - Com o fim de examinar os progressos realizados na aplicação da presente Convenção, é constituído um Comité para a Eliminação da Discriminação contra as Mulheres (em seguida denominado Comité), que se compõe, no momento da entrada em vigor da Convenção, de dezoito e, depois da sua ratificação ou da adesão do 35.º Estado Parte, de vinte e três peritos de uma alta autoridade moral e de grande competência no domínio abrangido pela presente Convenção. Os peritos são eleitos pelos Estados Partes de entre os seus nacionais e exercem as suas funções a título pessoal, devendo ter-se em conta o princípio de uma repartição geográfica equitativa e de representação das diferentes formas de civilização, assim como dos principais sistemas jurídicos. 
  2 - Os membros do Comité são eleitos por escrutínio secreto de entre uma lista de candidatos designados pelos Estados Partes. Cada Estado Parte pode designa','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('r um candidato escolhido de entre os seus nacionais. 
  3 - A primeira eleição tem lugar seis meses depois da data da entrada em vigor da presente Convenção. Pelo menos três meses antes da data de cada eleição, o Secretário-Geral da Organização das Nações Unidas dirige uma carta aos Estados Partes para os convidar a submeter as suas candidaturas num prazo de dois meses. O Secretário-Geral elabora uma lista alfabética de todos os candidatos, indicando por que Estado foram designados, lista que comunica aos Estados Partes. 
  4 - Os membros do Comité são eleitos no decurso de uma reunião dos Estados Partes convocada pelo Secretário-Geral para a sede da Organização das Nações Unidas. Nesta reunião, em que o quórum é constituído por dois terços dos Estados Partes, são eleitos membros do Comité os candidatos que tenham obtido o maior número de votos e a maioria absoluta dos votos dos representantes dos Estados Partes presentes e votantes. 
  5 - Os membros do Comité são eleitos para um período de quatro anos. No entanto, o mandato de nove dos membros eleitos na primeira eleição termina ao fim de dois anos; o presidente do Comité tira à sorte os nomes destes nove membros imediatamente depois da primeira eleição. 
  6 - A eleição dos cinco membros adicionais do Comité realiza-se nos termos das disposições dos parágrafos 2, 3 e 4 do presente artigo, a seguir à 35.ª ratificação ou adesão. O mandato de dois dos membros adicionais eleitos nesta ocasião termina ao fim de dois anos; o nome destes dois membros é tirado à sorte pelo presidente do Comité. 
  7 - Para suprir eventuais vagas, o Estado Parte cujo perito tenha cessado de exercer as suas funções de membro do Comité nomeia um outro perito de entre os seus nacionais, sob reserva da aprovação do Comité. 
  8 - Os membros do Comité recebem, com a aprovação da Assembleia Geral, emolumentos retirados dos fundos da Organização das Nações Unidas, nas condições fixadas pela Assembleia, tendo em conta a importância das funções do Comité. 
  9 - O Secretário-Geral da Organização das Nações Unidas põe à disposição do Comité o pessoal e os meios materiais que lhe são necessários para o desempenho eficaz das funções que lhe são confiadas pela presente Convenção.            
         
   
     
                         
                          
  ARTIGO 18.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes comprometem-se a apresentar ao Secretário-Geral da Organização das Nações Unidas, para exame pelo Comité, um relatório sobre as medidas de ordem legislativa, judiciária, administrativa ou outra que tenham adoptado para dar aplicação às disposições da presente Convenção e sobre os progressos realizados a este respeito: 
  a) No ano seguinte à entrada em vigor da Convenção para o Estado interessado;
  b) Em seguida, de quatro em quatro anos, e sempre que o Comité o pedir.
  2 - Os relatór','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ios podem indicar os factores e dificuldades que afectam a medida em que são cumpridas as obrigações previstas pela presente Convenção.            
         
   
     
                         
                          
  ARTIGO 19.º
                            
                           
                             
                               
                             
     1 - O Comité adopta o seu próprio regulamento interior.
  2 - O Comité elege o seu secretariado para um período de dois anos.            
         
   
     
                         
                          
  ARTIGO 20.º
                            
                           
                             
                               
                             
     1 - O Comité reúne normalmente durante um período de duas semanas no máximo em cada ano para examinar os relatórios apresentados nos termos do artigo 18.º da presente Convenção. 
  2 - As sessões do Comité têm lugar normalmente na sede da Organização das Nações Unidas ou em qualquer outro lugar adequado determinado pelo Comité.            
         
   
     
                         
                          
  ARTIGO 21.º
                            
                           
                             
                               
                             
     1 - O Comité presta contas todos os anos à Assembleia Geral da Organização das Nações Unidas, por intermédio do Conselho Económico e Social, das suas actividades e pode formular sugestões e recomendações gerais fundadas no exame dos relatórios e das informações recebidas dos Estados Partes. Estas sugestões e recomendações são incluídas no relatório do Comité, acompanhadas, sendo caso disso, das observações dos Estados Partes. 
  2 - O Secretário-Geral transmite os relatórios do Comité à Comissão do Estatuto das Mulheres para informação.            
         
   
     
                         
                          
  ARTIGO 22.º
                            
                           
                             
                               
                             
     As instituições especializadas têm o direito de estar representadas aquando do exame da aplicação de qualquer disposição da presente Convenção que entre no âmbito das suas actividades. O Comité pode convidar as instituições especializadas a submeter relatórios sobre a aplicação da Convenção nos domínios que entram no âmbito das suas actividades.            
         
   
     
                         
                          
PARTE VI  ARTIGO 23.º
                            
                           
                             
                               
                             
     Nenhuma das disposições da presente Convenção põe em causa as disposições mais propícias à realização da igualdade entre os homens e as mulheres que possam conter-se: 
  a) Na legislação de um Estado Parte;
  b) Em qualquer outra convenção, tra','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('tado ou acordo internacional em vigor nesse Estado.            
         
   
     
                         
                          
  ARTIGO 24.º
                            
                           
                             
                               
                             
     Os Estados Partes comprometem-se a adoptar todas as medidas necessárias ao nível nacional para assegurar o pleno exercício dos direitos reconhecidos pela presente Convenção.            
         
   
     
                         
                          
  ARTIGO 25.º
                            
                           
                             
                               
                             
     1 - A presente Convenção está aberta à assinatura de todos os Estados.
  2 - O Secretário-Geral da Organização das Nações Unidas é designado como depositário da presente Convenção. 
  3 - A presente Convenção está sujeita a ratificação e os instrumentos de ratificação são depositados junto do Secretário-Geral da Organização das Nações Unidas. 
  4 - A presente Convenção está aberta à adesão de todos os Estados. A adesão efectua-se pelo depósito de um instrumento de adesão junto do Secretário-Geral da Organização das Nações Unidas.            
         
   
     
                         
                          
  ARTIGO 26.º
                            
                           
                             
                               
                             
     1 - Qualquer Estado Parte pode pedir em qualquer momento a revisão da presente Convenção, dirigindo uma comunicação escrita para este efeito ao Secretário-Geral da Organização das Nações Unidas. 
  2 - A Assembleia Geral da Organização das Nações Unidas decide das medidas a tomar, sendo caso disso, em relação a um pedido desta natureza.            
         
   
     
                         
                          
  ARTIGO 27.º
                            
                           
                             
                               
                             
     1 - A presente Convenção entra em vigor no 30.º dia a seguir à data do depósito junto do Secretário-Geral da Organização das Nações Unidas do 20.º instrumento de ratificação ou de adesão. 
  2 - Para cada um dos Estados que ratifiquem a presente Convenção ou a ela adiram depois do depósito do 20.º instrumento de ratificação ou de adesão, a mesma Convenção entra em vigor no 30.º dia a seguir à data do depósito por esse Estado do seu instrumento de ratificação ou de adesão.            
         
   
     
                         
                          
  ARTIGO 28.º
                            
                           
                             
                               
                             
     1 - O Secretário-Geral da Organização das Nações Unidas recebe e comunica a todos os Estados o texto das reservas que forem feitas no momento da ratificação','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' ou da adesão. 
  2 - Não é autorizada nenhuma reserva incompatível com o objecto e o fim da presente Convenção. 
  3 - As reservas podem ser retiradas em qualquer momento por via de notificação dirigida ao Secretário-Geral da Organização das Nações Unidas, o qual informa todos os Estados Partes na Convenção. A notificação tem efeitos na data da recepção.            
         
   
     
                         
                          
  ARTIGO 29.º
                            
                           
                             
                               
                             
     1 - Qualquer diferendo entre dois ou mais Estados Partes relativamente à interpretação ou à aplicação da presente Convenção que não seja resolvido por via de negociação é submetido a arbitragem, a pedido de um de entre eles. Se nos seis meses a seguir à data do pedido de arbitragem as Partes não chegarem a acordo sobre a organização da arbitragem, qualquer delas pode submeter o diferendo ao Tribunal Internacional de Justiça, mediante um requerimento nos termos do Estatuto do Tribunal. 
  2 - Qualquer Estado Parte pode, no momento em que assinar a presente Convenção, a ratificar ou a ela aderir, declarar que não se considera vinculado pelas disposições do parágrafo 1 do presente artigo. Os outros Estados Partes não estão vinculados pelas mesmas disposições nas suas relações com um Estado Parte que tiver formulado uma tal reserva. 
  3 - Qualquer Estado Parte que tenha formulado uma reserva conformemente às disposições do parágrafo 2 do presente artigo pode em qualquer momento retirar essa reserva por uma notificação dirigida ao Secretário-Geral da Organização das Nações Unidas.            
         
   
     
                         
                          
  ARTIGO 30.º
                            
                           
                             
                               
                             
     A presente Convenção, cujos textos em inglês, árabe, chinês, espanhol, francês e russo fazem igualmente fé, é depositada junto do Secretário-Geral da Organização das Nações Unidas. 
  O Vice-Presidente da Assembleia da República, em exercício, Nuno Aires Rodrigues dos Santos.','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:82  
    
  Resol. da AR n.º 4/2013, de 21 de Janeiro  (versão actualizada) CONVENÇÃO DE ISTAMBUL    
    
 
  
                         
                          
SUMÁRIOAprova a Convenção do Conselho da Europa para a Prevenção e o Combate à Violência contra as Mulheres e a Violência Doméstica, adotada em Istambul, a 11 de maio de 2011 
Resolução da Assembleia da República n.º 4/2013 
  Aprova a Convenção do Conselho da Europa para a Prevenção e o Combate à Violência contra as Mulheres e a Violência Doméstica, adotada em Istambul, a 11 de maio de 2011. 
  A Assembleia da República resolve, nos termos da alínea i) do artigo 161.º e do n.º 5 do artigo 166.º da Constituição, aprovar a Convenção do Conselho da Europa para a Prevenção e o Combate à Violência contra as Mulheres e a Violência Doméstica, adotada em Istambul, a 11 de maio de 2011, cujo texto na versão autenticada nas línguas francesa e inglesa e respetiva tradução em língua portuguesa se publicam em anexo. 
  Aprovada em 14 de dezembro de 2012. 
  A Presidente da Assembleia da República, Maria da Assunção A. Esteves. 
  
  CONVENÇÃO DO CONSELHO DA EUROPA PARA A PREVENÇÃO E O COMBATE À VIOLÊNCIA CONTRA AS MULHERES E A VIOLÊNCIA DOMÉSTICA 
  Preâmbulo 
  Os Estados membros do Conselho da Europa e os outros signatários da presente Convenção: 
  Relembrando a Convenção para a Proteção dos Direitos do Homem e das Liberdades Fundamentais (STE n.º 5, 1950) e respetivos Protocolos, a Carta Social Europeia (STE n.º 35, 1961, revista em 1996, STE n.º 163), a Convenção do Conselho da Europa Relativa à Luta contra o Tráfico de Seres Humanos (STE n.º 197, 2005) e a Convenção do Conselho da Europa Relativa à Proteção das Crianças contra a Exploração Sexual e o Abuso Sexual (STE n.º 201, 2007); 
  Relembrando as seguintes recomendações do Comité de Ministros aos Estados membros do Conselho da Europa: Recomendação Rec(2002)5 sobre a proteção das mulheres contra a violência, a Recomendação CM/Rec(2007)17 sobre normas e mecanismos para a igualdade de género, a Recomendação CM/Rec(2010)10 sobre o papel das mulheres e dos homens na prevenção e resolução de conflitos e na construção da paz, e outras recomendações pertinentes; 
  Tendo em conta o volume crescente de jurisprudência do Tribunal Europeu dos Direitos do Homem que estabelece regras importantes no domínio da violência contra as mulheres; 
  Tendo em consideração o Pacto Internacional sobre os Direitos Civis e Políticos (1966), o Pacto Internacional sobre os Direitos Económicos, Sociais e Culturais (1966), a Convenção das Nações Unidas sobre a Eliminação de todas as Formas de Discriminação contra as Mulheres (CEDAW, 1979) e o seu Protocolo Opcional (1999), bem como a Recomendação Geral n.º 19 do Comité CEDAW sobre a violência contra as mulheres, a Convenção das Nações Unidas sobre os Direitos da Criança (1989) e respetivos Protocolos Facultativos (2000) e a Convenção das Nações Unidas sobre os Direitos das Pessoas com Deficiência (200','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('6); 
  Tendo em consideração o Estatuto de Roma do Tribunal Penal Internacional (2002); 
  Relembrando os princípios básicos de Direito Humanitário Internacional, e em particular a Convenção (IV) de Genebra Relativa à Proteção de Pessoas Civis em Tempo de Guerra (1949) e respetivos Protocolos Adicionais I e II (1977); 
  Condenando todas as formas de violência contra as mulheres e a violência doméstica; 
  Reconhecendo que a realização de jure e de facto da igualdade entre mulheres e homens é um elemento-chave na prevenção da violência contra as mulheres; 
  Reconhecendo que a violência contra as mulheres é uma manifestação das relações de poder historicamente desiguais entre mulheres e homens que conduziram à dominação e discriminação contra as mulheres pelos homens, o que as impediu de progredirem plenamente; 
  Reconhecendo que a natureza estrutural da violência exercida contra as mulheres é baseada no género, e que a violência contra as mulheres é um dos mecanismos sociais cruciais pelo qual as mulheres são forçadas a assumir uma posição de subordinação em relação aos homens; 
  Reconhecendo, com profunda preocupação, que mulheres e raparigas estão muitas vezes expostas a formas graves de violência, tais como a violência doméstica, o assédio sexual, a violação, o casamento forçado, os chamados crimes de honra e a mutilação genital, os quais constituem uma violação grave dos direitos humanos das mulheres e das raparigas e um obstáculo importante à realização da igualdade entre mulheres e homens; 
  Reconhecendo as constantes violações dos direitos humanos que ocorrem durante os conflitos armados e afetam a população civil, em especial as mulheres, sob a forma de violação e violência sexual generalizadas ou sistemáticas, bem como o potencial para o aumento da violência de género em situação de conflito e de pós-conflito; 
  Reconhecendo que as mulheres e as raparigas estão expostas a um maior risco de violência de género que os homens; 
  Reconhecendo que a violência doméstica afeta as mulheres de forma desproporcional e que os homens também podem ser vítimas de violência doméstica; 
  Reconhecendo que as crianças são vítimas de violência doméstica, designadamente como testemunhas de violência na família; 
  Aspirando a criar uma Europa livre de violência contra as mulheres e de violência doméstica; 
  acordam no seguinte:CAPÍTULO I 
  Finalidade, definições, igualdade e não discriminação, obrigações gerais  Artigo 1.º Finalidade da Convenção
                            
                           
                             
                               
                             
     1. A presente Convenção tem por finalidade: 
  a) Proteger as mulheres contra todas as formas de violência, bem como prevenir, instaurar o procedimento penal relativamente à violência contra as mulheres e à violência doméstica e eliminar estes dois tipos de violência; 
  b) Contribuir para a eliminação de todas as formas de discriminação contra as mulhere','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('s e promover a igualdade real entre mulheres e homens, incluindo o empoderamento das mulheres; 
  c) Conceber um quadro global, bem como políticas e medidas de proteção e assistência para todas as vítimas de violência contra as mulheres e de violência doméstica; 
  d) Promover a cooperação internacional, tendo em vista a eliminação da violência contra as mulheres e da violência doméstica; 
  e) Apoiar e assistir as organizações e os serviços responsáveis pela aplicação da lei para que cooperem de maneira eficaz, tendo em vista a adoção de uma abordagem integrada para a eliminação da violência contra as mulheres e da violência doméstica. 
  2. A presente Convenção cria um mecanismo de monitorização específico a fim de assegurar que as Partes apliquem efetivamente as suas disposições.            
         
   
     
                         
                          
  Artigo 2.º Âmbito de aplicação da Convenção
                            
                           
                             
                               
                             
     1. A presente Convenção aplica-se a todas as formas de violência contra as mulheres, incluindo a violência doméstica que afeta desproporcionalmente as mulheres. 
  2. As Partes são encorajadas a aplicar a presente Convenção a todas as vítimas de violência doméstica. Ao aplicarem o disposto na presente Convenção, as Partes deverão dar particular atenção às mulheres vítimas de violência de género. 
  3. A presente Convenção aplica-se em tempos de paz e em situações de conflito armado.            
         
   
     
                         
                          
  Artigo 3.º Definições
                            
                           
                             
                               
                             
     Para efeitos da presente Convenção: 
  a) Violência contra as mulheres constitui uma violação dos direitos humanos e é uma forma de discriminação contra as mulheres, abrangendo todos os atos de violência de género que resultem, ou possam resultar, em danos ou sofrimentos físicos, sexuais, psicológicos ou económicos para as mulheres, incluindo a ameaça de tais atos, a coação ou a privação arbitrária da liberdade, tanto na vida pública como na vida privada; 
  b) Violência doméstica abrange todos os atos de violência física, sexual, psicológica ou económica que ocorrem na família ou na unidade doméstica, ou entre cônjuges ou ex-cônjuges, ou entre companheiros ou ex-companheiros, quer o agressor coabite ou tenha coabitado, ou não, com a vítima; 
  c) Género refere-se aos papéis, aos comportamentos, às atividades e aos atributos socialmente construídos que uma determinada sociedade considera serem adequados para mulheres e homens; 
  d) Violência de género exercida contra as mulheres abrange toda a violência dirigida contra a mulher por ser mulher ou que afeta desproporcionalmente as mulheres; 
  e) Vítima é qualquer pessoa singular que seja sujeita aos co','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('mportamentos especificados nas alíneas a) e b); 
  f) Mulheres abrange as raparigas com menos de 18 anos de idade.            
         
   
     
                         
                          
  Artigo 4.º Direitos fundamentais, igualdade e não discriminação
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para promover e proteger o direito de cada pessoa, em especial das mulheres, de viver sem violência, tanto na esfera pública como na esfera privada. 
  2. As Partes condenam todas as formas de discriminação contra as mulheres e adotam de imediato as medidas legislativas e outras que se revelem necessárias para a evitar, em especial através da: 
  - Consagração do princípio da igualdade entre mulheres e homens na sua constituição nacional ou em outra legislação apropriada, e da garantia da concretização deste princípio; 
  - Proibição da discriminação contra as mulheres, designadamente através do recurso a sanções, se for caso disso; 
  - Abolição de leis e práticas que discriminam as mulheres. 
  3. As Partes deverão aplicar o disposto na presente Convenção, em especial as medidas que visam proteger os direitos das vítimas, sem discriminação alguma baseada nomeadamente no sexo, no género, na raça, na cor, na língua, na religião, na opinião política ou outra, na origem nacional ou social, na pertença a uma minoria nacional, na fortuna, no nascimento, na orientação sexual, na identidade de género, na idade, no estado de saúde, na deficiência, no estado civil, no estatuto de migrante ou de refugiado ou qualquer outro. 
  4. As medidas especiais que sejam necessárias para prevenir e proteger as mulheres da violência de género não são consideradas discriminatórias nos termos da presente Convenção.            
         
   
     
                         
                          
  Artigo 5.º Obrigações do Estado e diligência devida
                            
                           
                             
                               
                             
     1. As Partes deverão abster-se de praticar qualquer ato de violência contra as mulheres e certificar-se de que as autoridades, os funcionários, os agentes e as instituições estatais e outros intervenientes que agem em nome do Estado agem em conformidade com esta obrigação. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para agir com a diligência devida a fim de prevenir, investigar, punir e conceder uma indemnização pelos atos de violência abrangidos pelo âmbito de aplicação da presente Convenção praticados por intervenientes não estatais.            
         
   
     
                         
                          
  Artigo 6.º Políticas sensíveis à dimensão de género
                            
                       ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('    
                             
                               
                             
     As Partes comprometem-se a integrar a perspetiva de género na aplicação e avaliação do impacto das disposições da presente Convenção, bem como a promover e a aplicar eficazmente políticas de igualdade entre as mulheres e os homens e de empoderamento das mulheres.            
         
   
     
                         
                          
CAPÍTULO II 
  Políticas integradas e recolha de dados  Artigo 7.º Políticas abrangentes e coordenadas
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para adotar e aplicar políticas nacionais eficazes, abrangentes e coordenadas, incluindo todas as medidas relevantes para prevenir e combater todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção e apresentar uma solução global para a violência contra as mulheres. 
  2. As Partes deverão assegurar que todas as medidas previstas pelas políticas referidas no n.º 1 estão centradas nos direitos da vítima e são aplicadas através de uma cooperação eficaz entre todos os organismos, instituições e organizações pertinentes. 
  3. As medidas adotadas nos termos do presente artigo deverão envolver, se for caso disso, todos os agentes pertinentes, tais como os organismos governamentais, os parlamentos e as autoridades nacionais, regionais e locais, as instituições nacionais de direitos humanos e as organizações da sociedade civil.            
         
   
     
                         
                          
  Artigo 8.º Recursos financeiros
                            
                           
                             
                               
                             
     As Partes deverão afetar os recursos financeiros e humanos adequados para executar convenientemente políticas, medidas e programas integrados de prevenção e combate de todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção, incluindo os que são executados pelas organizações não governamentais e pela sociedade civil.            
         
   
     
                         
                          
  Artigo 9.º Organizações não governamentais e a sociedade civil
                            
                           
                             
                               
                             
     As Partes deverão reconhecer, encorajar e apoiar, a todos os níveis, o trabalho da sociedade civil e das organizações não governamentais pertinentes, ativas no domínio do combate à violência contra as mulheres, bem como encetar uma cooperação eficaz com estas organizações.            
         
   
     
                         
                          
  Artigo 10.º Órgão coordenador
                     ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('       
                           
                             
                               
                             
     1. As Partes deverão designar ou criar um ou mais órgãos oficiais responsáveis pela coordenação, aplicação, monitorização e avaliação das políticas e medidas tendentes a prevenir e combater todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção. Estes órgãos deverão coordenar a recolha de dados referida no artigo 11.º, analisar e divulgar os resultados. 
  2. As Partes deverão assegurar que os órgãos designados ou criados nos termos do presente artigo recebem informação de caráter geral sobre as medidas adotadas nos termos do capítulo viii. 
  3. As Partes deverão assegurar que os órgãos designados ou criados nos termos do presente artigo podem comunicar diretamente e fomentar relações com os serviços congéneres noutras Partes.            
         
   
     
                         
                          
  Artigo 11.º Recolha de dados e investigação
                            
                           
                             
                               
                             
     1. Para efeitos de aplicação da presente Convenção, as Partes comprometem-se a: 
  a) Recolher, a intervalos regulares, dados estatísticos desagregados relevantes sobre casos que envolvam todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção; 
  b) Apoiar a investigação na área da violência sob todas as formas abrangidas pelo âmbito de aplicação da presente Convenção, a fim de estudar as causas que estão na sua origem e os seus efeitos, as taxas de incidência e de condenação, bem como a eficácia das medidas adotadas para aplicar a presente Convenção. 
  2. As Partes deverão esforçar-se por realizar, a intervalos regulares, inquéritos populacionais, a fim de avaliar a prevalência e as tendências das formas de violência abrangidas pelo âmbito de aplicação da presente Convenção. 
  3. As Partes deverão facultar as informações recolhidas nos termos deste artigo ao grupo de peritos referido no artigo 66.º da presente Convenção, a fim de estimular a cooperação internacional e de permitir uma avaliação comparativa internacional. 
  4. As Partes deverão assegurar que as informações recolhidas nos termos deste artigo estão disponíveis ao público.            
         
   
     
                         
                          
CAPÍTULO III 
  Prevenção  Artigo 12.º Obrigações gerais
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas necessárias para promover mudanças nos padrões de comportamento socioculturais das mulheres e dos homens, tendo em vista a erradicação de preconceitos, costumes, tradições e de todas as outras práticas assentes na ideia de inferioridade das mulheres ou nos papéis estereotipados das mulhe','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('res e dos homens. 
  2. As Partes deverão adotar as medidas que se revelem necessárias para prevenir todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção praticadas por qualquer pessoa singular ou coletiva. 
  3. Todas as medidas adotadas nos termos do presente capítulo deverão ter em conta e visar as necessidades específicas das pessoas que se tornaram vulneráveis devido a circunstâncias particulares, bem como centrar-se nos direitos humanos de todas as vítimas. 
  4. As Partes deverão adotar as medidas que se revelem necessárias para encorajar todos os membros da sociedade, em particular homens e rapazes, a contribuir ativamente para a prevenção de todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção. 
  5. As Partes deverão garantir que a cultura, os costumes, a religião, a tradição ou a pretensa honra não sirvam de justificação para os atos de violência abrangidos pelo âmbito de aplicação da presente Convenção. 
  6. As Partes deverão adotar as medidas que se revelem necessárias para promover programas e atividades conducentes ao empoderamento das mulheres.            
         
   
     
                         
                          
  Artigo 13.º Sensibilização
                            
                           
                             
                               
                             
     1. As Partes deverão promover ou desenvolver regularmente campanhas ou programas de sensibilização a todos os níveis, incluindo em cooperação com as instituições nacionais de direitos humanos e os órgãos competentes em matéria de igualdade, as organizações da sociedade civil e as organizações não governamentais, em especial as organizações de mulheres, se for caso disso, para aumentar a consciencialização e compreensão do grande público acerca das diferentes manifestações de todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção, das suas consequências para as crianças e da necessidade de prevenir tal violência. 
  2. As Partes deverão assegurar junto do grande público uma ampla divulgação de informação sobre as medidas disponíveis para prevenir atos de violência abrangidos pelo âmbito de aplicação da presente Convenção.            
         
   
     
                         
                          
  Artigo 14.º Educação
                            
                           
                             
                               
                             
     1. As Partes deverão, se for caso disso, adotar as medidas necessárias para incluir nos currículos escolares de todos os níveis de ensino material didático, adaptado ao nível de desenvolvimento dos alunos, sobre questões tais como a igualdade entre as mulheres e os homens, os papéis de género não estereotipados, o respeito mútuo, a resolução não violenta dos conflitos nas relações interpessoais, a violência de género exercida contra as mulheres e o direit','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o à integridade pessoal. 
  2. As Partes deverão adotar as medidas que se revelem necessárias para promover os princípios referidos no n.º 1 nos estabelecimentos de ensino informal, bem como nos equipamentos desportivos, culturais e de lazer e nos meios de comunicação social.            
         
   
     
                         
                          
  Artigo 15.º Formação de profissionais
                            
                           
                             
                               
                             
     1. As Partes deverão proporcionar aos profissionais adequados que lidam com as vítimas ou com os perpetradores de todos os atos de violência abrangidos pelo âmbito de aplicação da presente Convenção formação adequada em matéria de prevenção e deteção dessa violência, igualdade entre mulheres e homens, necessidades e direitos das vítimas, bem como quanto à forma de prevenir a vitimização secundária, ou reforçar essa mesma formação. 
  2. As Partes deverão encorajar a inclusão de uma formação em matéria de cooperação interinstitucional coordenada na formação referida no n.º 1, a fim de permitir uma gestão abrangente e adequada dos casos de encaminhamento de situações de violência abrangidas pelo âmbito de aplicação da presente Convenção.            
         
   
     
                         
                          
  Artigo 16.º Programas preventivos de intervenção e de tratamento
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para criar ou apoiar programas cujo objetivo é ensinar os perpetradores de violência doméstica a adotar um comportamento não violento nas relações interpessoais, a fim de evitar mais violência e mudar padrões de comportamento violento. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para criar ou apoiar programas de tratamento cujo objetivo é prevenir a reincidência de agressores e em particular de agressores sexuais. 
  3. Ao adotar as medidas referidas nos n.os 1 e 2, as Partes deverão certificar-se de que a segurança, o apoio e os direitos humanos das vítimas constituem uma preocupação fundamental e, se for caso disso, de que estes programas são criados e aplicados em estreita coordenação com os serviços de apoio especializado às vítimas.            
         
   
     
                         
                          
  Artigo 17.º Participação do setor privado e dos meios de comunicação social
                            
                           
                             
                               
                             
     1. As Partes deverão encorajar o setor privado, o setor das tecnologias de informação e os meios de comunicação a participarem, com o devido respeito pela liberdade de expressão e pela sua i','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ndependência, na elaboração e aplicação das políticas, bem como a definirem diretrizes e regras de autorregulação para prevenir a violência contra as mulheres e reforçar o respeito pela sua dignidade. 
  2. As Partes deverão, em cooperação com agentes do setor privado, desenvolver e promover as capacidades das crianças, dos pais e dos educadores para lidarem com um ambiente de tecnologias de informação e comunicação que dá acesso a conteúdos degradantes de natureza sexual ou violenta que podem ser prejudiciais.            
         
   
     
                         
                          
CAPÍTULO IV 
  Proteção e apoio  Artigo 18.º Obrigações gerais
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para proteger todas as vítimas de quaisquer novos atos de violência. 
  2. As Partes deverão adotar, em conformidade com o seu direito interno, as medidas legislativas ou outras que se revelem necessárias para garantir a existência de mecanismos apropriados que permitam a todos os serviços estatais competentes, entre eles o poder judicial, o Ministério Público, os serviços responsáveis pela aplicação da lei, as autoridades locais e regionais, bem como as organizações não governamentais e outras organizações e entidades pertinentes, cooperarem eficazmente na proteção e no apoio das vítimas e das testemunhas de todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção, incluindo através do encaminhamento para serviços de apoio geral e serviços de apoio especializado, tal como previstos nos artigos 20.º e 22.º desta Convenção. 
  3. As Partes deverão garantir que as medidas adotadas nos termos deste capítulo: 
  - Assentem numa compreensão da violência contra as mulheres e da violência doméstica, que tem em conta o género, e estejam centradas nos direitos humanos e na segurança da vítima; 
  - Tenham por base uma abordagem integrada que tem em conta a relação entre vítimas, perpetradores, crianças e o seu ambiente social mais alargado; 
  - Visem evitar a vitimização secundária; 
  - Visem o empoderamento e a independência económica das mulheres vítimas de violência; 
  - Permitam, se for caso disso, a localização de um conjunto de serviços de proteção e apoio no mesmo edifício; 
  - Visem satisfazer as necessidades específicas de pessoas vulneráveis, incluindo as crianças vítimas, e que estas pessoas possam recorrer a elas. 
  4. A prestação de serviços não deverá depender da vontade das vítimas de apresentar queixa ou de testemunhar contra qualquer perpetrador. 
  5. As Partes deverão adotar as medidas adequadas para prestar proteção consular ou outra e apoio aos seus nacionais e a outras vítimas que têm direito a essa proteção, em conformidade com as suas obrigações decorrentes do Direito Internacional.            
         
  ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' 
     
                         
                          
  Artigo 19.º Informação
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para garantir que as vítimas recebam, numa língua que compreendam, informação adequada e atempada sobre os serviços de apoio e as medidas legais disponíveis.            
         
   
     
                         
                          
  Artigo 20.º Serviços de apoio geral
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para garantir que as vítimas de violência tenham acesso a serviços que facilitem a sua recuperação das consequências da violência. Estas medidas deveriam incluir, se necessário, serviços tais como o aconselhamento jurídico e psicológico, a assistência financeira, o alojamento, a educação, a formação e assistência na procura de emprego. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias de modo a garantir que as vítimas tenham acesso a cuidados de saúde e a serviços sociais, e os serviços disponham dos recursos adequados e os profissionais sejam habilitados a prestar assistência às vítimas e a encaminhá-las para os serviços apropriados.            
         
   
     
                         
                          
  Artigo 21.º Assistência em matéria de queixas individuais/coletivas
                            
                           
                             
                               
                             
     As Partes deverão garantir que as vítimas disponham de informação sobre os mecanismos aplicáveis, regionais e internacionais, de apresentação de queixas individuais/coletivas, e tenham acesso aos mesmos. As Partes deverão promover a prestação de uma assistência especializada e atenta às vítimas aquando da apresentação das suas queixas.            
         
   
     
                         
                          
  Artigo 22.º Serviços de apoio especializado
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para disponibilizar ou providenciar no sentido de serem disponibilizados a qualquer vítima que tenha sido sujeita a atos de violência abrangidos pelo âmbito de aplicação da presente Convenção, com uma distribuição geográfica adequada, serviços de apoio especializado imediatos, a curto e longo prazo. 
  2. As Partes deverão disponibilizar ou providenciar no sentido de serem disponibilizados a todas as mulheres vítimas de violência e aos seus','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' filhos serviços de apoio especializado para mulheres.            
         
   
     
                         
                          
  Artigo 23.º Casas de abrigo
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para criar casas de abrigo adequadas, de fácil acesso e em número suficiente, a fim de proporcionar às vítimas, em especial mulheres com filhos, um alojamento seguro, e as ajudar de forma proativa.            
         
   
     
                         
                          
  Artigo 24.º Linhas de apoio telefónico
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para criar um serviço nacional de apoio, anónimo, confidencial e gratuito, que funciona pelo telefone, vinte e quatro horas por dia, sete dias por semana, a fim de dar às pessoas que ligam conselhos sobre todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção.            
         
   
     
                         
                          
  Artigo 25.º Apoio às vítimas de violência sexual
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias à criação de centros de crise adequados, de acesso fácil e em número suficiente, que procedam ao encaminhamento de vítimas de violação ou de violência sexual e onde estas sejam sujeitas a exame médico e exame médico-legal e recebam apoio associado ao trauma bem como aconselhamento.            
         
   
     
                         
                          
  Artigo 26.º Proteção e apoio às crianças testemunhas
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que os direitos e as necessidades das crianças testemunhas de todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção sejam devidamente tidos em conta na prestação de serviços de proteção e apoio às vítimas. 
  2. As medidas adotadas nos termos deste artigo deverão incluir o aconselhamento psicossocial adequado à idade para crianças testemunhas de todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção e deverão ter devidamente em conta o interesse superior da criança.            
         
   
     
                         
                          
  Artigo 27.º Denúncia
                            
             ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('              
                             
                               
                             
     As Partes deverão adotar as medidas que se revelem necessárias para encorajar qualquer pessoa que testemunhe a prática de atos de violência abrangidos pelo âmbito de aplicação da presente Convenção, ou que tenha motivos razoáveis para crer que tal ato possa ser praticado ou que seja de prever a prática de novos atos de violência, a comunicá-los às organizações ou autoridades competentes.            
         
   
     
                         
                          
  Artigo 28.º Denúncia pelos profissionais
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas que se revelem necessárias para garantir que as regras de confidencialidade a que de acordo com o direito interno estão sujeitos certos profissionais não constituam um obstáculo à possibilidade de sob determinadas condições eles apresentarem denúncia junto das organizações ou autoridades competentes, caso tenham motivos razoáveis para crer que foi praticado um ato de violência grave, abrangido pelo âmbito de aplicação da presente Convenção, e seja de prever a prática de novos atos de violência graves.            
         
   
     
                         
                          
CAPÍTULO V 
  Direito material  Artigo 29.º Ações e vias de recurso cíveis
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para proporcionar às vítimas vias de recurso cíveis adequadas contra o perpetrador. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para proporcionar às vítimas, em conformidade com os princípios gerais de Direito Internacional, vias de recurso cíveis adequadas contra as autoridades estatais que não cumpriram o seu dever de adotar, no âmbito das suas competências, as medidas de prevenção ou de proteção necessárias.            
         
   
     
                         
                          
  Artigo 30.º Indemnização
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para garantir que as vítimas tenham o direito de exigir dos perpetradores uma indemnização pela prática de qualquer uma das infrações previstas na presente Convenção. 
  2. Deverá ser concedida uma indemnização estatal adequada aos que sofreram ofensas corporais graves ou ofensa grave à saúde, na medida em que o dano não esteja coberto por outras fontes, tais como o perpetrador, um seguro ou medidas sanitárias e sociais financiadas pelo Estado. Is','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('so não impede as Partes de exercerem o direito de regresso contra o perpetrador pela indemnização concedida, desde que a segurança da vítima seja devidamente tida em conta. 
  3. As medidas adotadas nos termos do n.º 2 deverão assegurar a concessão da indemnização dentro de um prazo razoável.            
         
   
     
                         
                          
  Artigo 31.º Direito de guarda, direito de visita e segurança
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar que os incidentes de violência abrangidos pelo âmbito de aplicação da presente Convenção sejam tidos em conta na tomada de decisões relativas à guarda das crianças e sobre o direito de visita das mesmas. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar que o exercício de um qualquer direito de visita ou de um qualquer direito de guarda não prejudique os direitos e a segurança da vítima ou das crianças.            
         
   
     
                         
                          
  Artigo 32.º Consequências civis dos casamentos forçados
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar que os casamentos celebrados à força possam ser anuláveis, anulados ou dissolvidos sem encargos financeiros ou administrativos excessivos para a vítima.            
         
   
     
                         
                          
  Artigo 33.º Violência psicológica
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar a criminalização da conduta de quem intencionalmente lesar gravemente a integridade psicológica de uma pessoa por meio de coação ou ameaças.            
         
   
     
                         
                          
  Artigo 34.º Perseguição
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar a criminalização da conduta de quem intencionalmente ameaçar repetidamente outra pessoa, levando-a a temer pela sua segurança.            
         
   
     
                         
                          
  Artigo 35.º Violência física
                            
                           
                             
                               
                             
     As Pa','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rtes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar a criminalização da conduta de quem intencionalmente praticar atos de violência física contra uma outra pessoa.            
         
   
     
                         
                          
  Artigo 36.º Violência sexual, incluindo violação
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar a criminalização da conduta de quem intencionalmente: 
  a) Praticar a penetração vaginal, anal ou oral, de natureza sexual, de quaisquer partes do corpo ou objetos no corpo de outra pessoa, sem consentimento desta última; 
  b) Praticar outros atos de natureza sexual não consentidos com uma pessoa; 
  c) Levar outra pessoa a praticar atos de natureza sexual não consentidos com terceiro. 
  2. O consentimento tem de ser prestado voluntariamente, como manifestação da vontade livre da pessoa, avaliado no contexto das circunstâncias envolventes. 
  3. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar que as disposições do n.º 1 também se aplicam a atos praticados contra os cônjuges ou companheiros ou contra os ex-cônjuges ou ex-companheiros, em conformidade com o direito interno.            
         
   
     
                         
                          
  Artigo 37.º Casamento forçado
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar a criminalização da conduta de quem intencionalmente forçar um adulto ou uma criança a contrair matrimónio. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar a criminalização da conduta de quem intencionalmente atrair uma criança ou um adulto para o território de outra Parte ou de outro Estado que não aquele onde residam, com o intuito de os forçar a contrair matrimónio.            
         
   
     
                         
                          
  Artigo 38.º Mutilação genital feminina
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar a criminalização da conduta de quem intencionalmente: 
  a) Praticar a excisão, infibulação ou qualquer outra mutilação total ou parcial da labia majora, da labia minora ou do clitóris de uma mulher; 
  b) Constranger ou criar as condições para que uma mulher se submeta a qualquer um dos atos enumerados na alínea a); 
  c) Incitar, constranger ou criar as condições para','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' que uma rapariga se submeta a qualquer um dos atos enumerados na alínea a).            
         
   
     
                         
                          
  Artigo 39.º Aborto forçado e esterilização forçada
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar a criminalização da conduta de quem intencionalmente: 
  a) Fizer abortar uma mulher sem o seu consentimento prévio e informado; 
  b) Realizar uma intervenção cirúrgica que tenha como finalidade ou efeito pôr fim à capacidade de reprodução natural de uma mulher, sem o seu consentimento prévio e informado ou sem que ela tenha compreendido o procedimento.            
         
   
     
                         
                          
  Artigo 40.º Assédio sexual
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar que qualquer tipo de comportamento indesejado de natureza sexual, sob forma verbal, não verbal ou física, com o intuito ou o efeito de violar a dignidade de uma pessoa, em particular quando cria um ambiente intimidante, hostil, degradante, humilhante ou ofensivo, seja passível de sanções penais ou outras sanções legais.            
         
   
     
                         
                          
  Artigo 41.º Auxílio ou instigação e tentativa
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para classificar como infração, quando praticados intencionalmente, o auxílio ou a instigação à prática das infrações previstas nos artigos 33.º, 34.º, 35.º, 36.º e 37.º, na alínea a) do artigo 38.º e no artigo 39.º da presente Convenção. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para classificar como infração a tentativa intencional de praticar as infrações previstas nos artigos 33.º, 34.º, 35.º, 36.º e 37.º, na alínea a) do artigo 38.º e no artigo 39.º da presente Convenção.            
         
   
     
                         
                          
  Artigo 42.º Justificações inaceitáveis para crimes, incluindo os crimes praticados em nome de uma pretensa honra
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para garantir que nos procedimentos penais iniciados em consequência da prática de qualquer um dos atos de violência abrangidos pel','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('o âmbito de aplicação da presente Convenção, a cultura, os costumes, a religião, a tradição ou a pretensa honra não sirvam de causa de justificação para esses atos. Isto abrange especialmente as alegações segundo as quais a vítima teria transgredido regras ou hábitos culturais, religiosos, sociais ou tradicionais de conduta apropriada. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar que a responsabilidade criminal de uma pessoa pelos atos praticados não será menor pelo facto de ter incitado uma criança à prática de qualquer um dos atos referidos no n.º 1.            
         
   
     
                         
                          
  Artigo 43.º Aplicação das infrações penais
                            
                           
                             
                               
                             
     As infrações previstas na presente Convenção aplicam-se, independentemente da natureza da relação entre a vítima e o perpetrador.            
         
   
     
                         
                          
  Artigo 44.º Jurisdição
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para estabelecer a sua jurisdição em relação às infrações previstas na presente Convenção sempre que a infração seja praticada: 
  a) No seu território; ou 
  b) A bordo de um navio que arvore a sua bandeira; ou 
  c) A bordo de uma aeronave registada em conformidade com o respetivo direito; ou 
  d) Por um dos seus nacionais; ou 
  e) Por uma pessoa que resida habitualmente no seu território. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para estabelecer a sua jurisdição em relação às infrações previstas na presente Convenção sempre que a infração seja praticada contra um dos seus nacionais ou uma pessoa que resida habitualmente no seu território. 
  3. Para a instauração do procedimento penal pelas infrações previstas nos artigos 36.º, 37.º, 38.º e 39.º desta Convenção, as Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para garantir que a sua jurisdição não dependa da condição de os atos constituírem crime no território onde foram praticados. 
  4. Para a instauração do procedimento penal pelas infrações previstas nos artigos 36.º, 37.º, 38.º e 39.º da presente Convenção, as Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para garantir que a sua jurisdição relativamente às alíneas d) e e) do n.º 1 não dependa da condição de só se poder iniciar o procedimento penal após apresentação de denúncia pela vítima da infração ou instauração do procedimento penal pelo Estado do lugar onde foi praticada a infração. 
  5. As Partes deverão adotar as medidas legislativas ou outras ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('que se revelem necessárias para estabelecer a sua jurisdição em relação às infrações previstas na presente Convenção nos casos em que o presumível perpetrador se encontre no seu território e elas não o extraditem para uma outra Parte por causa da sua nacionalidade. 
  6. Sempre que várias Partes reclamem a jurisdição em relação a uma alegada infração prevista na presente Convenção, as Partes visadas deverão, se for caso disso, consultar-se a fim de determinar a jurisdição mais apropriada para instaurar o procedimento penal. 
  7. Sem prejuízo das normas gerais de Direito Internacional, a presente Convenção não exclui o exercício de qualquer jurisdição penal estabelecida por uma Parte em conformidade com o seu direito interno.            
         
   
     
                         
                          
  Artigo 45.º Sanções e medidas
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar que as infrações previstas na presente Convenção sejam puníveis com sanções efetivas, proporcionais e dissuasoras, tendo em conta a sua gravidade. Essas sanções deverão, se for caso disso, incluir penas privativas de liberdade passíveis de dar origem a extradição. 
  2. As Partes podem adotar outras medidas em relação aos perpetradores, tais como: 
  - A monitorização ou vigilância de pessoas condenadas; 
  - Retirada da responsabilidade parental, se de outro modo não puder ser garantido o superior interesse da criança, o qual pode incluir a segurança da vítima.            
         
   
     
                         
                          
  Artigo 46.º Circunstâncias agravantes
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para garantir que as circunstâncias que se seguem, na medida em que ainda não façam parte dos elementos constitutivos da infração, possam, nos termos das disposições pertinentes do direito interno, ser tidas em conta como circunstâncias agravantes na determinação da pena aplicável às infrações previstas na presente Convenção: 
  a) Ter a infração sido praticada por um membro da família, uma pessoa que coabita com a vítima ou uma pessoa que abusou da sua autoridade contra o cônjuge ou ex-cônjuge, ou contra o companheiro ou ex-companheiro, tal como previsto no direito interno; 
  b) Ter a infração, ou terem as infrações conexas, sido repetidamente praticadas; 
  c) Ter a infração sido praticada contra uma pessoa que se tornou vulnerável devido a circunstâncias particulares; 
  d) Ter a infração sido praticada contra uma criança ou na sua presença; 
  e) Ter a infração sido praticada por duas ou mais pessoas agindo conjuntamente; 
  f) Ter a in','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('fração sido precedida ou acompanhada de uma violência de gravidade extrema; 
  g) Ter a infração sido praticada com a utilização ou a ameaça de uma arma; 
  h) Ter a infração causado danos físicos ou psicológicos graves à vítima; 
  i) Ter o perpetrador sido anteriormente condenado pela prática de infrações da mesma natureza.            
         
   
     
                         
                          
  Artigo 47.º Sentenças proferidas numa outra Parte
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para prever a possibilidade de serem tidas em conta, no âmbito da ponderação da pena a aplicar, as sentenças condenatórias transitadas em julgado, proferidas numa outra Parte relativamente às infrações previstas na presente Convenção.            
         
   
     
                         
                          
  Artigo 48.º Proibição de processos alternativos de resolução de conflitos ou de pronúncia de sentença obrigatórios
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para proibir os processos alternativos de resolução de conflitos obrigatórios, incluindo a mediação e a conciliação em relação a todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para garantir que, no caso de ser exigido o pagamento de multa, a capacidade do perpetrador para cumprir as suas obrigações financeiras para com a vítima é devidamente tida em conta.            
         
   
     
                         
                          
CAPÍTULO VI 
  Investigação, ação penal, direito processual e medidas de proteção  Artigo 49.º Obrigações gerais
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que as investigações e os processos judiciais relativos a todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção sejam levados a cabo sem demora indevida, tendo em conta os direitos da vítima em todas as fases do procedimento penal. 
  2. As Partes deverão, em conformidade com os princípios fundamentais de direitos humanos e tendo presente a compreensão da violência sob o ponto de vista do género, adotar as medidas legislativas ou outras que se revelem necessárias para assegurar a eficácia da investigação e do procedimento penal relativamente às infrações previstas na presente Convenção.            
         
   
     
                  ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('       
                          
  Artigo 50.º Resposta imediata, prevenção e proteção
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que as autoridades competentes de aplicação da lei respondam de imediato e adequadamente a todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção, assegurando uma proteção adequada e imediata às vítimas. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que as autoridades competentes de aplicação da lei se empenhem de imediato e adequadamente na prevenção de todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção e na proteção contra as mesmas, incluindo através de medidas operacionais preventivas e da recolha de provas.            
         
   
     
                         
                          
  Artigo 51.º Avaliação e gestão do risco
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para garantir que todas as autoridades competentes avaliem o risco de mortalidade, a gravidade da situação e o risco de repetição da violência, de modo a gerirem o risco e, se necessário, proporcionarem segurança e apoio coordenados. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que, em todas as fases da investigação e da aplicação das medidas de proteção, a avaliação referida no n.º 1 tenha devidamente em conta o facto de os perpetradores de atos de violência abrangidos pelo âmbito de aplicação da presente Convenção possuírem ou terem acesso a armas de fogo.            
         
   
     
                         
                          
  Artigo 52.º Medidas de interdição urgentes
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que seja concedido às autoridades competentes o poder para, em situações de perigo imediato, ordenar ao autor de violência doméstica que deixe a residência da vítima ou da pessoa em risco por um período de tempo suficiente e proibi-lo de entrar na residência da vítima ou da pessoa em perigo ou de as contactar. As medidas adotadas nos termos do presente artigo deverão dar prioridade à segurança das vítimas ou das pessoas em risco.            
         
   
     
                         
                          
  Artigo 53.º Medidas cautelares ou medidas de proteção
                            
                           
                             
  ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                             
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que haja medidas de injunção ou de proteção adequadas que possam ser aplicadas em defesa das vítimas de todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar que as medidas de injunção ou de proteção referidas no n.º 1: 
  - Assegurem uma proteção imediata e sem encargos financeiros ou administrativos excessivos para a vítima; 
  - Sejam emitidas por um determinado período de tempo ou até serem alteradas ou revogadas; 
  - Sejam emitidas, se for caso disso, ex parte, com efeito imediato; 
  - Possam ser aplicadas, independentemente de ou para além de outros processos judiciais; 
  - Possam ser aplicadas em ações judiciais subsequentes. 
  3. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que as violações das medidas de injunção ou de proteção emitidas de acordo com o n.º 1 sejam passíveis de sanções penais ou outras legais efetivas, proporcionais e dissuasoras.            
         
   
     
                         
                          
  Artigo 54.º Investigações e meios de prova
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que os meios de prova relacionados com os antecedentes sexuais e a conduta da vítima só sejam admissíveis em qualquer processo civil ou penal quando tal for relevante e necessário.            
         
   
     
                         
                          
  Artigo 55.º Processos ex parte e ex officio
                            
                           
                             
                               
                             
     1. As Partes deverão garantir que as investigações das infrações previstas nos artigos 35.º, 36.º, 37.º, 38.º e 39.º da presente Convenção ou o procedimento penal instaurado em relação a essas mesmas infrações não dependam totalmente da denúncia ou da queixa apresentada pela vítima, se a infração tiver sido praticada no todo ou em parte no seu território, e que o procedimento possa prosseguir ainda que a vítima retire a sua declaração ou queixa. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para assegurar, nas condições previstas no seu direito interno, que organizações governamentais e não governamentais, bem como conselheiros especializados em violência doméstica, possam assistir e ou apoiar as vítimas, se elas o solicitarem, durante as investigações e processos judiciais relativamente às infrações previstas na presente Convenção.            
         
   
     
                  ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('       
                          
  Artigo 56.º Medidas de proteção
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para proteger os direitos e interesses das vítimas, incluindo as suas necessidades especiais enquanto testemunhas, em todas as fases das investigações criminais e dos processos judiciais, o que implica designadamente: 
  a) Providenciar no sentido de as proteger a elas e às suas famílias e às testemunhas contra atos de intimidação e de represália, bem como contra a vitimização reiterada; 
  b) Em caso de fuga ou libertação temporária ou definitiva do perpetrador, garantir que as vítimas sejam informadas, pelo menos quando as vítimas e a família possam estar em perigo; 
  c) Informá-las, nas condições previstas pelo direito interno, sobre os seus direitos e os serviços colocados à sua disposição, sobre o seguimento dado à sua queixa, a pronúncia, o andamento da investigação ou do processo, o seu papel no âmbito dos mesmos, bem como sobre o resultado do seu processo; 
  d) Dar às vítimas, em conformidade com as normas processuais do direito interno, a possibilidade de serem ouvidas, fornecerem elementos de prova e apresentarem, diretamente ou através de um intermediário, as suas opiniões, necessidades e preocupações e estas serem tidas em conta; 
  e) Disponibilizar às vítimas serviços de apoio adequados para que os seus direitos e interesses sejam devidamente apresentados e tidos em conta; 
  f) Providenciar no sentido de poderem ser adotadas medidas de proteção da privacidade e da imagem da vítima; 
  g) Sempre que possível, providenciar no sentido de impedir o contacto entre as vítimas e os perpetradores dentro dos tribunais e das instalações dos serviços responsáveis pela aplicação da lei; 
  h) Assegurar às vítimas o serviço de intérpretes independentes e competentes, quando elas são parte no processo ou quando estão a apresentar elementos de prova; 
  i) Permitir que as vítimas testemunhem em tribunal, em conformidade com as regras previstas no direito interno, sem estarem presentes, ou pelo menos sem que o presumível autor da infração esteja presente, nomeadamente através do recurso às tecnologias de comunicação adequadas, se as mesmas estiverem disponíveis. 
  2. Uma criança vítima e uma criança testemunha de violência contra as mulheres e de violência doméstica deverão, se for caso disso, beneficiar de medidas de proteção especiais, tendo em conta o superior interesse da criança.            
         
   
     
                         
                          
  Artigo 57.º Apoio judiciário
                            
                           
                             
                               
                             
     As Partes deverão providenciar no sentido de prever o direito das vítimas a apoio judiciár','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('io e a assistência jurídica gratuita nas condições previstas no seu direito interno.            
         
   
     
                         
                          
  Artigo 58.º Prescrição
                            
                           
                             
                               
                             
     As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que o prazo de prescrição para instaurar qualquer procedimento judicial pelas infrações previstas nos artigos 36.º, 37.º, 38.º e 39.º da presente Convenção tenha uma duração suficiente e proporcional à gravidade da infração em questão, a fim de permitir que o procedimento penal seja eficazmente instaurado depois de a vítima atingir a idade da maioridade.            
         
   
     
                         
                          
CAPÍTULO VII 
  Migração e asilo  Artigo 59.º Estatuto de residente
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que, em caso de dissolução do casamento ou fim da relação, havendo circunstâncias particularmente difíceis, seja concedido às vítimas, cujo estatuto de residente dependa, nos termos do direito interno, do estatuto do cônjuge ou do companheiro, e o solicitem, uma autorização de residência autónoma, independentemente da duração do casamento ou da relação. As condições de concessão e duração de uma autorização de residência autónoma são fixadas pelo direito interno. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que as vítimas, cujo estatuto de residente dependa, nos termos do direito interno, do estatuto do cônjuge ou do companheiro, possam obter a suspensão do processo de expulsão iniciado, a fim de poderem solicitar uma autorização de residência autónoma. 
  3. As Partes deverão emitir uma autorização de residência renovável às vítimas numa das seguintes situações ou nas duas: 
  a) A autoridade competente considera que a sua estada é necessária devido à sua situação pessoal; 
  b) A autoridade competente considera que a sua estada é necessária para efeitos da sua cooperação com as autoridades competentes no âmbito de uma investigação ou de um procedimento penal. 
  4. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que as vítimas de casamentos forçados levadas para outro país para efeitos do casamento e que por isso tenham perdido o seu estatuto de residente no país onde habitualmente residem, possam recuperar esse estatuto.            
         
   
     
                         
                          
  Artigo 60.º Pedidos de asilo baseados no género
                            
                           
                             
                               
     ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                        
     1. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que a violência de género exercida contra as mulheres possa ser reconhecida como uma forma de perseguição, na aceção da alínea 2) do ponto A do artigo 1.º da Convenção de 1951 relativa ao Estatuto dos Refugiados, e como uma forma de dano grave exigindo proteção complementar/subsidiária. 
  2. As Partes deverão assegurar que a interpretação dada a cada um dos fundamentos previstos na Convenção tenha em conta a dimensão do género e, nos casos em que se verifique que o receio de perseguição se baseia em um ou mais desses fundamentos, garantir a concessão do estatuto de refugiado aos requerentes de asilo de acordo com os instrumentos pertinentes e aplicáveis. 
  3. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para desenvolver processos de acolhimento que têm em conta o fator género e serviços de apoio para os requerentes de asilo, bem como diretrizes baseadas no género e processos de asilo que têm em conta o fator género, incluindo a atribuição do estatuto de refugiado e o pedido de proteção internacional.            
         
   
     
                         
                          
  Artigo 61.º Non-refoulement
                            
                           
                             
                               
                             
     1. As Partes deverão adotar as medidas legislativas e outras que se revelem necessárias para respeitarem o princípio de non-refoulement, em conformidade com as obrigações existentes decorrentes do Direito Internacional. 
  2. As Partes deverão adotar as medidas legislativas e outras que se revelem necessárias para assegurar que, independentemente do seu estatuto ou residência, as vítimas de violência contra as mulheres que precisem de proteção não sejam em circunstância alguma reenviadas para um país onde corram perigo de vida ou onde possam ser submetidas a tortura ou a tratamentos ou penas desumanos ou degradantes.            
         
   
     
                         
                          
CAPÍTULO VIII 
  Cooperação internacional  Artigo 62.º Princípios gerais
                            
                           
                             
                               
                             
     1. As Partes deverão cooperar o mais amplamente possível entre si, em conformidade com o disposto na presente Convenção, bem como nos termos dos instrumentos internacionais e regionais, pertinentes, relativos à cooperação em matéria civil e penal, e das disposições acordadas com base nas legislações uniformes ou recíprocas e no respetivo direito interno para: 
  a) Prevenir, combater e instaurar o procedimento penal relativamente a todas as formas de violência abrangidas pelo âmbito de aplicação da presente Convenção; 
  b) Proteger e prestar assistência às vítimas; 
  c) Conduzir investigações ou instau','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rar procedimentos pelas infrações previstas na presente Convenção; 
  d) Executar as decisões pertinentes proferidas, em matéria civil e penal, pelas autoridades judiciárias das Partes, incluindo as medidas de proteção. 
  2. As Partes deverão adotar as medidas legislativas ou outras que se revelem necessárias para que as vítimas de uma infração estabelecida nos termos da presente Convenção e cometida no território de uma Parte que não aquela em que elas residem possam apresentar queixa às autoridades competentes do seu Estado de residência. 
  3. Se uma Parte, que condiciona o auxílio judiciário mútuo em matéria penal, a extradição ou a execução de decisões judiciais proferidas, em matéria civil ou penal, por uma outra Parte da presente Convenção à existência de um acordo, receber um pedido desse tipo de cooperação judiciária de uma Parte com a qual não celebrou um tal acordo, pode considerar a presente Convenção como base jurídica para o auxílio judiciário mútuo em matéria penal, a extradição ou a execução de decisões judiciais proferidas, em matéria civil ou penal, por uma outra Parte relativamente às infrações previstas na presente Convenção. 
  4. As Partes deverão esforçar-se por integrar, se for caso disso, a prevenção e o combate à violência contra as mulheres e a violência doméstica em programas de ajuda ao desenvolvimento conduzidos em benefício de Estados terceiros, incluindo através da celebração de acordos bilaterais e multilaterais com Estados terceiros com vista a facilitar a proteção das vítimas, de acordo com o n.º 5 do artigo 18.º            
         
   
     
                         
                          
  Artigo 63.º Medidas relativas às pessoas em risco
                            
                           
                             
                               
                             
     Quando, com base na informação de que dispõe, uma Parte tiver razões sérias para crer que uma pessoa está em risco iminente de ser sujeita a qualquer um dos atos de violência referidos nos artigos 36.º, 37.º, 38.º e 39.º desta Convenção no território de outra Parte, a Parte que possui a informação é encorajada a transmiti-la de imediato à outra Parte, a fim de assegurar a adoção de medidas de proteção adequadas. Esta informação deverá eventualmente incluir pormenores sobre as disposições de proteção que existem para benefício da pessoa em risco.            
         
   
     
                         
                          
  Artigo 64.º Informação
                            
                           
                             
                               
                             
     1. A Parte requerida deverá de imediato informar a Parte requerente do resultado final da ação levada a cabo ao abrigo deste capítulo. A Parte requerida também deverá de imediato informar a Parte requerente de todas as circunstâncias que impossibilitam a execução da ação pedida, ou suscetíveis de a atrasar significat','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ivamente. 
  2. Uma Parte pode, nos limites previstos no seu direito interno e sem pedido prévio, transmitir a uma outra Parte informações obtidas no âmbito das suas próprias investigações, sempre que considerar que a divulgação dessas informações pode ajudar a Parte recetora a prevenir as infrações penais previstas na presente Convenção ou a iniciar ou a efetuar investigações ou procedimentos relativos a essas infrações penais, ou sempre que considerar que ela pode dar origem a um pedido de cooperação formulado por essa Parte nos termos do presente capítulo. 
  3. Uma Parte que receba qualquer informação em conformidade com o n.º 2 deverá transmiti-la às suas autoridades competentes a fim de permitir a instauração do procedimento, se tal for considerado conveniente, ou de modo que esta informação possa ser tida em conta nos processos civis e penais pertinentes.            
         
   
     
                         
                          
  Artigo 65.º Proteção de dados
                            
                           
                             
                               
                             
     Os dados pessoais deverão ser conservados e utilizados em conformidade com as obrigações assumidas pelas Partes ao abrigo da Convenção para a Proteção das Pessoas relativamente ao Tratamento Automatizado de Dados de Caráter Pessoal (STE n.º 108).            
         
   
     
                         
                          
CAPÍTULO IX 
  Mecanismo de monitorização  Artigo 66.º Grupo de Peritos para o Combate à Violência contra as Mulheres e a Violência Doméstica
                            
                           
                             
                               
                             
     1. O Grupo de Peritos para o Combate à Violência contra as Mulheres e a Violência Doméstica (doravante denominado GREVIO) deverá monitorizar a aplicação da presente Convenção pelas Partes. 
  2. O GREVIO deverá ser composto por um mínimo de 10 e um máximo de 15 membros, tendo em conta uma representação equilibrada de género e uma distribuição geográfica equitativa, bem como uma especialização multidisciplinar. Os seus membros deverão ser eleitos pelo Comité das Partes de entre os candidatos designados pelas Partes, por um mandato de quatro anos, renovável uma vez, e escolhidos de entre os nacionais das Partes. 
  3. A eleição inicial de 10 membros deverá realizar-se no prazo de um ano após a entrada em vigor da presente Convenção. A eleição de cinco membros adicionais deverá realizar-se após a 25.ª ratificação ou adesão. 
  4. A eleição dos membros do GREVIO deverá basear-se nos seguintes princípios: 
  a) Eles deverão ser escolhidos através de um processo transparente, de entre pessoas de elevado caráter moral, com reconhecida competência nos domínios dos direitos humanos, da igualdade de géneros, da violência contra as mulheres e da violência doméstica, ou da assistência e proteção às vítimas, ou que tenh','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('am demonstrado ter experiência profissional nas áreas abrangidas pela presente Convenção; 
  b) Entre os membros do GREVIO não pode haver mais do que um nacional do mesmo Estado; 
  c) Eles devem representar os principais sistemas jurídicos; 
  d) Eles devem representar os agentes e serviços competentes no domínio da violência contra as mulheres e da violência doméstica; 
  e) Eles deverão exercer as suas funções a título individual, com independência e imparcialidade, bem como estar disponíveis para desempenhar efetivamente as suas funções. 
  5. O processo eleitoral dos membros do GREVIO deverá ser definido pelo Comité de Ministros do Conselho da Europa, após consulta e obtenção do acordo unânime das Partes, no prazo de seis meses após a entrada em vigor da presente Convenção. 
  6. O GREVIO deverá adotar o seu próprio regulamento interno. 
  7. Os membros do GREVIO e outros membros das delegações que realizam as visitas aos países, tal como estipulado nos n.os 9 e 14 do artigo 68.º, gozam dos privilégios e imunidades previstos no anexo à presente Convenção.            
         
   
     
                         
                          
  Artigo 67.º Comité das Partes
                            
                           
                             
                               
                             
     1. O Comité das Partes é constituído por representantes das Partes na Convenção. 
  2. O Comité das Partes deverá ser convocado pelo Secretário-Geral do Conselho da Europa. A sua primeira reunião deverá realizar-se no prazo de um ano a contar da data de entrada em vigor da presente Convenção a fim de eleger os membros do GREVIO. Subsequentemente, ele reunir-se-á sempre que um terço das Partes, o Presidente do Comité das Partes ou o Secretário-Geral o solicitarem. 
  3. O Comité das Partes deverá adotar o seu próprio regulamento interno.            
         
   
     
                         
                          
  Artigo 68.º Processo
                            
                           
                             
                               
                             
     1. Tendo por base um questionário preparado pelo GREVIO, as Partes deverão apresentar ao Secretário-Geral do Conselho da Europa, para apreciação pelo GREVIO, um relatório sobre as medidas legislativas e outras conducentes à efetivação das disposições da presente Convenção. 
  2. O GREVIO deverá analisar com os representantes da Parte visada o relatório apresentado em conformidade com o n.º 1. 
  3. Os processos de avaliação subsequentes deverão ser divididos em ciclos, cuja duração será definida pelo GREVIO. No início de cada ciclo, o GREVIO deverá selecionar as disposições específicas em que se deverá basear o processo de avaliação e enviar um questionário. 
  4. O GREVIO deverá definir os meios adequados para pôr em prática o processo de monitorização. Ele pode nomeadamente adotar um questionário para cada ciclo de avaliação que serv','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('e de base ao processo de avaliação da aplicação pelas Partes. Este questionário deverá ser dirigido a todas as Partes. As Partes deverão responder a este questionário, bem como a qualquer outro pedido de informação do GREVIO. 
  5. O GREVIO pode receber de organizações não governamentais e da sociedade civil, bem como de instituições nacionais para a proteção dos direitos humanos, informação sobre a aplicação da Convenção. 
  6. O GREVIO deverá tomar devidamente em consideração a informação existente disponível noutros instrumentos e organizações regionais e internacionais nos domínios abrangidos pelo âmbito de aplicação da presente Convenção. 
  7. Ao adotar um questionário para cada ciclo de avaliação, o GREVIO deverá ter devidamente em conta os dados recolhidos e as pesquisas feitas nas Partes, tal como referido no artigo 11.º da presente Convenção. 
  8. O GREVIO pode receber informação sobre a aplicação da Convenção por parte do Comissário para os Direitos Humanos do Conselho da Europa, da Assembleia Parlamentar e dos órgãos especializados competentes do Conselho da Europa, bem como daqueles criados ao abrigo de outros instrumentos internacionais. As queixas apresentadas a estes órgãos e o seu resultado serão facultados ao GREVIO. 
  9. Subsidiariamente, o GREVIO pode, em cooperação com as autoridades nacionais e com a assistência de peritos nacionais independentes, organizar visitas aos países, se a informação obtida for insuficiente ou nos casos previstos no n.º 14. Nessas visitas, o GREVIO pode ser assistido por especialistas em domínios específicos. 
  10. O GREVIO deverá preparar um projeto de relatório dando conta da análise que fez da aplicação das disposições nas quais se baseia a avaliação, bem como das suas sugestões e propostas sobre o modo como a Parte visada pode resolver os problemas que foram identificados. O projeto de relatório deverá ser transmitido à Parte objeto da avaliação para comentários. Aquando da adoção do seu relatório, o GREVIO deverá ter em conta os comentários dessa mesma Parte. 
  11. Com base em toda a informação recebida e nos comentários das Partes, o GREVIO deverá adotar o seu relatório e as suas conclusões sobre as medidas adotadas pela Parte visada para aplicar as disposições da presente Convenção. O relatório e as conclusões deverão ser enviados à Parte visada e ao Comité das Partes. O relatório e as conclusões do GREVIO deverão ser publicados aquando da sua adoção, juntamente com os eventuais comentários da Parte visada. 
  12. Sem prejuízo do processo previsto nos n.os 1 a 8, o Comité das Partes pode, com base no relatório e nas conclusões do GREVIO, adotar as recomendações dirigidas a esta Parte: 
  a) Quanto às medidas a adotar para implementar as conclusões do GREVIO, fixando, se necessário, uma data para a apresentação de informação sobre a sua aplicação; e 
  b) Que visam promover a cooperação com essa mesma Parte, tendo em vista a aplicação adequada da presente Convenção. 
  13. Se receber infor','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('mação fiável sobre uma situação na qual os problemas exijam atenção imediata para impedir ou limitar a escala ou o número de violações graves da Convenção, o GREVIO pode solicitar a apresentação urgente de um relatório especial sobre as medidas adotadas com vista a prevenir um padrão de violência grave, generalizada ou recorrente contra as mulheres. 
  14. O GREVIO pode, com base na informação apresentada pela Parte visada, bem como em qualquer outra informação fiável disponível, designar um ou vários dos seus membros para conduzir um inquérito e apresentar urgentemente um relatório ao GREVIO. Quando tal se justifique e com o consentimento da Parte, o inquérito pode incluir uma visita ao território dessa mesma Parte. 
  15. Analisadas as conclusões do inquérito referido no n.º 14, o GREVIO deverá transmitir estas conclusões à Parte visada e, se for caso disso, ao Comité das Partes e ao Comité de Ministros do Conselho da Europa, juntamente com quaisquer comentários ou recomendações.            
         
   
     
                         
                          
  Artigo 69.º Recomendações gerais
                            
                           
                             
                               
                             
     O GREVIO pode adotar, se for caso disso, recomendações gerais sobre a aplicação da presente Convenção.            
         
   
     
                         
                          
  Artigo 70.º Participação parlamentar na monitorização
                            
                           
                             
                               
                             
     1. Os parlamentos nacionais deverão ser convidados a participar na monitorização das medidas adotadas para a aplicação da presente Convenção. 
  2. As Partes deverão submeter os relatórios do GREVIO à apreciação dos respetivos parlamentos nacionais. 
  3. A Assembleia Parlamentar do Conselho da Europa deverá ser convidada a fazer regularmente um balanço da aplicação da presente Convenção.            
         
   
     
                         
                          
CAPÍTULO X 
  Relação com outros instrumentos internacionais  Artigo 71.º Relação com outros instrumentos internacionais
                            
                           
                             
                               
                             
     1. A presente Convenção não afeta as obrigações decorrentes de outros instrumentos internacionais dos quais as Partes nesta Convenção são ou se tornem parte e que contêm disposições sobre matérias regidas pela presente Convenção. 
  2. As Partes na presente Convenção podem celebrar entre si acordos bilaterais ou multilaterais sobre as matérias tratadas na presente Convenção a fim de completar ou reforçar as suas disposições ou facilitar a aplicação dos princípios nela consagrados.            
         
   
     
                         
                          
CAPÍTULO','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' XI 
  Emendas à Convenção  Artigo 72.º Emendas
                            
                           
                             
                               
                             
     1. Qualquer proposta de emenda à presente Convenção apresentada por uma Parte deverá ser comunicada ao Secretário-Geral do Conselho da Europa, o qual deverá transmiti-la aos Estados membros do Conselho da Europa, aos signatários, às Partes, à União Europeia, aos Estados convidados a assinar a presente Convenção, em conformidade com o artigo 75.º, e aos Estados convidados a aderir à presente Convenção, em conformidade com o artigo 76.º 
  2. O Comité de Ministros deverá examinar a emenda proposta e, depois de ter consultado as Partes nesta Convenção que não são membros do Conselho da Europa, pode adotar a emenda pela maioria prevista na alínea d) do artigo 20.º do Estatuto do Conselho da Europa. 
  3. O texto de qualquer emenda adotada pelo Comité de Ministros em conformidade com o n.º 2 deverá ser comunicado às Partes com vista à sua aceitação. 
  4. Qualquer emenda adotada em conformidade com o n.º 2 entra em vigor no 1.º dia do mês seguinte ao termo de um período de um mês após a data em que todas as Partes tenham comunicado ao Secretário-Geral a aceitação dessa mesma emenda.            
         
   
     
                         
                          
CAPÍTULO XII 
  Cláusulas finais  Artigo 73.º Efeitos da presente Convenção
                            
                           
                             
                               
                             
     As disposições da presente Convenção não afetam o disposto no direito interno e noutros instrumentos internacionais vinculativos, que já estejam em vigor ou que possam vir a entrar em vigor e nos termos dos quais são ou seriam concedidos direitos mais favoráveis às pessoas em matéria de prevenção e combate à violência contra as mulheres e à violência doméstica.            
         
   
     
                         
                          
  Artigo 74.º Resolução de diferendos
                            
                           
                             
                               
                             
     1. As Partes num diferendo relativo à aplicação ou interpretação das disposições da presente Convenção deverão primeiro procurar resolvê-lo por meio de negociação, conciliação, arbitragem ou por qualquer outro meio de resolução pacífica, aceite por mútuo acordo entre elas. 
  2. O Comité de Ministros do Conselho da Europa pode estabelecer procedimentos de resolução que podem ser utilizados pelas Partes num diferendo, se elas assim o entenderem.            
         
   
     
                         
                          
  Artigo 75.º Assinatura e entrada em vigor
                            
                           
                             
                               
                             
     1. A presente C','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('onvenção está aberta à assinatura dos Estados membros do Conselho da Europa, dos Estados não membros que participaram na sua elaboração e da União Europeia. 
  2. A presente Convenção está sujeita a ratificação, aceitação ou aprovação. Os instrumentos de ratificação, aceitação ou aprovação deverão ser depositados junto do Secretário-Geral do Conselho da Europa. 
  3. A presente Convenção entra em vigor no 1.º dia do mês seguinte ao termo de um período de três meses após a data em que 10 signatários, incluindo, pelo menos, oito Estados membros do Conselho da Europa, tenham manifestado o seu consentimento em ficarem vinculados pela presente Convenção, em conformidade com o disposto no n.º 2. 
  4. Para qualquer Estado referido no n.º 1 ou para a União Europeia que manifestem posteriormente o seu consentimento em ficarem vinculados pela Convenção, esta entra em vigor no 1.º dia do mês seguinte ao termo de um período de três meses após a data do depósito do respetivo instrumento de ratificação, aceitação ou aprovação.            
         
   
     
                         
                          
  Artigo 76.º Adesão à Convenção
                            
                           
                             
                               
                             
     1. Após a entrada em vigor da presente Convenção, o Comité de Ministros do Conselho da Europa pode, uma vez consultadas as Partes na Convenção e obtido o seu acordo unânime, convidar qualquer Estado não membro do Conselho que não tenha participado na elaboração da Convenção a aderir à presente Convenção. A decisão deverá ser tomada pela maioria prevista na alínea d) do artigo 20.º do Estatuto do Conselho da Europa e por unanimidade de votos dos representantes dos Estados com assento no Comité de Ministros. 
  2. Para qualquer Estado aderente, a Convenção entra em vigor no 1.º dia do mês seguinte ao termo de um período de três meses após a data do depósito do instrumento de adesão junto do Secretário-Geral do Conselho da Europa.            
         
   
     
                         
                          
  Artigo 77.º Aplicação territorial
                            
                           
                             
                               
                             
     1. Qualquer Estado ou a União Europeia podem, aquando da assinatura ou do depósito do seu instrumento de ratificação, aceitação ou aprovação, especificar o ou os territórios aos quais se aplica a presente Convenção. 
  2. Qualquer Parte pode, em qualquer momento posterior, mediante declaração dirigida ao Secretário-Geral do Conselho da Europa, estender a aplicação da presente Convenção a qualquer outro território indicado na declaração e cujas relações internacionais sejam por ela asseguradas ou em nome do qual ela esteja autorizada a assumir compromissos. A Convenção entra em vigor, para esse território, no 1.º dia do mês seguinte ao termo de um período de três meses após a d','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ata de receção da declaração pelo Secretário-Geral. 
  3. Qualquer declaração feita nos termos dos dois números anteriores, em relação a qualquer território nela indicado, pode ser retirada mediante notificação dirigida ao Secretário-Geral do Conselho da Europa. A retirada produz efeitos no 1.º dia do mês seguinte ao termo de um período de três meses após a data de receção dessa notificação pelo Secretário-Geral.            
         
   
     
                         
                          
  Artigo 78.º Reservas
                            
                           
                             
                               
                             
     1. Não são admitidas reservas às disposições da presente Convenção, com exceção das previstas nos n.os 2 e 3. 
  2. Qualquer Estado ou a União Europeia podem, aquando da assinatura ou do depósito do seu instrumento de ratificação, aceitação, aprovação ou adesão, mediante declaração dirigida ao Secretário-Geral do Conselho da Europa, declarar que se reservam o direito de não aplicar, ou de aplicar apenas em casos ou condições específicos, as disposições estabelecidas: 
  - No n.º 2 do artigo 30.º; 
  - Na alínea e) do n.º 1 e nos n.os 3 e 4 do artigo 44.º; 
  - No n.º 1 do artigo 55.º no que toca ao artigo 35.º quanto aos pequenos delitos; 
  - No artigo 58.º no que toca aos artigos 37.º, 38.º e 39.º; 
  - No artigo 59.º 
  3. Qualquer Estado ou a União Europeia podem, aquando da assinatura ou do depósito do seu instrumento de ratificação, aceitação, aprovação ou adesão, mediante declaração dirigida ao Secretário-Geral do Conselho da Europa, declarar que se reservam o direito de prever sanções não penais em vez de sanções penais para os comportamentos referidos nos artigos 33.º e 34.º 
  4. Qualquer Parte pode retirar, no todo ou em parte, uma reserva mediante declaração dirigida ao Secretário-Geral do Conselho da Europa. Esta declaração produz efeitos na data da sua receção pelo Secretário-Geral.            
         
   
     
                         
                          
  Artigo 79.º Validade e revisão das reservas
                            
                           
                             
                               
                             
     1. As reservas referidas nos n.os 2 e 3 do artigo 78.º são válidas por um período de cinco anos a contar da data de entrada em vigor da presente Convenção para a Parte em causa. Contudo, tais reservas podem ser renovadas por iguais períodos de tempo. 
  2. Dezoito meses antes do termo de vigência da reserva, o Secretário-Geral do Conselho da Europa deverá informar a Parte em causa desse termo. O mais tardar três meses antes do termo de vigência, a Parte deverá notificar o Secretário-Geral da sua intenção de manter, alterar ou retirar a reserva. Na falta de notificação pela Parte em causa, o Secretário-Geral deverá informar essa Parte de que se considera a sua reserva automaticamente renovada por um período de','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' seis meses. Se a Parte em causa não proceder à notificação da sua intenção de manter ou alterar a sua reserva antes do termo desse período, a reserva cessa os seus efeitos. 
  3. Se uma Parte formular uma reserva em conformidade com os n.os 2 e 3 do artigo 78.º, deverá, antes da sua renovação ou a pedido, apresentar uma explicação ao GREVIO quanto aos motivos que justificam mantê-la.            
         
   
     
                         
                          
  Artigo 80.º Denúncia
                            
                           
                             
                               
                             
     1. Qualquer Parte pode, em qualquer momento, denunciar a presente Convenção mediante notificação dirigida ao Secretário-Geral do Conselho da Europa. 
  2. A denúncia produz efeitos no 1.º dia do mês seguinte ao termo de um período de três meses após a data de receção da notificação pelo Secretário-Geral.            
         
   
     
                         
                          
  Artigo 81.º Notificação
                            
                           
                             
                               
                             
     O Secretário-Geral do Conselho da Europa deverá notificar os Estados membros do Conselho da Europa, os Estados não membros que participaram na elaboração da presente Convenção, todos os signatários, todas as Partes, a União Europeia e qualquer Estado convidado a aderir a ela: 
  a) De qualquer assinatura; 
  b) Do depósito de qualquer instrumento de ratificação, aceitação, aprovação ou adesão; 
  c) De qualquer data de entrada em vigor da presente Convenção, em conformidade com os artigos 75.º e 76.º; 
  d) De qualquer emenda adotada em conformidade com o artigo 72.º e da data de entrada em vigor dessa emenda; 
  e) De qualquer reserva e retirada de reserva feitas nos termos do artigo 78.º; 
  f) De qualquer denúncia feita em conformidade com o disposto no artigo 80.º; 
  g) De qualquer outro ato, notificação ou comunicação relacionados com a presente Convenção. 
  Em fé do que, os abaixo assinados, devidamente autorizados para o efeito, assinaram a presente Convenção. 
  Feita em Istambul, em 11 de maio de 2011, num único original, nas línguas francesa e inglesa, fazendo ambos os textos igualmente fé. O original deverá ser depositado nos arquivos do Conselho da Europa. O Secretário-Geral do Conselho da Europa deverá remeter uma cópia autenticada a cada um dos Estados membros do Conselho da Europa, aos Estados não membros que tenham participado na elaboração da presente Convenção, à União Europeia e a qualquer Estado convidado a aderir a ela.            
         
   
     
                         
                          
  ANEXO Privilégios e imunidades (artigo 66.º)
                            
                           
                             
                               
                             
     1. O presente anexo aplica','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('-se aos membros do GREVIO referidos no artigo 66.º da Convenção, bem como aos outros membros das delegações que visitem os países. Para efeitos do presente anexo, a expressão outros membros das delegações que visitem os países deverá abranger os peritos nacionais independentes e os especialistas referidos no n.º 9 do artigo 68.º da Convenção, os funcionários do Conselho da Europa e os intérpretes contratados pelo Conselho da Europa que acompanham o GREVIO nas suas visitas aos países. 
  2. Os membros do GREVIO e os outros membros das delegações que visitem os países gozam, no exercício das suas funções ligadas à preparação e realização das visitas aos países, bem como ao seguimento que lhes é dado, e nas deslocações relacionadas com essas funções, dos seguintes privilégios e imunidades: 
  a) Imunidade de prisão ou de detenção e de apreensão da sua bagagem pessoal, e imunidade de jurisdição em relação às declarações, orais ou escritas, e a todos os atos por eles praticados na sua capacidade oficial; 
  b) Isenção de quaisquer restrições à sua liberdade de circulação no que toca à saída do seu país de residência e ao regresso a ele, bem como à entrada no país em que exercem as suas funções e à saída do mesmo, e das formalidades de registo de estrangeiros no país em que se encontrem em visita ou em trânsito no exercício das suas funções. 
  3. Em matéria aduaneira e de controlo cambial, os membros do GREVIO e os outros membros das delegações que visitem os países gozam, no decurso das viagens realizadas no exercício das suas funções, das mesmas facilidades que as concedidas aos representantes de governos estrangeiros em missão oficial temporária. 
  4. Os documentos relativos à avaliação da aplicação da Convenção que estejam na posse dos membros do GREVIO e dos outros membros das delegações que visitem os países são invioláveis na medida em que dizem respeito à atividade do GREVIO. A correspondência oficial do GREVIO ou as comunicações oficiais dos membros do GREVIO e dos outros membros das delegações que visitem os países não podem ser nem retidas nem censuradas. 
  5. A fim de assegurar aos membros do GREVIO e aos outros membros das delegações que visitem os países uma total liberdade de expressão e uma total independência no exercício das suas funções, a imunidade de jurisdição relativamente às declarações, orais ou escritas, e a todos os atos por eles praticados no exercício das suas funções deverá continuar a ser-lhes concedida mesmo após o termo do período de exercício das suas funções. 
  6. Os privilégios e imunidades não são concedidos para benefício pessoal das pessoas referidas no n.º 1 do presente anexo, mas para assegurar o desempenho independente das suas funções no interesse do GREVIO. As imunidades concedidas às pessoas referidas no n.º 1 do presente anexo deverão ser levantadas pelo Secretário-Geral do Conselho da Europa, sempre que, em seu entender, a imunidade possa constituir um obstáculo à Justiça e desde que possa ser levantad','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a sem prejuízo dos interesses do GREVIO.','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:54  
    
  Resol. da AR n.º 20/90, de 12 de Setembro  (versão actualizada) CONVENÇÃO SOBRE OS DIREITOS DA CRIANÇA    
    
 
  
                         
                          
SUMÁRIOAprova, para ratificação, a Convenção sobre os Direitos da Criança, assinada em Nova Iorque a 26 de Janeiro de 1990 
Resolução da Assembleia da República n.º 20/90
  Convenção sobre os Direitos da Criança
  A Assembleia da República resolve, nos termos dos artigos 164.º, alínea j), e 169.º, n.º 5, da Constituição, aprovar, para ratificação, a Convenção sobre os Direitos da Criança, assinada em Nova Iorque a 26 de Janeiro de 1990, cujo original em inglês e a respectiva tradução em português seguem em anexo. 
  Aprovada em 8 de Junho de 1990.
  O Presidente da Assembleia da República, Vítor Pereira Crespo.
  
  CONVENÇÃO SOBRE OS DIREITOS DA CRIANÇA
  
  Preâmbulo
  Os Estados Partes na presente Convenção:
  Considerando que, em conformidade com os princípios proclamados pela Carta das Nações Unidas, o reconhecimento da dignidade inerente a todos os membros da família humana e dos seus direitos iguais e inalienáveis constitui o fundamento da liberdade, da justiça e da paz no mundo; 
  Tendo presente que, na Carta, os povos das Nações Unidas proclamaram, de novo, a sua fé nos direitos fundamentais do homem, na dignidade e no valor da pessoa humana e que resolveram favorecer o progresso social e instaurar melhores condições de vida numa liberdade mais ampla; 
  Reconhecendo que as Nações Unidas, na Declaração Universal dos Direitos do Homem e nos pactos internacionais relativos aos direitos do homem, proclamaram e acordaram em que toda a pessoa humana pode invocar os direitos e liberdades aqui enunciados, sem distinção alguma, nomeadamente de raça, cor, sexo, língua, religião, opinião política ou outra, de origem nacional ou social, de fortuna, nascimento ou de qualquer outra situação; 
  Recordando que, na Declaração Universal dos Direitos do Homem, a Organização das Nações Unidas proclamou que a infância tem direito a uma ajuda e assistência especiais; 
  Convictos de que a família, elemento natural e fundamental da sociedade e meio natural para o crescimento e bem-estar de todos os seus membros, e em particular das crianças, deve receber a protecção e a assistência necessárias para desempenhar plenamente o seu papel na comunidade; 
  Reconhecendo que a criança, para o desenvolvimento harmonioso da sua personalidade, deve crescer num ambiente familiar, em clima de felicidade, amor e compreensão; 
  Considerando que importa preparar plenamente a criança para viver uma vida individual na sociedade e ser educada no espírito dos ideais proclamados na Carta das Nações Unidas e, em particular, num espírito de paz, dignidade, tolerância, liberdade, igualdade e solidariedade; 
  Tendo presente que a necessidade de garantir uma protecção especial à criança foi enunciada pela Declaração de Genebra de 1924 sobre os Direitos da Criança e pela Declaração dos Dir','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('eitos da Criança adoptada pelas Nações Unidas em 1959, e foi reconhecida pela Declaração Universal dos Direitos do Homem, pelo Pacto Internacional sobre os Direitos Civis e Políticos (nomeadamente nos artigos 23.º e 24.º), pelo Pacto Internacional sobre os Direitos Económicos, Sociais e Culturais (nomeadamente o artigo 10.º) e pelos estatutos e instrumentos pertinentes das agências especializadas e organizações internacionais que se dedicam ao bem-estar da criança; 
  Tendo presente que, como indicado na Declaração dos Direitos da Criança, adoptada em 20 de Novembro de 1959 pela Assembleia Geral das Nações Unidas, a criança, por motivo da sua falta de maturidade física e intelectual, tem necessidade de uma protecção e cuidados especiais, nomeadamente de protecção jurídica adequada, tanto antes como depois do nascimento; 
  Recordando as disposições da Declaração sobre os Princípios Sociais e Jurídicos Aplicáveis a Protecção e Bem-Estar das Crianças, com Especial Referência à Adopção e Colocação Familiar nos Planos Nacional e Internacional (Resolução n.º 41/85 da Assembleia Geral, de 3 de Dezembro de 1986), o Conjunto de Regras Mínimas das Nações Unidas relativas à Administração da Justiça para Menores (Regras de Beijing) (Resolução n.º 40/33 da Assembleia Geral, de 29 de Novembro de 1985) e a Declaração sobre Protecção de Mulheres e Crianças em Situação de Emergência ou de Conflito Armado Resolução n.º 3318 (XXIX) da Assembleia Geral, de 14 de Dezembro de 1974; 
  Reconhecendo que em todos os países do mundo há crianças que vivem em condições particularmente difíceis e que importa assegurar uma atenção especial a essas crianças; 
  Tendo devidamente em conta a importância das tradições e valores culturais de cada povo para a protecção e o desenvolvimento harmonioso da criança; 
  Reconhecendo a importância da cooperação internacional para a melhoria das condições de vida das crianças em todos os países, em particular nos países em desenvolvimento; 
  acordam no seguinte:PARTE I  ARTIGO 1.º
                            
                           
                             
                               
                             
     Nos termos da presente Convenção, criança é todo o ser humano menor de 18 anos, salvo se, nos termos da lei que lhe for aplicável, atingir a maioridade mais cedo.            
         
   
     
                         
                          
  ARTIGO 2.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes comprometem-se a respeitar e a garantir os direitos previstos na presente Convenção a todas as crianças que se encontrem sujeitas à sua jurisdição, sem discriminação alguma, independentemente de qualquer consideração de raça, cor, sexo, língua, religião, opinião política ou outra da criança, de seus pais ou representantes legais, ou da sua origem nacional, étnica ou social, fortuna','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (', incapacidade, nascimento ou de qualquer outra situação. 
  2 - Os Estados Partes tomam todas as medidas adequadas para que a criança seja efectivamente protegida contra todas as formas de discriminação ou de sanção decorrentes da situação jurídica, de actividades, opiniões expressas ou convicções de seus pais, representantes legais ou outros membros da sua família.            
         
   
     
                         
                          
  ARTIGO 3.º
                            
                           
                             
                               
                             
     1 - Todas as decisões relativas a crianças, adoptadas por instituições públicas ou privadas de protecção social, por tribunais, autoridades administrativas ou órgãos legislativos, terão primacialmente em conta o interesse superior da criança. 
  2 - Os Estados Partes comprometem-se a garantir à criança a protecção e os cuidados necessários ao seu bem-estar, tendo em conta os direitos e deveres dos pais, representantes legais ou outras pessoas que a tenham legalmente a seu cargo e, para este efeito, tomam todas as medidas legislativas e administrativas adequadas. 
  3 - Os Estados Partes garantem que o funcionamento de instituições, serviços e estabelecimentos que têm crianças a seu cargo e asseguram que a sua protecção seja conforme às normas fixadas pelas autoridades competentes, nomeadamente nos domínios da segurança e saúde, relativamente ao número e qualificação do seu pessoal, bem como quanto à existência de uma adequada fiscalização.            
         
   
     
                         
                          
  ARTIGO 4.º
                            
                           
                             
                               
                             
     Os Estados Partes comprometem-se a tomar todas as medidas legislativas, administrativas e outras necessárias à realização dos direitos reconhecidos pela presente Convenção. No caso de direitos económicos, sociais e culturais, tomam essas medidas no limite máximo dos seus recursos disponíveis e, se necessário, no quadro da cooperação internacional.            
         
   
     
                         
                          
  ARTIGO 5.º
                            
                           
                             
                               
                             
     Os Estados Partes respeitam as responsabilidades, direitos e deveres dos pais e, sendo caso disso, dos membros da família alargada ou da comunidade nos termos dos costumes locais, dos representantes legais ou de outras pessoas que tenham a criança legalmente a seu cargo, de assegurar à criança, de forma compatível com o desenvolvimento das suas capacidades, a orientação e os conselhos adequados ao exercício dos direitos que lhe são reconhecidos pela presente Convenção.            
         
   
     
                         
                          
  ARTIGO 6.','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('º
                            
                           
                             
                               
                             
     1 - Os Estados Partes reconhecem à criança o direito inerente à vida.
  2 - Os Estados Partes asseguram na máxima medida possível a sobrevivência e o desenvolvimento da criança.            
         
   
     
                         
                          
  ARTIGO 7.º
                            
                           
                             
                               
                             
     1 - A criança é registada imediatamente após o nascimento e tem desde o nascimento o direito a um nome, o direito a adquirir uma nacionalidade e, sempre que possível, o direito de conhecer os seus pais e de ser educada por eles. 
  2 - Os Estados Partes garantem a realização destes direitos de harmonia com a legislação nacional e as obrigações decorrentes dos instrumentos jurídicos internacionais relevantes neste domínio, nomeadamente nos casos em que, de outro modo, a criança ficasse apátrida.            
         
   
     
                         
                          
  ARTIGO 8.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes comprometem-se a respeitar o direito da criança e a preservar a sua identidade, incluindo a nacionalidade, o nome e relações familiares, nos termos da lei, sem ingerência ilegal. 
  2 - No caso de uma criança ser ilegalmente privada de todos os elementos constitutivos da sua identidade ou de alguns deles, os Estados Partes devem assegurar-lhe assistência e protecção adequadas, de forma que a sua identidade seja restabelecida o mais rapidamente possível.            
         
   
     
                         
                          
  ARTIGO 9.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes garantem que a criança não é separada de seus pais contra a vontade destes, salvo se as autoridades competentes decidirem, sem prejuízo de revisão judicial e de harmonia com a legislação e o processo aplicáveis, que essa separação é necessária no interesse superior da criança. Tal decisão pode mostrar-se necessária no caso de, por exemplo, os pais maltratarem ou negligenciarem a criança ou no caso de os pais viverem separados e uma decisão sobre o lugar da residência da criança tiver de ser tomada. 
  2 - Em todos os casos previstos no n.º 1 todas as partes interessadas devem ter a possibilidade de participar nas deliberações e de dar a conhecer os seus pontos de vista. 
  3 - Os Estados Partes respeitam o direito da criança separada de um ou de ambos os seus pais de manter regularmente relações pessoais e contactos directos com ambos, salvo se tal se mostrar contrário ao interesse superior da c','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('riança. 
  4 - Quando a separação resultar de medidas tomadas por um Estado Parte, tais como a detenção, prisão, exílio, expulsão ou morte (incluindo a morte ocorrida no decurso de detenção, independentemente da sua causa) de ambos os pais ou de um deles, ou da criança, o Estado Parte, se tal lhe for solicitado, dará aos pais, à criança ou, sendo esse o caso, a um outro membro da família informações essenciais sobre o local onde se encontram o membro ou membros da família, a menos que a divulgação de tais informações se mostre prejudicial ao bem-estar da criança. Os Estados Partes comprometem-se, além disso, a que a apresentação de um pedido de tal natureza não determine em si mesmo consequências adversas para a pessoa ou pessoas interessadas.            
         
   
     
                         
                          
  ARTIGO 10.º
                            
                           
                             
                               
                             
     1 - Nos termos da obrigação decorrente para os Estados Partes ao abrigo do n.º 1 do artigo 9.º, todos os pedidos formulados por uma criança ou por seus pais para entrar num Estado Parte ou para o deixar, com o fim de reunificação familiar, são considerados pelos Estados Partes de forma positiva, com humanidade e diligência. Os Estados Partes garantem, além disso, que a apresentação de um tal pedido não determinará consequências adversas para os seus autores ou para os membros das suas famílias. 
  2 - Uma criança cujos pais residem em diferentes Estados Partes tem o direito de manter, salvo circunstâncias excepcionais, relações pessoais e contactos directos regulares com ambos. Para esse efeito, e nos termos da obrigação que decorre para os Estados Partes ao abrigo do n.º 2 do artigo 9.º, os Estados Partes respeitam o direito da criança e de seus pais de deixar qualquer país, incluindo o seu, e de regressar ao seu próprio país. O direito de deixar um país só pode ser objecto de restrições que, sendo previstas na lei, constituam disposições necessárias para proteger a segurança nacional, a ordem pública, a saúde ou moral públicas, ou os direitos e liberdades de outrem, e se mostrem compatíveis com os outros direitos reconhecidos na presente Convenção.            
         
   
     
                         
                          
  ARTIGO 11.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes tomam as medidas adequadas para combater a deslocação e a retenção ilícitas de crianças no estrangeiro. 
  2 - Para esse efeito, os Estados Partes promovem a conclusão de acordos bilaterais ou multilaterais ou a adesão a acordos existentes.            
         
   
     
                         
                          
  ARTIGO 12.º
                            
                           
                             
                    ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('           
                             
     1 - Os Estados Partes garantem à criança com capacidade de discernimento o direito de exprimir livremente a sua opinião sobre as questões que lhe respeitem, sendo devidamente tomadas em consideração as opiniões da criança, de acordo com a sua idade e maturidade. 
  2 - Para este fim, é assegurada à criança a oportunidade de ser ouvida nos processos judiciais e administrativos que lhe respeitem, seja directamente, seja através de representante ou de organismo adequado, segundo as modalidades previstas pelas regras de processo da legislação nacional.            
         
   
     
                         
                          
  ARTIGO 13.º
                            
                           
                             
                               
                             
     1 - A criança tem direito à liberdade de expressão. Este direito compreende a liberdade de procurar, receber e expandir informações e ideias de toda a espécie, sem considerações de fronteiras, sob forma oral, escrita, impressa ou artística ou por qualquer outro meio à escolha da criança. 
  2 - O exercício deste direito só pode ser objecto de restrições previstas na lei e que sejam necessárias: 
  a) Ao respeito dos direitos e da reputação de outrem;
  b) À salvaguarda da segurança nacional, da ordem pública, da saúde ou da moral públicas.            
         
   
     
                         
                          
  ARTIGO 14.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes respeitam o direito da criança à liberdade de pensamento, de consciência e de religião. 
  2 - Os Estados Partes respeitam os direitos e deveres dos pais e, sendo caso disso, dos respresentantes legais, de orientar a criança no exercício deste direito, de forma compatível com o desenvolvimento das suas capacidades. 
  3 - A liberdade de manifestar a sua religião ou as suas convicções só pode ser objecto de restrições previstas na lei e que se mostrem necessárias à protecção da segurança, da ordem e da saúde públicas, ou da moral e das liberdades e direitos fundamentais de outrem.            
         
   
     
                         
                          
  ARTIGO 15.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes reconhecem os direitos da criança à liberdade de associação e à liberdade de reunião pacífica. 
  2 - O exercício destes direitos só pode ser objecto de restrições previstas na lei e que sejam necessárias, numa sociedade democrática, no interesse da segurança nacional ou da segurança pública, da ordem pública, para proteger a saúde ou a moral públicas ou os direitos e liberdades de outrem.            
         
   
     
                         
           ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('               
  ARTIGO 16.º
                            
                           
                             
                               
                             
     1 - Nenhuma criança pode ser sujeita a intromissões arbitrárias ou ilegais na sua vida privada, na sua família, no seu domicílio ou correspondência, nem a ofensas ilegais à sua honra e reputação. 
  2 - A criança tem direito à protecção da lei contra tais intromissões ou ofensas.            
         
   
     
                         
                          
  ARTIGO 17.º
                            
                           
                             
                               
                             
     Os Estados Partes reconhecem a importância da função exercida pelos órgãos de comunicação social e asseguram o acesso da criança à informação e a documentos provenientes de fontes nacionais e internacionais diversas, nomeadamente aqueles que visem promover o seu bem-estar social, espiritural e moral, assim como a sua saúde física e mental. Para esse efeito, os Estados Partes devem: 
  a) Encorajar os órgãos de comunicação social a difundir informação e documentos que revistam utilidade social e cultural para a criança e se enquadrem no espírito do artigo 29.º; 
  b) Encorajar a cooperação internacional tendente a produzir, trocar e difundir informação e documentos dessa natureza, provenientes de diferentes fontes culturais, nacionais e internacionais; 
  c) Encorajar a produção e a difusão de livros para crianças;
  d) Encorajar os órgãos de comunicação social a ter particularmente em conta as necessidades linguísticas das crianças indígenas ou que pertençam a um grupo minoritário; 
  e) Favorecer a elaboração de princípios orientadores adequados à protecção da criança contra a informação e documentos prejudiciais ao seu bem-estar, nos termos do disposto nos artigos 13.º e 18.º            
         
   
     
                         
                          
  ARTIGO 18.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes diligenciam de forma a assegurar o reconhecimento do princípio segundo o qual ambos os pais têm uma responsabilidade comum na educação e no desenvolvimento da criança. A responsabilidade de educar a criança e de assegurar o seu desenvolvimento cabe primacialmente aos pais e, sendo caso disso, aos representantes legais. O interesse superior da criança deve constituir a sua preocupação fundamental. 
  2 - Para garantir e promover os direitos enunciados na presente Convenção, os Estados Partes asseguram uma assistência adequada aos pais e representantes legais da criança no exercício da responsabilidade que lhes cabe de educar a criança e garantem o estabelecimento de instituições, instalações e serviços de assistência à infância. 
  3 - Os Estados Partes tomam todas as medidas adequadas para garantir ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('às crianças cujos pais trabalhem o direito de beneficiar de serviços e instalações de assistência às crianças para os quais reúnam as condições requeridas.            
         
   
     
                         
                          
  ARTIGO 19.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes tomam todas as medidas legislativas, administrativas, sociais e educativas adequadas à protecção da criança contra todas as formas de violência física ou mental, dano ou sevícia, abandono ou tratamento negligente, maus tratos ou exploração, incluindo a violência sexual, enquanto se encontrar sob a guarda de seus pais ou de um deles, dos representantes legais ou de qualquer outra pessoa a cuja guarda haja sido confiada. 
  2 - Tais medidas de protecção devem incluir, consoante o caso, processos eficazes para o estabelecimento de programas sociais destinados a assegurar o apoio necessário à criança e àqueles a cuja guarda está confiada, bem como outras formas de prevenção, e para identificação, elaboração de relatório, transmissão, investigação, tratamento e acompanhamento dos casos de maus tratos infligidos à criança, acima descritos, compreendendo igualmente, se necessário, processos de intervenção judicial.            
         
   
     
                         
                          
  ARTIGO 20.º
                            
                           
                             
                               
                             
     1 - A criança temporária ou definitivamente privada do seu ambiente familiar ou que, no seu interesse superior, não possa ser deixada em tal ambiente tem direito à protecção e assistência especiais do Estado. 
  2 - Os Estados Partes asseguram a tais crianças uma protecção alternativa, nos termos da sua legislação nacional. 
  3 - A protecção alternativa pode incluir, entre outras, a forma de colocação familiar, a kafala do direito islâmico, a adopção ou, no caso de tal se mostrar necessário, a colocação em estabelecimentos adequados de assistência às crianças. Ao considerar tais soluções, importa atender devidamente à necessidade de assegurar continuidade à educação da criança, bem como à sua origem étnica, religiosa, cultural e linguística.            
         
   
     
                         
                          
  ARTIGO 21.º
                            
                           
                             
                               
                             
     Os Estados Partes que reconhecem e ou permitem a adopção asseguram que o interesse superior da criança será a consideração primordial neste domínio e: 
  a) Garantem que a adopção de uma criança é autorizada unicamente pelas autoridades competentes, que, nos termos da lei e do processo aplicáveis e baseando-se em todas as informações credíveis relativas ao caso concreto, verificam que ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a adopção pode ter lugar face à situação da criança relativamente a seus pais, parentes e representantes legais e que, se necessário, as pessoas interessadas deram em consciência o seu consentimento à adopção, após se terem socorrido de todos os pareceres julgados necessários; 
  b) Reconhecem que a adopção internacional pode ser considerada como uma forma alternativa de protecção da criança se esta não puder ser objecto de uma medida de colocação numa família de acolhimento ou adoptiva, ou se não puder ser convenientemente educada no seu país de origem; 
  c) Garantem à criança sujeito de adopção internacional o gozo das garantias e normas equivalentes às aplicáveis em caso de adopção nacional; 
  d) Tomam todas as medidas adequadas para garantir que, em caso de adopção internacional, a colocação da criança se não traduza num benefício material indevido para os que nela estejam envolvidos; 
  e) Promovem os objectivos deste artigo pela conclusão de acordos ou tratados bilaterais ou multilaterais, consoante o caso, e neste domínio procuram assegurar que as colocações de crianças no estrangeiro sejam efectuadas por autoridades ou organismos competentes.            
         
   
     
                         
                          
  ARTIGO 22.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes tomam as medidas necessárias para que a criança que requeira o estatuto de refugiado ou que seja considerada refugiado, de harmonia com as normas e processos de direito internacional ou nacional aplicáveis, quer se encontre só, quer acompanhada de seus pais ou de qualquer outra pessoa, beneficie de adequada protecção e assistência humanitária, de forma a permitir o gozo dos direitos reconhecidos pela presente Convenção e outros instrumentos internacionais relativos aos direitos do homem ou de carácter humanitário, de que os referidos Estados sejam Partes. 
  2 - Para esse efeito, os Estados Partes cooperam, nos termos considerados adequados, nos esforços desenvolvidos pela Organização das Nações Unidas e por outras organizações intergovernamentais ou não governamentais competentes que colaborem com a Organização das Nações Unidas na protecção e assistência de crianças que se encontrem em tal situação, e na procura dos pais ou de outros membros da família da criança refugiada, de forma a obter as informações necessárias à reunificação familiar. No caso de não terem sido encontrados os pais ou outros membros da família, a criança deve beneficiar, à luz dos princípios enunciados na presente Convenção, da protecção assegurada a toda a criança que, por qualquer motivo, se encontre privada temporária ou definitivamente do seu ambiente familiar.            
         
   
     
                         
                          
  ARTIGO 23.º
                            
                           
                             
       ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                        
                             
     1 - Os Estados Partes reconhecem à criança mental e fisicamente deficiente o direito a uma vida plena e decente em condições que garantam a sua dignidade, favoreçam a sua autonomia e facilitem a sua participação activa na vida da comunidade. 
  2 - Os Estados Partes reconhecem à criança deficiente o direito de beneficiar de cuidados especiais e encorajam e asseguram, na medida dos recursos disponíveis, a prestação à criança que reúna as condições requeridas e àqueles que a tenham a seu cargo de uma assistência correspondente ao pedido formulado e adaptada ao estado da criança e à situação dos pais ou daqueles que a tiverem a seu cargo. 
  3 - Atendendo às necessidades particulares da criança deficiente, a assistência fornecida nos termos do n.º 2 será gratuita sempre que tal seja possível, atendendo aos recursos financeiros dos pais ou daqueles que tiverem a criança a seu cargo, e é concebida de maneira a que a criança deficiente tenha efectivo acesso à educação, à formação, aos cuidados de saúde, à reabilitação, à preparação para o emprego e a actividades recreativas, e beneficie desses serviços de forma a assegurar uma integração social tão completa quanto possível e o desenvolvimento pessoal, incluindo nos domínios cultural e espiritual. 
  4 - Num espírito de cooperação internacional, os Estados Partes promovem a troca de informações pertinentes no domínio dos cuidados preventivos de saúde e do tratamento médico, psicológico e funcional das crianças deficientes, incluindo a difusão de informações respeitantes aos métodos de reabilitação e aos serviços de formação profissional, bem como o acesso a esses dados, com vista a permitir que os Estados Partes melhorem as suas capacidades e qualificações e alarguem a sua experiência nesses domínios. A este respeito atender-se-á de forma particular às necessidades dos países em desenvolvimento.            
         
   
     
                         
                          
  ARTIGO 24.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes reconhecem à criança o direito a gozar do melhor estado de saúde possível e a beneficiar de serviços médicos e de reeducação. Os Estados Partes velam pela garantia de que nenhuma criança seja privada do direito de acesso a tais serviços de saúde. 
  2 - Os Estados Partes prosseguem a realização integral deste direito e, nomeadamente, tomam medidas adequadas para: 
  a) Fazer baixar a mortalidade entre as crianças de tenra idade e a mortalidade infantil; 
  b) Assegurar a assistência médica e os cuidados de saúde necessários a todas as crianças, enfatizando o desenvolvimento dos cuidados de saúde primários; 
  c) Combater a doença e a má nutrição, no quadro dos cuidados de saúde primários, graças nomeadamente à utilização de técnicas facilmente disponíveis e ao fornecimento de aliment','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('os nutritivos e de água potável, tendo em consideração os perigos e riscos da poluição do ambiente; 
  d) Assegurar às mães os cuidados de saúde, antes e depois do nascimento;
  e) Assegurar que todos os grupos da população, nomeadamente os pais e as crianças, sejam informados, tenham acesso e sejam apoiados na utilização de conhecimentos básicos sobre a saúde e a nutrição da criança, as vantagens do aleitamento materno, a higiene e a salubridade do ambiente, bem como a prevenção de acidentes; 
  f) Desenvolver os cuidados preventivos de saúde, os conselhos aos pais e a educação sobre planeamento familiar e os serviços respectivos. 
  3 - Os Estados Partes tomam todas as medidas eficazes e adequadas com vista a abolir as práticas tradicionais prejudiciais à saúde das crianças. 
  4 - Os Estados Partes comprometem-se a promover e a encorajar a cooperação internacional, de forma a garantir progressivamente a plena realização do direito reconhecido no presente artigo. A este respeito atender-se-á de forma particular às necessidades dos países em desenvolvimento.            
         
   
     
                         
                          
  ARTIGO 25.º
                            
                           
                             
                               
                             
     Os Estados Partes reconhecem à criança que foi objecto de uma medida de colocação num estabelecimento pelas autoridades competentes, para fins de assistência, protecção ou tratamento físico ou mental, o direito à revisão periódica do tratamento a que foi submetida e de quaisquer outras circunstâncias ligadas à sua colocação.            
         
   
     
                         
                          
  ARTIGO 26.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes reconhecem à criança o direito de beneficiar da segurança social e tomam todas as medidas necessárias para assegurar a plena realização deste direito, nos termos da sua legislação nacional. 
  2 - As prestações, se a elas houver lugar, devem ser atribuídas tendo em conta os recursos e a situação da criança e das pessoas responsáveis pela sua manutenção, assim como qualquer outra consideração relativa ao pedido de prestação feito pela criança ou em seu nome.            
         
   
     
                         
                          
  ARTIGO 27.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes reconhecem à criança o direito a um nível de vida suficiente, de forma a permitir o seu desenvolvimento físico, mental, espiritual, moral e social. 
  2 - Cabe primacialmente aos pais e às pessoas que têm a criança a seu cargo a responsabilidade de assegurar, dentro das suas possibilidades e disponibilidades económicas, as condiçõ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('es de vida necessárias ao desenvolvimento da criança. 
  3 - Os Estados Partes, tendo em conta as condições nacionais e na medida dos seus meios, tomam as medidas adequadas para ajudar os pais e outras pessoas que tenham a criança a seu cargo a realizar este direito e asseguram, em caso de necessidade, auxílio material e programas de apoio, nomeadamente no que respeita à alimentação, vestuário e alojamento. 
  4 - Os Estados Partes tomam todas as medidas adequadas tendentes a assegurar a cobrança da pensão alimentar devida à criança, de seus pais ou de outras pessoas que tenham a criança economicamente a seu cargo, tanto no seu território quanto no estrangeiro. Nomeadamente, quando a pessoa que tem a criança economicamente a seu cargo vive num Estado diferente do da criança, os Estados Partes devem promover a adesão a acordos internacionais ou a conclusão de tais acordos, assim como a adopção de quaisquer outras medidas julgadas adequadas.            
         
   
     
                         
                          
  ARTIGO 28.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes reconhecem o direito da criança a educação e tendo, nomeadamente, em vista assegurar progressivamente o exercício desse direito na base da igualdade de oportunidades: 
  a) Tornam o ensino primário obrigatório e gratuito para todos;
  b) Encorajam a organização de diferentes sistemas de ensino secundário, geral e profissional, tornam estes públicos e acessíveis a todas as crianças e tomam medidas adequadas, tais como a introdução da gratuitidade do ensino e a oferta de auxílio financeiro em caso de necessidade; 
  c) Tornam o ensino superior acessível a todos, em função das capacidades de cada um, por todos os meios adequados; 
  d) Tornam a informação e a orientação escolar e profissional públicas e acessíveis a todas as crianças; 
  e) Tomam medidas para encorajar a frequência escolar regular e a redução das taxas de abandono escolar. 
  2 - Os Estados Partes tomam todas as medidas adequadas para velar por que a disciplina escolar seja assegurada de forma compatível com a dignidade humana da criança e nos termos da presente Convenção. 
  3 - Os Estados Partes promovem e encorajam a cooperação internacional no domínio da educação, nomeadamente de forma a contribuir para a eliminação da ignorância e do analfabetismo no mundo e a facilitar o acesso aos conhecimentos científicos e técnicos e aos modernos métodos de ensino. A este respeito atender-se-á de forma particular às necessidades dos países em desenvolvimento.            
         
   
     
                         
                          
  ARTIGO 29.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes acordam em que a educação da criança deve destinar-se a:
','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('  a) Promover o desenvolvimento da personalidade da criança, dos seus dons e aptidões mentais e físicos na medida das suas potencialidades; 
  b) Inculcar na criança o respeito pelos direitos do homem e liberdades fundamentais e pelos princípios consagrados na Carta das Nações Unidas; 
  c) Inculcar na criança o respeito pelos pais, pela sua identidade cultural, língua e valores, pelos valores nacionais do país em que vive, do país de origem e pelas civilizações diferentes da sua; 
  d) Preparar a criança para assumir as responsabilidades da vida numa sociedade livre, num espírito de compreensão, paz, tolerância, igualdade entre os sexos e de amizade entre todos os povos, grupos étnicos, nacionais e religiosos e com pessoas de origem indígena; 
  e) Promover o respeito da criança pelo meio ambiente.
  2 - Nenhuma disposição deste artigo ou do artigo 28.º pode ser interpretada de forma a ofender a liberdade dos indivíduos ou das pessoas colectivas de criar e dirigir estabelecimentos de ensino, desde que sejam respeitadas os princípios enunciados no n.º 1 do presente artigo e que a educação ministrada nesses estabelecimentos seja conforme às regras mínimas prescritas pelo Estado.            
         
   
     
                         
                          
  ARTIGO 30.º
                            
                           
                             
                               
                             
     Nos Estados em que existam minorias étnicas, religiosas ou linguísticas ou pessoas de origem indígena, nenhuma criança indígena ou que pertença a uma dessas minorias poderá ser privada do direito de, conjuntamente com membros do seu grupo, ter a sua própria vida cultural, professar e praticar a sua própria religião ou utilizar a sua própria língua.            
         
   
     
                         
                          
  ARTIGO 31.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes reconhecem à criança o direito ao repouso e aos tempos livres, o direito de participar em jogos e actividades recreativas próprias da sua idade e de participar livremente na vida cultural e artística. 
  2 - Os Estados Partes respeitam e promovem o direito da criança de participar plenamente na vida cultural e artística e encorajam a organização, em seu benefício, de formas adequadas de tempos livres e de actividades recreativas, artísticas e culturais, em condições de igualdade.            
         
   
     
                         
                          
  ARTIGO 32.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes reconhecem à criança o direito de ser protegida contra a exploração económica ou a sujeição a trabalhos perigosos ou capazes de comprometer a sua educação, prejudic','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ar a sua saúde ou o seu desenvolvimento físico, mental, espiritual, moral ou social. 
  2 - Os Estados Partes tomam medidas legislativas, administrativas, sociais e educativas para assegurar a aplicação deste artigo. Para esse efeito, e tendo em conta as disposições relevantes de outros instrumentos jurídicos internacionais, os Estados Partes devem, nomeadamente: 
  a) Fixar uma idade mínima ou idades mínimas para a admissão a um emprego;
  b) Adoptar regulamentos próprios relativos à duração e às condições de trabalho; e 
  c) Prever penas ou outras sanções adequadas para assegurar uma efectiva aplicação deste artigo.            
         
   
     
                         
                          
  ARTIGO 33.º
                            
                           
                             
                               
                             
     Os Estados Partes adoptam todas as medidas adequadas, incluindo medidas legislativas, administrativas, sociais e educativas para proteger as crianças contra o consumo ilícito de estupefacientes e de substâncias psicotrópicas, tais como definidos nas convenções internacionais aplicáveis, e para prevenir a utilização de crianças na produção e no tráfico ilícitos de tais substâncias.            
         
   
     
                         
                          
  ARTIGO 34.º
                            
                           
                             
                               
                             
     Os Estados Partes comprometem-se a proteger a criança contra todas as formas de exploração e de violência sexuais. Para esse efeito, os Estados Partes devem, nomeadamente, tomar todas as medidas adequadas, nos planos nacional, bilateral e multilateral para impedir: 
  a) Que a criança seja incitada ou coagida dedicar-se a uma actividade sexual ilícita; 
  b) Que a criança seja explorada para fins de prostituição ou de outras práticas sexuais ilícitas; 
  c) Que a criança seja explorada na produção de espectáculos ou de material de natureza pornográfica.            
         
   
     
                         
                          
  ARTIGO 35.º
                            
                           
                             
                               
                             
     Os Estados Partes tomam todas as medidas adequadas, nos planos nacional, bilateral e multilateral, para impedir o rapto, a venda ou o tráfico de crianças, independentemente do seu fim ou forma.            
         
   
     
                         
                          
  ARTIGO 36.º
                            
                           
                             
                               
                             
     Os Estados Partes protegem a criança contra todas as formas de exploração prejudiciais a qualquer aspecto do seu bem-estar.            
         
   
     
                         
                          
  ARTIGO 37.º
','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('                            
                           
                             
                               
                             
     Os Estados Partes garantem que:
  a) Nenhuma criança será submetida à tortura ou a penas ou tratamentos cruéis, desumanos ou degradantes. A pena de morte e a prisão perpétua sem possibilidade de libertação não serão impostas por infracções cometidas por pessoas com menos de 18 anos; 
  b) Nenhuma criança será privada de liberdade de forma ilegal ou arbitrária: a captura, detenção ou prisão de uma criança devem ser conformes à lei, serão utilizadas unicamente como medida de último recurso e terão a duração mais breve possível; 
  c) A criança privada de liberdade deve ser tratada com a humanidade e o respeito devidos à dignidade da pessoa humana e de forma consentânea com as necessidades das pessoas da sua idade. Nomeadamente, a criança privada de liberdade deve ser separada dos adultos, a menos que, no superior interesse da criança, tal não pareça aconselhável e tem o direito de manter contacto com a sua família através de correspondência e visitas, salvo em circunstâncias excepcionais; 
  d) A criança privada de liberdade tem o direito de aceder rapidamente à assistência jurídica ou a outra assistência adequada e o direito de impugnar a legalidade da sua privação de liberdade perante um tribunal ou outra autoridade competente, independente e imparcial, bem como o direito a uma rápida decisão sobre tal matéria.            
         
   
     
                         
                          
  ARTIGO 38.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes comprometem-se a respeitar e a fazer respeitar as normas de direito humanitário internacional que lhes sejam aplicáveis em caso de conflito armado e que se mostrem relevantes para a criança. 
  2 - Os Estados Partes devem tomar todas as medidas possíveis na prática para garantir que nenhuma criança com menos de 15 anos participe directamente nas hostilidades. 
  3 - Os Estados Partes devem abster-se de incorporar nas forças armadas as pessoas que não tenham a idade de 15 anos. No caso de incorporação de pessoas de idade superior a 15 anos e inferior a 18 anos, os Estados Partes devem incorporar prioritariamente os mais velhos. 
  4 - Nos termos das obrigações contraídas à luz do direito internacional humanitário para a protecção da população civil em caso de conflito armado, os Estados Partes na presente Convenção devem tomar todas as medidas possíveis na prática para assegurar protecção e assistência às crianças afectadas por um conflito armado.            
         
   
     
                         
                          
  ARTIGO 39.º
                            
                           
                             
                               
                             
     Os Estados Partes tomam ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('todas as medidas adequadas para promover a recuperação física e psicológica e a reinserção social da criança vítima de qualquer forma de negligência, exploração ou sevícias, de tortura ou qualquer outra pena ou tratamento cruéis, desumanos ou degradantes ou de conflito armado. Essas recuperação e reinserção devem ter lugar num ambiente que favoreça a saúde, o respeito por si próprio e a dignidade da criança.            
         
   
     
                         
                          
  ARTIGO 40.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes reconhecem à criança suspeita, acusada ou que se reconheceu ter infringido a lei penal o direito a um tratamento capaz de favorecer o seu sentido de dignidade e valor, reforçar o seu respeito pelos direitos do homem e as liberdades fundamentais de terceiros e que tenha em conta a sua idade e a necessidade de facilitar a sua reintegração social e o assumir de um papel construtivo no seio da sociedade. 
  2 - Para esse efeito, e atendendo às disposições pertinentes dos instrumentos jurídicos internacionais, os Estados Partes garantem, nomeadamente, que: 
  a) Nenhuma criança seja suspeita, acusada ou reconhecida como tendo infringindo a lei penal por acções ou omissões que, no momento da sua prática, não eram proibidas pelo direito nacional ou internacional; 
  b) A criança suspeita ou acusada de ter infringido a lei penal tenha, no mínimo, direito às garantias seguintes: 
  i) Presumir-se inocente até que a sua culpabilidade tenha sido legalmente estabelecida; 
  ii) A ser informada pronta é directamente das acusações formuladas contra si ou, se necessário, através de seus pais representantes legais, e beneficiar de assistência jurídica ou de outra assistência adequada para a preparação e apresentação da sua defesa; 
  iii) A sua causa ser examinada sem demora por uma autoridade competente, independente e imparcial ou por um tribunal, de forma equitativa nos termos da lei, na presença do seu defensor ou de outrem assegurando assistência adequada e, a menos que tal se mostre contrário ao interesse superior da criança, nomeadamente atendendo à sua idade ou situação, na presença de seus pais ou representantes legais; 
  iv) A não ser obrigada a testemunhar ou a confessar-se culpada; a interrogar ou fazer interrogar as testemunhas de acusação e a obter a comparência e o interrogatório das testemunhas de defesa em condições de igualdade; 
  v) No caso de se considerar que infringiu a lei penal, a recorrer dessa decisão e das medidas impostas em sequência desta para uma autoridade superior, competente, independente e imparcial, ou uma autoridade judicial, nos termos da lei; 
  vi) A fazer-se assistir gratuitamente por um intérprete, se não compreender ou falar a língua utilizada; 
  vii) A ver plenamente respeitada a sua vida privada em todos os momentos do processo. 
  3 - Os Es','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('tados Partes procuram promover o estabelecimento de leis, processos, autoridades e instituições especificamente adequadas a crianças suspeitas, acusadas ou reconhecidas como tendo infringido a lei penal, e, nomeadamente: 
  a) O estabelecimento de uma idade mínima abaixo da qual se presume que as crianças não têm capacidade para infringir a lei penal; 
  b) Quando tal se mostre possível e desejável, a adopção de medidas relativas a essas crianças sem recurso ao processo judicial, assegurando-se o pleno respeito dos direitos do homem e das garantias previstas pela lei. 
  4 - Um conjunto de disposições relativas, nomeadamente, à assistência, orientação e controlo, conselhos, regime de prova, colocação familiar, programas de educação geral e profissional, bem como outras soluções alternativas às institucionais, serão previstas de forma a assegurar às crianças um tratamento adequado ao seu bem-estar e proporcionado à sua situação e à infracção.            
         
   
     
                         
                          
  ARTIGO 41.º
                            
                           
                             
                               
                             
     Nenhuma disposição da presente Convenção afecta as disposições mais favoráveis à realização dos direitos da criança que possam figurar: 
  a) Na legislação de um Estado Parte;
  b) No direito internacional em vigor para esse Estado.            
         
   
     
                         
                          
PARTE II  ARTIGO 42.º
                            
                           
                             
                               
                             
     Os Estados Partes comprometem-se a tornar amplamente conhecidos, por meios activos e adequados, os princípios e as disposições da presente Convenção, tanto pelos adultos como pelas crianças.            
         
   
     
                         
                          
  ARTIGO 43.º
                            
                           
                             
                               
                             
     1 - Com o fim de examinar os progressos realizados pelos Estados Partes no cumprimento das obrigações que lhes cabem nos termos da presente Convenção, é instituído um Comité dos Direitos da Criança, que desempenha as funções seguidamente definidas. 
  2 - O Comité é composto de 10 peritos de alta autoridade moral e de reconhecida competência no domínio abrangido pela presente Convenção. Os membros do Comité são eleitos pelos Estados Partes de entre os seus nacionais e exercem as suas funções a título pessoal, tendo em consideração a necessidade de assegurar uma repartição geográfica equitativa e atendendo aos principais sistemas jurídicos. 
  3 - Os membros do Comité são eleitos por escrutínio secreto de entre uma lista de candidatos designados pelos Estados Partes. Cada Estado Parte pode designar um perito de entre os seus nacionais. 
  4 -','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' A primeira eleição tem lugar nos seis meses seguintes à data da entrada em vigor da presente Convenção e, depois disso, todos os dois anos. Pelo menos quatro meses antes da data de cada eleição, o Secretário-Geral da Organização das Nações Unidas convida, por escrito, os Estados Partes a proporem os seus candidatos num prazo de dois meses. O Secretário-Geral elabora, em seguida, a lista alfabética dos candidatos assim apresentados, indicando por que Estado foram designados, e comunica-a aos Estados Partes na presente Convenção. 
  5 - As eleições realizam-se aquando das reuniões dos Estados Partes convocadas pelo Secretário-Geral para a sede da Organização das Nações Unidas. Nestas reuniões, em que o quórum é constituído por dois terços dos Estados Partes, são eleitos para o Comité os candidatos que obtiverem o maior número de votos e a maioria absoluta dos votos dos representantes dos Estados Partes presentes e votantes. 
  6 - Os membros do Comité são eleitos por um período de quatro anos. São reelegíveis no caso de recandidatura. O mandato de cinco dos membros eleitos na primeira eleição termina ao fim de dois anos. O presidente da reunião tira à sorte, imediatamente após a primeira eleição os nomes destes cinco elementos. 
  7 - Em caso de morte ou de demissão de um membro do Comité ou se, por qualquer outra razão, um membro declarar que não pode continuar a exercer funções no seio do Comité, o Estado Parte que havia proposto a sua candidatura designa um outro perito, de entre os seus nacionais, para preencher a vaga até ao termo do mandato, sujeito a aprovação do Comité. 
  8 - O Comité adopta o seu regulamento interno.
  9 - O Comité elege o seu secretariado por um período de dois anos.
  10 - As reuniões do Comité têm habitualmente lugar na sede da Organização das Nações Unidas ou em qualquer outro lugar julgado conveniente e determinado pelo Comité. O Comité reúne em regra anualmente. A duração das sessões do Comité é determinada, e se necessário revista, por uma reunião dos Estados Partes na presente Convenção, sujeita à aprovação da Assembleia Geral. 
  11 - O Secretário-Geral da Organização das Nações Unidas põe à disposição do Comité o pessoal e as instalações necessárias para o desempenho eficaz das funções que lhe são confiadas ao abrigo da presente Convenção. 
  12 - Os membros do Comité instituído pela presente Convenção recebem, com a aprovação da Assembleia Geral, emolumentos provenientes dos recursos financeiros das Nações Unidas, segundo as condições e modalidades fixadas pela Assembleia Geral.            
         
   
     
                         
                          
  ARTIGO 44.º
                            
                           
                             
                               
                             
     1 - Os Estados Partes comprometem-se a apresentar ao Comité, através do Secretário-Geral da Organização das Nações Unidas, relatórios sobre as medidas que hajam adoptado para dar aplicaç','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ão aos direitos reconhecidos pela Convenção e sobre os progressos realizados no gozo desses direitos: 
  a) Nos dois anos subsequentes à data da entrada em vigor da presente Convenção para os Estados Partes; 
  b) Em seguida, de cinco em cinco anos.
  2 - Os relatórios apresentados em aplicação do presente artigo devem indicar os factores e as dificuldades, se a elas houver lugar, que impeçam o cumprimento, pelos Estados Partes, das obrigações decorrentes da presente Convenção. Devem igualmente conter informações suficientes para dar ao Comité uma ideia precisa da aplicação da Convenção no referido país. 
  3 - Os Estados Partes que tenham apresentado ao Comité um relatório inicial completo não necessitam de repetir, nos relatórios subsequentes, submetidos nos termos do n.º 1, alínea b), as informações de base anteriormente comunicadas. 
  4 - O Comité pode solicitar aos Estados Partes informações complementares relevantes para a aplicação da Convenção. 
  5 - O Comité submete de dois em dois anos a Assembleia Geral, através do Conselho Económico e Social, um relatório das suas actividades. 
  6 - Os Estados Partes asseguram aos seus relatórios uma larga difusão nos seus próprios países.            
         
   
     
                         
                          
  ARTIGO 45.º
                            
                           
                             
                               
                             
     De forma a promover a aplicação efectiva da Convenção e a encorajar a cooperação internacional no domínio coberto pela Convenção: 
  a) As agências especializadas, a UNICEF e outros órgãos das Nações Unidas podem fazer-se representar quando for apreciada a aplicação de disposições da presente Convenção que se inscrevam no seu mandato. O Comité pode convidar as agências especializadas, a UNICEF e outros organismos competentes considerados relevantes a fornecer o seu parecer técnico sobre a aplicação da convenção no âmbito dos seus respectivos mandatos. O Comité pode convidar as agências especializadas, a UNICEF e outros órgãos das Nações Unidas a apresentar relatórios sobre a aplicação da Convenção nas áreas relativas aos seus domínios de actividade; 
  b) O Comité transmite, se o julgar necessário, às agências especializadas, à UNICEF e a outros organismos competentes os relatórios dos Estados Partes que contenham pedidos ou indiquem necessidades de conselho ou de assistência técnicos, acompanhados de eventuais observações e sugestões do Comité relativos àqueles pedidos ou indicações; 
  c) O Comité pode recomendar à Assembleia Geral que solicite ao Secretário-Geral a realização, para o Comité, de estudos sobre questões específicas relativas aos direitos da criança; 
  d) O Comité pode fazer sugestões e recomendações de ordem geral com base nas informações recebidas em aplicação dos artigos 44.º e 45.º da presente Convenção. Essas sugestões e recomendações de ordem geral são transmitidas aos Estados interessados e ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('levadas ao conhecimento da Assembleia Geral, acompanhadas, se necessário, dos comentários dos Estados Partes.            
         
   
     
                         
                          
PARTE III  ARTIGO 46.º
                            
                           
                             
                               
                             
     A presente Convenção está aberta à assinatura de todos os Estados.            
         
   
     
                         
                          
  ARTIGO 47.º
                            
                           
                             
                               
                             
     A presente Convenção está sujeita a ratificação. Os instrumentos de ratificação serão depositados junto do Secretário-Geral da Organização das Nações Unidas.            
         
   
     
                         
                          
  ARTIGO 48.º
                            
                           
                             
                               
                             
     A presente Convenção está aberta a adesão de todos os Estados. A adesão far-se-á pelo depósito de um instrumento de adesão junto do Secretário-Geral da Organização das Nações Unidas.            
         
   
     
                         
                          
  ARTIGO 49.º
                            
                           
                             
                               
                             
     1 - A presente Convenção entrará em vigor no 30.º dia após a data do depósito junto do Secretário-Geral da Organização das Nações Unidas do 20.º instrumento de ratificação ou de adesão. 
  2 - Para cada um dos Estados que ratificarem a presente Convenção ou a ela aderirem após o depósito do 20.º instrumento de ratificação ou de adesão, a Convenção entrará em vigor no 30.º dia após a data do depósito, por parte desse Estado, do seu instrumento de ratificação ou de adesão.            
         
   
     
                         
                          
  ARTIGO 50.º
                            
                           
                             
                               
                             
     1 - Qualquer Estado Parte pode propor uma emenda e depositar o seu texto junto do Secretário-Geral da Organização das Nações Unidas. O Secretário-Geral transmite, em seguida, a proposta de emenda aos Estados Partes na presente Convenção, solicitando que lhe seja comunicado se são favoráveis à convocação de uma conferência de Estados Partes para apreciação e votação da proposta. Se, nos quatro meses subsequentes a essa comunicação, pelo menos um terço dos Estados Partes se declarar a favor da realização da referida conferência, o Secretário-Geral convocá-la-á sob os auspícios da Organização das Nações Unidas. As emendas adoptadas pela maioria dos Estados Partes presentes e votantes na conferência são submetidas à Assembleia','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' Geral das Nações Unidas para aprovação. 
  2 - As emendas adoptadas nos termos do disposto no n.º 1 do presente artigo entram em vigor quando aprovadas pela Assembleia Geral das Nações Unidas e aceites por uma maioria de dois terços dos Estados Partes. 
  3 - Quando uma emenda entrar em vigor, terá força vinculativa para os Estados que a hajam aceite, ficando os outros Estados Partes ligados pelas disposições da presente Convenção e por todas as emendas anteriores que tenham aceite.            
         
   
     
                         
                          
  ARTIGO 51.º
                            
                           
                             
                               
                             
     1 - O Secretário-Geral da Organização das Nações Unidas recebe e comunica a todos os Estados o texto das reservas que forem feitas pelos Estados no momento da ratificação ou da adesão. 
  2 - Não é autorizada nenhuma reserva incompatível com o objecto e com o fim da presente Convenção. 
  3 - As reservas podem ser retiradas em qualquer momento por via de notificação dirigida ao Secretário-Geral da Organização das Nações Unidas, o qual informará todos os Estados Partes na Convenção. A notificação produz efeitos na data da sua recepção pelo Secretário-Geral.            
         
   
     
                         
                          
  ARTIGO 52.º
                            
                           
                             
                               
                             
     Um Estado Parte pode denunciar a presente Convenção por notificação escrita dirigida ao Secretário-Geral da Organização das Nações Unidas. A denúncia produz efeitos um ano após a data de recepção da notificação pelo Secretário-Geral.            
         
   
     
                         
                          
  ARTIGO 53.º
                            
                           
                             
                               
                             
     O Secretário-Geral da Organização das Nações Unidas é designado como depositário da presente Convenção.            
         
   
     
                         
                          
  ARTIGO 54.º
                            
                           
                             
                               
                             
     A presente Convenção, cujos textos em inglês, árabe, chinês, espanhol, francês e russo fazem igualmente fé, será depositada junto do Secretário-Geral da Organização das Nações Unidas. 
  Em fé do que os plenipotenciários abaixo assinados, devidamente habilitados pelos seus governos respectivos, assinaram a Convenção. 
  
  Feita em Nova Iorque, aos 20 dias do mês de Novembro de 1989.','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:9  
    
  Portaria n.º 138-E/2021, de 01 de Julho  (versão actualizada) DOCUMENTOS COMPROVATIVOS DA ATRIBUIÇÃO DO ESTATUTO DE VÍTIMA    
    
 
  
                         
                          
SUMÁRIOAprova os modelos dos documentos comprovativos da atribuição do estatuto de vítima e do estatuto de vítima especialmente vulnerável, incluindo por crime de violência doméstica
Portaria n.º 138-E/2021, de 1 de julho
  À pessoa singular que sofreu um dano, nomeadamente um atentado à sua integridade física ou psíquica, um dano emocional ou moral, ou um dano patrimonial, diretamente causado por um crime, ou aos familiares dessa pessoa que haja falecido em consequência direta de um crime e que tenham sofrido um dano em consequência dessa morte, assistem um conjunto de direitos de informação, de assistência, de proteção e de participação ativa no processo penal.
  Estes direitos encontram-se previstos na Lei de Proteção de Testemunhas, no Código de Processo Penal e, mais concretamente, no Estatuto da Vítima, aprovado em anexo à Lei n.º 130/2015, de 4 de setembro, que inclui o estatuto de vítima especialmente vulnerável e, no caso das vítimas de violência doméstica, no estatuto que lhes é específico e que se encontra previsto no artigo 14.º da Lei n.º 112/2009, de 16 de setembro, na sua redação atual.
  Com a consagração formal, em 2015, da vítima como sujeito processual e a publicação do referido Estatuto da Vítima, as vítimas do crime de violência doméstica, crime que integra a criminalidade violenta, passaram a ser sempre consideradas vítimas especialmente vulneráveis. Por essa via, passou a ser atribuído às vítimas de violência doméstica, de forma autónoma e especial, de acordo com o previsto na Lei n.º 130/2015, de 4 de setembro, e no n.º 3 do artigo 67.º-A do Código de Processo Penal, aprovado pelo Decreto-Lei n.º 78/87, de 17 de fevereiro, na sua atual redação, um estatuto de vítima especialmente vulnerável.
  Este procedimento tem demonstrado constituir um fator acrescido de incompreensão para a vítima sobre a sua intervenção processual, dificultando, ainda, a interpretação dos seus direitos e deveres, conforme foi constatado pela Comissão Técnica Multidisciplinar para a Melhoria da Prevenção e Combate à Violência Doméstica, cuja recomendação de revisão dos modelos de atribuição do estatuto de vítima foi acolhida na Resolução do Conselho de Ministros n.º 139/2019, de 19 de agosto, que aprovou um conjunto de medidas e ações prioritárias de prevenção e combate à violência doméstica, entre as quais a alteração do modelo de documento comprovativo da atribuição do estatuto de vítima previsto no n.º 1 do artigo 14.º da Lei n.º 112/2009, de 16 de setembro, na sua redação atual, aprovado pela Portaria n.º 229-A/2010, de 23 de abril.
  A presente portaria visa, assim, solucionar os constrangimentos verificados na prática com a atribuição de dois estatutos de vítima distintos às vítimas de violência doméstica: o decorrente da Lei n.º 112','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('/2009, de 16 de setembro, na sua redação atual, e o previsto para as vítimas especialmente vulneráveis, decorrente da Lei n.º 130/2015, de 4 de setembro.
  A presente portaria tem ainda como objetivo consagrar os modelos que devem ser utilizados para efeitos de atribuição do estatuto de vítima e de atribuição do estatuto de vítima especialmente vulnerável, de acordo com as disposições previstas no Anexo à Lei n.º 130/2015, de 4 de setembro.
  Atendendo ainda à existência de direitos específicos, consagrados na legislação em vigor, previstos para outras vítimas especialmente vulneráveis, como sejam as vítimas de tráfico de pessoas, de auxílio à imigração ilegal (Lei n.º 23/2007, de 4 de julho, na sua redação atual) e de terrorismo (Lei n.º 52/2003, de 22 de agosto, na sua redação atual), os mesmos foram igualmente tidos em conta no modelo respetivo.
  Por força do n.º 4 do artigo 14.º da Lei n.º 112/2009, de 16 de setembro, na sua redação atual, em circunstâncias excecionais e devidamente fundamentadas, o estatuto de vítima de violência doméstica pode ser atribuído pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, pelo que o modelo de documento comprovativo de atribuição deste estatuto de vítima, igualmente previsto na Portaria n.º 229-A/2010, de 23 de abril, é também agora objeto de atualização.
  Qualquer que seja a natureza do crime sofrido ou a fragilidade especial da vítima, é-lhe garantido, nos termos da presente portaria, independentemente da sua ascendência, nacionalidade, condição social, sexo, etnia, raça, idade, religião, deficiência, convicções políticas ou ideológicas, orientação sexual e identidade de género, cultura e do nível educacional, a atribuição de um de três modelos de estatuto de vítima de crime: estatuto de vítima, estatuto de vítima especialmente vulnerável, incluindo por crime de violência doméstica, ou o estatuto de vítima de violência doméstica atribuído pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género.
  Assim, nos termos conjugados do n.º 2 do artigo 20.º do Anexo à Lei n.º 130/2015, de 4 de setembro, do n.º 2 do artigo 83.º da Lei n.º 112/2009, de 16 de setembro, na sua redação atual, e da alínea c) do artigo 199.º da Constituição, manda o Governo, pela Ministra de Estado e da Presidência, pelo Ministro da Administração Interna e pela Ministra da Justiça, o seguinte:
  
  Artigo 1.º 
Objeto
                            
                           
                             
                               
                             
     A presente portaria aprova os modelos dos documentos comprovativos da atribuição do estatuto de vítima e do estatuto de vítima especialmente vulnerável, incluindo por crime de violência doméstica, de acordo com as disposições previstas no Anexo à Lei n.º 130/2015, de 4 de setembro, e no n.º 1 do artigo 14.º, bem como o modelo do documento comprovativo da atribuição do estatuto d','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('e vítima de violência doméstica previsto no n.º 4 do artigo 14.º, ambos da Lei n.º 112/2009, de 16 de setembro, na sua redação atual.            
         
   
     
                         
                          
  Artigo 2.º 
Âmbito de aplicação
                            
                           
                             
                               
                             
     1 - O modelo do documento comprovativo da atribuição do estatuto de vítima nos termos do disposto nos capítulos i, ii e iii do Anexo à Lei n.º 130/2015, de 4 de setembro, aplica-se a todas as vítimas de crime, com exceção das abrangidas pelo modelo do documento comprovativo da atribuição do estatuto de vítima especialmente vulnerável, e consta no anexo i à presente portaria, que dela faz parte integrante.
  2 - O modelo do documento comprovativo da atribuição do estatuto de vítima especialmente vulnerável nos termos do disposto no capítulo iv do Anexo à Lei n.º 130/2015, de 4 de setembro, aplica-se nas seguintes situações, e consta no anexo ii à presente portaria, que dela faz parte integrante:
  a) Às vítimas de criminalidade violenta ou especialmente violenta, conforme previsto nas alíneas j) e l) do artigo 1.º e nos n.os 3 e 4 do artigo 67.º-A, ambos do Código de Processo Penal, na sua atual redação, nomeadamente, por crime de:
  i) Violência doméstica;
  ii) Tráfico de pessoas/auxílio à imigração ilegal;
  iii) Terrorismo;
  b) Às demais vítimas de crime, conforme previsto na alínea b) do n.º 1 do artigo 67.º-A do Código de Processo Penal, após realização da avaliação individual a que alude o n.º 1 do artigo 20.º da Lei n.º 130/2015, de 4 de setembro, por situação de particular fragilidade resultante, nomeadamente, da idade, do seu estado de saúde ou de deficiência, bem como do facto de o tipo, o grau e a duração da vitimização haver resultado em lesões com consequências graves no seu equilíbrio psicológico ou nas condições da sua integração social.
  3 - O modelo do documento comprovativo da atribuição do estatuto de vítima de violência doméstica, em situações excecionais e devidamente fundamentadas, pelo organismo da Administração Pública responsável pela área da cidadania e da igualdade de género, nos termos do disposto no n.º 4 do artigo 14.º da Lei n.º 112/2009, de 16 de setembro, na sua redação atual, aplica-se às vítimas de violência doméstica, e consta no anexo iii à presente portaria, que dela faz parte integrante.
  4 - Nas situações previstas no n.º 2, o modelo do documento comprovativo da atribuição do estatuto de vítima especialmente vulnerável tem uma configuração variável, incluindo, na parte final, os direitos e deveres específicos do tipo de criminalidade em causa.
  5 - Sem prejuízo do disposto nos números anteriores, sempre que nos termos da lei sejam criados ou constituídos novos direitos ou deveres, as entidades com competência para a atribuição dos estatutos de vítima devem proceder à sua inserção no respetivo documento c','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('omprovativo.            
         
   
     
                         
                          
  Artigo 3.º 
Emissão
                            
                           
                             
                               
                             
     1 - O documento comprovativo da atribuição do estatuto de vítima e do estatuto de vítima especialmente vulnerável, incluindo por crime de violência doméstica, é entregue às vítimas pelas autoridades judiciárias ou pelos órgãos de polícia criminal.
  2 - Sem prejuízo do número anterior, em situações excecionais e devidamente fundamentadas previstas no n.º 4 do artigo 14.º da Lei n.º 112/2009, de 16 de setembro, na sua redação atual, o documento comprovativo da atribuição do estatuto de vítima de violência doméstica é entregue pela Comissão para a Cidadania e a Igualdade de Género, por iniciativa própria ou mediante requerimento fundamentado das estruturas ou respostas que integram a Rede Nacional de Apoio às Vítimas de Violência Doméstica.
  3 - Compete ao presidente da Comissão para a Cidadania e a Igualdade de Género fixar, por despacho, os critérios que fundamentam as situações excecionais previstas no n.º 4 do artigo 14.º da Lei n.º 112/2009, de 16 de setembro, na sua redação atual.
  4 - Compete à Comissão para a Cidadania e a Igualdade de Género, em articulação com as entidades e os órgãos previstos no n.º 1, garantir a produção dos suportes de informação a que se refere o n.º 1 do artigo 4.º da presente portaria, e a respetiva atualização, no que respeita aos crimes de violência doméstica e de tráfico de pessoas.
  5 - A obtenção dos documentos comprovativos da atribuição dos estatutos de vítima previstos no presente artigo é gratuita.
  6 - Sempre que solicitado, os documentos comprovativos da atribuição dos estatutos de vítima devem ser exibidos, em simultâneo, com documento oficial de identificação.            
         
   
     
                         
                          
  Artigo 4.º 
Direito à informação
                            
                           
                             
                               
                             
     1 - Às vítimas de crime deve ser garantido, desde o seu primeiro contacto com as autoridades policiais ou judiciárias, inclusivamente no momento anterior à apresentação da denúncia, e sem atrasos injustificados, o acesso a informações sobre os seus direitos.
  2 - Na comunicação a estabelecer com as vítimas devem ser tomadas as medidas necessárias para garantir que estas compreendam e sejam compreendidas, desde o primeiro contacto e durante todos os outros contactos com as autoridades competentes no âmbito do processo penal.            
         
   
     
                         
                          
  Artigo 5.º 
Norma revogatória
                            
                           
                             
                               
                             
     É revogada a  ','443');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Portaria n.º 229-A/2010, de 23 de abril.            
         
   
     
                         
                          
  Artigo 6.º 
Entrada em vigor
                            
                           
                             
                               
                             
     A presente portaria entra em vigor 60 dias após a sua publicação.
  
  A Ministra de Estado e da Presidência, Mariana Guimarães Vieira da Silva, em 30 de junho de 2021. - O Ministro da Administração Interna, Eduardo Arménio do Nascimento Cabrita, em 29 de junho de 2021. - A Ministra da Justiça, Francisca Eugénia da Silva Dias Van Dunem, em 30 de junho de 2021.            
         
   
     
                         
                          
  ANEXO I 
Modelo do documento comprovativo da atribuição do estatuto de vítima pelas autoridades judiciárias e pelos órgãos de polícia criminal, a que se refere o n.º 1 do artigo 2.º da presente portaria
                            
                           
                             
                               
                             
     (ver documento original)            
         
   
     
                         
                          
  ANEXO II 
Modelo do documento comprovativo da atribuição do estatuto de vítima especialmente vulnerável, incluindo por crime de violência doméstica, pelas autoridades judiciárias e pelos órgãos de polícia criminal, a que se refere o n.º 2 do artigo 2.º da presente portaria
                            
                           
                             
                               
                             
     (ver documento original)            
         
   
     
                         
                          
  ANEXO III 
Modelo do documento comprovativo da atribuição do estatuto de vítima de violência doméstica pela Comissão para a Cidadania e a Igualdade de Género, a que se refere o n.º 3 do artigo 2.º da presente portaria
                            
                           
                             
                               
                             
     (ver documento original)','443');
